function queryDatabase(sql, params = []) {
    return new Promise((resolve, reject) => {
        db.query(sql, params, (error, results) => {
            if (error) {
                reject(error);
            } else {
                resolve(results);
            }
        });
    });
}

function validateStuklijstLine(line) {
    const required = ['aantal', 'houtsoort', 'dikte', 'breedte', 'lengte'];
    const validation = required.map(field => ({
        field,
        value: line[field],
        valid: line[field] !== undefined && line[field] !== null && line[field] !== ''
    }));
    
    return required.every(field => {
        const value = line[field];
        return value !== undefined && value !== null && value !== '';
    });
}



function generateAllPatternsForStockType(stk, pieceTypes) {
    const patterns = [];

    pieceTypes.forEach(piece => {
        const currentPieces = [];
        
        // Begin met een front cut van 50mm
        let usedLength = FRONT_CUT;

        for (let i = 0; i < MAX_PATTERN_SIZE; i++) {
            // Bepaal de lengte voor dit volgende stuk
            const requiredLength = piece.length + (currentPieces.length > 0 ? SAW_THICKNESS : 0);

            // Check of we nog een stuk plus de BACK_CUT kunnen toevoegen binnen de totale lengte
            if (usedLength + requiredLength + BACK_CUT <= stk.lengte) {
                // Stuk past
                currentPieces.push({ ...piece });
                usedLength += requiredLength;
            } else {
                // Past niet meer
                break;
            }
        }

        // Als we minstens één stuk hebben
        if (currentPieces.length > 0) {
            // Tel de BACK_CUT op
            usedLength += BACK_CUT;

            const waste = stk.lengte - usedLength;
            const efficiency = usedLength / stk.lengte;
            patterns.push({
                pieces: [...currentPieces],
                waste: waste,
                efficiency: efficiency
            });
        }
    });

    console.log(`Generated ${patterns.length} valid patterns for stock length ${stk.lengte}`);
    if (patterns.length > 0) {
        console.log('Sample patterns:', 
            patterns.slice(0, 3).map(p => ({
                numPieces: p.pieces.length,
                totalLength: stk.lengte - p.waste,
                waste: p.waste,
                efficiency: p.efficiency
            }))
        );
    }

    return patterns;
}


// Optimalisatie probleem setup functie
function setupOptimizationProblem(usableStock, pieceTypes) {
    const lp = {
        optimize: "totalWaste",
        opType: "min",
        constraints: {},
        variables: {},
        ints: {}
    };

    console.log('\nSetting up optimization problem:');
    console.log('Piece requirements:', pieceTypes);
    console.log('Available stock:', usableStock);

    // Requirements constraints met 10% overproductie toegestaan
    pieceTypes.forEach((piece, index) => {
        const constraintName = `req_${index}`;
        lp.constraints[constraintName] = { 
            min: piece.required,
            max: piece.required * 1.1
        };
        console.log(`Added requirement constraint: ${constraintName}`, lp.constraints[constraintName]);
    });

    // Verwerk elke voorraadplank
    usableStock.forEach((stk, stockIndex) => {
        const patterns = generateAllPatternsForStockType(stk, pieceTypes);
        const stockConstraintName = `stock_${stockIndex}`;
        lp.constraints[stockConstraintName] = { max: stk.aantal };

        patterns.forEach((pattern, patternIndex) => {
            const varName = `x_${stockIndex}_${patternIndex}`;
            
            // Variabele voor dit zaagpatroon
            lp.variables[varName] = {
                totalWaste: pattern.waste * stk.aantal
            };
            lp.ints[varName] = 1;
            
            // Tel hoeveel van elk stuk in dit patroon zit
            const pieceCounts = {};
            pattern.pieces.forEach(piece => {
                pieceCounts[piece.id] = (pieceCounts[piece.id] || 0) + 1;
            });

            // Voeg bij aan requirements constraints
            pieceTypes.forEach((_, pieceIndex) => {
                if (pieceCounts[pieceIndex]) {
                    const reqConstraintName = `req_${pieceIndex}`;
                    if (!lp.variables[varName][reqConstraintName]) {
                        lp.variables[varName][reqConstraintName] = 0;
                    }
                    lp.variables[varName][reqConstraintName] = pieceCounts[pieceIndex];
                }
            });

            // Stock constraint
            lp.variables[varName][stockConstraintName] = 1;
            
            console.log(`Added pattern variable: ${varName}`, {
                waste: pattern.waste,
                pieceCounts,
                totalWaste: pattern.waste * stk.aantal
            });
        });
    });

    return lp;
}

// Group requirements by dimensions
function groupRequirements(reqs) {
    const map = new Map();
    for (const r of reqs) {
        const key = `${r.houtsoort}_${r.dikte}_${r.breedte}`;
        if (!map.has(key)) map.set(key, []);
        map.get(key).push(r);
    }
    return map;
}

