// Route handler voor optimalisatie
app.get('/api/optimal_cutting_plan', async (req, res) => {
    console.log('\n=== Starting Optimization Request ===');
    const orderId = parseInt(req.query.orderId);
    
    if (isNaN(orderId) || orderId <= 0) {
        return res.status(400).json({
            success: false,
            message: 'Invalid orderId provided'
        });
    }

    try {
        // Haal order items op
        const orderItems = await queryDatabase(
            "SELECT * FROM order_items WHERE order_id = ?",
            [orderId]
        );

        if (!orderItems || orderItems.length === 0) {
            return res.status(404).json({
                success: false,
                message: "No order items found for this order"
            });
        }

        // Verwerk requirements
        let requirementsMap = new Map();
        for (const item of orderItems) {
            if (item.stuklijst && item.stuklijst.trim() !== '') {
                try {
                    const stuklijst = JSON.parse(item.stuklijst);
                    
                    for (const line of stuklijst) {
                        if (!validateStuklijstLine(line)) {
                            return res.status(400).json({
                                success: false,
                                message: "Missing required fields in stuklijst",
                                itemId: item.id,
                                line: line
                            });
                        }

                        const needed = line.aantal * item.hoeveelheid;
                        const key = `${line.houtsoort}_${line.dikte}_${line.breedte}_${line.lengte}`;

                        if (!requirementsMap.has(key)) {
                            requirementsMap.set(key, {
                                houtsoort: line.houtsoort,
                                dikte: line.dikte,
                                breedte: line.breedte,
                                lengte: line.lengte,
                                needed: needed
                            });
                        } else {
                            requirementsMap.get(key).needed += needed;
                        }
                    }
                } catch (e) {
                    return res.status(400).json({
                        success: false,
                        message: "Invalid stuklijst format",
                        itemId: item.id,
                        error: e.message
                    });
                }
            }
        }

        const requirements = Array.from(requirementsMap.values());
        if (requirements.length === 0) {
            return res.json({
                success: true,
                message: "Geen stuklijst nodig voor deze order."
            });
        }

        // Haal voorraad op
        const stockRows = await queryDatabase("SELECT * FROM hout_stock");
        if (!stockRows || stockRows.length === 0) {
            return res.status(404).json({
                success: false,
                message: "No stock items available"
            });
        }

        // Groepeer requirements
        const reqGroups = groupRequirements(requirements);
        const finalSolution = [];
        
        // Process each group
        for (const [groupKey, reqGroup] of reqGroups) {
            const [gSoort, gDikte, gBreedte] = groupKey.split('_');
            const parsedDikte = parseFloat(gDikte);
            const parsedBreedte = parseFloat(gBreedte);

            // Map en filter bruikbare voorraad
            const usableStock = stockRows
                .map(s => ({
                    id: s.id,
                    soort: s.soort,
                    dikte: s.dikte,
                    breedte: s.breedte,
                    lengte: s.lengte,
                    locatie: s.locatie,
                    aantal: s.aantal
                }))
                .filter(stk => 
                    stk.soort.toLowerCase() === gSoort.toLowerCase() &&
                    stk.dikte >= parsedDikte &&
                    stk.breedte >= parsedBreedte &&
                    stk.aantal > 0
                );

            if (usableStock.length === 0) {
                finalSolution.push({
                    group: groupKey,
                    message: "Geen bruikbare voorraad gevonden."
                });
                continue;
            }

            // Maak piece types voor deze groep
            const pieceTypes = reqGroup.map((r, idx) => ({
                id: idx,
                length: r.lengte,
                required: r.needed
            }));

            try {
                // Setup en los het optimalisatie probleem op
                const lp = setupOptimizationProblem(usableStock, pieceTypes);
                console.log('\nAttempting to solve LP problem...');
                const results = Solver.Solve(lp);
                console.log('Solver results:', results);

                if (!results || !results.feasible) {
                    finalSolution.push({
                        group: groupKey,
                        message: "Geen oplossing gevonden.",
                        debug: {
                            numPieces: pieceTypes.length,
                            totalRequired: pieceTypes.reduce((sum, p) => sum + p.required, 0),
                            availableStock: usableStock.map(s => ({
                                length: s.lengte,
                                aantal: s.aantal
                            }))
                        }
                    });
                    continue;
                }

                // Verwerk resultaten
                const groupSolution = { 
                    group: groupKey, 
                    usedPlanks: []
                };

                // Verwerk gebruikte planken
                for (const variable in results) {
                    if (variable.startsWith('x_') && results[variable] > 0) {
                        const [, stockIndex, patternIndex] = variable.split('_').map(Number);
                        const stockItem = usableStock[stockIndex];
                        const patterns = generateAllPatternsForStockType(stockItem, pieceTypes);
                        const pattern = patterns[patternIndex];

                        if (pattern) {
                            groupSolution.usedPlanks.push({
                                plank: stockItem,
                                pattern: pattern,
                                count: Math.round(results[variable])
                            });
                        }
                    }
                }

                // Bereken statistieken
                const groupStats = {
                    totalWood: 0,
                    totalWaste: 0,
                    totalCuts: 0
                };

                groupSolution.usedPlanks.forEach(usedPlank => {
                    const piecesLength = usedPlank.pattern.pieces.reduce((sum, p) => sum + p.length, 0);
                    const cuts = usedPlank.pattern.pieces.length - 1;
                    const sawLoss = cuts * SAW_THICKNESS;
                    const waste = usedPlank.plank.lengte - (piecesLength + sawLoss);

                    groupStats.totalWood += usedPlank.plank.lengte * usedPlank.count;
                    groupStats.totalWaste += waste * usedPlank.count;
                    groupStats.totalCuts += cuts * usedPlank.count;
                });

                groupSolution.statistics = {
                    ...groupStats,
                    wastePercentage: (groupStats.totalWaste / groupStats.totalWood * 100).toFixed(2)
                };

                finalSolution.push(groupSolution);

            } catch (error) {
                console.error('Optimization error:', error);
                finalSolution.push({
                    group: groupKey,
                    message: "Error during optimization",
                    error: error.message
                });
            }
        }

        const overallStats = {
            totalWood: 0,
            totalWaste: 0,
            totalCuts: 0,
            groupsWithSolutions: 0
        };

        finalSolution.forEach(groupSol => {
            if (groupSol.statistics) {
                overallStats.totalWood += groupSol.statistics.totalWood;
                overallStats.totalWaste += groupSol.statistics.totalWaste;
                overallStats.totalCuts += groupSol.statistics.totalCuts;
                overallStats.groupsWithSolutions++;
            }
        });

        if (overallStats.totalWood > 0) {
            overallStats.averageWastePercentage = 
                (overallStats.totalWaste / overallStats.totalWood * 100).toFixed(2);
        }

        return res.json({
            success: true,
            solution: finalSolution,
            overallStats: overallStats
        });

    } catch (error) {
        console.error('Critical error:', error);
        return res.status(500).json({
            success: false,
            message: "Internal server error",
            error: error.message
        });
    }
});
        
        


    
            
            

