// Aanname: je hebt een app.post('/api/register') al, we passen hem aan:

app.post('/api/register', (req, res) => {
    const { username, password } = req.body;

    db.query('SELECT id FROM users WHERE username = ?', [username], (err, results) => {
        if (err) {
            console.error('Database error:', err);
            return res.status(500).json({ error: 'Database error' });
        }

        if (results.length > 0) {
            return res.status(400).json({ error: 'Gebruikersnaam bestaat al' });
        }

        bcrypt.hash(password, 10, (err, hash) => {
            if (err) {
                console.error('Error hashing password:', err);
                return res.status(500).json({ error: 'Server error' });
            }

            // Stel de rol in op 'pending' zodat een admin deze later kan goedkeuren
            db.query('INSERT INTO users (username, password, role) VALUES (?, ?, ?)', [username, hash, 'pending'], (err, result) => {
                if (err) {
                    console.error('Database error:', err);
                    return res.status(500).json({ error: 'Database error' });
                }

                const mailOptions = {
                    from: 'jason@prodwilrijk.be',
                    to: 'jasonploegaerts@gmail.com',
                    subject: 'Nieuwe Registratie Goedkeuren',
                    html: `
                        <h3>Nieuwe Gebruiker Registratie</h3>
                        <p><strong>Gebruikersnaam:</strong> ${username}</p>
                        <p>Ga naar de admin pagina om deze gebruiker goed te keuren (rol aanpassen).</p>
                    `
                };

                transporter.sendMail(mailOptions, (error, info) => {
                    if (error) {
                        console.error('Error sending mail:', error);
                        // Registratie is wel gelukt, mail niet.
                    } else {
                        console.log('Email sent:', info.response);
                    }

                    res.json({ message: 'Registratie ontvangen. Een admin zal je goedkeuren voordat je kunt inloggen.' });
                });
            });
        });
    });
});




