// Tasks
app.get('/api/tasks', isAuthenticated, (req, res) => {
    const query = `
        SELECT *
        FROM tasks
        WHERE
          (
            frequency = 'daily'
            AND (lastCompleted IS NULL OR DATE(lastCompleted) < CURDATE())
          ) OR (
            frequency = 'weekly'
            AND (lastCompleted IS NULL OR DATE(lastCompleted) < DATE_SUB(CURDATE(), INTERVAL 7 DAY))
          ) OR (
            frequency = 'monthly'
            AND (lastCompleted IS NULL OR DATE(lastCompleted) < DATE_SUB(CURDATE(), INTERVAL 30 DAY))
          )
        ORDER BY id DESC
    `;

    db.query(query, (err, tasks) => {
        if (err) return res.status(500).json({ error: 'Database error' });
        db.query('SELECT * FROM completed_tasks ORDER BY completedAt DESC', (err, completed) => {
            if (err) return res.status(500).json({ error: 'Database error' });

            // Verwerk tasks om tags te converteren naar een array
            const processedTasks = tasks.map(task => {
                if (task.tags && typeof task.tags === 'string') {
                    // Splits de string op komma's, trim de resultaten, en filter lege strings
                    task.tags = task.tags.split(',').map(tag => tag.trim()).filter(tag => tag.length > 0) || [];
                } else if (!task.tags) {
                    // Als tags undefined of null is, maak een lege array
                    task.tags = [];
                }
                return task;
            });

            // Verwerk completedTasks op dezelfde manier
            const processedCompletedTasks = completed.map(task => {
                if (task.tags && typeof task.tags === 'string') {
                    task.tags = task.tags.split(',').map(tag => tag.trim()).filter(tag => tag.length > 0) || [];
                } else if (!task.tags) {
                    task.tags = [];
                }
                return task;
            });

            res.json({ tasks: processedTasks || [], completedTasks: processedCompletedTasks || [] });
        });
    });
});



