// Saw Maintenance remains unchanged
app.get('/api/saw_maintenance', async (req, res) => {
  try {
    const query = `
        SELECT 
            s.*,
            COALESCE(
                JSON_ARRAYAGG(
                    IF(br.id IS NOT NULL,
                        JSON_OBJECT(
                            'id', br.id,
                            'replacement_date', DATE_FORMAT(br.replacement_date, '%Y-%m-%d'),
                            'blade_type', br.blade_type,
                            'technician', br.technician,
                            'notes', br.notes
                        ),
                        NULL
                    )
                ),
                JSON_ARRAY()
            ) as blade_logs,
            COALESCE(
                JSON_ARRAYAGG(
                    IF(ml.id IS NOT NULL,
                        JSON_OBJECT(
                            'id', ml.id,
                            'maintenance_date', DATE_FORMAT(ml.maintenance_date, '%Y-%m-%d'),
                            'maintenance_type', ml.maintenance_type,
                            'technician', ml.technician,
                            'description', ml.description,
                            'resolution', ml.resolution,
                            'status', ml.status,
                            'cost', ml.cost
                        ),
                        NULL
                    )
                ),
                JSON_ARRAY()
            ) as maintenance_logs
        FROM saws s
        LEFT JOIN blade_replacements br ON s.id = br.saw_id
        LEFT JOIN saw_maintenance_logs ml ON s.id = ml.saw_id
        GROUP BY s.id`;

    const saws = await new Promise((resolve, reject) => {
      db.query(query, (err, results) => {
        if (err) {
          console.error('Error fetching saws:', err);
          return reject(err);
        }
        
        results.forEach(saw => {
          try {
            if (saw.blade_logs === null || saw.blade_logs === 'null') {
              saw.blade_logs = [];
            } else {
              const parsed = JSON.parse(saw.blade_logs);
              saw.blade_logs = parsed.filter(log => log !== null && log.id !== null);
            }
            
            if (saw.maintenance_logs === null || saw.maintenance_logs === 'null') {
              saw.maintenance_logs = [];
            } else {
              const parsed = JSON.parse(saw.maintenance_logs);
              saw.maintenance_logs = parsed.filter(log => log !== null && log.id !== null);
            }
          } catch (e) {
            console.error('Error parsing logs for saw:', saw.id, e);
            saw.blade_logs = [];
            saw.maintenance_logs = [];
          }
        });
        resolve(results);
      });
    });

    res.json(saws);
  } catch (error) {
    console.error('Error in /api/saw_maintenance:', error);
    res.status(500).json({ error: 'Database error', details: error.message });
  }
});

