// Socket.io setup
const http = require('http');
const server = http.createServer(app);
const { Server } = require('socket.io');

const io = new Server(server, {
    cors: {
        origin: [
            "https://prodwilrijk.be:25022",
            "https://prodwilrijk.be", 
            "http://prodwilrijk.be:25022",
            "http://prodwilrijk.be"
        ],
        methods: ["GET", "POST", "OPTIONS"],
        credentials: true,
        allowedHeaders: ["Content-Type", "Authorization", "Cookie"]
    },
    transports: ['websocket', 'polling'],
    allowEIO3: true,
    pingTimeout: 60000,
    pingInterval: 25000
});

// Sessies integreren met Socket.io
io.use((socket, next) => {
    const cookieString = socket.handshake.headers.cookie;
    if (!cookieString) return next(new Error("No cookie transmitted"));

    const match = cookieString.match(/connect\.sid=s%3A([^;]+)/);
    if (!match) return next(new Error("Session not found"));

    const sessionId = match[1].split('.')[0];
    sessionStore.get(sessionId, (err, session) => {
        if (err || !session) {
            return next(new Error("Session not found"));
        }
        if (session.user) {
            socket.user = session.user;
            next();
        } else {
            next(new Error("Not authenticated"));
        }
    });
});

io.on('connection', (socket) => {
    console.log('User connected:', socket.user.username);

    // ==================== EXISTING MESSAGE HANDLERS ====================
    socket.on('send_message', (data) => {
        const { receiverId, message, fileUrl } = data;
        const senderId = socket.user.id;

        db.query('INSERT INTO messages (sender_id, receiver_id, message, fileUrl) VALUES (?, ?, ?, ?)',
            [senderId, receiverId, message || '', fileUrl || null],
            (err, result) => {
                if (err) {
                    console.error('Error inserting message:', err);
                    return;
                }

                const msg = {
                    id: result.insertId,
                    sender_id: senderId,
                    receiver_id: receiverId,
                    message: message,
                    fileUrl: fileUrl || null,
                    timestamp: new Date(),
                    read: false
                };

                // Send to receiver if online
                for (const [id, s] of io.sockets.sockets) {
                    if (s.user && s.user.id === parseInt(receiverId, 10)) {
                        s.emit('receive_message', msg);
                    }
                }

                // Send back to sender so it appears immediately
                socket.emit('message_sent', msg);
            }
        );
    });

    // ==================== NEW TASK MANAGEMENT HANDLERS ====================
    
    // Join task updates room
    socket.on('join_tasks', () => {
        socket.join('task_updates');
        console.log(`User ${socket.user.username} joined task updates room`);
    });
    
    // Handle cursor movements for live collaboration
    socket.on('cursor:move', (data) => {
        // Add user info to the cursor data
        const cursorData = {
            ...data,
            user_id: socket.user.id,
            username: socket.user.username,
            full_name: socket.user.full_name || socket.user.username
        };
        
        // Broadcast to all other users in the task updates room
        socket.to('task_updates').emit('cursor:move', cursorData);
    });
    
    // Handle task creation
    socket.on('task:create', (task) => {
        // Broadcast to all other users
        socket.to('task_updates').emit('task:created', {
            ...task,
            created_by_name: socket.user.full_name || socket.user.username
        });
        
        console.log(`Task created by ${socket.user.username}: ${task.title}`);
    });
    
    // Handle task updates
    socket.on('task:update', (task) => {
        // Broadcast to all other users
        socket.to('task_updates').emit('task:updated', {
            ...task,
            updated_by: socket.user.id,
            updated_by_name: socket.user.full_name || socket.user.username
        });
        
        console.log(`Task updated by ${socket.user.username}: ${task.id}`);
    });
    
    // Handle task deletion
    socket.on('task:delete', (taskId) => {
        // Broadcast to all other users
        socket.to('task_updates').emit('task:deleted', taskId);
        
        console.log(`Task ${taskId} deleted by ${socket.user.username}`);
    });
    
    // Handle comment addition
    socket.on('comment:add', (comment) => {
        // Broadcast to all other users
        socket.to('task_updates').emit('comment:added', {
            ...comment,
            author_name: socket.user.full_name || socket.user.username
        });
        
        console.log(`Comment added by ${socket.user.username} on task ${comment.task_id}`);
    });

    // Handle user typing in task
    socket.on('task:typing', (data) => {
        socket.to('task_updates').emit('task:user_typing', {
            task_id: data.task_id,
            user_id: socket.user.id,
            username: socket.user.username,
            is_typing: data.is_typing
        });
    });

    // Handle user viewing task
    socket.on('task:viewing', (taskId) => {
        socket.to('task_updates').emit('task:user_viewing', {
            task_id: taskId,
            user_id: socket.user.id,
            username: socket.user.username,
            full_name: socket.user.full_name || socket.user.username
        });
    });

    // Leave task updates room
    socket.on('leave_tasks', () => {
        socket.leave('task_updates');
        console.log(`User ${socket.user.username} left task updates room`);
    });

    // ==================== DISCONNECT HANDLER ====================
    socket.on('disconnect', () => {
        console.log('User disconnected:', socket.user.username);
        
        // Notify others that this user's cursor should be removed
        socket.to('task_updates').emit('cursor:remove', {
            user_id: socket.user.id
        });
        
        // Notify others that this user stopped viewing any task
        socket.to('task_updates').emit('task:user_stopped_viewing', {
            user_id: socket.user.id
        });
    });
});

// Add maintenance logs
app.post('/api/saw_maintenance/add_maintenance_log', async (req, res) => {
    try {
        const { 
            saw_id, 
            maintenance_date, 
            maintenance_type, 
            technician, 
            description, 
            resolution, 
            status,
            cost 
        } = req.body;

        if (!saw_id || !maintenance_date || !maintenance_type || !technician || !description) {
            return res.status(400).json({ error: 'Missing required fields' });
        }

        const query = `
            INSERT INTO saw_maintenance_logs 
            (saw_id, maintenance_date, maintenance_type, technician, description, resolution, status, cost) 
            VALUES (?, ?, ?, ?, ?, ?, ?, ?)
        `;
        
        await new Promise((resolve, reject) => {
            db.query(query, [
                saw_id, 
                maintenance_date, 
                maintenance_type, 
                technician, 
                description, 
                resolution || null, 
                status || 'completed',
                cost || null
            ], (err, result) => {
                if (err) {
                    console.error('Error adding maintenance log:', err);
                    return reject(err);
                }
                resolve(result);
            });
        });

        res.json({ success: true });
    } catch (error) {
        console.error('Error in /api/saw_maintenance/add_maintenance_log:', error);
        res.status(500).json({ error: 'Database error', details: error.message });
    }
});

