// Task stats endpoint
app.get('/api/task_stats', isAuthenticated, (req, res) => {
    const dueTodayQuery = `
        SELECT COUNT(*) AS count FROM tasks
        WHERE dueDate = CURDATE()
        AND (
            lastCompleted IS NULL
            OR (frequency = 'daily' AND DATE(lastCompleted) <= DATE_SUB(CURDATE(), INTERVAL 1 DAY))
            OR (frequency = 'weekly' AND DATE(lastCompleted) <= DATE_SUB(CURDATE(), INTERVAL 1 WEEK))
            OR (frequency = 'monthly' AND DATE(lastCompleted) <= DATE_SUB(CURDATE(), INTERVAL 1 MONTH))
        )
    `;
    db.query(dueTodayQuery, (err, dueTodayRes) => {
        if (err) {
            console.error('Error fetching dueToday:', err);
            return res.status(500).json({ error: 'Database error' });
        }

        const overdueQuery = `
            SELECT COUNT(*) AS count FROM tasks
            WHERE dueDate < CURDATE()
            AND (
                lastCompleted IS NULL
                OR (frequency = 'daily' AND DATE(lastCompleted) <= DATE_SUB(CURDATE(), INTERVAL 1 DAY))
                OR (frequency = 'weekly' AND DATE(lastCompleted) <= DATE_SUB(CURDATE(), INTERVAL 1 WEEK))
                OR (frequency = 'monthly' AND DATE(lastCompleted) <= DATE_SUB(CURDATE(), INTERVAL 1 MONTH))
            )
        `;
        db.query(overdueQuery, (err, overdueRes) => {
            if (err) {
                console.error('Error fetching overdue:', err);
                return res.status(500).json({ error: 'Database error' });
            }

            const completedThisWeekQuery = `
                SELECT COUNT(*) AS count FROM completed_tasks
                WHERE completedAt >= DATE_SUB(CURDATE(), INTERVAL 7 DAY)
            `;
            db.query(completedThisWeekQuery, (err, completedRes) => {
                if (err) {
                    console.error('Error fetching completedThisWeek:', err);
                    return res.status(500).json({ error: 'Database error' });
                }

                res.json({
                    dueToday: dueTodayRes[0].count,
                    overdue: overdueRes[0].count,
                    completedThisWeek: completedRes[0].count
                });
            });
        });
    });
});

// GET /api/cnh_sessions
app.get('/api/cnh_sessions', async (req, res) => {
  try {
    const sql=`
      SELECT s.*,
             sm.motor_id,
             m.motor_nr,
             m.shipping_note
      FROM cnh_sessions s
      LEFT JOIN cnh_session_motors sm ON s.id=sm.session_id
      LEFT JOIN cnh_motors m ON sm.motor_id=m.id
      ORDER BY s.id DESC
    `;
    const rows=await queryPromise(sql);
    const sessionsById={};
    rows.forEach(r=>{
      if(!sessionsById[r.id]){
        sessionsById[r.id]={
          id:               r.id,
          location:         r.location,
          loading_minutes:  r.loading_minutes,
          loading_count:    r.loading_count,
          loading_persons:  r.loading_persons,
          load_reference:   r.load_reference,
          container_no:     r.container_no,
          truck_plate:      r.truck_plate,
          // Nieuw:
          booking_ref:      r.booking_ref||'',
          your_ref:         r.your_ref||'',
          // Container tarra
          container_tarra:  r.container_tarra || null,

          created_at:       r.created_at,
          packaging_minutes:r.packaging_minutes,
          packaging_count:  r.packaging_count,
          packaging_persons:r.packaging_persons,
          motors:[]
        };
      }
      if(r.motor_id){
        sessionsById[r.id].motors.push({
          motor_id:      r.motor_id,
          motor_nr:      r.motor_nr,
          shipping_note: r.shipping_note
        });
      }
    });
    const sessionsArray=Object.values(sessionsById);
    res.json(sessionsArray);
  } catch(e){
    console.error('Error /api/cnh_sessions join:', e);
    res.status(500).json({ error:'DB error cnh_sessions join' });
  }
});


// In je Node/Express code:
app.post('/api/cnh_session/cancel_load', async (req, res) => {
  const { sessionId } = req.body;
  if (!sessionId) {
    return res.status(400).json({ success: false, error: 'sessionId is vereist' });
  }
  try {
    // 1) zoek in DB of sessie bestaat
    const sql = 'SELECT * FROM cnh_sessions WHERE id=? LIMIT 1';
    const rows = await queryPromise(sql, [ sessionId ]);
    if (!rows.length) {
      return res.status(404).json({ success: false, error: 'Load-sessie niet gevonden' });
    }

    // 2) update DB, markeer sessie als geannuleerd
    await queryPromise(`
      UPDATE cnh_sessions
      SET state = 'cancelled'
      WHERE id = ?
    `, [ sessionId ]);

    // 3) return succes
    return res.json({ success: true });
  } catch(e) {
    console.error('cancel_load error:', e);
    return res.status(500).json({ success: false, error: e.message });
  }
});



app.post('/api/cnh_sessions/email_load_overview', async (req, res) => {
    const { sessionId, toEmail } = req.body;
    if (!sessionId || !toEmail) {
      return res.status(400).json({ error: 'sessionId en toEmail zijn vereist' });
    }

    try {
      // 1) Data ophalen
      const sql = `
        SELECT s.*,
               sm.motor_id,
               m.motor_nr,
               m.shipping_note
        FROM cnh_sessions s
        LEFT JOIN cnh_session_motors sm ON s.id = sm.session_id
        LEFT JOIN cnh_motors m ON sm.motor_id = m.id
        WHERE s.id = ?
      `;
      const rows = await queryPromise(sql, [sessionId]);
      if (!rows.length) {
        return res.status(404).json({ error: 'Sessie niet gevonden' });
      }

      // Sessie data voorbereiden
      const s = rows[0];
      const sessData = {
        'Laad Referentie:': s.load_reference || '—',
        'Locatie:': s.location || '—',
        'Vrachtwagen:': s.truck_plate || '—',
        'Container:': s.container_no || '—',
        'Booking Ref.:': s.booking_ref || '—',
        'Your Ref.:': s.your_ref || '—',
        'Container Tarra (kg):': s.container_tarra || '—',
      };

      // Motors voorbereiden
      const motors = rows
        .filter(r => r.motor_id)
        .map(r => ({
          motorNr: r.motor_nr || '??',
          verzendnota: r.shipping_note || '—'
        }));

      // 2) PDF Configuratie
      const PDFDocument = require('pdfkit');
      const buffers = [];

      // Styling configuratie
      const COLORS = {
        primary: '#00897B',      // Foresco groen voor titels
        text: '#333333',         // Standaard tekst kleur
        lightGray: '#f5f5f5',    // Lichte achtergrond
        border: '#dddddd',       // Randen
        rowBg: '#f9f9f9'         // Afwisselende rij achtergrond
      };

      const PAGE_CONFIG = {
        margin: 50,
        width: 495,              // A4 breedte - 2 * margin
        maxY: 750               // Ondergrens voor nieuwe pagina
      };

      // Motor tabel generator functie
      const generateMotorTable = (doc, motors, startY, pageConfig, COLORS) => {
  let currentY = startY;
  const rowHeight = 25;
  const headerHeight = 25;
  let headerDrawnOnCurrentPage = false;
  
  // Header voor elke pagina
  const drawHeader = (y) => {
    // Header achtergrond
    doc.rect(50, y - 5, pageConfig.width, headerHeight)
       .fillColor(COLORS.lightGray)
       .fill();

    // Header tekst
    doc.fillColor(COLORS.text)
       .fontSize(11)
       .text('Motor Nr.', 70, y)
       .text('Verzendnota', 300, y);
    
    headerDrawnOnCurrentPage = true;
    return y + headerHeight;
  };

  let currentIndex = 0;
  
  while (currentIndex < motors.length) {
    // Check of we een nieuwe pagina nodig hebben
    if (currentY + rowHeight > pageConfig.maxY) {
      doc.addPage();
      currentY = 50; // Reset Y positie voor nieuwe pagina
      headerDrawnOnCurrentPage = false; // Reset header flag voor nieuwe pagina
    }

    // Teken header alleen als nog niet gedaan op huidige pagina
    if (!headerDrawnOnCurrentPage) {
      currentY = drawHeader(currentY);
    }

    // Teken motor rij
    if (currentIndex % 2 === 0) {
      doc.rect(50, currentY - 5, pageConfig.width, rowHeight)
         .fillColor(COLORS.rowBg)
         .fill();
    }

    doc.fillColor(COLORS.text)
       .font('Helvetica')
       .fontSize(11)
       .text(motors[currentIndex].motorNr, 70, currentY)
       .text(motors[currentIndex].verzendnota, 300, currentY);

    currentY += rowHeight;
    currentIndex++;
  }

  return currentY;
};

      // PDF document aanmaken
      const doc = new PDFDocument({ 
        margin: PAGE_CONFIG.margin, 
        size: 'A4',
        bufferPages: true,
        info: {
          Title: `Laadoverzicht ${sessData['Laad Referentie:']}`,
          Author: 'Foresco'
        }
      });

      // Event handlers voor PDF data
      doc.on('data', chunk => buffers.push(chunk));
      doc.on('end', async () => {
        const pdfData = Buffer.concat(buffers);

        // Email configuratie
        const transporter = nodemailer.createTransport({
          host: 'mail.prodwilrijk.be',
          port: 465,
          secure: true,
          auth: {
            user: 'jason@prodwilrijk.be',
            pass: 'prodwilrijk147'
          }
        });

        // Attachments voorbereiden
        const attachments = [{
          filename: `Laadoverzicht_${sessData['Laad Referentie:']}.pdf`,
          content: pdfData
        }];

        if (s.container_photo && fs.existsSync(s.container_photo)) {
          attachments.push({
            filename: path.basename(s.container_photo),
            path: s.container_photo
          });
        }

        try {
          await transporter.sendMail({
            from: 'jason@prodwilrijk.be',
            to: toEmail,
            subject: `Laadoverzicht: ${sessData['Laad Referentie:']}`,
            html: `
              <p>Beste,<br/>
                 In bijlage het laadoverzicht van <b>${sessData['Laad Referentie:']}</b>.<br/>
                 Groeten,<br/>
                 Foresco Wilrijk
              </p>
            `,
            attachments
          });
          
          return res.json({ success: true, message: 'PDF verzonden!' });
        } catch (e) {
          console.error('Mail error:', e);
          return res.status(500).json({ error: 'Fout bij verzenden mail: ' + e.message });
        }
      });

      // 3) PDF Content genereren

      // Header sectie
      // Logo
      if (fs.existsSync('/home/prodwilr/website/uploads/foresco.png')) {
        doc.image('/home/prodwilr/website/uploads/foresco.png', 50, 40, {
          width: 150
        });
      }

      // Referentie titel
      doc.font('Helvetica-Bold')
         .fontSize(24)
         .fillColor(COLORS.primary)
         .text(sessData['Laad Referentie:'], 220, 50);

      // Datum
      doc.font('Helvetica')
         .fontSize(10)
         .fillColor(COLORS.text)
         .text(new Date().toLocaleDateString('nl-BE'), 495, 50, {
           align: 'right'
         });

      // Algemene Informatie sectie
      doc.moveDown(3);
      doc.font('Helvetica-Bold')
         .fontSize(14)
         .fillColor(COLORS.primary)
         .text('Algemene Informatie', 50, doc.y);

      // Info box met grijze achtergrond
      const infoBoxY = doc.y + 10;
      const infoBoxHeight = Object.keys(sessData).length * 25 + 30; // Hoogte berekenen

      doc.rect(50, infoBoxY, PAGE_CONFIG.width, infoBoxHeight)
         .fillColor(COLORS.lightGray)
         .fill();

      // Info items
      let currentY = infoBoxY + 15;
      Object.entries(sessData).forEach(([key, value]) => {
        // Label
        doc.font('Helvetica-Bold')
           .fontSize(11)
           .fillColor(COLORS.text)
           .text(key, 70, currentY);
        
        // Waarde
        doc.font('Helvetica')
           .text(value, 220, currentY);
        
        currentY += 25;
      });

      // Motoren sectie
      doc.moveDown(4);
      doc.font('Helvetica-Bold')
         .fontSize(14)
         .fillColor(COLORS.primary)
         .text('Motoren in deze Lading');

      // Genereer motor tabel met paginering
      const tableStartY = doc.y + 20;
      const finalY = generateMotorTable(doc, motors, tableStartY, PAGE_CONFIG, COLORS);

      // Voeg paginanummers toe aan alle paginas
      const pages = doc.bufferedPageRange();
      for (let i = 0; i < pages.count; i++) {
        doc.switchToPage(i);
        doc.font('Helvetica')
           .fontSize(9)
           .fillColor('#999999')
           .text(
             `Pagina ${i + 1} van ${pages.count}`,
             50,
             doc.page.height - 50,
             {
               align: 'center',
               width: PAGE_CONFIG.width
             }
           );
      }

      // PDF afronden
      doc.end();

    } catch (err) {
      console.error('email_load_overview error:', err);
      return res.status(500).json({ error: 'Fout bij mail: ' + err.message });
    }
});

app.post('/api/cnh_motors/email_received_packaged', async (req, res) => {
  const { toEmail } = req.body;
  if (!toEmail) {
    return res.status(400).json({ error: 'toEmail is vereist' });
  }

  try {
    // 1) Haal alle motoren met state=received of packaged op
    const sql = `
      SELECT *
      FROM cnh_motors
      WHERE state IN ('received','packaged')
      ORDER BY shipping_note, motor_nr
    `;
    const motors = await queryPromise(sql);
    if (!motors.length) {
      return res.status(404).json({ error: 'Geen motoren gevonden in status received of packaged.' });
    }

    // 2) Maak PDF
    const PDFDocument = require('pdfkit');
    const buffers = [];

    // PDF Styling configuratie
    const COLORS = {
      primary: '#00897B',
      secondary: '#555555',
      border: '#e0e0e0',
      background: '#f9f9f9',
      rowBackground: '#f0f0f0',
      text: '#2c2c2c',
    };
    const FONTS = {
      normal: 'Helvetica',
      bold: 'Helvetica-Bold',
      italic: 'Helvetica-Oblique',
    };
    
    // Layout configuratie
    const PAGE_CONFIG = {
      margin: 50,
      contentWidth: 495,   // A4 breedte - 2 * 50px margin = 495
      maxY: 750           // Een indicatieve ondergrens om een nieuwe pagina te beginnen
    };

    // Nieuw PDFDocument (laat autoFirstPage op true staan)
    const doc = new PDFDocument({ 
      margin: PAGE_CONFIG.margin, 
      size: 'A4',
      bufferPages: true
    });
    
    doc.on('data', (d) => buffers.push(d));
    doc.on('end', async () => {
      const pdfData = Buffer.concat(buffers);

      // 3) Verstuur mail via nodemailer
      const nodemailer = require('nodemailer');
      const transporter = nodemailer.createTransport({
        host: 'mail.prodwilrijk.be',
        port: 465,
        secure: true,
        auth: {
          user: 'jason@prodwilrijk.be',
          pass: 'prodwilrijk147'
        }
      });

      const mailOptions = {
        from: 'jason@prodwilrijk.be',
        to: toEmail,
        subject: 'Overzicht van motoren momenteel bij Foresco',
        html: `<p>Beste,<br>In bijlage het overzicht van alle motoren die momenteel bij Foresco staan.<br>Groeten,<br>Team Foresco</p>`,
        attachments: [{
          filename: `Overzicht motoren momenteel bij Foresco.pdf`,
          content: pdfData
        }]
      };

      try {
        await transporter.sendMail(mailOptions);
        return res.json({ success: true, message: 'PDF verzonden!' });
      } catch (e) {
        console.error('Mailfout:', e);
        return res.status(500).json({ error: 'Fout bij mailen: ' + e.message });
      }
    });

    /**********************************************
     * PDF helper-functies
     **********************************************/

    function addDivider(doc) {
      doc.strokeColor(COLORS.border)
        .lineWidth(0.5)
        .moveTo(PAGE_CONFIG.margin, doc.y)
        .lineTo(PAGE_CONFIG.margin + PAGE_CONFIG.contentWidth, doc.y)
        .stroke();
      doc.moveDown(0.5);
    }

    function addHeader(doc, title) {
      doc.fontSize(20)
        .font(FONTS.bold)
        .fillColor(COLORS.primary)
        .text(title, PAGE_CONFIG.margin, doc.y);

      const date = new Date().toLocaleDateString('nl-BE');
      doc.fontSize(10)
        .font(FONTS.normal)
        .fillColor(COLORS.secondary)
        .text(date, PAGE_CONFIG.margin + 380, doc.y - 18, {
          width: 120,
          align: 'right',
        });

      doc.moveDown(1);
      addDivider(doc);
    }

    function addSectionTitle(doc, title) {
      const y = doc.y;
      // Licht gekleurde achtergrondbalk
      doc.save()
        .fillColor(COLORS.rowBackground)
        .rect(PAGE_CONFIG.margin, y - 2, PAGE_CONFIG.contentWidth, 20)
        .fill()
        .restore();

      doc.fillColor(COLORS.primary)
        .fontSize(13)
        .font(FONTS.bold)
        .text(title, PAGE_CONFIG.margin + 10, y);

      doc.moveDown(2);
    }

    function addStatistics(doc, motors) {
      const stats = motors.reduce((acc, motor) => {
        const key = `${motor.location || 'Onbekend'}-${motor.state || 'Onbekend'}`;
        if (!acc[key]) {
          acc[key] = {
            location: motor.location || 'Onbekend',
            state: motor.state || 'Onbekend',
            count: 0
          };
        }
        acc[key].count++;
        return acc;
      }, {});

      // Kolom definities
      const statsColumns = {
        location: { x: PAGE_CONFIG.margin,         width: 200 },
        state:    { x: PAGE_CONFIG.margin + 200,   width: 150 },
        count:    { x: PAGE_CONFIG.margin + 350,   width: 100 }
      };

      // Stats header
      doc.font(FONTS.bold)
        .fontSize(11)
        .fillColor(COLORS.primary);

      const headerY = doc.y;
      doc.save()
        .fillColor(COLORS.background)
        .rect(PAGE_CONFIG.margin, headerY - 5, PAGE_CONFIG.contentWidth, 22)
        .fill()
        .restore();

      doc.text('Locatie', statsColumns.location.x + 10, headerY, 
        { width: statsColumns.location.width - 10, align: 'left' });
      doc.text('Status', statsColumns.state.x, headerY,
        { width: statsColumns.state.width, align: 'left' });
      doc.text('Aantal', statsColumns.count.x, headerY,
        { width: statsColumns.count.width - 10, align: 'right' });

      doc.moveDown(1);

      // Stats rijen
      const statsList = Object.values(stats).sort((a, b) => {
        if (a.location !== b.location) return a.location.localeCompare(b.location);
        return a.state.localeCompare(b.state);
      });

      let totalMotors = 0;
      statsList.forEach((stat, i) => {
        // Om en om achtergrond
        if (i % 2 === 0) {
          doc.save()
            .fillColor(COLORS.rowBackground)
            .rect(PAGE_CONFIG.margin, doc.y - 2, PAGE_CONFIG.contentWidth, 20)
            .fill()
            .restore();
        }

        const yPos = doc.y;
        doc.font(FONTS.normal)
          .fontSize(10)
          .fillColor(COLORS.text)
          .text(stat.location, statsColumns.location.x + 10, yPos, 
            { width: statsColumns.location.width - 10, align: 'left' })
          .text(stat.state, statsColumns.state.x, yPos,
            { width: statsColumns.state.width, align: 'left' })
          .text(stat.count.toString(), statsColumns.count.x, yPos,
            { width: statsColumns.count.width - 10, align: 'right' });

        totalMotors += stat.count;
        doc.moveDown(1);
      });

      // Totaal met verbeterde uitlijning
      doc.moveDown(0.5);
      addDivider(doc);

      // Totaal in dezelfde stijl als de tabel
      doc.font(FONTS.bold)
        .fontSize(11)
        .fillColor(COLORS.primary)
        .text(
          'Totaal aantal motoren:', 
          PAGE_CONFIG.margin + 15, 
          doc.y,
          { continued: true }
        )
        .text(
          ` ${totalMotors}`,
          { align: 'left' }
        );
      
      doc.moveDown(2);
    }

    function addTableHeader(doc) {
      // Kolom-definities; iets anders uitgelijnd / breder
      const columns = {
        id:           { x: 60,  width: 40  },
        motor_nr:     { x: 110, width: 100 },
        location:     { x: 215, width: 90  },
        state:        { x: 310, width: 60  },
        shippingNote: { x: 375, width: 135 },
      };

      const headerY = doc.y;
      // Achtergrondbalk voor header
      doc.save()
        .fillColor(COLORS.background)
        .rect(PAGE_CONFIG.margin, headerY - 5, PAGE_CONFIG.contentWidth, 22)
        .fill()
        .restore();

      doc.font(FONTS.bold)
        .fontSize(11)
        .fillColor(COLORS.primary);

      doc.text('ID', columns.id.x, headerY, {
        width: columns.id.width,
        align: 'left',
      });
      doc.text('MotorNr', columns.motor_nr.x, headerY, {
        width: columns.motor_nr.width,
        align: 'left',
      });
      doc.text('Locatie', columns.location.x, headerY, {
        width: columns.location.width,
        align: 'left',
      });
      doc.text('State', columns.state.x, headerY, {
        width: columns.state.width,
        align: 'left',
      });
      doc.text('Verzendnota', columns.shippingNote.x, headerY, {
        width: columns.shippingNote.width,
        align: 'left',
      });

      doc.moveDown(1);
      addDivider(doc);
      return columns;
    }

    function addMotorsTable(doc, motors) {
      const columns = addTableHeader(doc);

      doc.font(FONTS.normal)
        .fontSize(10)
        .fillColor(COLORS.text);

      motors.forEach((m, i) => {
        // Check voor pagina break
        if (doc.y > PAGE_CONFIG.maxY) {
          doc.addPage();
          addHeader(doc, 'Overzicht Motoren: Momenteel bij Foresco');
          addSectionTitle(doc, 'Motoren in received/packaged status');
          addTableHeader(doc);
        }

        // Om en om achtergrond
        if (i % 2 === 0) {
          doc.save()
            .fillColor(COLORS.rowBackground)
            .rect(PAGE_CONFIG.margin, doc.y - 2, PAGE_CONFIG.contentWidth, 20)
            .fill()
            .restore();
        }

        const yPos = doc.y;
        doc.fillColor(COLORS.text)
          .text(m.id || '', columns.id.x, yPos, { width: columns.id.width })
          .text(m.motor_nr || '', columns.motor_nr.x, yPos, { width: columns.motor_nr.width })
          .text(m.location || '', columns.location.x, yPos, { width: columns.location.width })
          .text(m.state || '', columns.state.x, yPos, { width: columns.state.width })
          .text(m.shipping_note || '', columns.shippingNote.x, yPos, { width: columns.shippingNote.width });
        
        doc.moveDown(1);
      });
    }

    function addFooters(doc) {
      const pages = doc.bufferedPageRange();
      for (let i = 0; i < pages.count; i++) {
        doc.switchToPage(i);
        doc.fontSize(9)
          .font(FONTS.normal)
          .fillColor(COLORS.secondary)
          .text(
            `Pagina ${i + 1} van ${pages.count}`,
            PAGE_CONFIG.margin,
            doc.page.height - 50,
            { align: 'center', width: PAGE_CONFIG.contentWidth }
          );
      }
    }

    // PDF genereren (eerste pagina)
    addHeader(doc, 'Overzicht Motoren: Momenteel bij Foresco');
    addSectionTitle(doc, 'Overzicht Aantallen');
    addStatistics(doc, motors);

    addSectionTitle(doc, 'Motoren in received/packaged status');
    addMotorsTable(doc, motors);

    addFooters(doc);
    
    // Sluit PDF af
    doc.end();

  } catch (e) {
    console.error('email_received_packaged error:', e);
    return res.status(500).json({ error: 'Fout bij mail: ' + e.message });
  }
});



app.post('/api/cnh_sessions/upload_container_photo', upload.single('photo'), async (req, res) => {
  const sessionId = req.body.sessionId;
  if (!sessionId || !req.file) {
    return res.status(400).json({ error: 'sessionId en photo zijn vereist' });
  }

  try {
    // Stap 1: Bepaal de bestandsnaam die Multer heeft weggeschreven
    const photoFilename = req.file.filename; 
    // Stap 2: Bouw het absolute pad (dat de mail-functie herkent)
    // vb. "/home/prodwilr/website/public/uploads/container_photos/1677678900-foto.jpg"
    const absolutePath = path.join(containerPhotoDir, photoFilename);

    // Stap 3: Sla dat pad op in de DB
    await queryPromise(`
      UPDATE cnh_sessions
      SET container_photo = ?
      WHERE id = ?
    `, [ absolutePath, sessionId ]);

    return res.json({ success: true });
  } catch (e) {
    console.error('upload_container_photo error:', e);
    return res.status(500).json({ error: e.message });
  }
});


// Voorbeeld (backend):
app.post('/api/containers', async (req, res) => {
  try {
    const {
      loadReference,
      containerNumber,
      truckPlate,
      bookingRef,
      yourRef,
      containerTarra,
      loadLocation
    } = req.body;

    // Basis validatie: controleer of verplichte velden aanwezig zijn.
    if (!loadReference || !containerNumber || !truckPlate || !loadLocation) {
      return res.status(400).json({ error: 'Verplichte velden ontbreken.' });
    }

    const sql = `
      INSERT INTO containers 
      (loadReference, containerNumber, truckPlate, bookingRef, yourRef, containerTarra, loadLocation, createdAt)
      VALUES (?, ?, ?, ?, ?, ?, ?, NOW())
    `;
    const result = await queryDatabase(sql, [
      loadReference,
      containerNumber,
      truckPlate,
      bookingRef || '',
      yourRef || '',
      containerTarra || 0,
      loadLocation
    ]);

    return res.status(201).json({ success: true, id: result.insertId });
  } catch (err) {
    console.error('Fout bij opslaan container:', err);
    res.status(500).json({ error: 'Interne serverfout bij opslaan.' });
  }
});





