// Create reorder record
// Update the POST endpoint
app.post('/api/c_kisten/reorder', async (req, res) => {
    const { location, items } = req.body;
    
    if (!location || !items || !items.length) {
        return res.status(400).json({ error: 'Location and items are required' });
    }

    try {
        await queryPromise('START TRANSACTION');
        
        // Create reorder record without transfer order number
        const orderSql = `
            INSERT INTO c_kisten_reorders 
            (production_location, status)
            VALUES (?, 'OPEN')
        `;
        const orderResult = await queryPromise(orderSql, [location]);
        const reorderId = orderResult.insertId;

        // Rest of the code remains the same
        const lineSql = `
            INSERT INTO c_kisten_reorder_lines 
            (reorder_id, kistnummer, line_number, ordered_amount)
            VALUES (?, ?, ?, ?)
        `;
        
        for (const item of items) {
            await queryPromise(lineSql, [
                reorderId,
                item.kistnummer,
                item.line_number || null,
                item.reorder_amount
            ]);
        }

        await queryPromise('COMMIT');
        res.json({ success: true, reorderId });
    } catch (error) {
        await queryPromise('ROLLBACK');
        console.error('Error creating reorder:', error);
        res.status(500).json({ error: 'Database error: ' + error.message });
    }
});

// Get reorder history
app.get('/api/c_kisten/reorder_history', async (req, res) => {
    try {
        const sql = `
            SELECT r.*, 
                   COUNT(rl.id) as total_items,
                   SUM(rl.ordered_amount) as total_ordered,
                   SUM(rl.received_amount) as total_received
            FROM c_kisten_reorders r
            LEFT JOIN c_kisten_reorder_lines rl ON r.id = rl.reorder_id
            GROUP BY r.id
            ORDER BY r.created_at DESC
        `;
        const rows = await queryPromise(sql);
        res.json(rows);
    } catch (error) {
        console.error('Error fetching reorder history:', error);
        res.status(500).json({ error: 'Database error: ' + error.message });
    }
});



app.post('/api/c_kisten/send_reorder_email', async (req, res) => {
    const { location, reorderList } = req.body;

    if (!location || !reorderList || !reorderList.length) {
        return res.status(400).json({ error: 'Location and reorder items are required' });
    }

    try {
        // Voorbeeld: we kunnen nog steeds in de DB iets wegschrijven.
        // We laten de transfer_order_number-velden weg of vullen die met NULL.
        // Voorbeeld van hoe we een reorder record opslaan:
        const orderSql = `
            INSERT INTO c_kisten_reorders 
            (production_location, status)
            VALUES (?, 'OPEN')
        `;
        const orderResult = await queryPromise(orderSql, [location]);
        const reorderId = orderResult.insertId;

        // Reorder lines
        const lineSql = `
            INSERT INTO c_kisten_reorder_lines 
            (reorder_id, kistnummer, line_number, ordered_amount)
            VALUES (?, ?, ?, ?)
        `;
        for (const item of reorderList) {
            await queryPromise(lineSql, [
                reorderId,
                item.kistnummer,
                item.line_number || null,
                item.reorder_amount
            ]);
        }

        // Eventueel e-mail versturen als PDF
        // (afhankelijk van jullie behoefte, hier kort voorbeeld)
        const doc = new PDFKit({ size: 'A4', margin: 50 });
        const chunks = [];

        doc.on('data', chunk => chunks.push(chunk));
        doc.on('end', async () => {
            const pdfData = Buffer.concat(chunks);

            // Voorbeeld van mail-opzet
            const transporter = nodemailer.createTransport({
                host: 'mail.prodwilrijk.be',
                port: 465,
                secure: true,
                auth: {
                    user: 'jason@prodwilrijk.be',
                    pass: 'prodwilrijk147'
                },
                tls: {
                    rejectUnauthorized: false
                }
            });

            await transporter.sendMail({
                from: 'jason@prodwilrijk.be',
                to: 'J.ploegaerts@foresco.eu',
                subject: `C-Kisten Reorder List: ${location}`,
                html: `
                    <p>Beste,<br><br>
                    In bijlage de reorder lijst voor ${location}.<br><br>
                    Groeten,<br>
                    Foresco
                    </p>
                `,
                attachments: [
                    {
                        filename: `Reorder_List_${location}.pdf`,
                        content: pdfData
                    }
                ]
            });

            res.json({ success: true, reorderId });
        });

        // Minimalistische PDF opmaak
        doc.font('Helvetica-Bold')
           .fontSize(22)
           .text(`C-Kisten Reorder List - ${location}`, { align: 'center' })
           .moveDown();

        doc.font('Helvetica')
           .fontSize(12)
           .text(`Generated on: ${new Date().toLocaleString()}`, { align: 'left' })
           .moveDown();

        doc.text(`Location: ${location}`).moveDown();

        // Tabel headers
        doc.font('Helvetica-Bold');
        const headers = ['Kistnummer', 'ERP Code', 'Line #', 'Amount'];
        let xPos = 50, yPos = doc.y;
        const colWidth = 120;

        headers.forEach(header => {
            doc.text(header, xPos, yPos, { width: colWidth });
            xPos += colWidth;
        });
        doc.moveDown();

        // Lijn onder headers
        doc.moveTo(50, doc.y).lineTo(550, doc.y).stroke();

        // Tabel rows
        doc.font('Helvetica');
        reorderList.forEach((item, index) => {
            yPos = doc.y + 10;
            xPos = 50;

            doc.text(item.kistnummer, xPos, yPos, { width: colWidth });
            xPos += colWidth;

            doc.text(item.erp_code || 'N/A', xPos, yPos, { width: colWidth });
            xPos += colWidth;

            doc.text(item.line_number?.toString() || '-', xPos, yPos, { width: colWidth });
            xPos += colWidth;

            doc.text(item.reorder_amount.toString(), xPos, yPos, { width: colWidth });
            doc.moveDown(1.2);
        });

        // Footer
        doc.moveDown(2);
        doc.fontSize(10).text('End of reorder list.', { align: 'center' });
        doc.end();

    } catch (error) {
        console.error('Error:', error);
        res.status(500).json({ 
            error: 'Failed to process reorder request',
            details: error.message
        });
    }
});

app.post('/api/c_kisten/locations', async (req, res) => {
    const { name } = req.body;
    
    if (!name) {
        return res.status(400).json({ error: 'Location name is required' });
    }

    try {
        // Check if location already exists
        const checkSql = 'SELECT id FROM production_locations WHERE name = ?';
        const existing = await queryPromise(checkSql, [name]);
        
        if (existing.length > 0) {
            // If exists, reactivate if needed
            const updateSql = 'UPDATE production_locations SET active = true WHERE name = ?';
            await queryPromise(updateSql, [name]);
        } else {
            // If doesn't exist, insert new
            const insertSql = 'INSERT INTO production_locations (name, active) VALUES (?, true)';
            await queryPromise(insertSql, [name]);
        }
        
        res.json({ success: true });
    } catch (error) {
        console.error('Error adding location:', error);
        res.status(500).json({ error: 'Database error: ' + error.message });
    }
});

