function handleDatabaseQuery(query) {
  return new Promise((resolve, reject) => {
    db.query(query, (error, results) => {
      if (error) return reject(error);
      resolve(results);
    });
  });
}


app.get('/api/daily_analysis', async (req, res) => {
    try {
        // Query voor Prepack dagelijkse data (laatste 7 dagen)
        const prepackQuery = `
            SELECT 
                DATE(date_packed) as pack_date,
                COUNT(*) as order_count,
                COALESCE(SUM(amount), 0) as total_items
            FROM packed_items
            WHERE date_packed >= DATE_SUB(CURRENT_DATE, INTERVAL 7 DAY)
            GROUP BY DATE(date_packed)
            ORDER BY pack_date ASC
        `;

        // Query voor Airtec dagelijkse data (laatste 7 dagen)
        const airtecQuery = `
            SELECT 
                DATE(date_packed) as pack_date,
                COUNT(*) as order_count,
                COALESCE(SUM(quantity), 0) as total_items
            FROM packed_items_airtec
            WHERE date_packed >= DATE_SUB(CURRENT_DATE, INTERVAL 7 DAY)
            GROUP BY DATE(pack_date)
            ORDER BY pack_date ASC
        `;

        // Uitvoeren van beide queries met error handling
        const [prepackData, airtecData] = await Promise.all([
            handleDatabaseQuery(prepackQuery),
            handleDatabaseQuery(airtecQuery)
        ]);

        // Controleer of we data hebben
        if (!Array.isArray(prepackData) || !Array.isArray(airtecData)) {
            throw new Error('Ongeldige data ontvangen van database');
        }

        // Vul ontbrekende dagen aan met nullwaarden
        const last7Days = [...Array(7)].map((_, i) => {
            const date = new Date();
            date.setDate(date.getDate() - i);
            return date.toISOString().split('T')[0];
        }).reverse();

        const fillMissingDays = (data) => {
            const dataMap = new Map(data.map(item => [item.pack_date.toISOString().split('T')[0], item]));
            return last7Days.map(date => {
                return dataMap.get(date) || {
                    pack_date: date,
                    order_count: 0,
                    total_items: 0
                };
            });
        };

        const normalizedPrepackData = fillMissingDays(prepackData);
        const normalizedAirtecData = fillMissingDays(airtecData);

        // Data voorbereiden voor de grafiek
        const analysisData = {
            prepack: {
                dailyData: normalizedPrepackData,
                totalItems: normalizedPrepackData.reduce((sum, day) => sum + (Number(day.total_items) || 0), 0),
                averageDaily: Math.round(
                    normalizedPrepackData.reduce((sum, day) => sum + (Number(day.total_items) || 0), 0) / 
                    normalizedPrepackData.length
                )
            },
            airtec: {
                dailyData: normalizedAirtecData,
                totalItems: normalizedAirtecData.reduce((sum, day) => sum + (Number(day.total_items) || 0), 0),
                averageDaily: Math.round(
                    normalizedAirtecData.reduce((sum, day) => sum + (Number(day.total_items) || 0), 0) / 
                    normalizedAirtecData.length
                )
            }
        };

        // Cache headers toevoegen
        res.setHeader('Cache-Control', 'public, max-age=300'); // 5 minuten cache
        
        // Stuur de data terug naar de frontend
        res.json({
            analysisData: analysisData,
            timestamp: new Date().toISOString()
        });

    } catch (error) {
        console.error('Error generating analysis data:', error);
        
        // Gedetailleerde error response
        res.status(500).json({ 
            error: 'Er is een fout opgetreden bij het genereren van de analyse data.',
            details: error.message,
            timestamp: new Date().toISOString(),
            errorType: error.name,
            errorCode: error.response?.status || 500
        });
    }
});









