app.post('/api/transfers/create-bulk-order', async (req, res) => {
    const { transfers, preview } = req.body;

    try {
        if (!Array.isArray(transfers) || transfers.length === 0) {
            return res.status(400).json({ error: 'No transfers provided' });
        }

        // Group transfers by from_location
        const transfersByLocation = {};
        transfers.forEach(transfer => {
            const fromLocation = (transfer.fromLocation || transfer.from_location || '').toUpperCase();
            if (!transfersByLocation[fromLocation]) {
                transfersByLocation[fromLocation] = [];
            }
            transfersByLocation[fromLocation].push(transfer);
        });

        // If it's a preview request, just generate and return the PDF
        if (preview) {
            const location = Object.keys(transfersByLocation)[0]; // Get first location for preview
            const locationTransfers = transfersByLocation[location];

            const pdfContent = await generatePDFContent(locationTransfers, location);
            const pdfDoc = await generatePDF(pdfContent);

            res.setHeader('Content-Type', 'application/pdf');
            res.setHeader('Content-Disposition', 'inline; filename=transfer_preview.pdf');
            return res.send(pdfDoc);
        }

        // Begin database transaction
        await new Promise((resolve, reject) => {
            db.beginTransaction(err => {
                if (err) reject(err);
                else resolve();
            });
        });

        try {
            console.log("Processing transfers for locations:", Object.keys(transfersByLocation));

            // First process all database updates
            for (const [fromLocation, locationTransfers] of Object.entries(transfersByLocation)) {
                console.log(`Processing database updates for ${fromLocation}...`);
                await processTransfers(locationTransfers);
            }

            // Then generate PDFs and send emails
            for (const [fromLocation, locationTransfers] of Object.entries(transfersByLocation)) {
                console.log(`Generating PDF and sending email for ${fromLocation}...`);
                try {
                    // Generate PDF for this location
                    const pdfContent = await generatePDFContent(locationTransfers, fromLocation);
                    const pdfDoc = await generatePDF(pdfContent);

                    // Send email
                    const date = new Date().toLocaleDateString('nl-BE');
                    const transporter = nodemailer.createTransport({
                        host: 'mail.prodwilrijk.be',
                        port: 465,
                        secure: true,
                        auth: { user: 'jason@prodwilrijk.be', pass: 'prodwilrijk147' }
                    });

                    await transporter.sendMail({
                        from: 'jason@prodwilrijk.be',
                        to: 'jasonploegaerts@gmail.com,j.ploegaerts@foresco.eu',
                        subject: `Transfer Order Request ${fromLocation} ${date}`,
                        html: `<h2>Transfer Order Request from ${fromLocation}</h2><p>Zie bijlage voor details van de transfer orders.</p>`,
                        attachments: [{
                            filename: `transfer_order_${fromLocation}_${date.replace(/\//g, '-')}.pdf`,
                            content: pdfDoc
                        }]
                    });

                    console.log(`Successfully sent email for ${fromLocation}`);

                } catch (emailError) {
                    console.error(`Error sending email for ${fromLocation}:`, emailError);
                    // Continue with other locations even if email fails
                }
            }

            // Commit transaction
            await new Promise((resolve, reject) => {
                db.commit(err => {
                    if (err) {
                        console.error('Error committing transaction:', err);
                        reject(err);
                    } else {
                        console.log('Successfully committed transaction');
                        resolve();
                    }
                });
            });

            res.json({
                success: true,
                message: 'Transfer orders created and emails sent'
            });

        } catch (error) {
            // Rollback the transaction if any error occurs
            await new Promise(resolve => db.rollback(() => resolve()));
            throw error;
        }

    } catch (error) {
        console.error('Error processing transfers:', error);
        res.status(500).json({
            error: 'Error creating transfer orders',
            message: error.message
        });
    }
});

// Helper function to generate PDF content
async function generatePDFContent(transfers, fromLocation) {
    // Group by transfer order number
    const transfersByOrderNumber = {};
    transfers.forEach(transfer => {
        const { transfer_order_number } = transfer;
        if (!transfersByOrderNumber[transfer_order_number]) {
            transfersByOrderNumber[transfer_order_number] = [];
        }
        transfersByOrderNumber[transfer_order_number].push(transfer);
    });

    const pdfContent = {
        content: [],
        styles: {
            header: { fontSize: 22, bold: true },
            subheader: { fontSize: 16, bold: true, margin: [0, 10, 0, 5] },
            tableHeader: { bold: true, fontSize: 13, color: 'black' }
        }
    };

    // Process each transfer order
    for (const transferOrderNumber in transfersByOrderNumber) {
        const transfersForOrder = transfersByOrderNumber[transferOrderNumber];
        const toLocation = ((transfersForOrder[0].toLocation || transfersForOrder[0].to_location) || "").toUpperCase();
        const combinedItems = transfersForOrder.flatMap(transfer => transfer.items);

        pdfContent.content.push(
            { text: `Transfer Order: ${transferOrderNumber}`, style: 'header', margin: [0, 10, 0, 10] },
            { text: `Van: ${fromLocation}`, style: 'subheader' },
            { text: `Naar: ${toLocation}`, style: 'subheader', margin: [0, 0, 0, 10] },
            {
                table: {
                    headerRows: 1,
                    widths: ['auto', '*', '*', 'auto', 'auto'],
                    body: [
                        [
                            { text: 'Regelnummer', style: 'tableHeader' },
                            { text: 'Type', style: 'tableHeader' },
                            { text: 'Glovia Code', style: 'tableHeader' },
                            { text: 'Revisie', style: 'tableHeader' },
                            { text: 'Aantal Nodig', style: 'tableHeader' }
                        ],
                        ...combinedItems.map(item => [
                            item.line_number || '-',
                            item.type || '-',
                            item.glovia_code || item.gloviaCode || '-',
                            item.revisie || item.revision || '-',
                            (item.needed_quantity || item.neededQuantity || item.requested_quantity || 1).toString()
                        ])
                    ]
                },
                layout: 'lightHorizontalLines',
                margin: [0, 0, 0, 20]
            }
        );
    }

    return pdfContent;
}

// Helper function to generate PDF
async function generatePDF(pdfContent) {
    return new Promise((resolve, reject) => {
        const printer = new PdfPrinter(fonts);
        const doc = printer.createPdfKitDocument(pdfContent);
        const chunks = [];
        doc.on('data', chunk => chunks.push(chunk));
        doc.on('end', () => resolve(Buffer.concat(chunks)));
        doc.on('error', err => reject(err));
        doc.end();
    });
}

// Helper function to process transfers in database
async function processTransfers(transfers) {
    for (const transfer of transfers) {
        const fromLocation = (transfer.fromLocation || transfer.from_location || '').toLowerCase();
        const toLocation = (transfer.toLocation || transfer.to_location || '').toLowerCase();

        for (const item of transfer.items) {
            // Insert transfer record
            const insertTransferQuery = `
                INSERT INTO transfers (
                    transfer_order_number,
                    type,
                    from_location,
                    to_location,
                    line_number,
                    glovia_code,
                    revisie,
                    requested_quantity,
                    received_quantity,
                    status,
                    created_at
                ) VALUES (?, ?, ?, ?, ?, ?, ?, ?, 0, 'active', NOW())
            `;

            await new Promise((resolve, reject) => {
                const quantity = item.needed_quantity || item.neededQuantity || item.requested_quantity || 1;
                db.query(
                    insertTransferQuery,
                    [
                        transfer.transfer_order_number,
                        item.type,
                        fromLocation,
                        toLocation,
                        item.line_number,
                        item.glovia_code || item.gloviaCode || '',
                        item.revisie || item.revision || '',
                        quantity
                    ],
                    (err, result) => {
                        if (err) {
                            console.error('Error inserting transfer:', err);
                            reject(err);
                        } else {
                            resolve(result);
                        }
                    }
                );
            });

            // Update stock levels
            const fromStockField = `stock_${fromLocation}`;
            const updateStockQuery = `
                UPDATE kisten 
                SET ${fromStockField} = ${fromStockField} - ? 
                WHERE type = ?
            `;
            
            await new Promise((resolve, reject) => {
                const quantity = item.needed_quantity || item.neededQuantity || item.requested_quantity || 1;
                db.query(
                    updateStockQuery,
                    [quantity, item.type],
                    (err, result) => {
                        if (err) {
                            console.error('Error updating stock:', err);
                            reject(err);
                        } else {
                            resolve(result);
                        }
                    }
                );
            });
        }
    }
}


