// Submit transfers
app.post('/api/transfers/submit', (req, res) => {
    const { transfers } = req.body;
    
    if (!Array.isArray(transfers) || transfers.length === 0) {
        return res.status(400).json({ error: 'Geen transfers geselecteerd' });
    }

    // Begin transaction
    db.beginTransaction(err => {
        if (err) {
            console.error('Transaction error:', err);
            return res.status(500).json({ 
                error: 'Transaction error', 
                details: err.message 
            });
        }

        const updateQuery = `
            UPDATE transfers 
            SET status = 'active', 
                updated_at = NOW()  /* Gebruik updated_at in plaats van submitted_at */
            WHERE id IN (?)
        `;

        const transferIds = transfers.map(t => t.id).filter(id => id); // Filter out null/undefined
        
        if (transferIds.length === 0) {
            return res.status(400).json({ error: 'Geen geldige transfer IDs gevonden' });
        }

        console.log('Updating transfers with IDs:', transferIds);

        db.query(updateQuery, [transferIds], (updateError) => {
            if (updateError) {
                return db.rollback(() => {
                    console.error('Update error:', updateError);
                    res.status(500).json({ 
                        error: 'Update error', 
                        details: updateError.message 
                    });
                });
            }

            const logQuery = `
                INSERT INTO transfer_logs 
                (transfer_id, action, details, created_at) 
                VALUES ?
            `;

            const logValues = transfers
                .filter(t => t && t.id) // Filter out invalid transfers
                .map(transfer => [
                    transfer.id,
                    'submitted',
                    `Transfer order ${transfer.transfer_order_number || 'unknown'} submitted`,
                    new Date()
                ]);

            if (logValues.length === 0) {
                return db.rollback(() => {
                    res.status(400).json({ error: 'Geen geldige transfers om te loggen' });
                });
            }

            db.query(logQuery, [logValues], (logError) => {
                if (logError) {
                    return db.rollback(() => {
                        console.error('Logging error:', logError);
                        res.status(500).json({ 
                            error: 'Logging error', 
                            details: logError.message 
                        });
                    });
                }

                db.commit(commitError => {
                    if (commitError) {
                        return db.rollback(() => {
                            console.error('Commit error:', commitError);
                            res.status(500).json({ 
                                error: 'Commit error', 
                                details: commitError.message 
                            });
                        });
                    }

                    res.json({ 
                        success: true, 
                        message: `${transfers.length} transfer orders succesvol verwerkt`,
                        processedIds: transferIds
                    });
                });
            });
        });
    });
});






app.put('/api/transfers/mark-as-received/:id', async (req, res) => {
    const { id } = req.params;

    try {
        // Begin a transaction
        await new Promise((resolve, reject) => {
            db.beginTransaction(err => {
                if (err) {
                    console.error('Error starting transaction:', err);
                    return reject(err);
                }
                resolve();
            });
        });

        // Fetch the transfer details
        const transfer = await new Promise((resolve, reject) => {
            db.query('SELECT * FROM transfers WHERE id = ?', [id], (err, results) => {
                if (err) {
                    console.error('Error fetching transfer:', err);
                    return reject(err);
                }
                resolve(results[0]);
            });
        });

        if (!transfer) {
            // Rollback the transaction
            await new Promise(resolve => db.rollback(() => resolve()));
            return res.status(404).json({ error: 'Transfer not found' });
        }

        // Update the transfer status to 'received' and set received_quantity
        const updateTransferQuery = `
            UPDATE transfers 
            SET status = 'received', received_quantity = requested_quantity, updated_at = NOW()
            WHERE id = ?
        `;
        await new Promise((resolve, reject) => {
            db.query(updateTransferQuery, [id], (err, result) => {
                if (err) {
                    console.error('Error updating transfer status:', err);
                    return reject(err);
                }
                resolve(result);
            });
        });

        // Update stock levels at the 'to_location'
        const toStockField = getStockField(transfer.to_location);
        if (!toStockField) {
            throw new Error('Invalid to_location');
        }

        const updateStockQuery = `
            UPDATE kisten 
            SET ${toStockField} = ${toStockField} + ? 
            WHERE type = ?
        `;
        await new Promise((resolve, reject) => {
            db.query(updateStockQuery, [transfer.requested_quantity, transfer.type], (err, result) => {
                if (err) {
                    console.error('Error updating stock:', err);
                    return reject(err);
                }
                resolve(result);
            });
        });

        // Log the stock movement
        const logQuery = `
            INSERT INTO stock_history (
                type,
                location,
                quantity_change,
                reason,
                created_at
            ) VALUES (?, ?, ?, ?, NOW())
        `;
        await new Promise((resolve, reject) => {
            db.query(
                logQuery,
                [transfer.type, transfer.to_location, transfer.requested_quantity, `Received transfer ID ${id}`],
                (err, result) => {
                    if (err) {
                        console.error('Error logging stock movement:', err);
                        return reject(err);
                    }
                    resolve(result);
                }
            );
        });

        // Commit the transaction
        await new Promise((resolve, reject) => {
            db.commit(err => {
                if (err) {
                    console.error('Error committing transaction:', err);
                    return reject(err);
                }
                resolve();
            });
        });

        res.json({ success: true, message: 'Transfer marked as received and stock updated' });
    } catch (error) {
        // Rollback the transaction on error
        await new Promise(resolve => db.rollback(() => resolve()));
        console.error('Error marking transfer as received:', error);
        res.status(500).json({ error: 'Error marking transfer as received' });
    }
});

// Helper function to map location to stock field
function getStockField(location) {
    switch (location.toLowerCase()) {
        case 'wilrijk':
            return 'stock_wilrijk';
        case 'genk':
            return 'stock_genk';
        case 'willebroek':
            return 'stock_willebroek';
        default:
            return null;
    }
}


// Helper function to log stock movements
async function logStockMovement(type, location, quantity_change, reason) {
    return new Promise((resolve, reject) => {
        const query = `
            INSERT INTO stock_history (
                type,
                location,
                quantity_change,
                reason,
                created_at
            ) VALUES (?, ?, ?, ?, NOW())
        `;
        db.query(
            query,
            [type, location, quantity_change, reason],
            (err, result) => {
                if (err) reject(err);
                else resolve(result);
            }
        );
    });
}






// Helper functie om transfers te loggen
async function logTransfers(items, fromLocation, toLocation) {
    const query = `
        INSERT INTO transfer_history 
        (type, glovia_code, revisie, quantity, from_location, to_location, created_at)
        VALUES ?
    `;

    const values = items.map(item => [
        item.type,
        item.glovia_code,
        item.revisie,
        item.needed_quantity,
        fromLocation,
        toLocation,
        new Date()
    ]);

    return new Promise((resolve, reject) => {
        db.query(query, [values], (err, result) => {
            if (err) reject(err);
            else resolve(result);
        });
    });
}

app.post('/api/compressors/:id/status', async (req, res) => {
    const { id } = req.params;
    const { status, reason, changedBy } = req.body;

    // Valideer input
    const validStatuses = ['pending', 'in_progress', 'completed'];
    if (!validStatuses.includes(status)) {
        return res.status(400).json({
            error: 'Invalid Status',
            message: 'Status moet een van de volgende zijn: pending, in_progress, completed'
        });
    }

    try {
        // Begin transactie
        await new Promise((resolve, reject) => {
            db.beginTransaction(err => {
                if (err) reject(err);
                else resolve();
            });
        });

        // Haal huidige status op
        const [currentCompressor] = await new Promise((resolve, reject) => {
            db.query(
                'SELECT status FROM compressor_tracking WHERE id = ?',
                [id],
                (err, results) => {
                    if (err) reject(err);
                    else resolve(results);
                }
            );
        });

        if (!currentCompressor) {
            await new Promise(resolve => db.rollback(() => resolve()));
            return res.status(404).json({
                error: 'Not Found',
                message: 'Compressor niet gevonden'
            });
        }

        // Update status
        await new Promise((resolve, reject) => {
            db.query(
                'UPDATE compressor_tracking SET status = ?, updated_at = CURRENT_TIMESTAMP WHERE id = ?',
                [status, id],
                (err, result) => {
                    if (err) reject(err);
                    else resolve(result);
                }
            );
        });

        // Log status wijziging
        await new Promise((resolve, reject) => {
            const logQuery = `
                INSERT INTO status_history (
                    compressor_id,
                    old_status,
                    new_status,
                    changed_by,
                    reason,
                    changed_at
                ) VALUES (?, ?, ?, ?, ?, CURRENT_TIMESTAMP)
            `;

            db.query(
                logQuery,
                [
                    id,
                    currentCompressor.status,
                    status,
                    changedBy || 'system',
                    reason || 'Status Update'
                ],
                (err, result) => {
                    if (err) reject(err);
                    else resolve(result);
                }
            );
        });

        // Commit transactie
        await new Promise((resolve, reject) => {
            db.commit(err => {
                if (err) reject(err);
                else resolve();
            });
        });

        res.json({
            success: true,
            message: 'Status succesvol bijgewerkt',
            oldStatus: currentCompressor.status,
            newStatus: status
        });

    } catch (error) {
        // Rollback bij fouten
        await new Promise(resolve => db.rollback(() => resolve()));

        console.error('Error updating status with metadata:', error);
        res.status(500).json({
            error: 'Database Error',
            message: error.message
        });
    }
});

// Helper functie om datum te formatteren voor MySQL
function formatMySQLDate(date) {
    return date.toISOString().slice(0, 19).replace('T', ' ');
}

app.post('/api/upload_csv', uploadMiddleware, async (req, res) => {
    try {
        console.log('Starting compressors upload process');

        if (!req.files || !req.files.file) {
            console.log('No file uploaded');
            return res.status(400).json({
                success: false,
                error: 'Geen bestand geüpload'
            });
        }

        const uploadedFile = req.files.file;
        
        // Lees het bestand
        let fileContent = await fsPromises.readFile(uploadedFile.tempFilePath, 'utf8');
        
        // Parse het CSV-bestand
        let records;
        try {
            records = await new Promise((resolve, reject) => {
                csv.parse(fileContent, {
                    delimiter: ';',
                    columns: headers => headers.slice(0, 8), // Alleen kolommen A-H
                    skip_empty_lines: true,
                    trim: true,
                    relax_column_count: true
                }, (err, data) => {
                    if (err) reject(err);
                    else resolve(data);
                });
            });
        } catch (parseError) {
            console.error('Error parsing CSV:', parseError);
            throw new Error('Fout bij het parsen van het CSV-bestand');
        }

        // Map en valideer de records
        const mappedRecords = records
            .filter(record => {
                return record['Packing Number']?.trim() && 
                       record['Case']?.trim() && 
                       record['Serial  number']?.trim() && 
                       record['20000000+t01.pccrdt']?.trim();
            })
            .map(record => ({
                packing: record['Packing Number']?.toString().trim() || '',
                case_number: record['Case']?.toString().trim() || '',
                type: record['Case Type']?.toString().trim() || '',
                division: record['Division']?.toString().trim() || '',
                item_number: record['Item number']?.toString().trim() || '',
                serial_number: record['Serial  number']?.toString().trim() || '',
                location: record['Stock Location']?.toString().trim() || '',
                creation_date: formatDate(record['20000000+t01.pccrdt']?.toString().trim())
            }));

        if (mappedRecords.length === 0) {
            return res.status(400).json({
                success: false,
                error: 'Geen geldige records gevonden in het bestand'
            });
        }

        // Haal bestaande records op
        const getExistingRecords = async () => {
            return new Promise((resolve, reject) => {
                const query = `
                    SELECT packing, case_number, serial_number, location, status 
                    FROM compressor_tracking
                    WHERE (packing, case_number, serial_number) IN (
                        ${mappedRecords.map(() => '(?, ?, ?)').join(',')}
                    )
                `;
                
                const values = mappedRecords.flatMap(record => [
                    record.packing,
                    record.case_number,
                    record.serial_number
                ]);

                db.query(query, values, (err, result) => {
                    if (err) reject(err);
                    else resolve(result);
                });
            });
        };

        const existingRecords = await getExistingRecords();
        
        // Maak een map van bestaande records voor snelle lookup
        const existingMap = new Map(
            existingRecords.map(record => [
                `${record.packing}-${record.case_number}-${record.serial_number}`,
                record
            ])
        );

        // Splits records in nieuwe en te updaten records
        const { newRecords, updateRecords } = mappedRecords.reduce(
            (acc, record) => {
                const key = `${record.packing}-${record.case_number}-${record.serial_number}`;
                const existing = existingMap.get(key);

                if (!existing) {
                    acc.newRecords.push(record);
                } else if (existing.location !== record.location) {
                    acc.updateRecords.push({
                        ...record,
                        oldLocation: existing.location
                    });
                }

                return acc;
            },
            { newRecords: [], updateRecords: [] }
        );

        // Begin transactie
        await new Promise((resolve, reject) => {
            db.beginTransaction(err => {
                if (err) reject(err);
                else resolve();
            });
        });

        try {
            // 1. Voeg nieuwe records toe
            if (newRecords.length > 0) {
                await new Promise((resolve, reject) => {
                    const query = `
                        INSERT INTO compressor_tracking 
                        (packing, case_number, type, division, item_number, 
                        serial_number, location, creation_date, status)
                        VALUES ?
                    `;

                    const values = newRecords.map(record => [
                        record.packing,
                        record.case_number,
                        record.type,
                        record.division,
                        record.item_number,
                        record.serial_number,
                        record.location,
                        record.creation_date,
                        'pending'
                    ]);

                    db.query(query, [values], (err, result) => {
                        if (err) reject(err);
                        else resolve(result);
                    });
                });
            }

            // 2. Update bestaande records en log historie
            if (updateRecords.length > 0) {
                // Update locaties
                await new Promise((resolve, reject) => {
                    const updateQuery = `
                        UPDATE compressor_tracking 
                        SET location = ?,
                            status = CASE 
                                WHEN ? = 'FORESC' THEN 'pending'
                                ELSE status 
                            END
                        WHERE packing = ? 
                        AND case_number = ? 
                        AND serial_number = ?
                    `;

                    const updates = updateRecords.map(record => 
                        new Promise((resolveUpdate, rejectUpdate) => {
                            db.query(
                                updateQuery, 
                                [
                                    record.location,
                                    record.location,
                                    record.packing,
                                    record.case_number,
                                    record.serial_number
                                ],
                                (err) => {
                                    if (err) rejectUpdate(err);
                                    else resolveUpdate();
                                }
                            );
                        })
                    );

                    Promise.all(updates).then(resolve).catch(reject);
                });

                // Log historie
                await new Promise((resolve, reject) => {
                    const historyQuery = `
                        INSERT INTO compressor_location_history 
                        (packing, case_number, serial_number, old_location, new_location)
                        VALUES ?
                    `;

                    const historyValues = updateRecords.map(record => [
                        record.packing,
                        record.case_number,
                        record.serial_number,
                        record.oldLocation,
                        record.location
                    ]);

                    db.query(historyQuery, [historyValues], (err, result) => {
                        if (err) reject(err);
                        else resolve(result);
                    });
                });
            }

            // Commit transactie
            await new Promise((resolve, reject) => {
                db.commit(err => {
                    if (err) reject(err);
                    else resolve();
                });
            });

            // Clean up temp file
            try {
                await fsPromises.unlink(uploadedFile.tempFilePath);
            } catch (unlinkError) {
                console.error('Error deleting temp file:', unlinkError);
            }

            // Stuur response
            res.json({
                success: true,
                details: {
                    totalRecords: mappedRecords.length,
                    newRecords: newRecords.length,
                    updatedLocations: updateRecords.length,
                    message: `${newRecords.length} nieuwe records toegevoegd en ${updateRecords.length} locaties bijgewerkt`
                }
            });

        } catch (error) {
            // Rollback bij error
            await new Promise((resolve) => {
                db.rollback(() => resolve());
            });
            throw error;
        }

    } catch (error) {
        console.error('Upload process error:', error);
        if (req.files?.file?.tempFilePath) {
            try {
                await fsPromises.unlink(req.files.file.tempFilePath);
            } catch (unlinkError) {
                console.error('Error deleting temp file:', unlinkError);
            }
        }
        
        res.status(500).json({
            success: false,
            error: error.message || 'Error processing file'
        });
    }
});

// Helper functie voor datum formatting
function formatDate(dateStr) {
    if (!dateStr) return null;
    
    try {
        // Verwacht formaat: YYYYMMDD
        const year = dateStr.substring(0, 4);
        const month = dateStr.substring(4, 6);
        const day = dateStr.substring(6, 8);
        
        // Valideer de datum
        if (!year || !month || !day) return null;
        const date = new Date(year, month - 1, day);
        if (isNaN(date.getTime())) return null;
        
        return `${year}-${month}-${day}`;
    } catch (error) {
        console.error('Error formatting date:', dateStr, error);
        return null;
    }
}

app.post('/api/upload_kisten', async (req, res) => {
  try {
    if (!req.files || !req.files.file) {
      return res.status(400).json({
        success: false,
        message: 'Geen bestand geüpload.'
      });
    }

    const uploadedFile = req.files.file;
    const fileBuffer = uploadedFile.data;

    // Excel inlezen:
    const workbook = xlsx.read(fileBuffer, { type: 'buffer' });
    const sheetName = workbook.SheetNames[0];
    const worksheet = workbook.Sheets[sheetName];

    // Converteer naar array-of-arrays
    const rows = xlsx.utils.sheet_to_json(worksheet, {
      header: 1,
      defval: null
    });

    let updateCount = 0;

    // Loop vanaf row[1], omdat row[0] meestal headers bevat
    for (let i = 1; i < rows.length; i++) {
      const row = rows[i];
      if (!row || row.length < 8) {
        // We hebben minstens 8 kolommen nodig (index 7 = kolom H)
        continue;
      }

      // A = row[0] = gloviaCode
      // B = row[1] = revisie
      // H = row[7] = stock
      const gloviaCode = row[0] ? row[0].toString().trim() : '';
      const revisie = row[1] != null ? row[1].toString().trim() : '';
      const stockCell = row[7];
      const stock = parseInt(stockCell, 10) || 0;

      // Skip als gloviaCode leeg is of als het de header is
      if (!gloviaCode || gloviaCode.toLowerCase() === 'gloviacode') {
        continue;
      }

      // Update DB
      const query = `
        UPDATE kisten
        SET stock = ?
        WHERE glovia_code = ?
          AND revisie = ?
      `;
      await new Promise((resolve, reject) => {
        db.query(query, [stock, gloviaCode, revisie], (err, result) => {
          if (err) return reject(err);
          if (result.affectedRows > 0) {
            updateCount++;
          }
          resolve();
        });
      });
    }

    res.json({
      success: true,
      message: `Excel verwerkt. ${updateCount} kisten geüpdatet.`
    });

  } catch (error) {
    console.error('Error processing Excel:', error);
    res.status(500).json({
      success: false,
      message: 'Fout bij verwerken van het bestand.',
      error: error.message
    });
  }
});




