app.put('/api/kisten/stock-update', async (req, res) => {
    const { type, stockField, quantity } = req.body;

    // Validatie
    if (!type || !stockField || typeof quantity !== 'number') {
        return res.status(400).json({
            error: 'Ongeldige parameters voor voorraad update'
        });
    }

    // Controleer of het een geldig voorraadveld is, inclusief 'stock_willebroek'
    const allowedStockFields = ['stock_wilrijk', 'stock_genk', 'stock_willebroek'];
    if (!allowedStockFields.includes(stockField)) {
        return res.status(400).json({
            error: 'Ongeldig voorraadveld'
        });
    }

    try {
        // Begin een transactie
        await new Promise((resolve, reject) => {
            db.beginTransaction(err => {
                if (err) reject(err);
                else resolve();
            });
        });

        // Update de voorraad
        const updateQuery = `
            UPDATE kisten 
            SET ${stockField} = ${stockField} + ?
            WHERE type = ?
        `;

        const result = await new Promise((resolve, reject) => {
            db.query(updateQuery, [quantity, type], (err, result) => {
                if (err) reject(err);
                else resolve(result);
            });
        });

        if (result.affectedRows === 0) {
            await new Promise(resolve => db.rollback(() => resolve()));
            return res.status(404).json({
                error: `Geen kist gevonden met type ${type}`
            });
        }

        // Log de voorraadwijziging
        const locationMap = {
            'stock_wilrijk': 'Wilrijk',
            'stock_genk': 'Genk',
            'stock_willebroek': 'Willebroek'
        };

        const location = locationMap[stockField] || 'Onbekende locatie';

        const logQuery = `
            INSERT INTO stock_history (
                type,
                location,
                quantity_change,
                reason
            ) VALUES (?, ?, ?, ?)
        `;

        await new Promise((resolve, reject) => {
            db.query(
                logQuery,
                [
                    type,
                    location,
                    quantity,
                    'Production Order Completed'
                ],
                (err, result) => {
                    if (err) reject(err);
                    else resolve(result);
                }
            );
        });

        // Commit de transactie
        await new Promise((resolve, reject) => {
            db.commit(err => {
                if (err) reject(err);
                else resolve();
            });
        });

        // Haal de bijgewerkte voorraad op
        const results = await new Promise((resolve, reject) => {
            db.query(
                'SELECT * FROM kisten WHERE type = ?',
                [type],
                (err, results) => {
                    if (err) reject(err);
                    else resolve(results);
                }
            );
        });

        if (!results || results.length === 0) {
            return res.status(404).json({
                error: `Geen kist gevonden met type ${type}`
            });
        }

        const updatedStock = results[0];

        res.json({
            success: true,
            message: `Voorraad bijgewerkt voor ${type}`,
            newStock: updatedStock[stockField]
        });

    } catch (error) {
        // Rollback bij fouten
        await new Promise(resolve => db.rollback(() => resolve()));
        
        console.error('Error updating stock:', error);
        res.status(500).json({
            error: 'Database error bij voorraad update',
            details: error.message
        });
    }
});

