app.put('/api/kisten/:id/stock', async (req, res) => {
    const { id } = req.params;
    const { stock_wilrijk, stock_willebroek, stock_genk } = req.body;

    // Validatie: minimaal één voorraadveld moet aanwezig zijn
    if (
        stock_wilrijk == null &&
        stock_willebroek == null &&
        stock_genk == null
    ) {
        return res.status(400).json({ 
            error: 'Ten minste één voorraadaanpassing is vereist' 
        });
    }

    // Controleer of de voorraadwaarden geldig zijn (getallen)
    if (
        (stock_wilrijk != null && typeof stock_wilrijk !== 'number') ||
        (stock_willebroek != null && typeof stock_willebroek !== 'number') ||
        (stock_genk != null && typeof stock_genk !== 'number')
    ) {
        return res.status(400).json({ 
            error: 'Voorraadaanpassingen moeten getallen zijn' 
        });
    }

    try {
        // Begin een transactie
        await new Promise((resolve, reject) => {
            db.beginTransaction(err => {
                if (err) reject(err);
                else resolve();
            });
        });

        // Haal de kist type op voor logging
        const [kistRows] = await new Promise((resolve, reject) => {
            db.query('SELECT type FROM kisten WHERE id = ?', [id], (err, results) => {
                if (err) reject(err);
                else resolve(results);
            });
        });

        if (kistRows.length === 0) {
            await new Promise(resolve => db.rollback(() => resolve()));
            return res.status(404).json({ error: 'Kist niet gevonden' });
        }

        const kistType = kistRows[0].type;

        // Dynamisch opbouwen van SET clausule
        const fieldsToUpdate = [];
        const values = [];

        if (stock_wilrijk != null) {
            fieldsToUpdate.push(`stock_wilrijk = GREATEST(stock_wilrijk + ?, 0)`);
            values.push(stock_wilrijk);
        }

        if (stock_willebroek != null) {
            fieldsToUpdate.push(`stock_willebroek = GREATEST(stock_willebroek + ?, 0)`);
            values.push(stock_willebroek);
        }

        if (stock_genk != null) {
            fieldsToUpdate.push(`stock_genk = GREATEST(stock_genk + ?, 0)`);
            values.push(stock_genk);
        }

        // Voeg id toe voor WHERE clause
        values.push(id);

        const updateQuery = `
            UPDATE kisten
            SET ${fieldsToUpdate.join(', ')}
            WHERE id = ?
        `;

        const result = await new Promise((resolve, reject) => {
            db.query(updateQuery, values, (err, result) => {
                if (err) reject(err);
                else resolve(result);
            });
        });

        if (result.affectedRows === 0) {
            await new Promise(resolve => db.rollback(() => resolve()));
            return res.status(404).json({ error: 'Kist niet gevonden' });
        }

        // Log de voorraadwijzigingen in stock_history
        const logPromises = [];

        if (stock_wilrijk != null) {
            logPromises.push(new Promise((resolve, reject) => {
                const logQuery = `
                    INSERT INTO stock_history (
                        type,
                        location,
                        quantity_change,
                        reason
                    ) VALUES (?, ?, ?, ?)
                `;
                db.query(
                    logQuery,
                    [kistType, 'Wilrijk', stock_wilrijk, 'Manual Stock Update'],
                    (err, result) => {
                        if (err) reject(err);
                        else resolve(result);
                    }
                );
            }));
        }

        if (stock_willebroek != null) {
            logPromises.push(new Promise((resolve, reject) => {
                const logQuery = `
                    INSERT INTO stock_history (
                        type,
                        location,
                        quantity_change,
                        reason
                    ) VALUES (?, ?, ?, ?)
                `;
                db.query(
                    logQuery,
                    [kistType, 'Willebroek', stock_willebroek, 'Manual Stock Update'],
                    (err, result) => {
                        if (err) reject(err);
                        else resolve(result);
                    }
                );
            }));
        }

        if (stock_genk != null) {
            logPromises.push(new Promise((resolve, reject) => {
                const logQuery = `
                    INSERT INTO stock_history (
                        type,
                        location,
                        quantity_change,
                        reason
                    ) VALUES (?, ?, ?, ?)
                `;
                db.query(
                    logQuery,
                    [kistType, 'Genk', stock_genk, 'Manual Stock Update'],
                    (err, result) => {
                        if (err) reject(err);
                        else resolve(result);
                    }
                );
            }));
        }

        // Wacht tot alle logs zijn toegevoegd
        await Promise.all(logPromises);

        // Commit de transactie
        await new Promise((resolve, reject) => {
            db.commit(err => {
                if (err) reject(err);
                else resolve();
            });
        });

        // Haal de bijgewerkte voorraad op
        const [updatedKist] = await new Promise((resolve, reject) => {
            db.query('SELECT * FROM kisten WHERE id = ?', [id], (err, results) => {
                if (err) reject(err);
                else resolve(results);
            });
        });

        res.json({
            success: true,
            message: 'Voorraad succesvol bijgewerkt',
            newStock: {
                stock_wilrijk: updatedKist[0].stock_wilrijk,
                stock_willebroek: updatedKist[0].stock_willebroek,
                stock_genk: updatedKist[0].stock_genk
            }
        });

    } catch (error) {
        // Rollback bij fouten
        await new Promise(resolve => db.rollback(() => resolve()));
        
        console.error('Error updating stock:', error);
        res.status(500).json({
            error: 'Database error bij voorraad update'
        });
    }
});


// e. POST Update Status
app.post('/api/update_status', async (req, res) => {
    const { id, status } = req.body;

    // Validatie: Controleer of zowel 'id' als 'status' aanwezig zijn
    if (!id || !status) {
        return res.status(400).json({ error: 'ID en status zijn vereist' });
    }

    // Definieer toegestane statuswaarden
    const allowedStatuses = ['pending', 'processed', 'completed']; // Pas dit aan indien nodig

    if (!allowedStatuses.includes(status)) {
        return res.status(400).json({ error: 'Ongeldige status waarde' });
    }

    try {
        // SQL-query om de status bij te werken
        const query = `
            UPDATE compressor_tracking
            SET status = ?
            WHERE id = ?
        `;

        // Voer de query uit
        const result = await new Promise((resolve, reject) => {
            db.query(query, [status, id], (err, result) => {
                if (err) {
                    console.error('Database error updating status:', err);
                    reject(err);
                } else {
                    resolve(result);
                }
            });
        });

        // Controleer of een rij is bijgewerkt
        if (result.affectedRows === 0) {
            return res.status(404).json({ error: 'Compressor niet gevonden' });
        }

        // Succesvolle reactie
        res.json({ success: true, message: 'Status succesvol bijgewerkt' });
    } catch (error) {
        console.error('Error updating status:', error);
        res.status(500).json({ error: 'Interne serverfout', details: error.message });
    }
});



