// Formatteringsfunctie
function formatDate(dateStr) {
    if (!dateStr) return null;
    
    const cleaned = dateStr.replace(/\D/g, '');
    
    if (cleaned.length === 8) {
        const year = cleaned.substring(0, 4);
        const month = cleaned.substring(4, 6);
        const day = cleaned.substring(6, 8);
        
        if (parseInt(year) >= 2000 && 
            parseInt(month) >= 1 && parseInt(month) <= 12 &&
            parseInt(day) >= 1 && parseInt(day) <= 31) {
            return `${year}-${month}-${day}`;
        }
    }
    
    return null;
}

// Productievoorstellen Logica
async function handleVoorraadControle(processedRecords) {
    try {
        // Maak een set van unieke kist types uit de records
        const kistTypes = [...new Set(processedRecords.map(r => r.type))];

        // Haal de kist gegevens op
        const query = `
            SELECT * FROM kisten WHERE type IN (?)
        `;

        const kisten = await new Promise((resolve, reject) => {
            db.query(query, [kistTypes], (err, results) => {
                if (err) {
                    console.error('Database error fetching kisten for voorraad controle:', err);
                    reject(err);
                } else {
                    resolve(results);
                }
            });
        });

        // Maak een map van type naar kist data
        const kistMap = {};
        kisten.forEach(kist => {
            kistMap[kist.type] = kist;
        });

        // Voorstel logica
        const productieVoorstellen = [];

        processedRecords.forEach(record => {
            const kist = kistMap[record.type];
            if (kist) {
                if (kist.stock < 1 && kist.production_location === 'FORESC') {
                    // Stel voor om 10 extra kisten te produceren
                    productieVoorstellen.push({
                        kist_id: kist.id,
                        voorgesteld_aantal: 10
                    });
                }
            }
        });

        // Insert productievoorstellen in de database
        if (productieVoorstellen.length > 0) {
            const values = productieVoorstellen.map(pv => [
                pv.kist_id,
                pv.voorgesteld_aantal
            ]);

            const insertQuery = `
                INSERT INTO productie_voorstellen (kist_id, voorgesteld_aantal)
                VALUES ?
                ON DUPLICATE KEY UPDATE 
                    voorgesteld_aantal = VALUES(voorgesteld_aantal),
                    status = 'voorstel'
            `;

            await new Promise((resolve, reject) => {
                db.query(insertQuery, [values], (err, result) => {
                    if (err) {
                        console.error('Database error inserting productievoorstellen:', err);
                        reject(err);
                    } else {
                        console.log(`Inserted/Updated ${result.affectedRows} productievoorstellen`);
                        resolve(result);
                    }
                });
            });

            // Log dat er productievoorstellen zijn aangemaakt
            console.log('Productievoorstellen aangemaakt voor kist types:', 
                productieVoorstellen.map(pv => pv.kist_id).join(', ')
            );

            // Eventueel kun je hier een e-mail of andere notificatie implementeren
        }

    } catch (error) {
        console.error('Error handling voorraad controle:', error);
    }
}

app.get('/api/production-orders', async (req, res) => {
    try {
        const query = `
            SELECT 
                po.id,
                po.type,
                po.quantity,
                po.completed_quantity, -- Include completed_quantity
                po.work_order,
                po.production_location,
                po.status,
                po.notes,
                po.created_at,
                po.updated_at,
                k.stock as kist_stock
            FROM production_orders po
            LEFT JOIN kisten k ON po.type = k.type
            ORDER BY po.created_at DESC
        `;
        
        db.query(query, (err, results) => {
            if (err) {
                console.error('Database error:', err);
                return res.status(500).json({ error: 'Database error' });
            }

            // Map the results to include the completed_quantity
            const sanitizedResults = results.map(row => ({
                id: row.id,
                type: row.type,
                quantity: row.quantity,
                completed_quantity: row.completed_quantity || 0, // Ensure it defaults to 0 if null
                work_order: row.work_order,
                production_location: row.production_location,
                status: row.status,
                notes: row.notes,
                created_at: row.created_at,
                updated_at: row.updated_at,
                kist_stock: row.kist_stock
            }));

            res.json(sanitizedResults);
        });
    } catch (error) {
        console.error('Error fetching production orders:', error);
        res.status(500).json({ error: 'Server error' });
    }
});


