app.put('/api/kisten/:id/stock-location', async (req, res) => {
    const { id } = req.params;
    const { quantity, location } = req.body;

    try {
        // Eerst huidige voorraad ophalen
        const [kist] = await db.query(
            'SELECT * FROM kisten WHERE id = ?',
            [id]
        );

        if (!kist) {
            return res.status(404).json({ error: 'Kist niet gevonden' });
        }

        // Update de voorraad voor de specifieke locatie
        let stockField;
        switch(location.toUpperCase()) {
            case 'WILRIJK':
                stockField = 'stock_wilrijk';
                break;
            case 'GENK':
                stockField = 'stock_genk';
                break;
            default:
                return res.status(400).json({ error: 'Ongeldige locatie' });
        }

        // Update de voorraad in de database
        await db.query(
            `UPDATE kisten SET ${stockField} = ${stockField} + ? WHERE id = ?`,
            [quantity, id]
        );

        // Log de voorraad wijziging
        await db.query(
            'INSERT INTO stock_history (kist_id, location, quantity_change, reason) VALUES (?, ?, ?, ?)',
            [id, location, quantity, 'Production Order Completed']
        );

        res.json({ success: true, message: 'Voorraad bijgewerkt' });

    } catch (error) {
        console.error('Error updating stock:', error);
        res.status(500).json({ error: 'Database error' });
    }
});

// Backend route voor stock updates
app.put('/api/kisten/:type/stock-update', async (req, res) => {
    const { type } = req.params;
    const { stockField, quantity, orderId } = req.body;

    try {
        // Input validatie
        if (!type || !stockField || typeof quantity !== 'number') {
            return res.status(400).json({
                error: 'Ongeldige parameters voor voorraad update'
            });
        }

        // Check of het een geldig voorraadveld is
        const validStockFields = ['stock_wilrijk', 'stock_willebroek', 'stock_genk'];
        if (!validStockFields.includes(stockField)) {
            return res.status(400).json({
                error: 'Ongeldig voorraadveld'
            });
        }

        // Begin transactie
        await new Promise((resolve, reject) => {
            db.beginTransaction(err => {
                if (err) reject(err);
                else resolve();
            });
        });

        try {
            // Check of deze order al verwerkt is (als er een orderId is)
            if (orderId) {
                const [existingUpdate] = await new Promise((resolve, reject) => {
                    db.query(
                        'SELECT id FROM stock_history WHERE reason = ? AND type = ?',
                        [`Production Order ${orderId} Completed`, type],
                        (err, results) => {
                            if (err) reject(err);
                            else resolve(results);
                        }
                    );
                });

                if (existingUpdate) {
                    throw new Error('Deze productie order is al verwerkt');
                }
            }

            // Update de voorraad
            const updateQuery = `
                UPDATE kisten 
                SET ${stockField} = ${stockField} + ?
                WHERE type = ?
            `;

            const updateResult = await new Promise((resolve, reject) => {
                db.query(updateQuery, [quantity, type], (err, result) => {
                    if (err) reject(err);
                    else resolve(result);
                });
            });

            if (updateResult.affectedRows === 0) {
                throw new Error(`Geen kist gevonden met type ${type}`);
            }

            // Log de voorraadwijziging
            const location = stockField.replace('stock_', '').charAt(0).toUpperCase() + 
                           stockField.replace('stock_', '').slice(1);
            
            await new Promise((resolve, reject) => {
                const reason = orderId ? 
                    `Production Order ${orderId} Completed` : 
                    'Manual Stock Update';

                db.query(
                    `INSERT INTO stock_history (
                        type,
                        location,
                        quantity_change,
                        reason
                    ) VALUES (?, ?, ?, ?)`,
                    [type, location, quantity, reason],
                    (err, result) => {
                        if (err) reject(err);
                        else resolve(result);
                    }
                );
            });

            // Commit transactie
            await new Promise((resolve, reject) => {
                db.commit(err => {
                    if (err) reject(err);
                    else resolve();
                });
            });

            // Haal bijgewerkte voorraad op
            const [updatedKist] = await new Promise((resolve, reject) => {
                db.query(
                    'SELECT * FROM kisten WHERE type = ?',
                    [type],
                    (err, results) => {
                        if (err) reject(err);
                        else resolve(results);
                    }
                );
            });

            res.json({
                success: true,
                message: `Voorraad bijgewerkt voor ${type}`,
                newStock: {
                    [stockField]: updatedKist[stockField]
                }
            });

        } catch (error) {
            await new Promise(resolve => db.rollback(() => resolve()));
            throw error;
        }

    } catch (error) {
        console.error('Stock update error:', error);
        res.status(500).json({
            error: error.message || 'Fout bij bijwerken voorraad'
        });
    }
});

app.put('/api/compressors/:id/status', async (req, res) => {
    const { id } = req.params;
    const { status } = req.body;

    // Valideer status waarden
    const validStatuses = ['pending', 'in_progress', 'completed'];
    if (!validStatuses.includes(status)) {
        return res.status(400).json({
            error: 'Invalid status',
            message: 'Status moet één van de volgende zijn: pending, in_progress, completed'
        });
    }

    try {
        // Begin transactie
        await new Promise((resolve, reject) => {
            db.beginTransaction(err => {
                if (err) reject(err);
                else resolve();
            });
        });

        // Update status
        const updateResult = await new Promise((resolve, reject) => {
            const query = `
                UPDATE compressor_tracking 
                SET status = ?,
                    updated_at = CURRENT_TIMESTAMP
                WHERE id = ?
            `;
            
            db.query(query, [status, id], (err, result) => {
                if (err) {
                    console.error('Status update error:', err);
                    reject(err);
                } else {
                    resolve(result);
                }
            });
        });

        if (updateResult.affectedRows === 0) {
            await new Promise(resolve => db.rollback(() => resolve()));
            return res.status(404).json({
                error: 'Compressor niet gevonden',
                message: `Geen compressor gevonden met ID ${id}`
            });
        }

        // Check of status_history tabel bestaat
        try {
            // Haal huidige status op voor logging
            const [currentCompressor] = await new Promise((resolve, reject) => {
                db.query(
                    'SELECT status FROM compressor_tracking WHERE id = ?',
                    [id],
                    (err, results) => {
                        if (err) reject(err);
                        else resolve(results);
                    }
                );
            });

            // Log status wijziging als de tabel bestaat
            await new Promise((resolve, reject) => {
                const logQuery = `
                    INSERT INTO status_history (
                        compressor_id,
                        old_status,
                        new_status,
                        changed_at
                    ) VALUES (?, ?, ?, CURRENT_TIMESTAMP)
                `;

                db.query(
                    logQuery,
                    [id, currentCompressor?.status || null, status],
                    (err) => {
                        if (err) {
                            // Als de tabel niet bestaat, log dan alleen een waarschuwing
                            if (err.code === 'ER_NO_SUCH_TABLE') {
                                console.warn('Status history table does not exist - skipping logging');
                                resolve();
                            } else {
                                reject(err);
                            }
                        } else {
                            resolve();
                        }
                    }
                );
            });
        } catch (logError) {
            console.warn('Error logging status change:', logError);
            // We gaan door ook als het loggen mislukt
        }

        // Commit transactie
        await new Promise((resolve, reject) => {
            db.commit(err => {
                if (err) reject(err);
                else resolve();
            });
        });

        // Stuur response
        res.json({
            success: true,
            message: 'Status succesvol bijgewerkt',
            newStatus: status
        });

    } catch (error) {
        // Rollback bij fouten
        await new Promise(resolve => db.rollback(() => resolve()));
        
        console.error('Error updating compressor status:', error);
        res.status(500).json({
            error: 'Database error',
            message: error.message
        });
    }
});

// Route om de status history op te halen
// Status Historie Routes
app.get('/api/compressors/:id/status-history', async (req, res) => {
    const { id } = req.params;

    try {
        // Check eerst of de compressor bestaat
        const [compressor] = await new Promise((resolve, reject) => {
            db.query(
                'SELECT id, type, serial_number FROM compressor_tracking WHERE id = ?',
                [id],
                (err, results) => {
                    if (err) reject(err);
                    else resolve(results);
                }
            );
        });

        if (!compressor) {
            return res.status(404).json({
                error: 'Not Found',
                message: 'Compressor niet gevonden'
            });
        }

        // Haal status historie op
        const history = await new Promise((resolve, reject) => {
            const query = `
                SELECT 
                    sh.id,
                    sh.compressor_id,
                    sh.old_status,
                    sh.new_status,
                    sh.changed_by,
                    sh.changed_at,
                    ct.type as compressor_type,
                    ct.serial_number
                FROM status_history sh
                JOIN compressor_tracking ct ON sh.compressor_id = ct.id
                WHERE sh.compressor_id = ?
                ORDER BY sh.changed_at DESC
            `;

            db.query(query, [id], (err, results) => {
                if (err) {
                    // Als de tabel niet bestaat, stuur een lege lijst
                    if (err.code === 'ER_NO_SUCH_TABLE') {
                        resolve([]);
                    } else {
                        reject(err);
                    }
                } else {
                    resolve(results);
                }
            });
        });

        res.json(history);

    } catch (error) {
        console.error('Error fetching status history:', error);
        res.status(500).json({
            error: 'Database Error',
            message: error.message
        });
    }
});

// Route om status historie te filteren op datum
app.get('/api/compressors/:id/status-history/filter', async (req, res) => {
    const { id } = req.params;
    const { startDate, endDate } = req.query;

    try {
        const query = `
            SELECT 
                sh.id,
                sh.compressor_id,
                sh.old_status,
                sh.new_status,
                sh.changed_by,
                sh.changed_at,
                ct.type as compressor_type,
                ct.serial_number
            FROM status_history sh
            JOIN compressor_tracking ct ON sh.compressor_id = ct.id
            WHERE sh.compressor_id = ?
            ${startDate ? 'AND sh.changed_at >= ?' : ''}
            ${endDate ? 'AND sh.changed_at <= ?' : ''}
            ORDER BY sh.changed_at DESC
        `;

        const params = [id];
        if (startDate) params.push(new Date(startDate));
        if (endDate) params.push(new Date(endDate));

        const history = await new Promise((resolve, reject) => {
            db.query(query, params, (err, results) => {
                if (err) {
                    if (err.code === 'ER_NO_SUCH_TABLE') {
                        resolve([]);
                    } else {
                        reject(err);
                    }
                } else {
                    resolve(results);
                }
            });
        });

        res.json(history);

    } catch (error) {
        console.error('Error fetching filtered status history:', error);
        res.status(500).json({
            error: 'Database Error',
            message: error.message
        });
    }
});



app.put('/api/kisten/update-stock', async (req, res) => {
    const { type, location, quantity, orderId } = req.body;

    try {
        // Input validatie
        if (!type || !location || typeof quantity !== 'number') {
            return res.status(400).json({
                error: 'Ongeldige parameters',
                details: 'Type, location en quantity zijn verplicht'
            });
        }

        // Begin transactie
        await new Promise((resolve, reject) => {
            db.beginTransaction(err => {
                if (err) reject(err);
                else resolve();
            });
        });

        try {
            // Controleer of deze order al verwerkt is
            const [existingUpdate] = await new Promise((resolve, reject) => {
                db.query(
                    'SELECT id FROM stock_history WHERE reason = ? AND type = ?',
                    [`Production Order ${orderId} Completed`, type],
                    (err, results) => {
                        if (err) reject(err);
                        else resolve(results);
                    }
                );
            });

            if (existingUpdate) {
                await new Promise(resolve => db.rollback(() => resolve()));
                return res.status(400).json({
                    error: 'Deze order is al verwerkt'
                });
            }

            // Bepaal welk voorraadveld moet worden bijgewerkt
            const stockField = location === 'wilrijk' ? 'stock_wilrijk' : 'stock_genk';

            // Update de voorraad
            await new Promise((resolve, reject) => {
                db.query(
                    `UPDATE kisten 
                     SET ${stockField} = ${stockField} + ?
                     WHERE type = ?`,
                    [quantity, type],
                    (err, result) => {
                        if (err) reject(err);
                        else if (result.affectedRows === 0) {
                            reject(new Error(`Geen kist gevonden met type ${type}`));
                        }
                        else resolve(result);
                    }
                );
            });

            // Log de voorraadwijziging
            await new Promise((resolve, reject) => {
                db.query(
                    `INSERT INTO stock_history 
                     (type, location, quantity_change, reason) 
                     VALUES (?, ?, ?, ?)`,
                    [type, location, quantity, `Production Order ${orderId} Completed`],
                    (err, result) => {
                        if (err) reject(err);
                        else resolve(result);
                    }
                );
            });

            // Commit de transactie
            await new Promise((resolve, reject) => {
                db.commit(err => {
                    if (err) reject(err);
                    else resolve();
                });
            });

            // Haal bijgewerkte voorraad op
            const [updatedKist] = await new Promise((resolve, reject) => {
                db.query(
                    'SELECT * FROM kisten WHERE type = ?',
                    [type],
                    (err, results) => {
                        if (err) reject(err);
                        else resolve(results);
                    }
                );
            });

            if (!updatedKist) {
                throw new Error(`Geen kist gevonden met type ${type}`);
            }

            res.json({
                success: true,
                message: `Voorraad bijgewerkt voor ${type}`,
                newStock: {
                    type: type,
                    location: location,
                    quantity: updatedKist[stockField]
                }
            });

        } catch (error) {
            // Rollback bij fouten
            await new Promise(resolve => db.rollback(() => resolve()));
            throw error;
        }

    } catch (error) {
        console.error('Error updating stock:', error);
        res.status(400).json({
            error: error.message || 'Fout bij bijwerken voorraad'
        });
    }
});

