// Voeg deze route toe aan je index.js (backend)
app.get('/api/admin/orders/:orderId', (req, res) => {
    const orderId = req.params.orderId;
    
    const query = `
    SELECT 
        o.id, 
        o.order_nummer, 
        o.klant, 
        o.beschrijving, 
        o.status,
        o.startdatum,         -- nieuw: startdatum
        o.einddatum,          -- nieuw: einddatum
        oi.id AS item_id, 
        oi.item_naam, 
        oi.hoeveelheid, 
        oi.afgewerkt_aantal,
        oi.verkoopprijs,
        oi.hout_kost,
        oi.hulpstoffen,
        oi.beschrijving AS item_beschrijving, 
        oi.status AS item_status,
        oi.wood_m3,
        ps.id AS productiestap_id,
        ps.naam AS productiestap_naam,
        tl.id AS timelog_id,
        tl.start_tijd,
        tl.eind_tijd,
        TIMESTAMPDIFF(SECOND, tl.start_tijd, 
            CASE 
                WHEN tl.eind_tijd IS NULL THEN NOW() 
                ELSE tl.eind_tijd 
            END
        ) as tijdsduur,
        w.naam AS werknemer_naam
    FROM orders o
    LEFT JOIN order_items oi ON o.id = oi.order_id
    LEFT JOIN time_logs tl ON oi.id = tl.order_item_id
    LEFT JOIN werknemers w ON tl.werknemer_id = w.id
    LEFT JOIN production_steps ps ON tl.production_step_id = ps.id
    WHERE o.id = ?`;

    db.query(query, [orderId], (err, results) => {
        if (err) {
            console.error('Database error:', err);
            return res.status(500).json({ 
                message: 'Er is een fout opgetreden bij het ophalen van de order details.',
                error: err.message 
            });
        }

        if (results.length === 0) {
            return res.status(404).json({ 
                message: 'Order niet gevonden.' 
            });
        }

        // Structureer de data
        const orderData = {
            id: results[0].id,
            order_nummer: results[0].order_nummer,
            klant: results[0].klant,
            beschrijving: results[0].beschrijving,
            status: results[0].status,
            startdatum: results[0].startdatum,  // nieuw
            einddatum: results[0].einddatum,    // nieuw
            items: {}
        };

        let totalTime = 0;

        // Verwerk de resultaten (zoals voorheen)
        results.forEach(row => {
            if (row.item_id) {
                if (!orderData.items[row.item_id]) {
                    orderData.items[row.item_id] = {
                        id: row.item_id,
                        item_naam: row.item_naam,
                        hoeveelheid: row.hoeveelheid,
                        afgewerkt_aantal: row.afgewerkt_aantal,
                        beschrijving: row.item_beschrijving,
                        status: row.item_status,
                        verkoopprijs: parseFloat(row.verkoopprijs) || 0,
                        hout_kost: parseFloat(row.hout_kost) || 0,
                        hulpstoffen: parseFloat(row.hulpstoffen) || 0,
                        wood_m3: parseFloat(row.wood_m3) || 0,
                        totale_tijd: 0,
                        productiestappen: {},
                        tijdsregistraties: []
                    };
                }
                const item = orderData.items[row.item_id];

                if (row.timelog_id) {
                    const tijd = row.tijdsduur || 0;
                    item.totale_tijd += tijd;
                    totalTime += tijd;

                    if (row.productiestap_id) {
                        if (!item.productiestappen[row.productiestap_id]) {
                            item.productiestappen[row.productiestap_id] = {
                                id: row.productiestap_id,
                                naam: row.productiestap_naam,
                                totale_tijd: 0,
                                werknemers: new Set()
                            };
                        }
                        item.productiestappen[row.productiestap_id].totale_tijd += tijd;
                        if (row.werknemer_naam) {
                            item.productiestappen[row.productiestap_id].werknemers.add(row.werknemer_naam);
                        }
                    }

                    item.tijdsregistraties.push({
                        id: row.timelog_id,
                        productiestap: row.productiestap_naam,
                        werknemer: row.werknemer_naam,
                        start_tijd: row.start_tijd,
                        eind_tijd: row.eind_tijd,
                        duur: tijd
                    });
                }
            }
        });

        orderData.totale_tijd = totalTime;
        orderData.items = Object.values(orderData.items).map(item => ({
            ...item,
            productiestappen: Object.values(item.productiestappen).map(stap => ({
                ...stap,
                werknemers: Array.from(stap.werknemers)
            }))
        }));

        res.json(orderData);
    });
});


app.get('/api/admin/orders/search', (req, res) => {
    const { orderNumber, customer, status, dateFrom, dateTo } = req.query;
    
    let query = `
        SELECT 
            o.id, 
            o.order_nummer, 
            o.klant, 
            o.beschrijving, 
            o.status,
            o.startdatum,      -- nieuw: startdatum
            o.einddatum,       -- nieuw: einddatum
            (
                SELECT COUNT(*)
                FROM order_items
                WHERE order_id = o.id
            ) as aantal_items,
            (
                SELECT COUNT(*)
                FROM order_items
                WHERE order_id = o.id AND status = 'Afgewerkt'
            ) as afgewerkte_items,
            COALESCE(
                SUM(
                    CASE 
                        WHEN tl.eind_tijd IS NOT NULL 
                        THEN TIMESTAMPDIFF(SECOND, tl.start_tijd, tl.eind_tijd)
                        ELSE TIMESTAMPDIFF(SECOND, tl.start_tijd, NOW())
                    END
                ), 0
            ) as totale_tijd
        FROM orders o
        LEFT JOIN order_items oi ON o.id = oi.order_id
        LEFT JOIN time_logs tl ON oi.id = tl.order_item_id
        WHERE 1=1
    `;
    
    const params = [];

    if (orderNumber) {
        query += ' AND o.order_nummer LIKE ?';
        params.push(`%${orderNumber}%`);
    }
    if (customer) {
        query += ' AND o.klant LIKE ?';
        params.push(`%${customer}%`);
    }
    if (status && status !== 'all') {
        query += ' AND o.status = ?';
        params.push(status);
    }
    if (dateFrom) {
        query += ' AND DATE(o.startdatum) >= ?';
        params.push(dateFrom);
    }
    if (dateTo) {
        query += ' AND DATE(o.startdatum) <= ?';
        params.push(dateTo);
    }

    query += `
        GROUP BY 
            o.id, 
            o.order_nummer, 
            o.klant, 
            o.beschrijving, 
            o.status
        ORDER BY 
            CASE WHEN o.status != 'Afgewerkt' THEN 0 ELSE 1 END,
            o.id DESC
    `;

    db.query(query, params, (err, results) => {
        if (err) {
            console.error('Error searching orders:', err);
            return res.status(500).json({ error: 'Database error' });
        }

        const orders = results.map(order => ({
            id: order.id,
            order_nummer: order.order_nummer,
            klant: order.klant,
            beschrijving: order.beschrijving || '',
            status: order.status,
            startdatum: order.startdatum,  // meegeven
            einddatum: order.einddatum,    // meegeven
            totale_tijd: order.totale_tijd,
            aantal_items: order.aantal_items || 0,
            afgewerkte_items: order.afgewerkte_items || 0,
            voortgang: order.aantal_items ? 
                Math.round((order.afgewerkte_items / order.aantal_items) * 100) : 0
        }));

        res.json({ success: true, orders: orders });
    });
});


