/**
 * PUT /api/admin/orders/:id/priority
 * Wijzigt de prioriteitsstatus van een order
 */
app.put('/api/admin/orders/:id/priority', async (req, res) => {
    const orderId = req.params.id;
    const { priority } = req.body; // Verwacht { priority: true/false }
    const username = req.session.user?.username || 'unknown'; // Gebruiker die de wijziging doet
    
    if (typeof priority !== 'boolean') {
        return res.status(400).json({ error: 'Priority must be a boolean value' });
    }
    
    try {
        // Begin een transactie
        const connection = await pool.getConnection();
        await connection.beginTransaction();
        
        try {
            // Update de order in de database
            const updateQuery = `
                UPDATE orders 
                SET priority = ?, priority_updated_at = NOW() 
                WHERE id = ?
            `;
            await connection.execute(updateQuery, [priority, orderId]);
            
            // Voeg een log entry toe voor audit trail
            const logQuery = `
                INSERT INTO priority_log (order_id, set_to, changed_by) 
                VALUES (?, ?, ?)
            `;
            await connection.execute(logQuery, [orderId, priority, username]);
            
            // Commit de transactie
            await connection.commit();
            
            // Haal de bijgewerkte order op
            const [updatedOrders] = await connection.execute('SELECT * FROM orders WHERE id = ?', [orderId]);
            const updatedOrder = updatedOrders[0];
            
            connection.release();
            
            res.json({
                success: true,
                message: `Priority for order ${orderId} updated to ${priority ? 'HIGH' : 'NORMAL'}`,
                order: updatedOrder
            });
        } catch (error) {
            // Rollback bij een fout
            await connection.rollback();
            connection.release();
            throw error;
        }
    } catch (error) {
        console.error('Error updating order priority:', error);
        res.status(500).json({ error: 'Failed to update order priority' });
    }
});

