// Admin orders endpoint
app.get('/api/admin/orders', (req, res) => {
    const status = req.query.status;
    let whereClause = '';
    
    if (status === 'active') {
        whereClause = "WHERE o.status != 'Afgewerkt'";
    } else if (status === 'completed') {
        whereClause = "WHERE o.status = 'Afgewerkt'";
    }

    const query = `
        SELECT 
            o.id, 
            o.order_nummer, 
            o.klant, 
            o.beschrijving, 
            o.status,
            o.startdatum,
            o.einddatum,
            o.priority,                 -- Toegevoegd
            o.priority_updated_at,      -- Toegevoegd
            o.prepack,                  -- Toegevoegd: prepack boolean
            o.prepack_division,         -- Toegevoegd: prepack division
            COUNT(DISTINCT oi.id) as aantal_items,
            SUM(CASE WHEN oi.status = 'Afgewerkt' THEN 1 ELSE 0 END) as afgewerkte_items,
            COUNT(DISTINCT tl.werknemer_id) as aantal_werknemers,
            SUM(oi.wood_m3) AS totaal_m3,
            COALESCE(
                SUM(
                    CASE 
                        WHEN tl.eind_tijd IS NOT NULL 
                        THEN TIMESTAMPDIFF(SECOND, tl.start_tijd, tl.eind_tijd)
                        ELSE TIMESTAMPDIFF(SECOND, tl.start_tijd, NOW())
                    END
                ), 0
            ) as totale_tijd
        FROM orders o
        LEFT JOIN order_items oi ON o.id = oi.order_id
        LEFT JOIN time_logs tl ON oi.id = tl.order_item_id
        ${whereClause}
        GROUP BY 
            o.id, 
            o.order_nummer, 
            o.klant, 
            o.beschrijving, 
            o.status,
            o.startdatum,
            o.einddatum,
            o.priority,                 -- Toegevoegd
            o.priority_updated_at,      -- Toegevoegd
            o.prepack,                  -- Toegevoegd: prepack boolean
            o.prepack_division          -- Toegevoegd: prepack division
        ORDER BY 
            o.priority DESC,            -- Toegevoegd: prioriteitsorders eerst
            CASE WHEN o.status != 'Afgewerkt' THEN 0 ELSE 1 END,
            o.id DESC
    `;

    db.query(query, (err, results) => {
        if (err) {
            console.error('Database error:', err);
            return res.status(500).json({ 
                message: 'Er is een fout opgetreden bij het ophalen van de orders.',
                error: err.message 
            });
        }

        const orders = results.map(order => ({
            id: order.id,
            order_nummer: order.order_nummer,
            klant: order.klant,
            beschrijving: order.beschrijving || '',
            status: order.status,
            startdatum: order.startdatum,
            einddatum: order.einddatum,
            priority: order.priority || false,       // Toegevoegd
            priority_updated_at: order.priority_updated_at, // Toegevoegd
            prepack: order.prepack || false,         // Toegevoegd: prepack boolean
            prepack_division: order.prepack_division || '', // Toegevoegd: prepack division value
            division: order.prepack_division || '',  // Alias voor prepack_division voor frontend compatibiliteit
            totale_tijd: order.totale_tijd,
            aantal_items: order.aantal_items || 0,
            aantal_werknemers: order.aantal_werknemers || 0,
            voortgang: order.aantal_items ? 
                Math.round((order.afgewerkte_items / order.aantal_items) * 100) : 0
        }));

        res.json(orders);
    });
});



// Hervat een specifieke tijdsregistratie
app.post('/api/timelog/:logId/resume', (req, res) => {
    const logId = req.params.logId;
    const resumeTime = new Date();

    if (!logId) {
        return res.status(400).json({ message: 'Geen tijdslog ID opgegeven.' });
    }

    // Controleer of de tijdslog bestaat en gepauzeerd is
    const getLogQuery = 'SELECT * FROM time_logs WHERE id = ?';
    db.query(getLogQuery, [logId], (err, results) => {
        if (err) {
            console.error('Database error:', err);
            return res.status(500).json({ message: 'Fout bij het ophalen van de tijdslog.' });
        }

        if (results.length === 0) {
            return res.status(404).json({ message: 'Tijdslog niet gevonden.' });
        }

        const log = results[0];

        if (!log.is_paused) {
            return res.status(400).json({ message: 'Tijdsregistratie is niet gepauzeerd.' });
        }

        // Bereken de duur tot nu toe
        const startTime = new Date(log.start_tijd);
        const pausedDuration = Math.floor((resumeTime - startTime) / 1000) - log.duur;

        // Hervat de tijdsregistratie door is_paused op FALSE te zetten en start_tijd bij te werken
        const updateLogQuery = `
            UPDATE time_logs 
            SET is_paused = FALSE, start_tijd = NOW() 
            WHERE id = ?
        `;

        db.query(updateLogQuery, [logId], (err2, result) => {
            if (err2) {
                console.error('Database error:', err2);
                return res.status(500).json({ message: 'Fout bij het hervatten van de tijdsregistratie.' });
            }

            res.json({ message: 'Tijdsregistratie succesvol hervat.' });
        });
    });
});


app.get('/api/timelog/active', (req, res) => {
    const orderId = req.query.orderId;

    const query = `
        SELECT 
            tl.id,
            tl.type,
            tl.start_tijd,
            tl.order_id,
            tl.order_item_id,       -- <<< TOEGEVOEGD
            w.naam AS werknemer,
            o.order_nummer,
            oi.item_naam,
            ps.naam AS productiestap
        FROM time_logs tl
        JOIN werknemers w ON tl.werknemer_id = w.id
        JOIN orders o ON tl.order_id = o.id
        LEFT JOIN order_items oi ON tl.order_item_id = oi.id
        LEFT JOIN production_steps ps ON tl.production_step_id = ps.id
        WHERE tl.eind_tijd IS NULL
        ${orderId ? 'AND tl.order_id = ?' : ''}
        ORDER BY tl.start_tijd DESC
    `;

    const params = orderId ? [orderId] : [];

    // Debug logging
    console.log('Executing query:', query.replace(/\s+/g, ' ').trim());
    console.log('With params:', params);

    // Gebruik callbacks consistent
    db.query(query, params, (err, results) => {
        if (err) {
            console.error('Database error:', err);
            return res.status(500).json({
                message: 'Fout bij het ophalen van tijdslogs.',
                error: err.message,
                query: query.replace(/\s+/g, ' ').trim()
            });
        }

        try {
            // Zorg dat results altijd een array is
            const resultsArray = Array.isArray(results) ? results : [];

            const transformedResults = resultsArray.map(log => ({
                id: log.id,
                type: log.type,
                start_tijd: log.start_tijd,
                order_id: log.order_id,
                orderItemId: log.order_item_id, // <<< TOEGEVOEGD (let op camelCase)
                order_nummer: log.order_nummer,
                werknemer: log.werknemer,
                item_naam: log.item_naam || '-', // Houd item_naam voor compatibiliteit/weergave
                productiestap: log.productiestap || '-'
            }));

            res.json(transformedResults);
        } catch (error) {
            console.error('Error transforming results:', error);
            res.status(500).json({
                message: 'Fout bij het verwerken van de resultaten.',
                error: error.message
            });
        }
    });
});


app.get('/api/orders/:id/items-with-times', (req, res) => {
    const orderId = req.params.id;
    const query = `
        SELECT oi.id as item_id, oi.item_naam, oi.hoeveelheid, oi.stuklijst, oi.status, 
               COALESCE(oi.afgewerkt_aantal,0) as afgewerkt_aantal
        FROM order_items oi
        WHERE oi.order_id = ?
    `;
    db.query(query, [orderId], (err, results) => {
        if (err) {
            console.error('Error fetching order items:', err);
            return res.status(500).json({ message: 'Error fetching order items.' });
        }

        const parsedResults = results.map(item => {
            let stuklijstData = [];
            if (item.stuklijst) {
                try {
                    stuklijstData = JSON.parse(item.stuklijst);
                } catch (parseError) {
                    console.error('Error parsing stuklijst JSON:', parseError);
                    // Als er een parsing error is, laten we het op een lege array
                }
            }
            return {
                ...item,
                stuklijst: stuklijstData
            };
        });

        res.json(parsedResults);
    });
});





