/* --------------------------------------------------------------------
 * POST /api/orders
 * Slaat een nieuw order op, inclusief:
 *   – upsert van nieuwe items       → tabel items
 *   – insert van order_items        → tabel order_items
 *   – insert van Prepack-verbruik   → tabel material_consumption
 *   - opslaan prepack_division      → tabel orders
 *   - opslaan prepack_code          → tabel order_items
 * ------------------------------------------------------------------ */
app.post('/api/orders', (req, res) => {
    const {
      order_nummer,
      klant,
      beschrijving,
      startdatum,
      einddatum,
      items,
      prepack, // Expecting a boolean true/false
      prepack_division
    } = req.body;
  
    // Log incoming data for debugging
    console.log('--- POST /api/orders ---');
    console.log('Received req.body:', JSON.stringify(req.body, null, 2));
    console.log('Parsed prepack:', prepack, typeof prepack);
    console.log('Parsed prepack_division:', prepack_division, typeof prepack_division);
  
    if (!order_nummer || !klant || !startdatum || !einddatum ||
        !Array.isArray(items) || items.length === 0) {
      console.error('Validation Error: Missing required fields.');
      return res.status(400).json({ message: 'Ongeldige invoer voor order.' });
    }
  
    // Basic validation for prepack fields if prepack is true
    if (prepack === true && (prepack_division === undefined || prepack_division === null || prepack_division.trim() === '')) {
      console.error('Validation Error: Prepack is true but prepack_division is missing or empty.');
      return res.status(400).json({ message: 'Prepack divisie is verplicht als prepack is aangevinkt.' });
    }
  
    db.beginTransaction(errTx => {
      if (errTx) {
        console.error('Transaction Start Error:', errTx);
        return res.status(500).json({ message: 'Transactie kon niet starten.' });
      }
  
      const sqlPrepackValue = prepack === true; // Converts to boolean, then DB driver handles (e.g., 1 or 0)
      const sqlPrepackDivisionValue = prepack === true ? prepack_division : null;
  
      console.log('SQL prepack value:', sqlPrepackValue);
      console.log('SQL prepack_division value:', sqlPrepackDivisionValue);
  
      const insertOrderSql = `
        INSERT INTO orders (
          order_nummer, klant, beschrijving, startdatum, einddatum, 
          prepack, prepack_division, status, active
        )
        VALUES (?, ?, ?, ?, ?, ?, ?, 'Open', 1) 
      `;
      
  db.query(insertOrderSql,
        [
          order_nummer, 
          klant, 
          beschrijving, 
          startdatum, 
          einddatum,
          sqlPrepackValue,   // Use the prepared boolean value
          sqlPrepackDivisionValue // Use the prepared division value or null
        ],
        (errOrder, orderRes) => {
          if (errOrder) {
            return db.rollback(() => {
              console.error('Order Insert SQL Error:', errOrder.sqlMessage || errOrder.message); 
              console.error('SQL State:', errOrder.sqlState);
              console.error('Error Number:', errOrder.errno);
              console.error('Failed SQL Query:', errOrder.sql);
              res.status(500).json({ message: 'Order kon niet toegevoegd worden.', error: errOrder.sqlMessage || errOrder.message });
            });
          }
          const orderId = orderRes.insertId;
          console.log(`Order inserted with ID: ${orderId}`);
  
          // Items upsert (assuming items table and logic remains similar)
          const upsertPromises = items.map(itm => new Promise((resolve, reject) => {
            const sql = `
              INSERT INTO items (naam, verkoopprijs, hout_kost, hulpstoffen, stuklijst, wood_m3)
              VALUES (?, ?, ?, ?, ?, ?)
              ON DUPLICATE KEY UPDATE
                verkoopprijs = VALUES(verkoopprijs),
                hout_kost    = VALUES(hout_kost),
                hulpstoffen  = VALUES(hulpstoffen),
                stuklijst    = VALUES(stuklijst),
                wood_m3      = VALUES(wood_m3)
            `;
            db.query(sql, [
              itm.item_naam,
              itm.verkoopprijs || 0,
              itm.hout_kost    || 0,
              itm.hulpstoffen  || 0,
              JSON.stringify(itm.stuklijst || []),
              itm.wood_m3 || 0
            ], err => err ? reject(err) : resolve());
          }));
  
          // Material consumption (remains similar)
          const consumptionValues = [];
          items.forEach(itm => {
            if (Array.isArray(itm.stuklijst)) {
              itm.stuklijst.forEach(line => {
                const qty = (Number(line.aantal) || 0) * (Number(itm.hoeveelheid) || 1);
                consumptionValues.push([
                  order_nummer, itm.item_naam, line.materiaal_code || line.houtsoort || '', 
                  line.description || '', qty, 'stk',
                  line.dikte || null, line.breedte || null, line.lengte || null
                ]);
              });
            }
          });
  
          const insertConsumption = () => new Promise((resolve, reject) => {
            if (!consumptionValues.length) return resolve();
            const cSql = `
              INSERT INTO material_consumption
                (order_nummer, item_code, material_code, description, quantity, unit,
                 thickness_mm, width_mm, length_mm)
              VALUES ?
            `;
            db.query(cSql, [consumptionValues], err => err ? reject(err) : resolve());
          });
  
          // Order_items (remains similar, prepack_code usage depends on your needs)
          const orderItemValues = items.map(itm => ([
            orderId, itm.item_naam, itm.hoeveelheid, itm.beschrijving || null,
            itm.verkoopprijs || 0, itm.hout_kost    || 0, itm.hulpstoffen  || 0,
            JSON.stringify(itm.stuklijst || []), itm.wood_m3 || 0,
            itm.prepack_code || null // Retained this if you use it for something else
          ]));
  
          const insertOrderItems = () => new Promise((resolve, reject) => {
            const sql = `
              INSERT INTO order_items
                (order_id, item_naam, hoeveelheid, beschrijving,
                 verkoopprijs, hout_kost, hulpstoffen, stuklijst, wood_m3, prepack_code)
              VALUES ?
            `;
            db.query(sql, [orderItemValues], err => err ? reject(err) : resolve());
          });
  
          Promise.all(upsertPromises)
            .then(insertConsumption)
            .then(insertOrderItems)
            .then(() => {
              db.commit(errCommit => {
                if (errCommit) {
                  return db.rollback(() => {
                    console.error('Commit Error:', errCommit);
                    res.status(500).json({ message: 'Commit mislukt.' });
                  });
                }
                console.log('Transaction committed successfully for order ID:', orderId);
                res.status(201).json({ message: 'Order succesvol toegevoegd!', orderId });
              });
            })
            .catch(errAll => {
              db.rollback(() => {
                console.error('Transaction Promise Chain Error:', errAll);
                res.status(500).json({ message: 'Opslaan van order mislukt.' });
              });
            });
        });
    });
  });
  




            



