// Haal orders op (alleen niet-afgewerkte orders)
app.get('/api/orders', (req, res) => {
    const searchTerm = req.query.search || '';

    // Query om orders op te halen die niet volledig afgewerkt zijn
    const query = `
        SELECT o.id, o.order_nummer, o.klant, o.beschrijving, o.status,
               SUM(oi.afgewerkt_aantal) AS totale_afgewerkte_aantal,
               SUM(oi.hoeveelheid) AS totale_hoeveelheid
        FROM orders o
        JOIN order_items oi ON o.id = oi.order_id
        WHERE o.order_nummer LIKE ? AND 
              (SELECT COUNT(*) FROM order_items WHERE order_id = o.id AND status != 'Afgewerkt') > 0
        GROUP BY o.id
    `;

    const likeSearchTerm = `%${searchTerm}%`;

    db.query(query, [likeSearchTerm], (err, results) => {
        if (err) {
            console.error('Database error:', err);
            return res.status(500).json({ message: 'Fout bij het ophalen van orders.' });
        }

        // Bereken de totale manuren alleen voor actieve items
        const orders = results.map(order => ({
            id: order.id,
            order_nummer: order.order_nummer,
            klant: order.klant,
            beschrijving: order.beschrijving,
            status: order.status,
            totale_manuren: order.totale_afgewerkte_aantal // Pas aan indien nodig
        }));

        res.json(orders);
    });
});


// Markeer een order als afgewerkt
app.post('/api/orders/:orderId/mark-complete', (req, res) => {
    const orderId = req.params.orderId;

    // Controleer of alle items in de order zijn afgewerkt
    const checkItemsQuery = 'SELECT COUNT(*) AS remaining FROM order_items WHERE order_id = ? AND status != "Afgewerkt"';
    db.query(checkItemsQuery, [orderId], (err, results) => {
        if (err) {
            console.error('Database error:', err);
            return res.status(500).json({ message: 'Fout bij het controleren van de items.' });
        }

        const remaining = results[0].remaining;

        if (remaining > 0) {
            return res.status(400).json({ message: 'Niet alle items in deze order zijn afgewerkt.' });
        }

        // Update de status van de order naar "Afgewerkt"
        const updateOrderStatusQuery = 'UPDATE orders SET status = "Afgewerkt" WHERE id = ?';
        db.query(updateOrderStatusQuery, [orderId], (err2) => {
            if (err2) {
                console.error('Database error:', err2);
                return res.status(500).json({ message: 'Fout bij het bijwerken van de orderstatus.' });
            }
            res.json({ message: 'Order succesvol als afgewerkt gemarkeerd.' });
        });
    });
});

