// Start tijdsregistratie met uitgebreidere logging
// Start tijdsregistratie met uitgebreidere logging
// Start tijdsregistratie
app.post('/api/timelog/start', (req, res) => {
    const { orderId, orderItemId, productionStepId, werknemers, type } = req.body;
    const startTime = new Date();
    
    console.log('Start Tijd Registratie:', { orderId, orderItemId, productionStepId, werknemers, type, startTime });
    
    if (!orderId || !productionStepId || !Array.isArray(werknemers) || werknemers.length === 0) {
        console.warn('Ongeldige invoer:', req.body);
        return res.status(400).json({ message: 'Ongeldige invoer voor tijdsregistratie.' });
    }
    
    // Controleer of er al een actieve tijdsregistratie is voor de werknemers en productie stap
    const checkActiveQuery = `
        SELECT werknemer_id FROM time_logs 
        WHERE werknemer_id IN (?) 
          AND production_step_id = ? 
          AND is_paused = FALSE 
          AND eind_tijd IS NULL
    `;
    
    db.query(checkActiveQuery, [werknemers, productionStepId], (err, activeLogs) => {
        if (err) {
            console.error('Database error tijdens het controleren van actieve tijdsregistraties:', err);
            return res.status(500).json({ message: 'Er is een fout opgetreden bij het controleren van actieve tijdsregistraties.' });
        }
        
        if (activeLogs.length > 0) {
            const werknemersMetActieveLogs = activeLogs.map(log => log.werknemer_id).join(', ');
            return res.status(400).json({ message: `Werknemers met ID's ${werknemersMetActieveLogs} hebben al een actieve tijdsregistratie.` });
        }
        
        // Als er geen actieve logs zijn, ga verder met het starten van de tijdsregistratie
        const values = werknemers.map((werknemerId) => [
            orderId,
            orderItemId || null,
            productionStepId,
            werknemerId,
            startTime,
            type
        ]);
        
        console.log('Invoegen waarden:', values);
        
        const insertQuery = `
            INSERT INTO time_logs (order_id, order_item_id, production_step_id, werknemer_id, start_tijd, \`type\`)
            VALUES ?
        `;
        
        db.query(insertQuery, [values], (err, result) => {
            if (err) {
                console.error('Database error tijdens tijdsregistratie:', err);
                return res.status(500).json({ message: 'Er is een fout opgetreden bij het starten van de tijdsregistratie.' });
            }
            console.log('Tijdsregistratie succesvol gestart:', result);
            res.json({ message: 'Tijdsregistratie gestart voor geselecteerde werknemers.' });
        });
    });
});




// Pauze tijdsregistratie met automatische pauze verwerking
// Pauzeer een specifieke tijdsregistratie
// Update deze route in je backend
app.post('/api/timelog/:logId/pause', (req, res) => {
    const logId = req.params.logId;

    // Eerst haal de huidige tijdslog op
    const getLogQuery = `
        SELECT id, start_tijd, is_paused, eind_tijd 
        FROM time_logs 
        WHERE id = ?`;

    db.query(getLogQuery, [logId], (err, results) => {
        if (err) {
            console.error('Database error:', err);
            return res.status(500).json({ 
                message: 'Fout bij het ophalen van de tijdslog.',
                error: err.message 
            });
        }

        if (results.length === 0) {
            return res.status(404).json({ 
                message: 'Tijdslog niet gevonden.' 
            });
        }

        const log = results[0];
        
        if (log.is_paused || log.eind_tijd !== null) {
            return res.status(400).json({ 
                message: 'Tijdsregistratie is al gepauzeerd of gestopt.' 
            });
        }

        // Update met expliciete tijdzone handling
        const updateQuery = `
            UPDATE time_logs 
            SET 
                is_paused = 1,
                eind_tijd = UTC_TIMESTAMP(),
                duur = TIMESTAMPDIFF(
                    SECOND, 
                    CONVERT_TZ(start_tijd, '+00:00', @@session.time_zone),
                    UTC_TIMESTAMP()
                )
            WHERE id = ? 
            AND is_paused = 0 
            AND eind_tijd IS NULL`;

        db.query(updateQuery, [logId], (updateErr, updateResult) => {
            if (updateErr) {
                console.error('Update error:', updateErr);
                return res.status(500).json({ 
                    message: 'Fout bij het pauzeren van de tijdsregistratie.',
                    error: updateErr.message 
                });
            }

            // Haal de bijgewerkte tijdslog op
            const getUpdatedLogQuery = `
                SELECT 
                    id,
                    start_tijd,
                    eind_tijd,
                    duur,
                    is_paused
                FROM time_logs 
                WHERE id = ?`;

            db.query(getUpdatedLogQuery, [logId], (err3, results3) => {
                if (err3) {
                    return res.status(200).json({ 
                        message: 'Tijdsregistratie gepauzeerd, maar kon details niet ophalen.',
                        success: true
                    });
                }

                const updatedLog = results3[0];
                res.json({
                    message: 'Tijdsregistratie succesvol gepauzeerd.',
                    data: updatedLog
                });
            });
        });
    });
});



