app.post('/api/timelog/resume', (req, res) => {
    const { orderId, orderItemId, productionStepId, werknemers, type } = req.body;
    const startTime = new Date();
    
    if (!orderId || !productionStepId || !Array.isArray(werknemers) || werknemers.length === 0) {
        return res.status(400).json({ message: 'Ongeldige invoer voor het hervatten van tijdsregistratie.' });
    }
    
    const values = werknemers.map((werknemerId) => [
        orderId,
        orderItemId || null,
        productionStepId,
        werknemerId,
        startTime,
        type
    ]);
    
    const query = `
        INSERT INTO time_logs (order_id, order_item_id, production_step_id, werknemer_id, start_tijd, type)
        VALUES ?
    `;
    
    db.query(query, [values], (err, result) => {
        if (err) {
            console.error('Database error:', err);
            return res.status(500).json({ message: 'Er is een fout opgetreden bij het hervatten van de tijdsregistratie.' });
        }
        res.json({ message: 'Tijdsregistratie hervat voor geselecteerde werknemers.' });
    });
});

// 5. Order Items Routes

// Update het aantal afgewerkte items (partiële afronding)
app.post('/api/order-items/:itemId/afgewerkt-aantal', (req, res) => {
    const itemId = req.params.itemId;
    const { afgewerkt_aantal } = req.body;

    if (typeof afgewerkt_aantal !== 'number' || afgewerkt_aantal < 0) {
        return res.status(400).json({ message: 'Ongeldig aantal afgewerkte items.' });
    }

    // Haal de totale hoeveelheid van het item op
    const getItemQuery = 'SELECT hoeveelheid, afgewerkt_aantal FROM order_items WHERE id = ?';
    db.query(getItemQuery, [itemId], (err, results) => {
        if (err) {
            console.error('Database error:', err);
            return res.status(500).json({ message: 'Fout bij het ophalen van het item.' });
        }

        if (results.length === 0) {
            return res.status(404).json({ message: 'Item niet gevonden.' });
        }

        const { hoeveelheid, afgewerkt_aantal: huidigeAfgewerktAantal } = results[0];
        const nieuweAfgewerktAantal = huidigeAfgewerktAantal + afgewerkt_aantal;

        if (nieuweAfgewerktAantal > hoeveelheid) {
            return res.status(400).json({ message: 'Afgewerkt aantal mag niet hoger zijn dan de totale hoeveelheid.' });
        }

        // Update het afgewerkt_aantal
        const updateAfgewerktAantalQuery = 'UPDATE order_items SET afgewerkt_aantal = ? WHERE id = ?';
        db.query(updateAfgewerktAantalQuery, [nieuweAfgewerktAantal, itemId], (err2) => {
            if (err2) {
                console.error('Database error:', err2);
                return res.status(500).json({ message: 'Fout bij het bijwerken van het afgewerkt aantal.' });
            }

            // Controleer of het item volledig is afgerond
            if (nieuweAfgewerktAantal === hoeveelheid) {
                // Markeer het item als 'Afgewerkt'
                const updateStatusQuery = 'UPDATE order_items SET status = "Afgewerkt" WHERE id = ?';
                db.query(updateStatusQuery, [itemId], (err3) => {
                    if (err3) {
                        console.error('Database error:', err3);
                        return res.status(500).json({ message: 'Fout bij het bijwerken van de itemstatus.' });
                    }

                    // Controleer of alle items in de order zijn afgewerkt
                    const getOrderIdQuery = 'SELECT order_id FROM order_items WHERE id = ?';
                    db.query(getOrderIdQuery, [itemId], (err4, results4) => {
                        if (err4) {
                            console.error('Database error:', err4);
                            return res.status(500).json({ message: 'Fout bij het ophalen van het order ID.' });
                        }

                        const orderId = results4[0].order_id;

                        const checkItemsQuery = 'SELECT COUNT(*) AS remaining FROM order_items WHERE order_id = ? AND status != "Afgewerkt"';
                        db.query(checkItemsQuery, [orderId], (err5, results5) => {
                            if (err5) {
                                console.error('Database error:', err5);
                                return res.status(500).json({ message: 'Fout bij het controleren van de items.' });
                            }

                            const remaining = results5[0].remaining;

                            if (remaining === 0) {
                                // Alle items zijn afgewerkt, update de orderstatus naar "Afgewerkt"
                                const updateOrderStatusQuery = 'UPDATE orders SET status = "Afgewerkt" WHERE id = ?';
                                db.query(updateOrderStatusQuery, [orderId], (err6) => {
                                    if (err6) {
                                        console.error('Database error:', err6);
                                        return res.status(500).json({ message: 'Fout bij het bijwerken van de orderstatus.' });
                                    }
                                    res.json({ message: 'Item en orderstatus succesvol bijgewerkt.' });
                                });
                            } else {
                                res.json({ message: 'Itemstatus succesvol bijgewerkt.' });
                            }
                        });
                    });
                });
            } else {
                res.json({ message: 'Afgewerkt aantal succesvol bijgewerkt.' });
            }
        });
    });
});

// Update de status van een item
app.post('/api/order-items/:itemId/status', (req, res) => {
    const itemId = req.params.itemId;
    const { status } = req.body;

    if (!status) {
        return res.status(400).json({ message: 'Geen status opgegeven.' });
    }

    const query = 'UPDATE order_items SET status = ? WHERE id = ?';
    db.query(query, [status, itemId], (err, result) => {
        if (err) {
            console.error('Database error:', err);
            return res.status(500).json({ message: 'Fout bij het bijwerken van de itemstatus.' });
        }
        // Controleer of alle items van de order zijn afgewerkt
        const getOrderQuery = 'SELECT order_id FROM order_items WHERE id = ?';
        db.query(getOrderQuery, [itemId], (err2, results) => {
            if (err2) {
                console.error('Database error:', err2);
                return res.status(500).json({ message: 'Fout bij het ophalen van het order.' });
            }
            const orderId = results[0].order_id;
            const checkItemsQuery = 'SELECT COUNT(*) AS remaining FROM order_items WHERE order_id = ? AND status != "Afgewerkt"';
            db.query(checkItemsQuery, [orderId], (err3, results2) => {
                if (err3) {
                    console.error('Database error:', err3);
                    return res.status(500).json({ message: 'Fout bij het controleren van de items.' });
                }
                if (results2[0].remaining === 0) {
                    // Alle items zijn afgewerkt, update de orderstatus
                    const updateOrderStatusQuery = 'UPDATE orders SET status = "Afgewerkt" WHERE id = ?';
                    db.query(updateOrderStatusQuery, [orderId], (err4) => {
                        if (err4) {
                            console.error('Database error:', err4);
                            return res.status(500).json({ message: 'Fout bij het bijwerken van de orderstatus.' });
                        }
                        res.json({ message: 'Item en orderstatus succesvol bijgewerkt.' });
                    });
                } else {
                    res.json({ message: 'Itemstatus succesvol bijgewerkt.' });
                }
            });
        });
    });
});

