async function convertToBCFormat(filePath) {
    try {
        console.log('Converting file:', filePath);
        const workbook = xlsx.readFile(filePath, {
            cellStyles: true,
            cellFormulas: true,
            cellDates: true,
            cellNF: true,
            sheetStubs: true
        });

        let volgnummer = 1;
        const allRows = [];

        // We only need the first sheet
        const sheet = workbook.Sheets[workbook.SheetNames[0]];
        const sheetData = xlsx.utils.sheet_to_json(sheet, {
            header: 1,
            raw: false,
            defval: null
        });

        const headerRow = sheetData[4];
        if (!headerRow) return;

        const itemIndex = headerRow.indexOf("Item");
        const customerIndex = headerRow.indexOf("Customer");
        const locationColumnIndex = 70; // Column BS (index 70)

        // Process each data row
        for (let i = 5; i < sheetData.length; i++) {
            const row = sheetData[i];
            if (!row || !row[itemIndex] || row[itemIndex] === "Total") continue;

            // Check if location is 'Dongen'
            const location = row[locationColumnIndex];
            if (!location || location !== 'Dongen') continue;

            const itemFull = row[itemIndex];
            const customerFull = row[customerIndex];

            if (!itemFull || !customerFull) continue;

            const item = itemFull.split(' - ')[0];
            const customer = customerFull.split(' - ')[0];

            // Get yearly totals from columns BG and BH for this customer/item combination
            const totalQuantity = parseFloat((row[58] || '0').toString().replace(/,/g, '')) || 0;
            const totalAmount = parseFloat((row[59] || '0').toString().replace(/,/g, '')) || 0;

            if (totalQuantity === 0 && totalAmount === 0) continue;

            // Calculate monthly values for this customer/item combination
            const monthlyQuantity = Math.round(totalQuantity / 12);
            const monthlyAmount = Number((totalAmount / 12).toFixed(2));

            // Create 12 monthly entries for this customer/item combination
            for (let month = 0; month < 12; month++) {
                const date = new Date(2024, month, 1);
                date.setMonth(date.getMonth() + 1);
                date.setDate(0);
                const formattedDate = date.toISOString().split('T')[0];

                allRows.push([
                    volgnummer++,              // Volgnummer
                    "Verkoop",                 // Analysegebied
                    "SALES 2024",             // Budget
                    formattedDate,            // Datum
                    item,                      // Artikelnr
                    "Klant",                  // Bronsoort
                    customer,                 // Bronnr
                    `Geïmporteerd vanuit Excel ${new Date().toLocaleDateString('nl-NL')}`, // Omschrijving
                    monthlyQuantity.toString(), // Aantal
                    "0",                      // Totale kosten
                    monthlyAmount.toFixed(2),  // Totale omzet
                    "R.KLUGKIST",             // Gebruikers-id
                    "",                       // Vestiging
                    "",                       // Globale dimensiecode 1
                    "",                       // Globale dimensiecode 2
                    "",                       // Code budgetdimensie 1
                    "",                       // Code budgetdimensie 2
                    "",                       // Code budgetdimensie 3
                    ""                        // Dimensieset-id
                ]);
            }
        }

        // Sort rows by:
        // 1. Artikelnr
        // 2. Bronnr (customer)
        // 3. Datum
        allRows.sort((a, b) => {
            // First by Artikelnr (index 4)
            const itemCompare = a[4].localeCompare(b[4]);
            if (itemCompare !== 0) return itemCompare;
            
            // Then by customer (index 6)
            const customerCompare = a[6].localeCompare(b[6]);
            if (customerCompare !== 0) return customerCompare;
            
            // Finally by date (index 3)
            return new Date(a[3]) - new Date(b[3]);
        });

        // Renumber the volgnummers after sorting
        allRows.forEach((row, index) => {
            row[0] = index + 1;
        });

        const headerRows = [
            ["VERKOOPBUDGETTEN", "Artikelbudgetpost", "7134"],
            [],
            ["Volgnummer", "Analysegebied", "Budget", "Datum", "Artikelnr.", "Bronsoort", 
             "Bronnr.", "Omschrijving", "Aantal", "Totale kosten", "Totale omzet", 
             "Gebruikers-id", "Vestiging", "Globale dimensiecode 1", "Globale dimensiecode 2",
             "Code budgetdimensie 1", "Code budgetdimensie 2", "Code budgetdimensie 3", "Dimensieset-id"]
        ];

        const finalData = [...headerRows, ...allRows];

        const outputFilename = `BC_Import_${new Date().toISOString().split('T')[0]}_${Date.now()}.xlsx`;
        const outputPath = path.join(uploadDir, outputFilename);

        const wb = xlsx.utils.book_new();
        const ws = xlsx.utils.aoa_to_sheet(finalData);
        xlsx.utils.book_append_sheet(wb, ws, "Artikelbudgetpost");
        xlsx.writeFile(wb, outputPath);

        return {
            filename: outputFilename,
            rowCount: allRows.length,
            sheetCount: 1
        };

    } catch (error) {
        console.error('Error in conversion:', error);
        throw error;
    }
}
