app.post('/api/excel/convert', upload.single('file'), async (req, res) => {
    try {
        if (!req.file) {
            return res.status(400).json({
                success: false,
                message: 'Geen bestand geüpload'
            });
        }

        const result = await convertToBCFormat(req.file.path);
        
        // Verwijder het originele bestand
        fs.unlinkSync(req.file.path);

        res.json({
            success: true,
            message: 'Excel succesvol geconverteerd',
            data: result
        });

    } catch (error) {
        console.error('Error tijdens Excel conversie:', error);
        if (req.file) {
            // Probeer het originele bestand op te ruimen bij een error
            try {
                fs.unlinkSync(req.file.path);
            } catch (e) {
                console.error('Error bij opruimen bestand:', e);
            }
        }
        res.status(500).json({
            success: false,
            message: 'Fout bij verwerken van Excel bestand',
            error: error.message
        });
    }
});

