app.post('/register_output', (req, res) => {
    const { work_order, machine_type, operator_name, start_time_fetching, end_time_fetching, start_time_cutting, end_time_cutting, total_time, comments } = req.body;

    // Controleer of er al een invoer is voor het werkorder en machine_type waar end_time_cutting of end_time_fetching nog NULL is
    const checkQuery = `
        SELECT id FROM saw_machine_output
        WHERE work_order = ? AND machine_type = ? AND (end_time_cutting IS NULL OR end_time_fetching IS NULL)
    `;

    db.query(checkQuery, [work_order, machine_type], (err, result) => {
        if (err) {
            console.error('Error checking existing output:', err);
            return res.status(500).send('Database error');
        }

        if (result.length > 0) {
            // Update de bestaande rij
            const updateQuery = `
                UPDATE saw_machine_output
                SET end_time_fetching = ?, end_time_cutting = ?, total_time = ?, comments = ?
                WHERE id = ?
            `;
            db.query(updateQuery, [end_time_fetching, end_time_cutting, total_time, comments, result[0].id], (err, updateResult) => {
                if (err) {
                    console.error('Error updating saw machine output:', err);
                    return res.status(500).send('Database error');
                }
                res.send('Output updated successfully');
            });
        } else {
            // Voeg een nieuwe invoer toe
            const insertQuery = `
                INSERT INTO saw_machine_output (work_order, machine_type, operator_name, start_time_fetching, end_time_fetching, start_time_cutting, end_time_cutting, total_time, comments)
                VALUES (?, ?, ?, ?, ?, ?, ?, ?, ?)
            `;
            db.query(insertQuery, [work_order, machine_type, operator_name, start_time_fetching, end_time_fetching, start_time_cutting, end_time_cutting, total_time, comments], (err, insertResult) => {
                if (err) {
                    console.error('Error inserting saw machine output:', err);
                    return res.status(500).send('Database error');
                }
                res.send('Output registered successfully');
            });
        }
    });
});


