function calculateTotalTime(start_time_fetching, end_time_fetching, start_time_cutting, end_time_cutting) {
    // Logic to calculate total time spent on the work order, excluding pauses
    // Example: difference in seconds or minutes between the given time intervals
    // Return the total time in minutes or any other unit
    return Math.floor((new Date(end_time_cutting) - new Date(start_time_fetching)) / 60000); // Example calculation in minutes
}

