app.post('/api/update_stock', (req, res) => {
    console.log('Ontvangen gegevens:', req.body);
    const { kistnummer, quantity } = req.body;

    // Eerst de huidige voorraad ophalen
    const fetchStockSql = `SELECT quantity FROM stock_airtec WHERE kistnummer = ?`;
    db.query(fetchStockSql, [kistnummer], (err, results) => {
        if (err) {
            console.error('Error fetching current stock:', err);
            return res.status(500).json({ error: 'Failed to fetch current stock.' });
        }

        if (results.length > 0) {
            const currentStock = results[0].quantity;
            const updatedStock = currentStock + parseInt(quantity, 10); // Voeg de nieuwe hoeveelheid toe aan de huidige stock

            // Update de stock met de nieuwe waarde
            const updateStockSql = `UPDATE stock_airtec SET quantity = ? WHERE kistnummer = ?`;
            db.query(updateStockSql, [updatedStock, kistnummer], (err, result) => {
                if (err) {
                    console.error('Error updating stock:', err);
                    return res.status(500).json({ error: 'Failed to update stock.' });
                }

                // Controleer direct na het bijwerken of de voorraad onder de minimumwaarde zit
                const checkStockSql = `SELECT quantity, minimum_stock FROM stock_airtec WHERE kistnummer = ?`;
                db.query(checkStockSql, [kistnummer], (err, results) => {
                    if (err) {
                        console.error('Error checking stock:', err);
                        return res.status(500).json({ error: 'Failed to check stock.' });
                    }

                    const { quantity, minimum_stock } = results[0];
                    if (quantity < minimum_stock) {
                        sendReorderNotification(kistnummer, quantity, minimum_stock); // Automatisch e-mail versturen
                    }
                });

                res.json({ success: true, message: 'Stock succesvol bijgewerkt.' });
            });
        } else {
            res.status(404).json({ error: 'Kistnummer niet gevonden.' });
        }
    });
});


