app.post('/api/update_stock_item', (req, res) => { // Route naam veranderd om duplicatie te voorkomen
    const { id, current_stock } = req.body;

    const sqlFetch = 'SELECT item_name, minimum_stock FROM Stock_telling WHERE id = ?';
    db.query(sqlFetch, [id], (err, results) => {
        if (err) {
            console.error('Error fetching minimum stock:', err);
            return res.status(500).json({ error: 'Failed to fetch minimum stock.' });
        }

        const minimumStock = results[0]?.minimum_stock || 0;
        const itemName = results[0]?.item_name;

        const sqlUpdate = 'UPDATE Stock_telling SET current_stock = ? WHERE id = ?';
        db.query(sqlUpdate, [current_stock, id], (err, result) => {
            if (err) {
                console.error('Error updating stock:', err);
                return res.status(500).json({ error: 'Failed to update stock.' });
            }

            if (current_stock < minimumStock) {
                const reorderAantal = minimumStock - current_stock;
                const reorderSql = `INSERT INTO reorders (artikel_id, aantal, besteld_op) VALUES (?, ?, NOW())`;
                db.query(reorderSql, [id, reorderAantal], err => {
                    if (err) {
                        console.error('Error creating reorder:', err);
                        return res.status(500).json({ error: 'Failed to create reorder' });
                    }
                    res.json({
                        success: true,
                        reorder: true,
                        aantal: reorderAantal,
                        message: `Stock updated, reorder ${reorderAantal} items.`
                    });
                });
            } else {
                res.json({ success: true, reorder: false, message: 'Stock updated successfully.' });
            }
        });
    });
});


