// Endpoint to upload and parse PDF work order
app.post('/api/upload_workorder', async (req, res) => {
    const start = Date.now(); // Start timing the process

    if (!req.files || !req.files.workorder) {
        console.error('No file uploaded');
        return res.status(400).json({ error: 'No file uploaded' });
    }

    const workorderFile = req.files.workorder;
    const filePath = path.join(__dirname, 'uploads', workorderFile.name);

    // Save the uploaded PDF to the server
    try {
        await workorderFile.mv(filePath);
        console.log('File successfully saved to:', filePath);
    } catch (err) {
        console.error('Error saving file:', err);
        return res.status(500).json({ error: 'Error saving file' });
    }

    try {
        // Convert PDF to images
        console.log('Starting PDF to image conversion...');
        const convertStart = Date.now();
        const outputImages = await pdf2img.convert(filePath);
        console.log('PDF to image conversion took:', Date.now() - convertStart, 'ms');

        if (outputImages.length === 0) {
            console.error('No images generated from PDF');
            return res.status(400).json({ error: 'No images generated from PDF' });
        }

        // Apply OCR to the first image
        console.log('Starting OCR processing...');
        const ocrStart = Date.now();
        const image = outputImages[0]; // Using the first page of the PDF
        const ocrResult = await Tesseract.recognize(image, 'eng', {
            corePath: '/tesseract-core.wasm', // Correct path to the WASM file
            logger: info => console.log(info), // Optional: logging for progress tracking
        });
        console.log('OCR processing took:', Date.now() - ocrStart, 'ms');

        // Log OCR result for debugging
        console.log('OCR Result:', ocrResult.data.text);

        // Extract planks information from OCR result
        const requiredPlanks = extractPlanksFromWorkOrder(ocrResult.data.text);
        if (!requiredPlanks || requiredPlanks.length === 0) {
            console.error('No planks found in work order');
            return res.status(400).json({ error: 'No planks found in work order' });
        }

        // Log the extracted planks for debugging
        console.log('Extracted planks:', requiredPlanks);

        // Perform any database queries or further processing here
        const plankDetails = await getMatchingPlanks(requiredPlanks);

        // Send the response back to the frontend
        res.json(plankDetails);

        console.log('Total processing time:', Date.now() - start, 'ms');
    } catch (err) {
        console.error('Error processing work order:', err);
        res.status(500).json({ error: 'Error processing work order' });
    } finally {
        // Clean up the uploaded file
        fs.unlink(filePath, (err) => {
            if (err) console.error('Error deleting uploaded file:', err);
        });
    }
});

