// Function to extract plank details from the OCR text
function extractPlanksFromWorkOrder(text) {
    const planks = [];

    // Split the text into lines and parse each line for plank information
    const lines = text.split('\n');
    lines.forEach(line => {
        // Example of simple regex to extract "Houtsoort", "Lengte", "Breedte", "Dikte"
        const match = line.match(/Houtsoort: (\w+), Lengte: (\d+), Breedte: (\d+), Dikte: (\d+)/);
        if (match) {
            const soort = match[1];
            const lengte = parseInt(match[2]);
            const breedte = parseInt(match[3]);
            const dikte = parseInt(match[4]);
            planks.push({ soort, lengte, breedte, dikte });
        }
    });

    return planks;
}

