// Add new packer
app.post('/api/item_packers', (req, res) => {
    const { itemId, employeeId } = req.body;
    
    // Check if employee is already active on this item
    db.query(
        'SELECT * FROM item_packers WHERE item_id = ? AND employee_id = ? AND active = TRUE',
        [itemId, employeeId],
        (err, results) => {
            if (err) {
                console.error('Error checking existing packer:', err);
                return res.status(500).json({ error: 'Database error' });
            }

            if (results.length > 0) {
                return res.status(400).json({ error: 'Employee already active on this item' });
            }

            // Add new packer with status 'active' instead of 'packed'
            db.query(
                'INSERT INTO item_packers (item_id, employee_id, status, active, start_time) VALUES (?, ?, "active", 1, NOW())',
                [itemId, employeeId],
                (err, result) => {
                    if (err) {
                        console.error('Error adding packer:', err);
                        return res.status(500).json({ error: 'Database error' });
                    }
                    res.json({ id: result.insertId });
                }
            );
        }
    );
});

