// In je app.js / server.js waar je andere routes hebt
// Pauzeer verpakker en registreer het pauzetijdstip
// Endpoint om een packer te pauzeren en het pauzetijdstip vast te leggen
// Pauzeer verpakker en registreer het pauzetijdstip, en zet ook active op FALSE
app.post('/api/item_packers/:packerId/pause', (req, res) => {
    const { packerId } = req.params;

    // Eerst de packer ophalen
    const selectQuery = 'SELECT * FROM item_packers WHERE id = ?';
    db.query(selectQuery, [packerId], (err, rows) => {
        if (err) {
            console.error('Error fetching packer:', err);
            return res.status(500).json({ success: false, error: 'Database error bij ophalen packer' });
        }
        if (rows.length === 0) {
            return res.status(404).json({ success: false, error: 'Packer niet gevonden' });
        }
        
        const packer = rows[0];
        
        // Als de packer al gepauzeerd is, geef direct een succesmelding
        if (packer.paused) {
            return res.json({ success: true, message: 'Packer is al gepauzeerd' });
        }
        
        if (!packer.active) {
            return res.status(400).json({ success: false, error: 'Packer is niet actief en kan niet worden gepauzeerd' });
        }
        
        // Update de packer-record:
        // - Zet paused op 1 en active op 0
        // - Registreer het pauzetijdstip en stel end_time in op NOW() zodat de bestede tijd wordt vastgelegd
        const updatePackerQuery = `
            UPDATE item_packers
            SET paused = 1,
                active = 0,
                pause_time = NOW(),
                end_time = NOW()
            WHERE id = ?`;
            
        db.query(updatePackerQuery, [packerId], (err, result) => {
            if (err) {
                console.error('Error updating packer for pause:', err);
                return res.status(500).json({ success: false, error: 'Database error bij pauzeren van verpakker' });
            }
            if (result.affectedRows === 0) {
                return res.status(404).json({ success: false, error: 'Geen packer bijgewerkt' });
            }
            
            // Omdat de verpakkingsprocessen alleen in item_packers worden geregistreerd,
            // is er geen update van een time_logs-tabel nodig.
            res.json({ success: true, message: 'Verpakker succesvol gepauzeerd en tijd geregistreerd' });
        });
    });
});


// Helper-functie: update de time_logs-tabel
function updateTimeLog(werknemerId, orderId, res) {
    const updateTimerQuery = `
        UPDATE time_logs
        SET eind_tijd = NOW()
        WHERE werknemer_id = ? 
          AND order_id = ?
          AND eind_tijd IS NULL
    `;
    db.query(updateTimerQuery, [werknemerId, orderId], (err, result) => {
        if (err) {
            console.error("Error updating time_logs for pause:", err);
            return res.status(500).json({ success: false, error: 'Database error bij pauzeren timer' });
        }
        res.json({ success: true, message: 'Verpakker succesvol gepauzeerd en timer gestopt' });
    });
}







