app.post('/api/assignments', (req, res) => {
    const assignments = req.body;
    const currentTime = new Date();  // Huidige tijd als starttijd

    // Controleer of alle verplichte velden aanwezig zijn
    if (!assignments || assignments.some(a => !a.employee_id || !a.workstation_id || !a.date)) {
        return res.status(400).json({ status: 'error', message: 'Verplichte velden ontbreken' });
    }

    // Voeg start_time toe aan de toewijzingen
    const values = assignments.map(a => [a.employee_id, a.workstation_id, currentTime, a.date]);

    const sql = 'INSERT INTO assignments (employee_id, workstation_id, start_time, date) VALUES ? ON DUPLICATE KEY UPDATE id = id';

    db.query(sql, [values], (err, result) => {
        if (err) {
            console.error('Databasefout:', err);
            return res.status(500).json({ status: 'error', message: 'Databasefout', error: err.sqlMessage });
        }
        res.json({ status: 'success', message: 'Toewijzingen succesvol opgeslagen' });
    });
});

