// Toewijzingen ophalen voor een bepaalde dag
// Toewijzingen ophalen met namen van medewerkers en werkposten
app.get('/api/assignments', (req, res) => {
    const { date } = req.query;
    let sql = `
        SELECT e.name AS employee_name, w.name AS workstation_name, a.start_time, a.end_time, 
               TIMESTAMPDIFF(HOUR, a.start_time, a.end_time) AS hours_worked
        FROM assignments a
        JOIN employees e ON a.employee_id = e.id
        JOIN workstations w ON a.workstation_id = w.id
    `;
    const params = [];

    if (date) {
        sql += ' WHERE a.date = ?';
        params.push(date);
    }

    sql += ' ORDER BY w.name, e.name';

    db.query(sql, params, (err, results) => {
        if (err) {
            console.error('Error fetching assignments:', err);
            return res.status(500).send({ message: 'Fout bij het ophalen van de toewijzingen' });
        }
        res.send(results);
    });
});






