// In je Express app
// In je Express app
app.put('/api/update_bestelling/:id', async (req, res) => {
    const { id } = req.params;
    const { field, value } = req.body;

    console.log('Updating bestelling:', { id, field, value }); // Debug logging

    // Lijst van toegestane velden om te updaten
    const allowedFields = [
        'houtsoort',
        'min_lengte',
        'dikte',
        'breedte',
        'aantal_pakken',
        'planken_per_pak',
        'locatie',
        'opmerkingen'
    ];

    try {
        // Valideer het veld
        if (!allowedFields.includes(field)) {
            console.log('Invalid field:', field); // Debug logging
            return res.status(400).json({
                success: false,
                message: `Dit veld (${field}) kan niet worden gewijzigd`
            });
        }

        // Valideer de waarde op basis van het veld
        let processedValue = value;
        if (['dikte', 'breedte', 'aantal_pakken', 'planken_per_pak'].includes(field)) {
            const numValue = parseFloat(value);
            if (isNaN(numValue)) {
                console.log('Invalid numeric value:', value); // Debug logging
                return res.status(400).json({
                    success: false,
                    message: 'Ongeldige numerieke waarde'
                });
            }
            processedValue = numValue;
        }

        // Zorg dat lege strings NULL worden in de database
        if (processedValue === '') {
            processedValue = null;
        }

        // Update de database
        const query = `
            UPDATE bestellingen 
            SET ${field} = ?
            WHERE id = ?
        `;

        console.log('Executing query:', query, [processedValue, id]); // Debug logging

        db.query(query, [processedValue, id], (err, result) => {
            if (err) {
                console.error('Database error:', err); // Debug logging
                return res.status(500).json({
                    success: false,
                    message: 'Database fout bij updaten',
                    error: err.message
                });
            }

            if (result.affectedRows === 0) {
                return res.status(404).json({
                    success: false,
                    message: 'Bestelling niet gevonden'
                });
            }

            res.json({
                success: true,
                message: 'Bestelling succesvol bijgewerkt',
                affected_rows: result.affectedRows
            });
        });

    } catch (error) {
        console.error('Error in update route:', error); // Debug logging
        res.status(500).json({
            success: false,
            message: 'Er is een fout opgetreden bij het updaten van de bestelling',
            error: error.message
        });
    }
});

// In je Express app
app.delete('/api/hout_ontvangen/:id', async (req, res) => {
    const { id } = req.params;

    try {
        // Controleer eerst of het item bestaat
        const checkQuery = 'SELECT id FROM hout_ontvangen WHERE id = ?';
        const item = await new Promise((resolve, reject) => {
            db.query(checkQuery, [id], (err, results) => {
                if (err) reject(err);
                else resolve(results[0]);
            });
        });

        if (!item) {
            return res.status(404).json({
                success: false,
                message: 'Item niet gevonden'
            });
        }

        // Verwijder het item
        const deleteQuery = 'DELETE FROM hout_ontvangen WHERE id = ?';
        await new Promise((resolve, reject) => {
            db.query(deleteQuery, [id], (err, result) => {
                if (err) reject(err);
                else resolve(result);
            });
        });

        res.json({
            success: true,
            message: 'Item succesvol verwijderd'
        });

    } catch (error) {
        console.error('Error deleting hout_ontvangen item:', error);
        res.status(500).json({
            success: false,
            message: 'Er is een fout opgetreden bij het verwijderen van het item',
            error: error.message
        });
    }
});

