// Function to send the order email
function sendOrderEmail(orderList, callback) {
    const transporter = nodemailer.createTransport({
        host: 'mail.prodwilrijk.be',
        port: 465,
        secure: true,
        auth: {
            user: 'jason@prodwilrijk.be',
            pass: 'prodwilrijk147'
        }
    });

    // Create the email body with the list of articles
    let emailBody = '<p>Bestelde artikelen:</p><ul>';
    orderList.forEach(item => {
        emailBody += `
            <li>
                <strong>Artikel Omschrijving:</strong> ${item.description} <br>
                <strong>Artikelnummer:</strong> ${item.articleNumber} <br>
                <strong>Aantal:</strong> ${item.quantity}
            </li>
        `;
    });
    emailBody += '</ul>';

    const mailOptions = {
        from: 'jason@prodwilrijk.be',
        to: 'j.ploegaerts@foresco.eu,prodwilrijk@foresco.eu',  // Update the recipient email as needed
        subject: 'Nieuwe Algemene Bestelling',
        html: `
            <p>Goedemiddag,</p>
            ${emailBody}
            <p><strong>Datum:</strong> ${new Date().toLocaleDateString()}</p>
            <p>Met vriendelijke groeten,</p>
            <p>Jason Ploegaerts</p>
        `
    };

    // Send the email
    transporter.sendMail(mailOptions, (error, info) => {
        if (error) {
            console.error('Error sending email:', error);
            return callback(error);  // Pass the error to the callback
        }
        console.log('Email sent: ' + info.response);
        callback(null);  // No error, pass null to the callback
    });
}






