// API route to get all checklists
app.get('/api/get_checklists', (req, res) => {
    const { werkorder, gebruiker, datum } = req.query;
    let sql = `
        SELECT c.*, w.order_description  -- Haal order_description op uit workorders
        FROM checklist c
        JOIN workorders w ON c.werkorder = w.order_number
        WHERE 1=1
    `;

    const params = [];
    if (werkorder) {
        sql += ' AND c.werkorder = ?';
        params.push(werkorder);
    }
    if (gebruiker) {
        sql += ' AND c.verantwoordelijke LIKE ?';
        params.push(`%${gebruiker}%`);
    }
    if (datum) {
        sql += ' AND c.datum = ?';
        params.push(datum);
    }

    db.query(sql, params, (err, results) => {
        if (err) {
            console.error('Error fetching checklists:', err);
            return res.status(500).json({ error: 'Error fetching checklists' });
        }
        res.json(results);  // Stuur de resultaten inclusief order_description terug
    });
});







