// Endpoint om BC code op te halen op basis van breedte, dikte en houtsoort
app.post('/api/get_bc_code', (req, res) => {
    const { breedte, dikte, houtsoort } = req.body;

    if (!breedte || !dikte || !houtsoort) {
        return res.status(400).json({ error: 'Missing parameters' });
    }

    const sql = `
        SELECT bc_code FROM bc_codes 
        WHERE breedte = ? AND dikte = ? AND LOWER(houtsoort) = LOWER(?) 
        LIMIT 1
    `;

    db.query(sql, [breedte, dikte, houtsoort], (err, results) => {
        if (err) {
            console.error('Error fetching BC code:', err);
            return res.status(500).json({ error: 'Database query error' });
        }

        if (results.length === 0) {
            return res.json({ bc_code: '' });
        }

        res.json({ bc_code: results[0].bc_code });
    });
});

