// Endpoint om meerdere BC-codes in bulk op te halen
app.post('/api/get_bc_codes', (req, res) => {
    const items = req.body.items;

    // Log de items die binnenkomen voor debuggen
    console.log('Ontvangen items voor BC-codes:', items);

    if (!Array.isArray(items) || items.length === 0) {
        return res.status(400).json({ error: 'Items array is leeg of ongeldig' });
    }

    // Bouw query dynamisch op voor meerdere items
    let placeholders = items.map(() => '(breedte = ? AND dikte = ? AND LOWER(houtsoort) = LOWER(?))').join(' OR ');
    let values = [];
    items.forEach(item => {
        const { breedte, dikte, houtsoort } = item;
        values.push(breedte, dikte, houtsoort);
    });

    const sql = `
        SELECT breedte, dikte, houtsoort, bc_code
        FROM bc_codes
        WHERE ${placeholders}
    `;

    // Log de gegenereerde query en de values
    console.log('SQL Query:', sql);
    console.log('Values voor de query:', values);

    db.query(sql, values, (err, results) => {
        if (err) {
            console.error('Error fetching BC codes:', err);
            return res.status(500).json({ error: 'Database query error' });
        }

        // Maak een mapping van combinatie naar BC-code
        let bcCodeMap = {};
        results.forEach(row => {
            const key = `${row.breedte}-${row.dikte}-${row.houtsoort.toLowerCase()}`;
            bcCodeMap[key] = row.bc_code;
        });

        // Log de resultaten die naar de frontend worden teruggestuurd
        console.log('BC-codes verzonden naar frontend:', bcCodeMap);

        res.json({ bc_codes: bcCodeMap });
    });
});


app.post('/api/send_combined_order_pdf', (req, res) => {
    const { orderList } = req.body;

    console.log('Received orderList with BC Codes:', orderList);

    if (!Array.isArray(orderList) || orderList.length === 0) {
        return res.status(400).json({ error: 'Order list is leeg of ongeldig' });
    }

    // Genereer de PDF
    const doc = new PDFDocument({ margin: 40, size: 'A4' });
    const fileName = `bestelling_${Date.now()}.pdf`;

    // Stream de PDF naar een bestand
    const writeStream = fs.createWriteStream(fileName);
    doc.pipe(writeStream);

    // Titel en datum toevoegen
    doc.fontSize(18).text('Openstaande Houtlijst', { align: 'center' });
    doc.moveDown(0.5);
    doc.fontSize(12).text(`Datum: ${moment().format('DD-MM-YYYY')}`, { align: 'center' });
    doc.moveDown(1);

    // Tabelkop definiëren
    const tableTop = doc.y;
    const itemSpacing = 25;
    const checkboxSize = 15;
    const columnWidths = [40, 100, 60, 60, 60, 60, 80, 100, 80]; // Kolombreedtes aanpassen indien nodig
    const columns = ['#', 'Houtsoort', 'Lengte', 'Dikte', 'Breedte', 'Aantal', 'BC Code', 'Opmerkingen', 'Besteld Op'];

    // Tabelkop tekenen
    let x = doc.page.margins.left + checkboxSize + 5;
    columns.forEach((column, i) => {
        doc.fontSize(10).text(column, x, tableTop, { width: columnWidths[i], align: 'left' });
        x += columnWidths[i];
    });

    // Lijn onder de tabelkop
    doc.moveTo(doc.page.margins.left, tableTop + 15)
        .lineTo(doc.page.width - doc.page.margins.right, tableTop + 15)
        .stroke();

    // Bestellingen toevoegen aan de tabel
    let y = tableTop + 20;
    orderList.forEach((item, index) => {
        x = doc.page.margins.left;

        // Checkbox voor aanduiding
        doc.rect(x, y - 2, checkboxSize, checkboxSize).stroke();
        x += checkboxSize + 5;

        // Gegevens invullen
        const row = [
            index + 1,
            item.houtsoort || 'N/A',
            item.minLengte || item.min_lengte || 'N/A',
            item.dikte || 'N/A',
            item.breedte || 'N/A',
            item.aantalPakken || item.aantal_pakken || 'N/A',
            item.bc_code || 'Geen code',
            item.opmerkingen || '',
            item.besteldOp || 'N/A'
        ];

        row.forEach((text, i) => {
            doc.fontSize(10).text(text, x, y, { width: columnWidths[i], align: 'left' });
            x += columnWidths[i];
        });

        y += itemSpacing;

        // Controleer of een nieuwe pagina nodig is
        if (y > doc.page.height - doc.page.margins.bottom - itemSpacing) {
            doc.addPage();
            y = doc.page.margins.top;

            // Tabelkop herhalen op nieuwe pagina
            x = doc.page.margins.left + checkboxSize + 5;
            columns.forEach((column, i) => {
                doc.fontSize(10).text(column, x, y, { width: columnWidths[i], align: 'left' });
                x += columnWidths[i];
            });

            doc.moveTo(doc.page.margins.left, y + 15)
                .lineTo(doc.page.width - doc.page.margins.right, y + 15)
                .stroke();

            y += 20;
        }
    });

    doc.end();

    // After the PDF is written, send the email
    writeStream.on('finish', function () {
        const mailOptions = {
            from: '"Bestellingen" <jason@prodwilrijk.be>',
            to: 'prodwilrijk@foresco.eu,j.ploegaerts@foresco.eu,jasonploegaerts@gmail.com',
            subject: 'Openstaande lijst Hout',
            text: 'Beste,\n\In bijlage lijst met openstaande hout.\n\nMet vriendelijke groet,\nForesco Wilrijk',
            attachments: [
                {
                    filename: fileName,
                    path: `./${fileName}`,
                    contentType: 'application/pdf'
                }
            ]
        };

        transporter.sendMail(mailOptions, (error, info) => {
            if (error) {
                console.error('Error sending email:', error);
                return res.status(500).json({ error: 'Fout bij verzenden van e-mail' });
            }
            console.log('E-mail verzonden:', info.response);

            // Remove the PDF file after sending
            fs.unlink(fileName, (err) => {
                if (err) {
                    console.error('Fout bij het verwijderen van het PDF-bestand:', err);
                }
            });

            res.json({ success: true, message: 'Bestelling succesvol verzonden als PDF' });
        });
    });

    writeStream.on('error', function (err) {
        console.error('Error writing PDF file:', err);
        return res.status(500).json({ error: 'Fout bij schrijven van PDF-bestand' });
    });
});

