// Update order with partially received packages
// Update order with partially received packages
app.put('/api/markeer_deels_ontvangen/:id', (req, res) => {
    const id = req.params.id;
    const { ontvangen_pakken } = req.body;

    // Fetch the order
    const getOrderSql = 'SELECT * FROM bestellingen WHERE id = ?';
    db.query(getOrderSql, [id], (err, results) => {
        if (err) {
            console.error('Error fetching order:', err);
            return res.status(500).json({ error: 'Database error' });
        }
        if (results.length === 0) {
            return res.status(404).json({ error: 'Order not found' });
        }
        const order = results[0];

        const totalOntvangenPakken = (order.ontvangen_pakken || 0) + ontvangen_pakken;

        // Validate total received packages
        if (totalOntvangenPakken > order.aantal_pakken) {
            return res.status(400).json({ error: 'Ontvangen pakketten overschrijden het aantal bestelde pakketten' });
        }

        // Start a database transaction
        db.beginTransaction(err => {
            if (err) {
                console.error('Error starting transaction:', err);
                return res.status(500).json({ error: 'Database error' });
            }

            // Insert received packages into 'hout_ontvangen'
            const insertOntvangenSql = `
                INSERT INTO hout_ontvangen (houtsoort, lengte, breedte, dikte, locatie, aantal_pakken, planken_per_pak, ontvangen_op, opmerkingen)
                VALUES (?, ?, ?, ?, ?, ?, ?, NOW(), ?)
            `;
            db.query(insertOntvangenSql, [
                order.houtsoort,
                order.min_lengte,
                order.breedte,
                order.dikte,
                order.locatie,
                ontvangen_pakken,
                order.planken_per_pak,
                order.opmerkingen
            ], (err, result) => {
                if (err) {
                    console.error('Error inserting into hout_ontvangen:', err);
                    return db.rollback(() => {
                        res.status(500).json({ error: 'Database error' });
                    });
                }

                // Update the order's ontvangen_pakken
                const updateOrderSql = 'UPDATE bestellingen SET ontvangen_pakken = ? WHERE id = ?';
                db.query(updateOrderSql, [totalOntvangenPakken, id], (err, result) => {
                    if (err) {
                        console.error('Error updating order:', err);
                        return db.rollback(() => {
                            res.status(500).json({ error: 'Database error' });
                        });
                    }

                    // If all packages are received, delete the order
                    if (totalOntvangenPakken === order.aantal_pakken) {
                        const deleteOrderSql = 'DELETE FROM bestellingen WHERE id = ?';
                        db.query(deleteOrderSql, [id], (err, result) => {
                            if (err) {
                                console.error('Error deleting order:', err);
                                return db.rollback(() => {
                                    res.status(500).json({ error: 'Database error' });
                                });
                            }

                            // Commit the transaction
                            db.commit(err => {
                                if (err) {
                                    console.error('Error committing transaction:', err);
                                    return db.rollback(() => {
                                        res.status(500).json({ error: 'Database error' });
                                    });
                                }
                                res.json({ success: true });
                            });
                        });
                    } else {
                        // Commit the transaction
                        db.commit(err => {
                            if (err) {
                                console.error('Error committing transaction:', err);
                                return db.rollback(() => {
                                    res.status(500).json({ error: 'Database error' });
                                });
                            }
                            res.json({ success: true });
                        });
                    }
                });
            });
        });
    });
});



