app.put('/api/volledig_gepickt/:id', async (req, res) => {
  const id = parseInt(req.params.id, 10);
  if (!id) {
    return res.status(400).json({ success: false, error: 'Ongeldig ID' });
  }

  const { soort, dikte, breedte, lengte, locatie } = req.body;
  // Of: const newValue = req.body[fieldName]; 
  //    hangt af van hoe je in finishEditingPicked(...) structureert

  try {
    // Stel je DB-tabel voor volledig gepickte items heet "volledig_gepickt"
    // En de kolommen heten "soort", "dikte", "breedte", "lengte", "locatie", ...
    // (pas desnoods de kolomnamen aan)
    let sql = 'UPDATE volledig_gepickt SET ';
    const fields = [];
    const values = [];
    
    // Voorbeeld: We bouwen dynamisch de SET.
    // Je kunt dit uiteraard anders oplossen als je weet welke kolommen je hebt.
    if (soort !== undefined) {
      fields.push('soort = ?');
      values.push(soort);
    }
    if (dikte !== undefined) {
      fields.push('dikte = ?');
      values.push(dikte);
    }
    if (breedte !== undefined) {
      fields.push('breedte = ?');
      values.push(breedte);
    }
    if (lengte !== undefined) {
      fields.push('lengte = ?');
      values.push(lengte);
    }
    if (locatie !== undefined) {
      fields.push('locatie = ?');
      values.push(locatie);
    }

    if (fields.length === 0) {
      return res.status(400).json({ success: false, error: 'Geen velden om te updaten' });
    }

    sql += fields.join(', ') + ' WHERE id=?';
    values.push(id);

    await queryPromise(sql, values);

    return res.json({ success: true });
  } catch (e) {
    console.error('PUT /api/volledig_gepickt/:id error:', e);
    return res.status(500).json({ success: false, error: e.message });
  }
});


