app.put('/api/hout_stock/:id', (req, res) => {
    const id = req.params.id;
    const updates = req.body;
    
    // Create the SET clause dynamically based on the provided updates
    const setClause = Object.entries(updates)
        .map(([key, _]) => `${key} = ?`)
        .join(', ');
    const values = [...Object.values(updates), id];
    
    const query = `UPDATE hout_stock SET ${setClause} WHERE id = ?`;
    
    db.query(query, values, (err, result) => {
        if (err) {
            console.error('Error updating stock:', err);
            return res.status(500).json({ 
                error: 'Database error',
                details: err.message 
            });
        }
        
        if (result.affectedRows === 0) {
            return res.status(404).json({ 
                error: 'Item not found' 
            });
        }
        
        res.json({ 
            success: true,
            message: 'Update successful',
            updatedFields: Object.keys(updates)
        });
    });
});



app.post('/api/voeg_bestelling_toe', (req, res) => {
    const { id, aantal_pakken } = req.body;

    // Check if ID is present
    if (!id || !aantal_pakken) {
        return res.status(400).json({ error: 'Alle velden zijn verplicht.' });
    }

    // First, fetch the pack details from the volledig_gepickt table using the ID
    const sqlFetch = `SELECT soort, lengte, breedte, dikte, locatie FROM volledig_gepickt WHERE id = ?`;

    db.query(sqlFetch, [id], (err, result) => {
        if (err) {
            console.error('Databasefout bij het ophalen van de volledig gepickte pak:', err.sqlMessage || err);
            return res.status(500).json({ error: 'Databasefout bij het ophalen van de volledig gepickte pak', details: err.sqlMessage || err });
        }

        // Extract the fetched data
        const { soort, lengte, breedte, dikte, locatie } = result[0];

        // Now, insert the pack details into the destination table
        const sqlInsert = `INSERT INTO bestellingen (houtsoort, min_lengte, breedte, dikte, aantal_pakken, ontvangen, planken_per_pak, besteld_op, opmerkingen, locatie)
                           VALUES (?, ?, ?, ?, ?, 0, 0, NOW(), NULL, ?)`;

        db.query(sqlInsert, [soort, lengte, breedte, dikte, aantal_pakken, locatie], (err, result) => {
            if (err) {
                console.error('Databasefout bij het toevoegen van de bestelling:', err.sqlMessage || err);
                return res.status(500).json({ error: 'Databasefout', details: err.sqlMessage || err });
            }

            // Verwijder de bestelling uit de volledig_gepickt tabel
            const sqlDelete = `DELETE FROM volledig_gepickt WHERE id = ?`;

            db.query(sqlDelete, [id], (err, result) => {
                if (err) {
                    console.error('Databasefout bij het verwijderen van de volledig gepickte pak:', err.sqlMessage || err);
                    return res.status(500).json({ error: 'Databasefout bij het verwijderen van de volledig gepickte pak', details: err.sqlMessage || err });
                }

                // Successfully added to "bestellingen" and removed from "volledig_gepickt"
                res.json({ success: true });
            });
        });
    });
});











