app.post('/api/hout_ontvangen/toevoegen_aan_voorraad_meerdere_pakken/:id', (req, res) => {
    const id = req.params.id;
    const { houtsoort, dikte, breedte, packs } = req.body;

    // Validate input
    if (!Array.isArray(packs) || packs.length === 0) {
        return res.status(400).json({ error: 'Geen pakken om toe te voegen' });
    }

    // Start a database transaction
    db.beginTransaction(err => {
        if (err) {
            console.error('Error starting transaction:', err);
            return res.status(500).json({ error: 'Database error' });
        }

        // Loop over each pack and insert into 'hout_stock'
        let insertPromises = packs.map(pack => {
            return new Promise((resolve, reject) => {
                const { lengte, aantal_pakken, planken_per_pak, locatie } = pack;

                // Validate pack data
                if (!lengte || !aantal_pakken || !planken_per_pak || !locatie) {
                    return reject(new Error('Ongeldige pakgegevens'));
                }

                // Calculate total number of planks
                const totaalAantal = aantal_pakken * planken_per_pak;

                const insertStockSql = `
                    INSERT INTO hout_stock (soort, lengte, breedte, dikte, locatie, aantal)
                    VALUES (?, ?, ?, ?, ?, ?)
                `;
                db.query(insertStockSql, [houtsoort, lengte, breedte, dikte, locatie, totaalAantal], (err, result) => {
                    if (err) {
                        console.error('Error inserting into hout_stock:', err);
                        return reject(err);
                    }
                    resolve();
                });
            });
        });

        // Execute all insert queries
        Promise.all(insertPromises)
            .then(() => {
                // Delete the item from 'hout_ontvangen'
                const deleteOntvangenSql = 'DELETE FROM hout_ontvangen WHERE id = ?';
                db.query(deleteOntvangenSql, [id], (err, result) => {
                    if (err) {
                        console.error('Error deleting from hout_ontvangen:', err);
                        return db.rollback(() => {
                            res.status(500).json({ error: 'Database error' });
                        });
                    }

                    // Commit the transaction
                    db.commit(err => {
                        if (err) {
                            console.error('Error committing transaction:', err);
                            return db.rollback(() => {
                                res.status(500).json({ error: 'Database error' });
                            });
                        }
                        res.json({ success: true });
                    });
                });
            })
            .catch(err => {
                console.error('Error processing packs:', err);
                db.rollback(() => {
                    res.status(500).json({ error: 'Database error' });
                });
            });
    });
});








