app.get('/api/wood_consumption', (req, res) => {
    let { start_date, end_date, houtsoort, dikte, breedte } = req.query;

    // Bouw de query dynamisch op
    let sql = `SELECT * FROM wood_consumption WHERE 1=1`;
    const params = [];

    // Voeg datumfilter toe als beide datums zijn opgegeven
    if (start_date && end_date) {
        sql += ' AND date_consumed BETWEEN ? AND ?';
        params.push(start_date, end_date);
    } else if (start_date || end_date) {
        // Als slechts één datum is opgegeven, geef een foutmelding
        return res.status(400).json({ error: 'Beide datums moeten worden opgegeven voor filtering' });
    }

    if (houtsoort) {
        sql += ' AND soort = ?';
        params.push(houtsoort);
    }
    if (dikte) {
        sql += ' AND dikte = ?';
        params.push(dikte);
    }
    if (breedte) {
        sql += ' AND breedte = ?';
        params.push(breedte);
    }

    sql += ' ORDER BY date_consumed ASC';

    db.query(sql, params, (err, results) => {
        if (err) {
            console.error('Error fetching consumption data:', err);
            return res.status(500).json({ error: 'Database query error' });
        }

        res.json(results);
    });
});


