function minimaliseerAfval(beschikbarePlanken, vereisteLengtes) {
    const eersteZaagsnede = 30;
    const zaagdikte = 5;
    const machinesCapaciteit = 10;
    
    beschikbarePlanken.sort((a, b) => a.lengte - b.lengte);  // Sort in ascending order of length
    
    let zaagorders = [];
    let afval = [];

    vereisteLengtes.forEach(vereiste => {
        let { length, count } = vereiste;

        while (count > 0) {
            let bestePlanken = beschikbarePlanken.filter(plank => plank.aantal > 0 && (plank.lengte - eersteZaagsnede) >= (length + zaagdikte));
            if (bestePlanken.length === 0) {
                // No more suitable planks available
                break;
            }

            let selectedPlank = bestePlanken[0];
            let maxPiecesPerPlank = Math.floor((selectedPlank.lengte - eersteZaagsnede + zaagdikte) / (length + zaagdikte));
            let piecesToCut = Math.min(maxPiecesPerPlank, count);
            let planksNeeded = Math.ceil(count / maxPiecesPerPlank);

            if (planksNeeded > 1) {
                // If more than one plank is needed, cut as many as possible up to the machine's capacity
                let batchSize = Math.min(planksNeeded, machinesCapaciteit);
                piecesToCut = maxPiecesPerPlank * batchSize;
                
                let zaagorder = {
                    plankIds: Array(batchSize).fill(selectedPlank.id),
                    origineleLengtes: Array(batchSize).fill(selectedPlank.lengte),
                    zaagsneden: Array(maxPiecesPerPlank).fill(length),
                    soort: selectedPlank.soort,
                    dikte: selectedPlank.dikte,
                    breedte: selectedPlank.breedte,
                    aantalPlanken: batchSize
                };
    
                zaagorders.push(zaagorder);
    
                selectedPlank.aantal -= batchSize;
                count -= piecesToCut;
    
                let restendeAfval = selectedPlank.lengte - (eersteZaagsnede + (length + zaagdikte) * maxPiecesPerPlank - zaagdikte);
                if (restendeAfval >= 100) {
                    afval.push({
                        lengte: restendeAfval,
                        aantal: batchSize,
                        soort: selectedPlank.soort,
                        dikte: selectedPlank.dikte,
                        breedte: selectedPlank.breedte
                    });
                }
            } else {
                // Cut the remaining pieces individually
                piecesToCut = Math.min(maxPiecesPerPlank, count);
                let zaagorder = {
                    plankId: selectedPlank.id,
                    origineleLengte: selectedPlank.lengte,
                    zaagsneden: Array(piecesToCut).fill(length),
                    soort: selectedPlank.soort,
                    dikte: selectedPlank.dikte,
                    breedte: selectedPlank.breedte,
                    aantalPlanken: 1
                };
    
                zaagorders.push(zaagorder);
    
                selectedPlank.aantal -= 1;
                count -= piecesToCut;
    
                let restendeAfval = selectedPlank.lengte - (eersteZaagsnede + (length + zaagdikte) * piecesToCut - zaagdikte);
                if (restendeAfval >= 100) {
                    afval.push({
                        lengte: restendeAfval,
                        aantal: 1,
                        soort: selectedPlank.soort,
                        dikte: selectedPlank.dikte,
                        breedte: selectedPlank.breedte
                    });
                }
            }
        }
    });

    // Combineer identieke afvalstukken
    let gecombineerdAfval = afval.reduce((acc, curr) => {
        let existing = acc.find(item => 
            item.lengte === curr.lengte && 
            item.soort === curr.soort && 
            item.dikte === curr.dikte && 
            item.breedte === curr.breedte
        );
        if (existing) {
            existing.aantal += curr.aantal;
        } else {
            acc.push({...curr});
        }
        return acc;
    }, []);

    return { zaagorders, afval: gecombineerdAfval };
}

