app.post('/optimize', (req, res) => {
    const { vereisteLengtes } = req.body;
    if (!Array.isArray(vereisteLengtes)) {
        return res.status(400).json({ error: 'Vereiste lengtes moeten arrays zijn.' });
    }
    
    const sql = 'SELECT * FROM beschikbare_lengtes';
    db.query(sql, (err, results) => {
        if (err) {
            console.error('Error fetching available lengths for optimization:', err);
            return res.status(500).json({ error: 'Database query error' });
        }
        const beschikbarePlanken = results.map(row => ({
            id: row.id,
            lengte: row.lengte,
            dikte: row.dikte,
            breedte: row.breedte,
            soort: row.soort,
            aantal: row.aantal
        }));
        
        const { zaagorders, afval } = minimaliseerAfval(beschikbarePlanken, vereisteLengtes);
        
        updatePlankenAantal(beschikbarePlanken);
        
        res.json({ zaagorders, afval });
    });
});

