// Endpoint to sync packed items to admin items
app.get('/api/sync_packed_items', async (req, res) => {
    try {
        // Fetch all packed items
        const packedItems = await new Promise((resolve, reject) => {
            db.query('SELECT * FROM packed_items', (err, results) => {
                if (err) return reject(err);
                resolve(results);
            });
        });

        // Iterate over each packed item and sync with admin_items
        for (const item of packedItems) {
            const { item_number, po_number, amount, date_added, date_packed } = item;

            // Check if the item already exists in admin_items
            const existingItems = await new Promise((resolve, reject) => {
                db.query('SELECT * FROM admin_items WHERE item_number = ? AND po_number = ?', [item_number, po_number], (err, results) => {
                    if (err) return reject(err);
                    resolve(results);
                });
            });

            if (existingItems.length === 0) {
                // Insert new item into admin_items
                await new Promise((resolve, reject) => {
                    db.query('INSERT INTO admin_items (item_number, po_number, amount, date_added, date_packed) VALUES (?, ?, ?, ?, ?)', 
                    [item_number, po_number, amount, date_added, date_packed], (err, results) => {
                        if (err) return reject(err);
                        resolve(results);
                    });
                });
            } else {
                // Update existing item in admin_items
                await new Promise((resolve, reject) => {
                    db.query('UPDATE admin_items SET amount = ?, date_added = ?, date_packed = ? WHERE item_number = ? AND po_number = ?', 
                    [amount, date_added, date_packed, item_number, po_number], (err, results) => {
                        if (err) return reject(err);
                        resolve(results);
                    });
                });
            }
        }

        res.json({ success: true, message: 'Synchronization completed successfully.' });
    } catch (error) {
        console.error('Error syncing packed items:', error);
        res.status(500).json({ error: 'Database error' });
    }
});

app.get('/api/admin_items', (req, res) => {
    const { dateFrom, dateTo } = req.query;

    let query = 'SELECT * FROM admin_items';
    const queryParams = [];

    if (dateFrom || dateTo) {
        query += ' WHERE';
        if (dateFrom) {
            query += ' date_packed >= ?';
            queryParams.push(dateFrom);
        }
        if (dateTo) {
            if (queryParams.length > 0) {
                query += ' AND';
            }
            query += ' date_packed <= ?';
            queryParams.push(dateTo);
        }
    }

    db.query(query, queryParams, (err, results) => {
        if (err) {
            console.error('Error fetching admin items:', err);
            res.status(500).json({ error: 'Database error' });
            return;
        }

        // Calculate total revenue
        const totalRevenue = results.reduce((sum, item) => sum + (item.price * item.amount), 0);

        res.json({ items: results, totalRevenue });
    });
});


