app.post('/api/add_packed_item', async (req, res) => {
    const { item_number, po_number, amount, date_added, date_packed } = req.body;

    try {
        // Insert into packed_items
        await db.query('INSERT INTO packed_items (item_number, po_number, amount, date_added, date_packed) VALUES (?, ?, ?, ?, ?)', 
        [item_number, po_number, amount, date_added, date_packed]);

        // Check if item already exists in admin_items and get the existing price
        const [existingItem] = await db.query('SELECT price FROM admin_items WHERE item_number = ? LIMIT 1', [item_number]);

        if (existingItem.length > 0 && existingItem[0].price != null) {
            const price = existingItem[0].price;
            // Insert or update item into admin_items with the existing price
            await db.query('INSERT INTO admin_items (item_number, po_number, amount, date_added, date_packed, price) VALUES (?, ?, ?, ?, ?, ?) ON DUPLICATE KEY UPDATE amount = VALUES(amount), date_added = VALUES(date_added), date_packed = VALUES(date_packed), price = VALUES(price)', 
            [item_number, po_number, amount, date_added, date_packed, price]);
        } else {
            // Insert or update item into admin_items without the price
            await db.query('INSERT INTO admin_items (item_number, po_number, amount, date_added, date_packed) VALUES (?, ?, ?, ?, ?) ON DUPLICATE KEY UPDATE amount = VALUES(amount), date_added = VALUES(date_added), date_packed = VALUES(date_packed)', 
            [item_number, po_number, amount, date_added, date_packed]);
        }

        res.json({ success: true });
    } catch (error) {
        console.error('Error adding packed item:', error);
        res.status(500).json({ error: 'Database error' });
    }
});




