// Define safeDbQuery function
const safeDbQuery = (query, params = []) => {
    return new Promise((resolve, reject) => {
        db.query(query, params, (error, results) => {
            if (error) {
                console.error('Database query error:', error);
                reject(error);
            } else {
                resolve(results);
            }
        });
    });
};

