// Fetch chests consumed by period (day, month, year)
app.get('/api/consumed_chests/:period', (req, res) => {
    const period = req.params.period; // day, month, year
    let groupByClause = '';
    let selectPeriod = '';

    switch (period) {
        case 'day':
            groupByClause = 'DATE(date_packed)';
            selectPeriod = 'DATE(date_packed) as period';
            break;
        case 'month':
            groupByClause = 'YEAR(date_packed), MONTH(date_packed)';
            selectPeriod = 'YEAR(date_packed) as year, MONTH(date_packed) as month';
            break;
        case 'year':
            groupByClause = 'YEAR(date_packed)';
            selectPeriod = 'YEAR(date_packed) as year';
            break;
        default:
            return res.status(400).json({ error: 'Invalid period specified' });
    }

    const query = `
        SELECT kistnummer, ${selectPeriod}, SUM(quantity) AS quantity
        FROM packed_items_airtec
        GROUP BY kistnummer, ${groupByClause}
    `;

    db.query(query, (err, results) => {
        if (err) {
            console.error('Error fetching consumed chests:', err);
            res.status(500).json({ error: 'Database error' });
            return;
        }
        res.json(results);
    });
});

// Predict reorder needs based on usage
app.get('/api/reorder_chests', (req, res) => {
    const consumptionQuery = `
        SELECT kistnummer, SUM(quantity) AS total_consumed, SUM(quantity) / COUNT(DISTINCT DATE(date_packed)) AS avg_daily_usage
        FROM packed_items_airtec
        WHERE date_packed >= DATE_SUB(CURDATE(), INTERVAL 30 DAY)
        GROUP BY kistnummer
    `;

    db.query(consumptionQuery, (err, consumptionResults) => {
        if (err) {
            console.error('Error fetching reorder predictions:', err);
            res.status(500).json({ error: 'Database error' });
            return;
        }

        const currentStockQuery = `SELECT kistnummer, SUM(quantity) AS quantity FROM stock_airtec GROUP BY kistnummer`;

        db.query(currentStockQuery, (err, stockResults) => {
            if (err) {
                console.error('Error fetching current stock:', err);
                res.status(500).json({ error: 'Database error' });
                return;
            }

            const stockMap = new Map();
            stockResults.forEach(stockItem => {
                stockMap.set(stockItem.kistnummer, stockItem.quantity);
            });

            const reorderPredictions = consumptionResults.map(consumptionItem => {
                const kistnummer = consumptionItem.kistnummer;
                const totalConsumed = consumptionItem.total_consumed;
                const avgDailyUsage = consumptionItem.avg_daily_usage;
                const currentStock = stockMap.get(kistnummer) || 0;
                const daysUntilStockOut = avgDailyUsage ? currentStock / avgDailyUsage : Infinity;
                const reorderThreshold = Math.max(0, Math.ceil(daysUntilStockOut - 5)); // Subtract 5 days for lead time

                return {
                    kistnummer,
                    total_consumed: totalConsumed,
                    avg_daily_usage: avgDailyUsage,
                    current_stock: currentStock,
                    days_until_stock_out: daysUntilStockOut,
                    reorder_threshold: reorderThreshold
                };
            });

            res.json(reorderPredictions);
        });
    });
});

