app.post('/api/update_stock', (req, res) => {
    const { id, current_stock } = req.body;

    const sqlFetch = 'SELECT minimum_stock FROM Stock_telling WHERE id = ?';
    db.query(sqlFetch, [id], (err, results) => {
        if (err) {
            console.error('Error fetching minimum stock:', err);
            return res.status(500).json({ error: 'Failed to fetch minimum stock.' });
        }

        const minimumStock = results[0]?.minimum_stock || 0;

        const sqlUpdate = 'UPDATE Stock_telling SET current_stock = ? WHERE id = ?';
        db.query(sqlUpdate, [current_stock, id], (err, result) => {
            if (err) {
                console.error('Error updating stock:', err);
                return res.status(500).json({ error: 'Failed to update stock.' });
            }
            res.json({ success: true, message: current_stock < minimumStock 
                ? 'Stock below minimum. Reorder required!' 
                : 'Stock updated successfully.' });
        });
    });
});




app.post('/api/add_stock_chests', (req, res) => {
    const { kistnummer, quantity } = req.body;

    // Gebruik ON DUPLICATE KEY UPDATE om de quantity te verhogen als de kist al bestaat
    const sql = `INSERT INTO stock_airtec (kistnummer, quantity) 
                 VALUES (?, ?) 
                 ON DUPLICATE KEY UPDATE quantity = quantity + ?`;
    db.query(sql, [kistnummer, quantity, quantity], (err, result) => {
        if (err) {
            console.error('Error adding stock:', err);
            return res.status(500).json({ error: 'Failed to add stock.' });
        }

        // Na het bijwerken van de voorraad, controleer of de voorraad onder de minimumwaarde is gekomen
        const checkStockSql = `SELECT quantity, minimum_stock 
                               FROM stock_airtec 
                               WHERE kistnummer = ?`;
        db.query(checkStockSql, [kistnummer], (err, results) => {
            if (err) {
                console.error('Error checking stock:', err);
                return res.status(500).json({ error: 'Failed to check stock.' });
            }
            const { quantity, minimum_stock } = results[0];
            if (quantity < minimum_stock) {
                // Stuur een e-mail notificatie
                sendReorderNotification(kistnummer, quantity, minimum_stock);
            }
        });

        res.json({ success: true, message: 'Stock added successfully.' });
    });
});





