app.get('/api/check_priority_column', async (req, res) => {
    try {
        // First try a simple query to check if the column exists
        const checkQuery = `
            SELECT 1 
            FROM bestellingen 
            WHERE priority IS NOT NULL 
            LIMIT 1
        `;

        try {
            await new Promise((resolve, reject) => {
                db.query(checkQuery, (err, results) => {
                    if (err && err.code === 'ER_BAD_FIELD_ERROR') {
                        // Column doesn't exist, create it
                        db.query(
                            'ALTER TABLE bestellingen ADD COLUMN priority BOOLEAN DEFAULT FALSE',
                            (alterErr) => {
                                if (alterErr) {
                                    reject(alterErr);
                                } else {
                                    resolve();
                                }
                            }
                        );
                    } else if (err) {
                        reject(err);
                    } else {
                        resolve();
                    }
                });
            });
        } catch (dbError) {
            console.error('Database error:', dbError);
            throw new Error(`Database error: ${dbError.message}`);
        }

        res.json({ success: true });

    } catch (error) {
        console.error('Error in check_priority_column:', error);
        res.status(500).json({ 
            error: 'Error checking priority column', 
            details: error.message 
        });
    }
});

// Route om priority te togglen
app.put('/api/toggle_priority/:id', (req, res) => {
    const id = req.params.id;
    
    // Haal huidige priority status op
    const checkQuery = 'SELECT priority FROM bestellingen WHERE id = ?';
    db.query(checkQuery, [id], (err, result) => {
        if (err) {
            console.error('Error fetching priority status:', err);
            return res.status(500).json({ error: 'Database error', details: err.message });
        }
        
        if (result.length === 0) {
            return res.status(404).json({ error: 'Bestelling niet gevonden' });
        }
        
        const currentPriority = result[0].priority || false;
        const newPriority = !currentPriority;
        
        // Update priority status
        const updateQuery = 'UPDATE bestellingen SET priority = ? WHERE id = ?';
        db.query(updateQuery, [newPriority, id], (err) => {
            if (err) {
                console.error('Error updating priority:', err);
                return res.status(500).json({ error: 'Database error', details: err.message });
            }
            
            res.json({ 
                success: true, 
                priority: newPriority,
                message: `Prioriteit ${newPriority ? 'toegevoegd' : 'verwijderd'}`
            });
        });
    });
});

