app.put('/api/update_item_kistnummer/:id', (req, res) => {
    const { id } = req.params;
    const { kistnummer } = req.body;

    if (!kistnummer) {
        return res.status(400).json({ error: 'Kistnummer is vereist' });
    }

    // 1. Haal het oude kistnummer op
    const selectOld = 'SELECT kistnummer FROM items_to_pack_airtec WHERE id = ?';
    db.query(selectOld, [id], (err, rows) => {
        if (err) {
            console.error('Error selecting old kistnummer:', err);
            return res.status(500).json({ error: 'Database error' });
        }
        if (rows.length === 0) {
            return res.status(404).json({ error: 'Item not found' });
        }

        const oldKistnummer = rows[0].kistnummer || '';

        // 2. Update het record naar het nieuwe kistnummer
        const updateQuery = 'UPDATE items_to_pack_airtec SET kistnummer = ? WHERE id = ?';
        db.query(updateQuery, [kistnummer, id], (err, result) => {
            if (err) {
                console.error('Error updating kistnummer:', err);
                return res.status(500).json({ error: 'Database error' });
            }
            if (result.affectedRows === 0) {
                return res.status(404).json({ error: 'Item not found' });
            }

            // 3. Log de wijziging in kistnummer_history
            const insertHistory = `
                INSERT INTO kistnummer_history (item_id, old_kistnummer, new_kistnummer)
                VALUES (?, ?, ?)
            `;
            db.query(insertHistory, [id, oldKistnummer, kistnummer], (err2) => {
                if (err2) {
                    console.error('Error inserting kistnummer history:', err2);
                    return res.status(500).json({ error: 'Database error (history)' });
                }

                res.json({ success: true, message: 'Kistnummer succesvol bijgewerkt en gelogd' });
            });
        });
    });
});


