// API route to get all work orders
app.get('/api/workorders', (req, res) => {
    const { step, status } = req.query;
    let query;

    if (step === 'zagerij') {
        query = "SELECT * FROM workorders WHERE steps LIKE '%zagerij%' AND status_zagerij != 'completed' AND status != 'completed'";
    } else if (step === 'assemblage') {
        query = "SELECT * FROM workorders WHERE steps LIKE '%assemblage%' AND status_assemblage != 'completed' AND status != 'completed'";
    } else if (status === 'completed') {
        query = "SELECT * FROM workorders WHERE status_zagerij = 'completed' OR status_assemblage = 'completed'";
    } else {
        query = 'SELECT * FROM workorders WHERE status != \'completed\'';
    }

    db.query(query, (err, results) => {
        if (err) {
            console.error('Error fetching work orders:', err);
            return res.status(500).json({ error: 'Database error' });
        }
        res.json(results);
    });
});


