// Route voor bulk transfer
// Route voor bulk transfer
app.post('/api/e_bodems/bulk-transfer', async (req, res) => {
    try {
        const { items, from_location, to_location } = req.body;

        // Validatie
        if (!items || !Array.isArray(items) || items.length === 0) {
            return res.status(400).json({ 
                success: false,
                message: 'Geen items geselecteerd voor transfer' 
            });
        }

        if (from_location === to_location) {
            return res.status(400).json({ 
                success: false,
                message: 'Van en naar locatie moeten verschillend zijn' 
            });
        }

        // Begin database transactie
        await new Promise((resolve, reject) => {
            db.beginTransaction(function(err) {
                if (err) {
                    console.error('Database transaction error:', err);
                    return reject(new Error('Database transactie fout'));
                }
                resolve();
            });
        });

        // Function to execute queries binnen de transactie
        const executeQuery = (query, params) => {
            return new Promise((resolve, reject) => {
                db.query(query, params, (err, results) => {
                    if (err) {
                        return reject(err);
                    }
                    resolve(results);
                });
            });
        };

        // Process each item sequentially
        for (const item of items) {
            const amountInt = parseInt(item.aantal, 10);
            const state = item.state;
            const bodem_id = item.bodem_id;
            const id = item.id;

            // Selecteer het item uit de fromTable
            const fromRecords = await executeQuery(
                `SELECT id, aantal FROM ${from_location === 'wilrijk' ? 'e_bodems_voorraad_wilrijk' : 'e_bodems_voorraad_genk'} WHERE id = ?`,
                [id]
            );

            if (!fromRecords.length || fromRecords[0].aantal < amountInt) {
                throw new Error(`Onvoldoende voorraad voor item ${bodem_id} op vertrek locatie`);
            }

            const fromRecordId = fromRecords[0].id;

            // Verminder voorraad op vertreklocatie
            await executeQuery(
                `UPDATE ${from_location === 'wilrijk' ? 'e_bodems_voorraad_wilrijk' : 'e_bodems_voorraad_genk'} SET aantal = aantal - ? WHERE id = ?`,
                [amountInt, fromRecordId]
            );

            // Verhoog voorraad op bestemming
            const toTable = to_location === 'wilrijk' ? 'e_bodems_voorraad_wilrijk' : 'e_bodems_voorraad_genk';
            const toRecords = await executeQuery(
                `SELECT id FROM ${toTable} WHERE bodem_id = ? AND staat = ?`,
                [bodem_id, state]
            );

            if (toRecords.length > 0) {
                const toRecordId = toRecords[0].id;
                await executeQuery(
                    `UPDATE ${toTable} SET aantal = aantal + ? WHERE id = ?`,
                    [amountInt, toRecordId]
                );
            } else {
                await executeQuery(
                    `INSERT INTO ${toTable} (bodem_id, aantal, staat) VALUES (?, ?, ?)`,
                    [bodem_id, amountInt, state]
                );
            }

            // Registreer de beweging
            await executeQuery(
                `INSERT INTO e_bodems_movements (bodem_id, from_location, to_location, amount, movement_type, state, remarks) VALUES (?, ?, ?, ?, 'transfer', ?, ?)`,
                [bodem_id, from_location, to_location, amountInt, state, `Bulk transfer van ${from_location} naar ${to_location}`]
            );
        }

        // Commit de transactie
        await new Promise((resolve, reject) => {
            db.commit(function(err) {
                if (err) {
                    console.error('Database commit error:', err);
                    return db.rollback(() => {
                        reject(new Error('Fout bij committen van transactie'));
                    });
                }
                resolve();
            });
        });

        // Succesresponse
        res.json({ success: true, message: 'Items succesvol getransfereerd' });

    } catch (error) {
        console.error('Error in bulk transfer:', error.message);

        // Rollback de transactie bij fout
        try {
            await new Promise((resolve, reject) => {
                db.rollback(() => {
                    resolve();
                });
            });
        } catch (rollbackError) {
            console.error('Error during rollback:', rollbackError);
        }

        res.status(500).json({ success: false, message: error.message || 'Fout bij bulk transfer' });
    }
});


// Route om transfers op te halen met filters
app.get('/api/e_bodems/transfers', (req, res) => {
    const { dateFrom, dateTo, search } = req.query;

    let query = `
        SELECT 
            m.*,
            e.glovia_code,
            e.referentie,
            e.verkoopprijs, -- Toegevoegd
            m.state
        FROM e_bodems_movements m
        JOIN e_bodems e ON m.bodem_id = e.id
        WHERE m.movement_type = 'transfer'
    `;

    const params = [];

    if (dateFrom) {
        query += ` AND DATE(m.timestamp) >= ?`;
        params.push(dateFrom);
    }

    if (dateTo) {
        query += ` AND DATE(m.timestamp) <= ?`;
        params.push(dateTo);
    }

    if (search) {
        query += ` AND (e.glovia_code LIKE ? OR e.referentie LIKE ?)`;
        params.push(`%${search}%`, `%${search}%`);
    }

    query += ` ORDER BY m.timestamp DESC LIMIT 1000`;

    db.query(query, params, (err, results) => {
        if (err) {
            console.error('Database error:', err);
            return res.status(500).json({ 
                message: 'Fout bij ophalen transfers',
                error: err.message 
            });
        }
        res.json(results);
    });
});




app.post('/api/e_bodems/send_pdf', async (req, res) => {
    // Definieer deze variabelen buiten de try-block
    let timestamp;
    let fileName;
    
    try {
        const { location, selectedItems } = req.body;

        // Valideer of er items zijn geselecteerd
        if (!selectedItems || selectedItems.length === 0) {
            return res.status(400).json({
                success: false,
                message: 'Geen items geselecteerd voor export'
            });
        }

        // Maak document definitie voor PDFMake
        const docDefinition = {
            pageOrientation: 'landscape',
            content: [
                {
                    text: `E-Bodems Verstuurd ${location.charAt(0).toUpperCase() + location.slice(1)}`,
                    style: 'header',
                    alignment: 'center'
                },
                {
                    text: `Gegenereerd op: ${moment().format('DD/MM/YYYY HH:mm')}`,
                    alignment: 'center',
                    margin: [0, 0, 0, 20]
                },
                {
                    table: {
                        headerRows: 1,
                        widths: ['*', '*', '*', 'auto', 'auto', 'auto'],
                        body: [
                            // Headers
                            [
                                { text: 'BC code', style: 'tableHeader' },
                                { text: 'Revisie', style: 'tableHeader' },
                                { text: 'Referentie', style: 'tableHeader' },
                                { text: 'Aantal', style: 'tableHeader' },
                                { text: 'Staat', style: 'tableHeader' },
                                { text: 'Verkoopprijs', style: 'tableHeader' }
                            ],
                            // Data rows - Gebruik nu de geselecteerde items
                            ...selectedItems.map(item => [
                                { text: item.glovia_code || '-' },
                                { text: item.revisie || '-' },
                                { text: item.referentie || '-' },
                                { text: item.aantal.toString() },
                                { 
                                    text: item.staat,
                                    fillColor: getStateColor(item.staat)
                                },
                                { text: item.verkoopprijs }
                            ])
                        ]
                    }
                }
            ],
            styles: {
                header: {
                    fontSize: 18,
                    bold: true,
                    margin: [0, 0, 0, 10]
                },
                tableHeader: {
                    bold: true,
                    fontSize: 13,
                    color: 'black',
                    fillColor: '#f5f5f5'
                }
            },
            defaultStyle: {
                fontSize: 10
            }
        };

        // Maak PDF
        const printer = new PdfPrinter(fonts);
        const pdfDoc = printer.createPdfKitDocument(docDefinition);

        // Maak temp directory als die niet bestaat
        const tempDir = path.join(__dirname, 'temp');
        if (!fs.existsSync(tempDir)) {
            fs.mkdirSync(tempDir, { recursive: true });
        }

        // Genereer unieke bestandsnaam met timestamp
        timestamp = moment().format('YYYYMMDD_HHmmss');
        fileName = path.join(tempDir, `e_bodems_voorraad_${location}_${timestamp}.pdf`);
        const writeStream = fs.createWriteStream(fileName);

        pdfDoc.pipe(writeStream);
        pdfDoc.end();

        // Wacht tot PDF is geschreven
        await new Promise((resolve, reject) => {
            writeStream.on('finish', resolve);
            writeStream.on('error', reject);
        });

        // Verstuur email
        const transporter = nodemailer.createTransport({
            host: 'mail.prodwilrijk.be',
            port: 465,
            secure: true,
            auth: {
                user: 'jason@prodwilrijk.be',
                pass: 'prodwilrijk147'
            },
            tls: {
                rejectUnauthorized: false
            }
        });

        await transporter.sendMail({
            from: '"E-Bodems Systeem" <jason@prodwilrijk.be>',
            to: 'j.ploegaerts@foresco.eu,prodwilrijk@foresco.eu',
            subject: `E-Bodems Verzonden ${location} - ${moment().format('DD/MM/YYYY')}`,
            html: `
                <p>Beste,</p>
                <p>In bijlage kan je het overzicht van de geselecteerde E-bodems terugvinden.</p>
                <p>Met vriendelijke groeten,</p>
                <p>Team Wilrijk</p>
            `,
            attachments: [{
                filename: `E-Bodems_Verstuurd_${location}_${timestamp}.pdf`,
                path: fileName
            }]
        });

        // Stuur succes response
        res.json({ success: true });

    } catch (error) {
        console.error('Error generating or sending PDF:', error);
        res.status(500).json({
            success: false,
            message: 'Fout bij genereren of versturen van PDF',
            error: error.message
        });
    } finally {
        // Cleanup: verwijder het tijdelijke bestand als het bestaat
        if (fileName && fs.existsSync(fileName)) {
            try {
                fs.unlinkSync(fileName);
            } catch (cleanupError) {
                console.error('Error cleaning up temporary file:', cleanupError);
            }
        }
    }
});

// Helper functie voor staat kleuren (ongewijzigd)
function getStateColor(staat) {
    const stateLower = staat.toLowerCase();
    if (stateLower === 'te repareren' || stateLower === 'reparatie') {
        return '#fff3e0';
    } else if (stateLower === 'goede staat' || stateLower === 'goed') {
        return '#e8f5e9';
    } else if (stateLower === 'afval') {
        return '#ffebee';
    }
    return null;
}

