app.get('/api/e_bodems/movements/export', (req, res) => {
    const { dateFrom, dateTo, type } = req.query;
    
    let query = `
        SELECT 
            m.*,
            e.glovia_code,
            e.referentie,
            e.verkoopprijs,
            (m.amount * e.verkoopprijs) as movement_value
        FROM e_bodems_movements m
        JOIN e_bodems e ON m.bodem_id = e.id
        WHERE 1=1
    `;
    
    const params = [];
    
    if (dateFrom) {
        query += ` AND DATE(m.timestamp) >= ?`;
        params.push(dateFrom);
    }
    if (dateTo) {
        query += ` AND DATE(m.timestamp) <= ?`;
        params.push(dateTo);
    }
    if (type) {
        query += ` AND m.movement_type = ?`;
        params.push(type);
    }
    
    query += ` ORDER BY m.timestamp DESC`;

    db.query(query, params, (err, results) => {
        if (err) {
            console.error('Database error:', err);
            return res.status(500).json({ message: 'Fout bij exporteren bewegingen' });
        }

        // Data voorbereiden voor Excel
        const excelData = results.map(row => ({
            Datum: new Date(row.timestamp).toLocaleString('nl-BE'),
            'Glovia Code': row.glovia_code,
            Type: formatMovementType(row.movement_type),
            Van: row.from_location || '-',
            Naar: row.to_location || '-',
            Aantal: row.amount,
            Staat: formatStaat(row.state),
            Stukprijs: parseFloat(row.verkoopprijs),
            'Totale Waarde': parseFloat(row.movement_value),
            'TO Nummer': row.TO_nummer || '-',
            Opmerkingen: row.remarks || '-'
        }));

        // Excel workbook maken
        const wb = xlsx.utils.book_new();
        const ws = xlsx.utils.json_to_sheet(excelData);

        // Kolombreedte aanpassen
        const colWidths = [
            { wch: 20 }, // Datum
            { wch: 15 }, // Glovia Code
            { wch: 15 }, // Type
            { wch: 15 }, // Van
            { wch: 15 }, // Naar
            { wch: 10 }, // Aantal
            { wch: 15 }, // Staat
            { wch: 15 }, // Stukprijs
            { wch: 15 }, // Totale Waarde
            { wch: 15 }, // TO Nummer
            { wch: 30 }  // Opmerkingen
        ];
        ws['!cols'] = colWidths;

        xlsx.utils.book_append_sheet(wb, ws, 'Bewegingen');

        // Buffer maken en versturen
        const buf = xlsx.write(wb, { type: 'buffer', bookType: 'xlsx' });

        res.setHeader('Content-Type', 'application/vnd.openxmlformats-officedocument.spreadsheetml.sheet');
        res.setHeader('Content-Disposition', 'attachment; filename=bewegingen.xlsx');
        res.send(buf);
    });
});

// Helper functies voor de export
function formatMovementType(type) {
    const types = {
        'transfer': 'Transfer',
        'state_change': 'Staat Wijziging',
        'usage': 'Verbruik',
        'addition': 'Toevoeging'
    };
    return types[type] || type;
}

function formatStaat(staat) {
    const states = {
        'goed': 'Goede staat',
        'reparatie': 'Te repareren',
        'afval': 'Afval'
    };
    return states[staat] || staat;
}

