// Add this endpoint to your server code (paste.txt)
app.post('/api/e_bodems_ontvangst', (req, res) => {
    const { bodem_id, aantal, staat, opmerkingen } = req.body;
    
    if (!bodem_id || !aantal || !staat) {
        return res.status(400).json({ 
            success: false,
            message: 'Alle velden zijn verplicht' 
        });
    }
    
    // Begin transaction
    db.beginTransaction(async (err) => {
        if (err) {
            console.error('Transaction error:', err);
            return res.status(500).json({ 
                success: false,
                message: 'Database transactie fout' 
            });
        }
        
        try {
            // 1. Insert into e_bodems_ontvangst
            const ontvangstResult = await new Promise((resolve, reject) => {
                db.query(
                    `INSERT INTO e_bodems_ontvangst (bodem_id, aantal, staat, opmerkingen) 
                     VALUES (?, ?, ?, ?)`,
                    [bodem_id, aantal, staat, opmerkingen || ''],
                    (err, result) => {
                        if (err) return reject(err);
                        resolve(result);
                    }
                );
            });
            
            // 2. Update Wilrijk voorraad
            // First check if there's already an entry for this bodem_id and staat
            const existingStock = await new Promise((resolve, reject) => {
                db.query(
                    `SELECT id FROM e_bodems_voorraad_wilrijk 
                     WHERE bodem_id = ? AND staat = ?`,
                    [bodem_id, staat],
                    (err, result) => {
                        if (err) return reject(err);
                        resolve(result);
                    }
                );
            });
            
            if (existingStock && existingStock.length > 0) {
                // Update existing stock
                await new Promise((resolve, reject) => {
                    db.query(
                        `UPDATE e_bodems_voorraad_wilrijk 
                         SET aantal = aantal + ? 
                         WHERE id = ?`,
                        [aantal, existingStock[0].id],
                        (err, result) => {
                            if (err) return reject(err);
                            resolve(result);
                        }
                    );
                });
            } else {
                // Insert new stock entry
                await new Promise((resolve, reject) => {
                    db.query(
                        `INSERT INTO e_bodems_voorraad_wilrijk (bodem_id, aantal, staat) 
                         VALUES (?, ?, ?)`,
                        [bodem_id, aantal, staat],
                        (err, result) => {
                            if (err) return reject(err);
                            resolve(result);
                        }
                    );
                });
            }
            
            // 3. Record the movement
            await new Promise((resolve, reject) => {
                db.query(
                    `INSERT INTO e_bodems_movements 
                     (bodem_id, to_location, amount, movement_type, state, remarks) 
                     VALUES (?, 'wilrijk', ?, 'addition', ?, ?)`,
                    [bodem_id, aantal, staat, 'Ontvangst geregistreerd en toegevoegd aan Wilrijk'],
                    (err, result) => {
                        if (err) return reject(err);
                        resolve(result);
                    }
                );
            });
            
            // Commit transaction
            db.commit((err) => {
                if (err) {
                    return db.rollback(() => {
                        console.error('Commit error:', err);
                        res.status(500).json({ 
                            success: false,
                            message: 'Fout bij committen van transactie' 
                        });
                    });
                }
                
                res.json({ 
                    success: true, 
                    message: 'Ontvangst succesvol geregistreerd en toegevoegd aan Wilrijk voorraad' 
                });
            });
        } catch (error) {
            return db.rollback(() => {
                console.error('Error in ontvangst processing:', error);
                res.status(500).json({ 
                    success: false,
                    message: error.message || 'Fout bij registreren van ontvangst' 
                });
            });
        }
    });
});

