app.post('/api/e_bodems/verbruik', (req, res) => {
    const { id, aantal } = req.body;

    // Controleer of het item bestaat en voldoende aantal heeft
    const checkQuery = `
        SELECT * FROM e_bodems_voorraad_genk WHERE id = ? AND aantal >= ?`;
    
    db.query(checkQuery, [id, aantal], (err, results) => {
        if (err) {
            console.error('Database error:', err);
            return res.status(500).json({ message: 'Fout bij controleren voorraad' });
        }

        if (results.length === 0) {
            return res.status(400).json({ message: 'Onvoldoende voorraad beschikbaar' });
        }

        // Verminder het aantal in de voorraad
        const updateQuery = `
            UPDATE e_bodems_voorraad_genk SET aantal = aantal - ? WHERE id = ?`;
        
        db.query(updateQuery, [aantal, id], (err) => {
            if (err) {
                console.error('Database error:', err);
                return res.status(500).json({ message: 'Fout bij registreren verbruik' });
            }

            res.json({ success: true, message: 'Verbruik succesvol geregistreerd' });
        });
    });
});

app.post('/api/e_bodems/add-stock', (req, res) => {
    const { bodem_id, amount, state, location, TO_nummer } = req.body;

    if (!bodem_id || !amount || !state || !location) {
        return res.status(400).json({ 
            success: false,
            message: 'Alle velden zijn verplicht' 
        });
    }

    if (location !== 'wilrijk' && location !== 'genk') {
        return res.status(400).json({ 
            success: false,
            message: 'Ongeldige locatie' 
        });
    }

    db.beginTransaction(function(err) {
        if (err) {
            console.error('Database transaction error:', err);
            return res.status(500).json({ 
                success: false,
                message: 'Database transactie fout' 
            });
        }

        // Bepaal de juiste voorraad tabel
        const voorraadTable = location === 'wilrijk' ? 'e_bodems_voorraad_wilrijk' : 'e_bodems_voorraad_genk';
        const extraFields = location === 'genk' ? ', TO_nummer' : '';
        const extraValues = location === 'genk' ? ', ?' : '';
        const TO_nummer_value = location === 'genk' ? TO_nummer || null : null;

        db.query(
            `SELECT id FROM ${voorraadTable} WHERE bodem_id = ? AND staat = ?${location === 'genk' ? ' AND TO_nummer = ?' : ''}`,
            location === 'genk' ? [bodem_id, state, TO_nummer_value] : [bodem_id, state],
            function(err, existingRecords) {
                if (err) {
                    return db.rollback(function() {
                        console.error('Database error:', err);
                        res.status(500).json({ success: false, message: 'Database fout bij controleren bestaande voorraad' });
                    });
                }

                const amountInt = parseInt(amount);
                if (existingRecords.length > 0) {
                    // Update bestaand record
                    const existingId = existingRecords[0].id;
                    db.query(
                        `UPDATE ${voorraadTable} SET aantal = aantal + ? WHERE id = ?`,
                        [amountInt, existingId],
                        function(err) {
                            if (err) {
                                return db.rollback(function() {
                                    console.error('Database error:', err);
                                    res.status(500).json({ success: false, message: 'Database fout bij updaten voorraad' });
                                });
                            }

                            // Registreer de beweging
                            recordMovement();

                        }
                    );
                } else {
                    // Voeg nieuw record toe
                    db.query(
                        `INSERT INTO ${voorraadTable} (bodem_id, aantal, staat${location === 'genk' ? ', TO_nummer' : ''}) VALUES (?, ?, ?${location === 'genk' ? ', ?' : ''})`,
                        location === 'genk' ? [bodem_id, amountInt, state, TO_nummer_value] : [bodem_id, amountInt, state],
                        function(err) {
                            if (err) {
                                return db.rollback(function() {
                                    console.error('Database error:', err);
                                    res.status(500).json({ success: false, message: 'Database fout bij toevoegen voorraad' });
                                });
                            }

                            // Registreer de beweging
                            recordMovement();
                        }
                    );
                }

                function recordMovement() {
                    db.query(
                        `INSERT INTO e_bodems_movements (bodem_id, from_location, to_location, amount, movement_type, remarks) VALUES (?, NULL, ?, ?, 'addition', ?)`,
                        [bodem_id, location, amountInt, `Voorraad toegevoegd aan ${location}`],
                        function(err) {
                            if (err) {
                                return db.rollback(function() {
                                    console.error('Database error:', err);
                                    res.status(500).json({ success: false, message: 'Database fout bij registreren beweging' });
                                });
                            }

                            db.commit(function(err) {
                                if (err) {
                                    return db.rollback(function() {
                                        console.error('Database commit error:', err);
                                        res.status(500).json({ success: false, message: 'Fout bij committen van transactie' });
                                    });
                                }

                                res.json({ success: true, message: 'Voorraad succesvol toegevoegd' });
                            });
                        }
                    );
                }
            }
        );
    });
});

app.post('/api/e_bodems/transfer-stock', (req, res) => {
    const { bodem_id, amount, state, from_location, to_location, TO_nummer } = req.body;

    if (!bodem_id || !amount || !state || !from_location || !to_location) {
        return res.status(400).json({ 
            success: false,
            message: 'Alle velden zijn verplicht' 
        });
    }

    if (from_location === to_location) {
        return res.status(400).json({ 
            success: false,
            message: 'Van en naar locatie moeten verschillend zijn' 
        });
    }

    if ((from_location !== 'wilrijk' && from_location !== 'genk') || (to_location !== 'wilrijk' && to_location !== 'genk')) {
        return res.status(400).json({ 
            success: false,
            message: 'Ongeldige locaties' 
        });
    }

    db.beginTransaction(function(err) {
        if (err) {
            console.error('Database transaction error:', err);
            return res.status(500).json({ 
                success: false,
                message: 'Database transactie fout' 
            });
        }

        const amountInt = parseInt(amount);
        const fromTable = from_location === 'wilrijk' ? 'e_bodems_voorraad_wilrijk' : 'e_bodems_voorraad_genk';
        const toTable = to_location === 'wilrijk' ? 'e_bodems_voorraad_wilrijk' : 'e_bodems_voorraad_genk';
        const fromExtraCondition = from_location === 'genk' ? ' AND TO_nummer = ?' : '';
        const toExtraFields = to_location === 'genk' ? ', TO_nummer' : '';
        const toExtraValues = to_location === 'genk' ? ', ?' : '';
        const from_TO_nummer_value = from_location === 'genk' ? TO_nummer || null : null;
        const to_TO_nummer_value = to_location === 'genk' ? TO_nummer || null : null;

        // Verminder voorraad op vertreklocatie
        db.query(
            `SELECT id, aantal FROM ${fromTable} WHERE bodem_id = ? AND staat = ?${fromExtraCondition}`,
            from_location === 'genk' ? [bodem_id, state, from_TO_nummer_value] : [bodem_id, state],
            function(err, fromRecords) {
                if (err) {
                    return db.rollback(function() {
                        console.error('Database error:', err);
                        res.status(500).json({ success: false, message: 'Database fout bij ophalen voorraad van vertrek locatie' });
                    });
                }

                if (!fromRecords.length || fromRecords[0].aantal < amountInt) {
                    return db.rollback(function() {
                        res.status(400).json({ success: false, message: 'Onvoldoende voorraad beschikbaar op vertrek locatie' });
                    });
                }

                const fromRecordId = fromRecords[0].id;

                // Verminder voorraad
                db.query(
                    `UPDATE ${fromTable} SET aantal = aantal - ? WHERE id = ?`,
                    [amountInt, fromRecordId],
                    function(err) {
                        if (err) {
                            return db.rollback(function() {
                                console.error('Database error:', err);
                                res.status(500).json({ success: false, message: 'Database fout bij verminderen voorraad van vertrek locatie' });
                            });
                        }

                        // Verhoog voorraad op bestemming
                        // Controleer of record bestaat
                        db.query(
                            `SELECT id FROM ${toTable} WHERE bodem_id = ? AND staat = ?${to_location === 'genk' ? ' AND TO_nummer = ?' : ''}`,
                            to_location === 'genk' ? [bodem_id, state, to_TO_nummer_value] : [bodem_id, state],
                            function(err, toRecords) {
                                if (err) {
                                    return db.rollback(function() {
                                        console.error('Database error:', err);
                                        res.status(500).json({ success: false, message: 'Database fout bij ophalen voorraad van bestemming' });
                                    });
                                }

                                if (toRecords.length > 0) {
                                    // Update bestaand record
                                    const toRecordId = toRecords[0].id;
                                    db.query(
                                        `UPDATE ${toTable} SET aantal = aantal + ? WHERE id = ?`,
                                        [amountInt, toRecordId],
                                        function(err) {
                                            if (err) {
                                                return db.rollback(function() {
                                                    console.error('Database error:', err);
                                                    res.status(500).json({ success: false, message: 'Database fout bij updaten voorraad van bestemming' });
                                                });
                                            }

                                            // Registreer de beweging
                                            recordMovement();
                                        }
                                    );
                                } else {
                                    // Voeg nieuw record toe
                                    db.query(
                                        `INSERT INTO ${toTable} (bodem_id, aantal, staat${to_location === 'genk' ? ', TO_nummer' : ''}) VALUES (?, ?, ?${to_location === 'genk' ? ', ?' : ''})`,
                                        to_location === 'genk' ? [bodem_id, amountInt, state, to_TO_nummer_value] : [bodem_id, amountInt, state],
                                        function(err) {
                                            if (err) {
                                                return db.rollback(function() {
                                                    console.error('Database error:', err);
                                                    res.status(500).json({ success: false, message: 'Database fout bij toevoegen voorraad aan bestemming' });
                                                });
                                            }

                                            // Registreer de beweging
                                            recordMovement();
                                        }
                                    );
                                }

                                function recordMovement() {
                                    db.query(
                                        `INSERT INTO e_bodems_movements (bodem_id, from_location, to_location, amount, movement_type, remarks) VALUES (?, ?, ?, ?, 'transfer', ?)`,
                                        [bodem_id, from_location, to_location, amountInt, `Voorraad getransfereerd van ${from_location} naar ${to_location}`],
                                        function(err) {
                                            if (err) {
                                                return db.rollback(function() {
                                                    console.error('Database error:', err);
                                                    res.status(500).json({ success: false, message: 'Database fout bij registreren beweging' });
                                                });
                                            }

                                            db.commit(function(err) {
                                                if (err) {
                                                    return db.rollback(function() {
                                                        console.error('Database commit error:', err);
                                                        res.status(500).json({ success: false, message: 'Fout bij committen van transactie' });
                                                    });
                                                }

                                                res.json({ success: true, message: 'Voorraad succesvol getransfereerd' });
                                            });
                                        }
                                    );
                                }
                            }
                        );
                    }
                );
            }
        );
    });
});

