// Backend route
app.get('/api/e_bodems/movements', (req, res) => {
    const { dateFrom, dateTo, type } = req.query;
    
    let query = `
        SELECT 
            m.*,
            e.glovia_code,
            e.referentie,
            e.verkoopprijs,
            (m.amount * e.verkoopprijs) as movement_value
        FROM e_bodems_movements m
        JOIN e_bodems e ON m.bodem_id = e.id
        WHERE 1=1
    `;
    
    const params = [];
    
    if (dateFrom) {
        query += ` AND DATE(m.timestamp) >= ?`;
        params.push(dateFrom);
    }
    if (dateTo) {
        query += ` AND DATE(m.timestamp) <= ?`;
        params.push(dateTo);
    }
    if (type) {
        query += ` AND m.movement_type = ?`;
        params.push(type);
    }
    
    query += ` ORDER BY m.timestamp DESC LIMIT 1000`;

    console.log('Executing query:', query, 'with params:', params);

    db.query(query, params, (err, results) => {
        if (err) {
            console.error('Database error:', err);
            return res.status(500).json({ 
                message: 'Fout bij ophalen bewegingen',
                error: err.message 
            });
        }
        console.log(`Found ${results.length} movements`);
        res.json(results);
    });
});



app.get('/api/e_bodems/bewegingen/:id', (req, res) => {
    const id = req.params.id;
    
    const query = `
        SELECT 
            COALESCE(t.datum_transport, o.datum_ontvangen, v.datum_verbruik) as datum,
            CASE 
                WHEN t.id IS NOT NULL THEN 'Transport'
                WHEN v.id IS NOT NULL THEN 'Verbruik'
                ELSE 'Ontvangst'
            END as type,
            CASE 
                WHEN t.id IS NOT NULL THEN t.aantal
                WHEN v.id IS NOT NULL THEN v.aantal
                ELSE o.aantal
            END as aantal,
            t.TO_nummer,
            COALESCE(t.staat, o.staat) as staat
        FROM e_bodems_ontvangst o
        LEFT JOIN e_bodems_transport t ON o.id = t.ontvangst_id
        LEFT JOIN e_bodems_verbruik v ON t.id = v.transport_id
        WHERE o.bodem_id = ?
        ORDER BY datum DESC`;

    db.query(query, [id], (err, results) => {
        if (err) {
            console.error('Database error:', err);
            return res.status(500).json({ message: 'Fout bij ophalen bewegingen' });
        }
        res.json(results);
    });
});

