app.post('/api/e_bodems/staat-wijzigen', (req, res) => {
    const { id, aantal, nieuweStaat, location, bodem_id, huidigeStaat } = req.body;
    
    if (!id || !aantal || !nieuweStaat || !location || !bodem_id) {
        console.log('Missing required fields:', { id, aantal, nieuweStaat, location, bodem_id });
        return res.status(400).json({ 
            success: false,
            message: 'Alle velden zijn verplicht' 
        });
    }

    console.log('Staat wijzigen request:', {
        id, aantal, nieuweStaat, location, bodem_id, huidigeStaat
    });

    const table = location === 'wilrijk' ? 'e_bodems_voorraad_wilrijk' : 'e_bodems_voorraad_genk';

    db.beginTransaction(err => {
        if (err) {
            console.error('Transaction error:', err);
            return res.status(500).json({
                success: false,
                message: 'Database transactie fout',
                error: err.message
            });
        }

        // Check voorraad - zonder TO_nummer
        db.query(
            `SELECT aantal FROM ${table} WHERE id = ?`,
            [id],
            (err, currentStock) => {
                if (err) {
                    return db.rollback(() => {
                        res.status(500).json({
                            success: false,
                            message: 'Fout bij controleren voorraad',
                            error: err.message
                        });
                    });
                }

                if (!currentStock.length) {
                    return db.rollback(() => {
                        res.status(500).json({
                            success: false,
                            message: 'Record niet gevonden'
                        });
                    });
                }

                if (currentStock[0].aantal < aantal) {
                    return db.rollback(() => {
                        res.status(500).json({
                            success: false,
                            message: 'Onvoldoende voorraad beschikbaar'
                        });
                    });
                }

                // Verminder originele voorraad
                db.query(
                    `UPDATE ${table} SET aantal = aantal - ? WHERE id = ?`,
                    [aantal, id],
                    (err) => {
                        if (err) {
                            return db.rollback(() => {
                                res.status(500).json({
                                    success: false,
                                    message: 'Fout bij updaten voorraad',
                                    error: err.message
                                });
                            });
                        }

                        // Check bestaand record met nieuwe staat
                        db.query(
                            `SELECT id FROM ${table} WHERE bodem_id = ? AND staat = ?`,
                            [bodem_id, nieuweStaat],
                            (err, existingRecord) => {
                                if (err) {
                                    return db.rollback(() => {
                                        res.status(500).json({
                                            success: false,
                                            message: 'Database fout',
                                            error: err.message
                                        });
                                    });
                                }

                                // Update of insert query
                                const updateOrInsert = existingRecord.length > 0 ?
                                    [`UPDATE ${table} SET aantal = aantal + ? WHERE id = ?`, 
                                     [aantal, existingRecord[0].id]] :
                                    [`INSERT INTO ${table} (bodem_id, aantal, staat) VALUES (?, ?, ?)`,
                                     [bodem_id, aantal, nieuweStaat]];

                                db.query(updateOrInsert[0], updateOrInsert[1], (err) => {
                                    if (err) {
                                        return db.rollback(() => {
                                            res.status(500).json({
                                                success: false,
                                                message: 'Fout bij updaten nieuwe staat',
                                                error: err.message
                                            });
                                        });
                                    }

                                    // Registreer beweging (zonder TO_nummer)
                                    const movementQuery = `
                                        INSERT INTO e_bodems_movements 
                                        (bodem_id, movement_type, amount, from_location, to_location, state, remarks)
                                        VALUES (?, ?, ?, ?, ?, ?, ?)
                                    `;

                                    const movementParams = [
                                        bodem_id,
                                        'state_change',
                                        aantal,
                                        location,
                                        location,
                                        nieuweStaat,
                                        `Staat gewijzigd van ${huidigeStaat} naar ${nieuweStaat}`
                                    ];

                                    db.query(movementQuery, movementParams, (err) => {
                                        if (err) {
                                            return db.rollback(() => {
                                                res.status(500).json({
                                                    success: false,
                                                    message: 'Fout bij registreren beweging',
                                                    error: err.message
                                                });
                                            });
                                        }

                                        db.commit(err => {
                                            if (err) {
                                                return db.rollback(() => {
                                                    res.status(500).json({
                                                        success: false,
                                                        message: 'Fout bij commit',
                                                        error: err.message
                                                    });
                                                });
                                            }

                                            res.json({
                                                success: true,
                                                message: 'Staat succesvol bijgewerkt'
                                            });
                                        });
                                    });
                                });
                            }
                        );
                    }
                );
            }
        );
    });
});

// Helper functie om bewegingen te registreren
function registerMovement(movement) {
    const query = `
        INSERT INTO e_bodems_movements 
        (bodem_id, movement_type, amount, from_location, to_location, state, TO_nummer, remarks)
        VALUES (?, ?, ?, ?, ?, ?, ?, ?)
    `;
    
    const params = [
        movement.bodem_id,
        movement.movement_type,
        movement.amount,
        movement.from_location,
        movement.to_location,
        movement.state,
        movement.TO_nummer || null,
        movement.remarks || ''
    ];

    return db.promise().query(query, params);
}


// 6. Database check route
app.get('/api/e_bodems/check-tables', (req, res) => {
    const queries = [
        'SHOW TABLES LIKE "e_bodems"',
        'SHOW TABLES LIKE "e_bodems_ontvangst"',
        'SHOW TABLES LIKE "e_bodems_transport"',
        'SHOW TABLES LIKE "e_bodems_verbruik"'
    ];

    Promise.all(queries.map(query => 
        new Promise((resolve, reject) => {
            db.query(query, (err, results) => {
                if (err) reject(err);
                resolve({
                    query: query,
                    exists: results.length > 0
                });
            });
        })
    ))
    .then(results => {
        res.json(results);
    })
    .catch(error => {
        console.error('Error checking tables:', error);
        res.status(500).json({ 
            message: 'Fout bij controleren van database tabellen',
            error: error.message 
        });
    });
});





// API route to create a new work order
app.post('/api/workorders', (req, res) => {
    const { orderNumber, orderDescription, orderQuantity, steps } = req.body;

    if (!orderNumber || !orderDescription || !orderQuantity || !steps || steps.length === 0) {
        return res.status(400).json({ error: 'All fields are required' });
    }

    const query = 'INSERT INTO workorders (order_number, order_description, order_quantity, steps) VALUES (?, ?, ?, ?)';
    const values = [orderNumber, orderDescription, orderQuantity, steps.join(',')];

    db.query(query, values, (err, results) => {
        if (err) {
            console.error('Error creating work order:', err);
            res.status(500).json({ error: 'Database error' });
            return;
        }
        res.json({ success: true, workOrderId: results.insertId });
    });
});

// API route to start a work order
app.post('/api/workorders/:id/start', (req, res) => {
    const { id } = req.params;
    const { step, workers } = req.body; // Added workers parameter
    const currentTime = moment().format('YYYY-MM-DD HH:mm:ss');
    let query;

    if (step === 'zagerij') {
        query = 'UPDATE workorders SET zagerij_start_time = IFNULL(zagerij_start_time, ?), status_zagerij = ?, is_paused_zagerij = false, zagerij_workers = ? WHERE id = ?';
    } else if (step === 'assemblage') {
        query = 'UPDATE workorders SET assemblage_start_time = IFNULL(assemblage_start_time, ?), status_assemblage = ?, is_paused_assemblage = false, assemblage_workers = ? WHERE id = ?';
    } else {
        return res.status(400).json({ error: 'Invalid step' });
    }

    db.query(query, [currentTime, 'in_progress', workers, id], (err, results) => {
        if (err) {
            console.error('Error updating work order start time:', err);
            return res.status(500).json({ error: 'Database error' });
        }
        res.json({ success: true });
    });
});

// API route to pause a work order
app.post('/api/workorders/:id/pause', (req, res) => {
    const { id } = req.params;
    const { step, reason } = req.body;
    const pauseTime = moment().format('YYYY-MM-DD HH:mm:ss');
    let query;

    if (step === 'zagerij') {
        query = `UPDATE workorders SET total_elapsed_time_zagerij = total_elapsed_time_zagerij + TIMESTAMPDIFF(SECOND, zagerij_start_time, ?),
                 last_pause_time_zagerij = ?, is_paused_zagerij = true, status_zagerij = ? WHERE id = ?`;
    } else if (step === 'assemblage') {
        query = `UPDATE workorders SET total_elapsed_time_assemblage = total_elapsed_time_assemblage + TIMESTAMPDIFF(SECOND, assemblage_start_time, ?),
                 last_pause_time_assemblage = ?, is_paused_assemblage = true, status_assemblage = ? WHERE id = ?`;
    } else {
        return res.status(400).json({ error: 'Invalid step' });
    }

    db.query(query, [pauseTime, pauseTime, 'paused', id], (err, results) => {
        if (err) {
            console.error('Error updating total elapsed time:', err);
            return res.status(500).json({ error: 'Database error' });
        }

        const insertPauseQuery = 'INSERT INTO workorder_pauses (workorder_id, step, pause_start_time, reason) VALUES (?, ?, ?, ?)';
        db.query(insertPauseQuery, [id, step, pauseTime, reason], (err, results) => {
            if (err) {
                console.error('Error inserting pause record:', err);
                return res.status(500).json({ error: 'Database error' });
            }
            res.json({ success: true });
        });
    });
});

// API route to resume a work order
app.post('/api/workorders/:id/resume', (req, res) => {
    const { id } = req.params;
    const { step, workers } = req.body; // Added workers parameter
    const resumeTime = moment().format('YYYY-MM-DD HH:mm:ss');
    let query, updatePauseQuery;

    if (step === 'zagerij') {
        query = 'UPDATE workorders SET is_paused_zagerij = false, status_zagerij = ?, zagerij_workers = ? WHERE id = ?';
        updatePauseQuery = 'UPDATE workorder_pauses SET pause_end_time = ? WHERE workorder_id = ? AND step = ? AND pause_end_time IS NULL';
    } else if (step === 'assemblage') {
        query = 'UPDATE workorders SET is_paused_assemblage = false, status_assemblage = ?, assemblage_workers = ? WHERE id = ?';
        updatePauseQuery = 'UPDATE workorder_pauses SET pause_end_time = ? WHERE workorder_id = ? AND step = ? AND pause_end_time IS NULL';
    } else {
        return res.status(400).json({ error: 'Invalid step' });
    }

    db.query(query, ['in_progress', workers, id], (err, results) => {
        if (err) {
            console.error('Error updating work order resume status:', err);
            return res.status(500).json({ error: 'Database error' });
        }

        db.query(updatePauseQuery, [resumeTime, id, step], (err, results) => {
            if (err) {
                console.error('Error updating pause record:', err);
                return res.status(500).json({ error: 'Database error' });
            }
            res.json({ success: true });
        });
    });
});

