// API route to end a work order
app.post('/api/workorders/:id/end', (req, res) => {
    const { id } = req.params;
    const { step } = req.body;
    const endTime = moment().format('YYYY-MM-DD HH:mm:ss');
    let totalElapsedTimeQuery;

    if (step === 'zagerij') {
        totalElapsedTimeQuery = `UPDATE workorders SET total_elapsed_time_zagerij = 
                                 CASE WHEN is_paused_zagerij = false THEN total_elapsed_time_zagerij + TIMESTAMPDIFF(SECOND, zagerij_start_time, ?)
                                 ELSE total_elapsed_time_zagerij END,
                                 zagerij_end_time = ?, status_zagerij = ? WHERE id = ?`;
    } else if (step === 'assemblage') {
        totalElapsedTimeQuery = `UPDATE workorders SET total_elapsed_time_assemblage = 
                                 CASE WHEN is_paused_assemblage = false THEN total_elapsed_time_assemblage + TIMESTAMPDIFF(SECOND, assemblage_start_time, ?)
                                 ELSE total_elapsed_time_assemblage END,
                                 assemblage_end_time = ?, status_assemblage = ? WHERE id = ?`;
    } else {
        return res.status(400).json({ error: 'Invalid step' });
    }

    db.query(totalElapsedTimeQuery, [endTime, endTime, 'completed', id], (err, results) => {
        if (err) {
            console.error('Error updating total elapsed time:', err);
            return res.status(500).json({ error: 'Database error' });
        }
        res.json({ success: true });
    });
});


