app.post('/api/lading_send_pdf', upload.single('photo'), async (req, res) => {
  

  // Stel we laden de "loaded" motors direct:
  db.query(`SELECT * FROM cnh_motors WHERE state='loaded'`, async (err, rows) => {
    if (err) return res.status(500).json({ error:'DB error'});

    // 1) PDF genereren
    const doc = new PDFDocument();
    let buffers = [];
    doc.on('data', d => buffers.push(d));
    doc.on('end', async () => {
      // PDF is gegenereerd in memory
      const pdfData = Buffer.concat(buffers);

      // 2) E-mail verzenden
      try {
        let transporter = nodemailer.createTransport({
          host: 'mail.prodwilrijk.be',
          port: 465,
          secure: true,
          auth: {
            user: 'jason@prodwilrijk.be',
            pass: 'prodwilrijk147'
          }
        });

        let mailOptions = {
          from: 'jason@prodwilrijk.be',
          to: 'klant@example.com',
          subject: 'Overzicht Lading',
          html: '<p>Hierbij het overzicht van de geladen motoren.</p>',
          attachments: [
            {
              filename: 'lading_overzicht.pdf',
              content: pdfData
            }
          ]
        };

        // Optioneel: als je de foto wilt meesturen als attachment:
        if (req.file) {
          mailOptions.attachments.push({
            filename: req.file.originalname || 'photo.jpg',
            path: req.file.path,
            contentType: req.file.mimetype
          });
        }

        await transporter.sendMail(mailOptions);
        return res.json({ success:true, message:'Mail verzonden!' });
      } catch(e) {
        console.error('SendMail error:', e);
        return res.status(500).json({ error:'Fout bij mailen: '+ e.message });
      }
    });

    // PDF inhoud:
    doc.fontSize(18).text('Overzicht Lading', { underline:true });
    doc.moveDown();

    rows.forEach(m => {
      doc.fontSize(12).text(`Motor #${m.id} => ${m.motor_nr} | Container: ${m.container_no||''} | Truck: ${m.truck_plate||''} | LoadRef: ${m.load_reference||''}`);
    });

    doc.end();
  });
});

