// Voorbeeld: POST/PUT body = { motors: [ { motorId, bodemsLow, bodemsHigh }, ... ] }

// PUT /api/cnh_motors/package
// body: { "motors": [ { "motorId":123, "bodemsLow":2, "bodemsHigh":1 }, ... ] }
// PUT /api/cnh_motors/package
// body: { "motors": [ {motorId, bodemsLow, bodemsHigh}, ... ] }
app.put('/api/cnh_motors/package', (req, res) => {
  const { motors } = req.body;
  if (!Array.isArray(motors) || motors.length === 0) {
    return res.status(400).json({ error: 'motors array vereist' });
  }

  // motor IDs
  const motorIds = motors.map(m => m.motorId);

  db.query(
    `SELECT id, location FROM cnh_motors WHERE id IN (?)`,
    [motorIds],
    async (err, rows) => {
      if (err) {
        console.error('Fout bij SELECT cnh_motors:', err);
        return res.status(500).json({ error: 'DB error package (select)' });
      }

      // promisified query helper
      const runQuery = (sqlQ, arr=[]) => new Promise((resolve, reject) => {
        db.query(sqlQ, arr, (e, r) => (e ? reject(e) : resolve(r)));
      });

      try {
        for (const item of motors) {
          const { motorId, bodemsLow=0, bodemsHigh=0 } = item;
          const row = rows.find(r => r.id === motorId);
          if (!row) {
            console.warn(`Motor ID=${motorId} niet gevonden`);
            continue;
          }

          if (row.location === 'China') {
            // Bodems afboeken
            await runQuery(`UPDATE bodems_stock SET quantity=quantity-? WHERE bodem_type='LOW'`, [bodemsLow]);
            await runQuery(`UPDATE bodems_stock SET quantity=quantity-? WHERE bodem_type='HIGH'`, [bodemsHigh]);
            
            // Markeer motor als packaged
            await runQuery(`
              UPDATE cnh_motors
              SET state='packaged', packed_at=NOW(),
                  bodem_low=?, bodem_high=?
              WHERE id=?
            `, [bodemsLow, bodemsHigh, motorId]);
          } else {
            // non-china
            await runQuery(`
              UPDATE cnh_motors
              SET state='packaged', packed_at=NOW()
              WHERE id=?
            `, [motorId]);
          }

          // optioneel: logging
          await runQuery(`
            INSERT INTO cnh_logs (motor_id, action, description, timestamp)
            VALUES (?, 'packaged', 'Motor verpakt', NOW())
          `, [motorId]);
        }

        return res.json({ success: true });
      } catch (error2) {
        console.error('Fout bij package updates:', error2);
        return res.status(500).json({ error: 'DB error package' });
      }
    }
  );
});







