// POST /api/cnh_session/stop_load
app.post('/api/cnh_session/stop_load', (req, res) => {
  const {
    sessionId,
    loading_minutes,
    loading_count,
    loading_persons,
    load_reference,
    container_no,
    truck_plate,
    booking_ref,
    your_ref,
    container_tarra,   // NIEUW
    motorIds
  } = req.body;

  if(!sessionId){
    return res.status(400).json({ error:'sessionId is vereist' });
  }

  const sql=`
    UPDATE cnh_sessions
    SET
      loading_minutes=?,
      loading_count=?,
      loading_persons=?,
      load_reference=?,
      container_no=?,
      truck_plate=?,
      booking_ref=?,
      your_ref=?,
      container_tarra=?  -- hier
    WHERE id=?
  `;
  db.query(sql, [
    loading_minutes||0,
    loading_count||0,
    loading_persons||1,
    load_reference||'',
    container_no||'',
    truck_plate||'',
    booking_ref||'',
    your_ref||'',
    container_tarra||0,   // zet default 0 als undefined
    sessionId
  ], (err, result)=>{
    if(err){
      console.error('Fout bij stop_load:', err);
      return res.status(500).json({ error:'DB error stop_load' });
    }
    if(result.affectedRows===0){
      return res.status(404).json({ error:'Sessie niet gevonden' });
    }

    // motorIds koppelen etc. ...
    if(Array.isArray(motorIds) && motorIds.length>0){
      const values = motorIds.map(mId=>[sessionId,mId]);
      db.query(`
        INSERT INTO cnh_session_motors (session_id,motor_id)
        VALUES ?
      `,[values],(err2)=>{
        if(err2){
          console.error('Error linking motors to load session:', err2);
          return res.status(500).json({ error:'DB error session_motors stop_load' });
        }
        return res.json({ success:true });
      });
    } else {
      return res.json({ success:true });
    }
  });
});








// POST /api/cnh_session/stop_pack
// body: {
//   sessionId, packaging_minutes, packaging_persons, packaging_count, location,
//   motors: [ { motorId }, { motorId }, ... ]
// }
app.post('/api/cnh_session/stop_pack', (req, res) => {
  const {
    sessionId,
    packaging_minutes=0,
    packaging_count=0,
    packaging_persons=1,
    location='N/A',
    motors=[]
  } = req.body;

  if (!sessionId) {
    return res.status(400).json({ error: 'sessionId is vereist' });
  }

  db.query(
    `UPDATE cnh_sessions
     SET packaging_minutes=?, packaging_count=?, packaging_persons=?, location=?
     WHERE id=?`,
    [packaging_minutes, packaging_count, packaging_persons, location, sessionId],
    (err, results) => {
      if (err) {
        console.error('Error stopping pack session:', err);
        return res.status(500).json({ error: 'DB error stop_pack' });
      }
      if (results.affectedRows===0) {
        return res.status(404).json({ error:'Sessie niet gevonden' });
      }
      
      // motors => cnh_session_motors
      if (!Array.isArray(motors) || motors.length===0) {
        return res.json({ success:true });
      }
      const values = motors.map(m => [sessionId, m.motorId]);
      db.query(`
        INSERT INTO cnh_session_motors (session_id, motor_id)
        VALUES ?`,
        [values],
        (err2) => {
          if (err2) {
            console.error('Error linking motors to session:', err2);
            return res.status(500).json({ error:'DB error session_motors' });
          }
          return res.json({ success:true });
        }
      );
    }
  );
});






