// API route to update problemen item
app.put('/api/problemen/:id', (req, res) => {
    const { id } = req.params;
    const updateData = req.body;

    if (Object.keys(updateData).length === 0) {
        return res.status(400).json({ error: 'No data provided to update' });
    }

    const fields = Object.keys(updateData);
    const values = Object.values(updateData);

    const setClause = fields.map(field => `${field} = ?`).join(', ');

    const query = `UPDATE problemen SET ${setClause} WHERE id = ?`;

    db.query(query, [...values, id], (err, results) => {
        if (err) {
            console.error('Error updating problemen item:', err);
            res.status(500).json({ error: 'Database error' });
            return;
        }
        res.json({ success: true, updatedRows: results.affectedRows });
    });
});


// API route to upload an image for problemen item
app.post('/api/problemen/:id/images', (req, res) => {
    const { id } = req.params;
    if (!req.files || !req.files.images) {
        return res.status(400).json({ error: 'No image files uploaded' });
    }

    const images = Array.isArray(req.files.images) ? req.files.images : [req.files.images];
    const imagePaths = [];

    // Fetch existing image paths from the database
    const selectQuery = 'SELECT image FROM problemen WHERE id = ?';
    db.query(selectQuery, [id], (selectErr, selectResults) => {
        if (selectErr) {
            console.error('Error fetching existing images:', selectErr);
            return res.status(500).json({ error: 'Database error' });
        }

        let existingImages = [];
        if (selectResults.length > 0 && selectResults[0].image) {
            try {
                existingImages = JSON.parse(selectResults[0].image);
            } catch (parseErr) {
                console.error('Error parsing existing images JSON:', parseErr);
                existingImages = [];
            }
        }

        images.forEach((image, index) => {
            const uploadPath = path.join(__dirname, 'public', 'uploads', `${id}_${Date.now()}_${image.name}`);
            image.mv(uploadPath, (err) => {
                if (err) {
                    console.error('Error uploading image:', err);
                    return res.status(500).json({ error: 'Failed to upload image' });
                }
                imagePaths.push(`/uploads/${path.basename(uploadPath)}`);
                if (imagePaths.length === images.length) {
                    // Update image paths in the database
                    const updatedImages = [...existingImages, ...imagePaths];
                    const updateQuery = 'UPDATE problemen SET image = ? WHERE id = ?';
                    db.query(updateQuery, [JSON.stringify(updatedImages), id], (updateErr, updateResults) => {
                        if (updateErr) {
                            console.error('Error updating image paths:', updateErr);
                            return res.status(500).json({ error: 'Database error' });
                        }
                        res.json({ success: true, imagePaths: updatedImages });
                    });
                }
            });
        });
    });
});






// API route to move item from Problemen to items_to_pack
app.post('/api/problemen/move_to_pack/:id', (req, res) => {
    const { id } = req.params;

    // Select item from Problemen
    const selectQuery = 'SELECT * FROM problemen WHERE id = ? AND po_number IS NOT NULL';
    db.query(selectQuery, [id], (err, results) => {
        if (err) {
            console.error('Error fetching problemen item:', err);
            return res.status(500).json({ error: 'Database error' });
        }

        if (results.length === 0) {
            return res.status(400).json({ error: 'Item not found or PO number is not assigned' });
        }

        const item = results[0];
        const insertQuery = 'INSERT INTO items_to_pack (item_number, po_number, amount) VALUES (?, ?, ?)';
        const deleteQuery = 'DELETE FROM problemen WHERE id = ?';

        db.query(insertQuery, [item.item_number, item.po_number, item.amount], (err, insertResults) => {
            if (err) {
                console.error('Error inserting item to items_to_pack:', err);
                return res.status(500).json({ error: 'Database error' });
            }

            db.query(deleteQuery, [id], (err, deleteResults) => {
                if (err) {
                    console.error('Error deleting item from problemen:', err);
                    return res.status(500).json({ error: 'Database error' });
                }
                res.json({ success: true });
            });
        });
    });
});

