app.get('/api/items_to_pack', (req, res) => {
    const query = `
        SELECT 
            i.*, 
            -- Tel het aantal actieve verpakkers per item
            COALESCE(p.active_packers, 0) AS activePackersCount,
            -- Of direct een boolean maken (in MySQL wordt het vaak 0 of 1)
            (COALESCE(p.active_packers, 0) > 0) AS hasActivePackers
        FROM items_to_pack i
        LEFT JOIN (
            SELECT 
                item_id, 
                COUNT(*) AS active_packers
            FROM item_packers
            WHERE active = 1
            GROUP BY item_id
        ) AS p ON i.id = p.item_id
    `;

    db.query(query, (err, results) => {
        if (err) {
            console.error('Error fetching items to pack:', err);
            res.status(500).json({ error: 'Database error' });
            return;
        }
        res.json(results);
    });
});


