// API route to generate a report of chest usage
// API route to generate a report of chest usage
app.get('/api/packed_items_airtec/report', (req, res) => {
    const { date_from, date_to } = req.query;

    let query = 'SELECT kistnummer, SUM(quantity) as total_quantity FROM packed_items_airtec WHERE 1=1';
    const params = [];

    if (date_from) {
        query += ' AND date_packed >= ?';
        params.push(new Date(date_from).toISOString().slice(0, 19).replace('T', ' '));
    }
    if (date_to) {
        query += ' AND date_packed <= ?';
        params.push(new Date(date_to).toISOString().slice(0, 19).replace('T', ' '));
    }
    query += ' GROUP BY kistnummer';

    db.query(query, params, (err, results) => {
        if (err) {
            console.error('Error fetching chest usage report:', err);
            res.status(500).json({ error: 'Database error' });
            return;
        }

        const chests = {};
        results.forEach(row => {
            chests[row.kistnummer] = row.total_quantity;
        });

        res.json({ chests });
    });
});

