app.post('/api/packed_items_airtec/send_email', (req, res) => {
    const { date_from, date_to, kistnummer_from, kistnummer_to, itemnumber_from, itemnumber_to, lotnumber } = req.query;

    let query = 'SELECT beschrijving, item_number, lot_number, datum_opgestuurd, kistnummer, divisie, quantity, datum_ontvangen, date_packed FROM packed_items_airtec WHERE 1=1';
    const params = [];

    if (date_from) {
        query += ' AND date_packed >= ?';
        params.push(new Date(date_from).toISOString().slice(0, 19).replace('T', ' '));
    }
    if (date_to) {
        query += ' AND date_packed <= ?';
        params.push(new Date(date_to).toISOString().slice(0, 19).replace('T', ' '));
    }
    if (kistnummer_from) {
        query += ' AND kistnummer >= ?';
        params.push(kistnummer_from);
    }
    if (kistnummer_to) {
        query += ' AND kistnummer <= ?';
        params.push(kistnummer_to);
    }
    if (itemnumber_from) {
        query += ' AND item_number >= ?';
        params.push(itemnumber_from);
    }
    if (itemnumber_to) {
        query += ' AND item_number <= ?';
        params.push(itemnumber_to);
    }
    if (lotnumber) {
        query += ' AND lot_number = ?';
        params.push(lotnumber);
    }

    db.query(query, params, (err, results) => {
        if (err) {
            console.error('Error fetching packed items for Airtec:', err);
            res.status(500).json({ error: 'Database error' });
            return;
        }

        // Ensure datum_ontvangen is set to datum_opgestuurd if not already set
        results.forEach(item => {
            item.datum_ontvangen = item.datum_opgestuurd;
        });

        // Convert results to Excel
        const workbook = xlsx.utils.book_new();
        const worksheetData = results.map(({ beschrijving, item_number, lot_number, datum_opgestuurd, kistnummer, divisie, quantity, datum_ontvangen, date_packed }) => ({
            beschrijving,
            item_number,
            lot_number,
            datum_opgestuurd: datum_opgestuurd ? new Date(datum_opgestuurd) : '',
            kistnummer,
            divisie,
            quantity,
            datum_ontvangen: datum_opgestuurd ? new Date(datum_opgestuurd) : '',
            date_packed: date_packed ? new Date(date_packed) : ''
        }));

        const worksheet = xlsx.utils.json_to_sheet(worksheetData, { header: ["beschrijving", "item_number", "lot_number", "datum_opgestuurd", "kistnummer", "divisie", "quantity", "datum_ontvangen", "date_packed"] });

        // Calculate total quantity
        const totalQuantity = results.reduce((sum, row) => sum + (row.quantity || 0), 0);
        xlsx.utils.sheet_add_aoa(worksheet, [['Total', '', '', '', '', '', totalQuantity]], { origin: -1 });

        // Apply styles
        const range = xlsx.utils.decode_range(worksheet['!ref']);
        for (let C = range.s.c; C <= range.e.c; ++C) {
            const address = xlsx.utils.encode_col(C) + '1';
            if (!worksheet[address]) continue;
            worksheet[address].s = { 
                font: { bold: true, color: { rgb: "FFFFFF" } },
                fill: { fgColor: { rgb: "0000FF" } } 
            };
        }

        // Set column widths to ensure text is fully visible
        const wscols = [
            { wch: 20 }, // beschrijving
            { wch: 15 }, // item_number
            { wch: 15 }, // lot_number
            { wch: 15 }, // datum_opgestuurd
            { wch: 10 }, // kistnummer
            { wch: 15 }, // divisie
            { wch: 10 }, // quantity
            { wch: 15 }, // datum_ontvangen
            { wch: 15 }  // date_packed
        ];
        worksheet['!cols'] = wscols;

        // Format date cells
        const dateColumns = ['D', 'H', 'I'];
        dateColumns.forEach(col => {
            for (let row = 2; row <= results.length + 1; row++) {
                const cellAddress = `${col}${row}`;
                if (worksheet[cellAddress]) {
                    worksheet[cellAddress].z = xlsx.SSF._table[14]; // Set date format to 'mm/dd/yyyy'
                }
            }
        });

        xlsx.utils.book_append_sheet(workbook, worksheet, 'Packed Items Airtec');

        // Write workbook to buffer
        const buffer = xlsx.write(workbook, { type: 'buffer', bookType: 'xlsx' });

        // Set up nodemailer transporter
        const transporter = nodemailer.createTransport({
            host: 'mail.prodwilrijk.be',
            port: 465,
            secure: true,
            auth: {
                user: 'jason@prodwilrijk.be',
                pass: 'prodwilrijk147'
            }
        });

        // Generate filename with current date
        const filename = `Coolers & Elementen verpakt ${moment().format('DD-MM-YYYY')}.xlsx`;

        // Set up email options
        const mailOptions = {
            from: 'jason@prodwilrijk.be',
            to: 'prodwilrijk@foresco.eu',
            subject: 'Verpakte Coolers/Elementen',
            html: `
                <p>Goedemiddag,</p>
                <p>In bijlage de lijst met verpakte Coolers/Elementen.</p>
                <p><strong>Datum:</strong> ${moment().format('DD-MM-YYYY')}</p>
                <p>Met vriendelijke groeten,</p>
                <p>Jason Ploegaerts</p>
            `,
            attachments: [
                {
                    filename: filename,
                    content: buffer,
                    contentType: 'application/vnd.openxmlformats-officedocument.spreadsheetml.sheet'
                }
            ]
        };

        // Send email
        transporter.sendMail(mailOptions, (error, info) => {
            if (error) {
                console.error('Error sending email:', error);
                res.status(500).json({ error: 'Error sending email' });
            } else {
                console.log('Email sent:', info.response);
                res.json({ success: true });
            }
        });
    });
});




