app.post('/api/cnh_records', (req, res) => {
  const {
    motor_type,
    motor_number,
    location,
    bodem_type,
    packaging_persons,
    packaging_minutes,
    packaging_count,
    loading_persons,
    loading_minutes,
    loading_count
  } = req.body;

  if (!motor_type || !motor_number || !location) {
    return res.status(400).json({ 
      error: 'motor_type, motor_number, en location zijn vereist.'
    });
  }
  if (location==='China' && !bodem_type) {
    return res.status(400).json({ 
      error: 'bodem_type is verplicht bij location=China'
    });
  }

  const sql = `
    INSERT INTO cnh_records (
      motor_type, motor_number, location, bodem_type,
      packaging_persons, packaging_minutes, packaging_count,
      loading_persons, loading_minutes, loading_count
    ) VALUES (?, ?, ?, ?, ?, ?, ?, ?, ?, ?)
  `;
  db.query(
    sql,
    [
      motor_type, motor_number, location, bodem_type||'',
      packaging_persons||1, packaging_minutes||0, packaging_count||0,
      loading_persons||1, loading_minutes||0, loading_count||0
    ],
    (err, result) => {
      if (err) {
        console.error('Error inserting CNH record:', err);
        return res.status(500).json({ error: 'Database error' });
      }
      res.json({ success:true, insertedId: result.insertId });
    }
  );
});

app.post('/api/cnh_motors/receive', (req, res) => {
  const { location, shippingNote, motors } = req.body;
  if (!location || !Array.isArray(motors) || motors.length === 0) {
    return res.status(400).json({ error: 'Locatie en motors[] vereist' });
  }

  let doneCount = 0;
  let errorOccurred = false;

  motors.forEach(motorNr => {
    db.query(
      `INSERT INTO cnh_motors (motor_nr, location, state, shipping_note, created_at)
       VALUES (?, ?, 'received', ?, NOW())`,
      [motorNr, location, shippingNote || null],
      (err, results) => {
        if (err) {
          console.error('Fout bij INSERT cnh_motors:', err);
          if (!errorOccurred) {
            errorOccurred = true;
            return res.status(500).json({ error: 'Database error bij receive' });
          }
          return;
        }
        doneCount++;
        if (doneCount === motors.length && !errorOccurred) {
          return res.json({ success: true });
        }
      }
    );
  });
});





