// Beëindig hele activiteit
app.post('/api/packing/complete', async (req, res) => {
    const { activity_id, total_items } = req.body;
    
    db.beginTransaction(async (err) => {
        if (err) return res.status(500).json({ error: err.message });
        
        try {
            // 1. Update activiteit
            await db.query(
                `UPDATE packing_activities 
                 SET status = 'completed', 
                     end_time = NOW(),
                     total_items = ?
                 WHERE id = ?`,
                [total_items, activity_id]
            );
            
            // 2. Sluit alle actieve werknemers
            await db.query(
                `UPDATE packing_workers
                 SET status = 'left',
                     leave_time = NOW()
                 WHERE activity_id = ? AND status = 'active'`,
                [activity_id]
            );
            
            await db.commit();
            res.json({ success: true });
            
        } catch (error) {
            await db.rollback();
            res.status(500).json({ error: error.message });
        }
    });
});

// Haal statistieken op
app.get('/api/packing/stats', async (req, res) => {
    const query = `
        SELECT 
            pa.id as activity_id,
            pa.start_time,
            pa.end_time,
            pa.total_items,
            pa.status,
            itp.item_number,
            GROUP_CONCAT(DISTINCT e.name) as worker_names,
            COUNT(DISTINCT pw.employee_id) as worker_count,
            SUM(
                TIMESTAMPDIFF(MINUTE, 
                    pw.join_time, 
                    COALESCE(pw.leave_time, NOW())
                )
            ) as total_worker_minutes,
            TIMESTAMPDIFF(MINUTE,
                pa.start_time,
                COALESCE(pa.end_time, NOW())
            ) as activity_duration
        FROM packing_activities pa
        JOIN items_to_pack itp ON pa.item_id = itp.id
        JOIN packing_workers pw ON pa.id = pw.activity_id
        JOIN employees e ON pw.employee_id = e.id
        GROUP BY pa.id
        ORDER BY pa.start_time DESC
    `;
    
    try {
        const [results] = await db.query(query);

        // Bereken efficiëntie per activiteit
        const stats = results.map(row => ({
            ...row,
            items_per_hour: row.total_worker_minutes > 0 ? 
                (row.total_items / (row.total_worker_minutes / 60)) : 0,
            efficiency: row.activity_duration > 0 ?
                (row.total_items / (row.activity_duration / 60)) : 0
        }));

        res.json(stats);
    } catch (error) {
        res.status(500).json({ error: error.message });
    }
});


// Haal huidige planning op
app.get('/api/planning/current', async (req, res) => {
    const connection = await pool.getConnection();
    try {
        await connection.beginTransaction();

        console.log('Fetching assignments...');
        const [assignments] = await connection.query(
            'SELECT * FROM department_assignments WHERE date = CURRENT_DATE()'
        );
        console.log('Assignments fetched:', assignments);

        console.log('Fetching hours...');
        const [hours] = await connection.query(
            'SELECT * FROM department_hours WHERE date = CURRENT_DATE()'
        );
        console.log('Hours fetched:', hours);

        await connection.commit();

        // Formateer data voor frontend
        const formattedAssignments = {};
        const formattedHours = {};

        assignments.forEach(assignment => {
            if (!formattedAssignments[assignment.department_id]) {
                formattedAssignments[assignment.department_id] = [];
            }
            formattedAssignments[assignment.department_id].push(String(assignment.employee_id));
        });

        hours.forEach(hour => {
            if (!formattedHours[hour.department_id]) {
                formattedHours[hour.department_id] = {};
            }
            formattedHours[hour.department_id][hour.employee_id] = hour.hours;
        });

        console.log('Sending response:', {
            assignments: formattedAssignments,
            hours: formattedHours
        });

        res.json({
            assignments: formattedAssignments,
            hours: formattedHours
        });

    } catch (error) {
        await connection.rollback();
        handleDatabaseError(error, res);
    } finally {
        connection.release();
    }
});

// Sla planning op met error handling
app.post('/api/planning/save', async (req, res) => {
    const { assignments, hours } = req.body;
    if (!assignments || !hours) {
        return res.status(400).json({ error: 'Missing required data' });
    }

    const connection = await pool.getConnection();
    try {
        await connection.beginTransaction();

        // Verwijder oude planning voor vandaag
        await connection.query(
            'DELETE FROM department_assignments WHERE date = CURRENT_DATE()'
        );
        await connection.query(
            'DELETE FROM department_hours WHERE date = CURRENT_DATE()'
        );

        // Voeg nieuwe assignments toe
        for (const [deptId, employeeIds] of Object.entries(assignments)) {
            if (!Array.isArray(employeeIds)) continue;
            
            for (const employeeId of employeeIds) {
                await connection.query(
                    'INSERT INTO department_assignments (department_id, employee_id, date) VALUES (?, ?, CURRENT_DATE())',
                    [deptId, employeeId]
                );
            }
        }

        // Voeg nieuwe uren toe
        for (const [deptId, employeeHours] of Object.entries(hours)) {
            for (const [employeeId, hoursValue] of Object.entries(employeeHours)) {
                if (hoursValue) {
                    await connection.query(
                        'INSERT INTO department_hours (department_id, employee_id, hours, date) VALUES (?, ?, ?, CURRENT_DATE())',
                        [deptId, employeeId, hoursValue]
                    );
                }
            }
        }

        await connection.commit();
        res.json({ success: true });
    } catch (error) {
        await connection.rollback();
        handleDatabaseError(error, res);
    } finally {
        connection.release();
    }
});

