// Customer request endpoint
app.post('/customers/request', async (req, res) => {
  try {
    const {
      companyName,
      contactPerson,
      email,
      phone,
      kvkNumber,
      notes
    } = req.body;

    // Validatie
    if (!companyName || !contactPerson || !email || !phone || !kvkNumber) {
      return res.status(400).json({ error: 'Alle velden zijn verplicht' });
    }

    // Email validatie
    const emailRegex = /^[^\s@]+@[^\s@]+\.[^\s@]+$/;
    if (!emailRegex.test(email)) {
      return res.status(400).json({ error: 'Ongeldig email adres' });
    }

    // Telefoon validatie per regio
    const phoneRegex = req.headers['x-region'] === 'nl' 
      ? /^((\+31|0)6[-\s]?[0-9]{8})$/
      : /^((\+32|0)4[0-9]{8})$/;
    
    if (!phoneRegex.test(phone)) {
      return res.status(400).json({ 
        error: 'Ongeldig telefoonnummer voor ' + 
        (req.headers['x-region'] === 'nl' ? 'Nederland' : 'België')
      });
    }

    // KvK/KBO validatie
    const kvkRegex = req.headers['x-region'] === 'nl'
      ? /^\d{8}$/
      : /^[0-9]{4}\.[0-9]{3}\.[0-9]{3}$/;
    
    if (!kvkRegex.test(kvkNumber)) {
      return res.status(400).json({ 
        error: 'Ongeldig ' + 
        (req.headers['x-region'] === 'nl' ? 'KvK' : 'KBO') + 
        ' nummer'
      });
    }

    const connection = await req.dbPool.getConnection();
    
    try {
      await connection.query(`
        INSERT INTO customer_requests 
        (company_name, contact_person, email, phone, kvk_number, notes, status) 
        VALUES (?, ?, ?, ?, ?, ?, 'PENDING')
      `, [companyName, contactPerson, email, phone, kvkNumber, notes]);

      // Email notificatie voor administrators
      await sendEmail({
        to: process.env.ADMIN_EMAIL,
        subject: 'Nieuwe klant aanvraag',
        text: `
          Nieuwe klant aanvraag ontvangen:
          Bedrijf: ${companyName}
          Contact: ${contactPerson}
          Email: ${email}
          Telefoon: ${phone}
          ${req.headers['x-region'] === 'nl' ? 'KvK' : 'KBO'}: ${kvkNumber}
          Regio: ${req.headers['x-region'].toUpperCase()}
        `
      });

      res.status(201).json({ 
        message: 'Klant aanvraag succesvol ingediend'
      });
    } finally {
      connection.release();
    }
  } catch (error) {
    console.error('Error creating customer request:', error);
    res.status(500).json({ 
      error: 'Er is een fout opgetreden bij het verwerken van uw aanvraag'
    });
  }
});

