app.post('/api/generate_xml', (req, res) => {
  // Haal de door de client meegegeven velden op
  // Verwacht dat de client een JSON stuurt met deze properties:
  // PurchaseOrderNumber, VendorCode, ItemNumber, Quantity
  const { PurchaseOrderNumber, VendorCode, ItemNumber, Quantity } = req.body;

  // Bereken de datums:
  // DeliveryDate: datum van vandaag (YYYY-MM-DD)
  const today = new Date();
  const deliveryDate = today.toISOString().split('T')[0];

  // DueDate: datum van vandaag + 3 dagen (YYYY-MM-DD)
  const dueDateObj = new Date(today);
  dueDateObj.setDate(today.getDate() + 3);
  const dueDate = dueDateObj.toISOString().split('T')[0];

  // Vaststaande velden (altijd hetzelfde)
  const Division = "3960";
  const UnitOf = "PC  ";      // Let op de spaties indien nodig
  const Location = "FPTD";
  const DeliveryTimeFrameCode = "00   "; // met spaties zoals gewenst
  const DueTimeFrameCode = "00   ";
  const PrepackVendorCode = "3301011799";
  const ActionDateTime = new Date().toISOString(); // Datum en tijd van actie

  // Bouw de XML-string op
  const xml = `<?xml version="1.0" encoding="utf-8"?>
<BE2NET_PO_PREPACK_START>
  <PurchaseOrderNumber>${PurchaseOrderNumber}</PurchaseOrderNumber>
  <Division>${Division}</Division>
  <VendorCode>${VendorCode}</VendorCode>
  <ItemNumber>${ItemNumber}</ItemNumber>
  <Quantity>${Quantity}</Quantity>
  <UnitOf>${UnitOf}</UnitOf>
  <Location>${Location}</Location>
  <DeliveryDate>${deliveryDate}</DeliveryDate>
  <DeliveryTimeFrame>
    <Code>${DeliveryTimeFrameCode}</Code>
    <From />
    <To />
  </DeliveryTimeFrame>
  <DueDate>${dueDate}</DueDate>
  <DueTimeFrame>
    <Code>${DueTimeFrameCode}</Code>
    <From />
    <To />
  </DueTimeFrame>
  <PrepackVendorCode>${PrepackVendorCode}</PrepackVendorCode>
  <ActionDateTime>${ActionDateTime}</ActionDateTime>
</BE2NET_PO_PREPACK_START>`;

  // Stel de headers in zodat de client het bestand kan downloaden
  res.set({
    'Content-Type': 'application/xml',
    'Content-Disposition': 'attachment; filename="order.xml"'
  });

  // Stuur de XML-string als response
  res.send(xml);
});




