// Authenticatie endpoints (als je deze nog niet hebt)
app.post('/api/login', async (req, res) => {
    try {
        const { username, password } = req.body;
        
        if (!username || !password) {
            return res.status(400).json({ error: 'Gebruikersnaam en wachtwoord zijn verplicht' });
        }
        
        // Query de gebruiker uit de database
        const [users] = await pool.query('SELECT * FROM users WHERE username = ?', [username]);
        const user = users[0];
        
        if (!user) {
            return res.status(401).json({ error: 'Ongeldige gebruikersnaam of wachtwoord' });
        }
        
        // Controleer het wachtwoord (met bcrypt)
        const passwordMatch = await bcrypt.compare(password, user.password);
        
        if (!passwordMatch) {
            return res.status(401).json({ error: 'Ongeldige gebruikersnaam of wachtwoord' });
        }
        
        // Sla gebruiker op in sessie
        req.session.user = {
            id: user.id,
            username: user.username
        };
        
        // Update laatste login tijd
        await pool.query('UPDATE users SET last_login = NOW() WHERE id = ?', [user.id]);
        
        return res.json({ success: true, user: { id: user.id, username: user.username } });
    } catch (error) {
        console.error('Login error:', error);
        return res.status(500).json({ error: 'Er is een fout opgetreden bij het inloggen' });
    }
});

app.post('/api/register', async (req, res) => {
    try {
        const { username, password } = req.body;
        
        if (!username || !password) {
            return res.status(400).json({ error: 'Gebruikersnaam en wachtwoord zijn verplicht' });
        }
        
        // Controleer of gebruikersnaam al bestaat
        const [existingUsers] = await pool.query('SELECT id FROM users WHERE username = ?', [username]);
        
        if (existingUsers.length > 0) {
            return res.status(400).json({ error: 'Gebruikersnaam bestaat al' });
        }
        
        // Hash het wachtwoord
        const hashedPassword = await bcrypt.hash(password, 10);
        
        // Voeg gebruiker toe
        await pool.query(
            'INSERT INTO users (username, password, created_at) VALUES (?, ?, NOW())',
            [username, hashedPassword]
        );
        
        return res.json({ success: true });
    } catch (error) {
        console.error('Registration error:', error);
        return res.status(500).json({ error: 'Er is een fout opgetreden bij het registreren' });
    }
});

