// Taken API endpoints
app.get('/api/tasks', async (req, res) => {
    try {
        // Haal actieve taken op
        let tasks = [];
        try {
            const [queryResult] = await pool.query(`
                SELECT t.*, 
                GROUP_CONCAT(DISTINCT tt.tag) as tags,
                GROUP_CONCAT(DISTINCT CONCAT(ta.id, ':', ta.filename, ':', ta.file_path)) as attachments
                FROM tasks t 
                LEFT JOIN task_tags tt ON t.id = tt.task_id
                LEFT JOIN task_attachments ta ON t.id = ta.task_id
                WHERE t.is_completed = 0 AND t.is_deleted = 0
                GROUP BY t.id
                ORDER BY 
                    CASE WHEN t.priority = 'High' THEN 1
                         WHEN t.priority = 'Medium' THEN 2
                         ELSE 3 END,
                    t.due_date ASC
            `);
            tasks = queryResult || [];
        } catch (queryError) {
            console.error('Error querying active tasks:', queryError);
            tasks = [];
        }
        
        // Haal voltooide taken op
        let completedTasks = [];
        try {
            const [queryResult] = await pool.query(`
                SELECT t.*, u.username as completed_by_name
                FROM tasks t
                LEFT JOIN users u ON t.completed_by = u.id
                WHERE t.is_completed = 1
                ORDER BY t.completed_at DESC
                LIMIT 50
            `);
            completedTasks = queryResult || [];
        } catch (queryError) {
            console.error('Error querying completed tasks:', queryError);
            completedTasks = [];
        }
        
        // Ensure tasks and completedTasks are arrays
        if (!Array.isArray(tasks)) {
            console.warn('Tasks result is not an array, converting to array');
            tasks = tasks ? [tasks] : [];
        }
        
        if (!Array.isArray(completedTasks)) {
            console.warn('CompletedTasks result is not an array, converting to array');
            completedTasks = completedTasks ? [completedTasks] : [];
        }
        
        // Verwerk taken voor frontend with defensive programming
        const formattedTasks = tasks.map(task => {
            if (!task) return null;
            
            return {
                id: task.id,
                title: task.title || '',
                description: task.description || '',
                assignedTo: task.assigned_to || '',
                dueDate: task.due_date || null,
                priority: task.priority || 'Medium',
                status: task.status || '',
                category: task.category || '',
                estimatedTime: task.estimated_time || null,
                frequency: task.frequency || '',
                createdAt: task.created_at || null,
                createdBy: task.created_by || '',
                tags: task.tags && typeof task.tags === 'string' ? task.tags.split(',').filter(Boolean) : [],
                attachments: formatAttachments(task.attachments || '')
            };
        }).filter(Boolean); // Filter out null values
        
        // Verwerk voltooide taken voor frontend with defensive programming
        const formattedCompletedTasks = completedTasks.map(task => {
            if (!task) return null;
            
            return {
                id: task.id,
                title: task.title || '',
                description: task.description || '',
                assignedTo: task.assigned_to || '',
                dueDate: task.due_date || null,
                priority: task.priority || 'Medium',
                completedAt: task.completed_at || null,
                completedBy: task.completed_by_name || ''
            };
        }).filter(Boolean); // Filter out null values
        
        return res.json({ tasks: formattedTasks, completedTasks: formattedCompletedTasks });
    } catch (error) {
        console.error('Error in /api/tasks endpoint:', error);
        // Instead of returning an error status, return empty arrays
        return res.json({ 
            tasks: [], 
            completedTasks: [],
            error: process.env.NODE_ENV === 'development' ? error.message : 'Er is een fout opgetreden'
        });
    }
});

// Improved helper function for formatting attachments
function formatAttachments(attachmentsString) {
    if (!attachmentsString || typeof attachmentsString !== 'string') return [];
    
    try {
        const attachments = [];
        const attachmentsData = attachmentsString.split(',');
        
        for (const attachment of attachmentsData) {
            if (!attachment) continue;
            
            const parts = attachment.split(':');
            if (parts.length === 3) {
                attachments.push({
                    id: parts[0] || '',
                    name: parts[1] || 'unknown-file',
                    url: parts[2] || '#'
                });
            }
        }
        
        return attachments;
    } catch (error) {
        console.error('Error formatting attachments:', error);
        return [];
    }
}

