app.post('/api/tasks/:taskId/duplicate', async (req, res) => {
    try {
        const { taskId } = req.params;
        const user = req.session.user;
        
        // Haal originele taak op
        const [tasks] = await pool.query('SELECT * FROM tasks WHERE id = ?', [taskId]);
        
        if (tasks.length === 0) {
            return res.status(404).json({ error: 'Taak niet gevonden' });
        }
        
        const originalTask = tasks[0];
        
        // Maak nieuwe taak als kopie
        const [result] = await pool.query(`
            INSERT INTO tasks (
                title, description, assigned_to, due_date, 
                priority, status, category, estimated_time, 
                frequency, created_at, created_by
            ) VALUES (?, ?, ?, ?, ?, ?, ?, ?, ?, NOW(), ?)
        `, [
            `${originalTask.title} (kopie)`,
            originalTask.description,
            originalTask.assigned_to,
            originalTask.due_date,
            originalTask.priority,
            'Te doen', // Altijd 'Te doen' voor kopieën
            originalTask.category,
            originalTask.estimated_time,
            originalTask.frequency,
            user.username
        ]);
        
        const newTaskId = result.insertId;
        
        // Kopieer tags
        const [tags] = await pool.query('SELECT tag FROM task_tags WHERE task_id = ?', [taskId]);
        
        if (tags.length > 0) {
            const tagValues = tags.map(t => [newTaskId, t.tag]);
            await pool.query('INSERT INTO task_tags (task_id, tag) VALUES ?', [tagValues]);
        }
        
        // Kopieer bijlagen
        const [attachments] = await pool.query(
            'SELECT filename, file_path FROM task_attachments WHERE task_id = ?',
            [taskId]
        );
        
        if (attachments.length > 0) {
            for (const att of attachments) {
                await pool.query(
                    'INSERT INTO task_attachments (task_id, filename, file_path) VALUES (?, ?, ?)',
                    [newTaskId, att.filename, att.file_path]
                );
            }
        }
        
        // Voeg timeline entry toe
        await pool.query(
            'INSERT INTO task_timeline (task_id, user, action, timestamp) VALUES (?, ?, ?, NOW())',
            [newTaskId, user.username, 'heeft de taak aangemaakt als kopie']
        );
        
        return res.json({ success: true, taskId: newTaskId });
    } catch (error) {
        console.error('Error duplicating task:', error);
        return res.status(500).json({ error: 'Er is een fout opgetreden bij het dupliceren van de taak' });
    }
});

