app.get('/api/tasks/pending', async (req, res) => {
    try {
        // Check if user is authenticated
        if (!req.session?.user) {
            return res.status(401).json({ 
                error: 'Niet ingelogd',
                redirect: '/login'
            });
        }
        
        // Query active tasks - using both camelCase and snake_case column names for compatibility
        const query = `
            SELECT 
                id, 
                title, 
                assignedTo,
                dueDate,
                priority, 
                category, 
                status
            FROM tasks 
            WHERE 
                (isCompleted = 0 OR is_completed = 0) 
                AND 
                (isDeleted IS NULL OR isDeleted = 0 OR is_deleted IS NULL OR is_deleted = 0)
                AND 
                (assignedTo = ? OR assigned_to = ? OR createdBy = ? OR created_by = ?)
            ORDER BY 
                CASE 
                    WHEN priority = 'High' THEN 1
                    WHEN priority = 'Medium' THEN 2
                    ELSE 3 
                END,
                dueDate ASC, due_date ASC
            LIMIT 10
        `;
        
        // Get the username for filtering
        const username = req.session.user.username;
        
        // Execute the query
        const [tasks] = await pool.query(query, [username, username, username, username]);
        
        // Format tasks for frontend
        const formattedTasks = tasks.map(task => ({
            id: task.id,
            title: task.title || '',
            assignedTo: task.assignedTo || task.assigned_to || '',
            dueDate: task.dueDate || task.due_date || null,
            priority: task.priority || 'Medium',
            category: task.category || '',
            status: task.status || 'Te doen'
        }));
        
        // Return successful response
        return res.json({ 
            success: true,
            tasks: formattedTasks,
            timestamp: new Date().toISOString()
        });
    } catch (error) {
        console.error('Error in /api/tasks/pending:', error);
        return res.status(500).json({ 
            error: 'Serverfout bij het ophalen van taken'
        });
    }
});

// Bestand upload voor taken
app.post('/api/tasks/upload', upload.single('file'), (req, res) => {
    try {
        if (!req.file) {
            return res.status(400).json({ error: 'Geen bestand geüpload' });
        }
        
        const uploadPath = req.file.path;
        const fileName = req.file.originalname || req.file.filename || 'unknown-file';
        
        // Log for debugging
        console.log('File uploaded:', {
            originalName: req.file.originalname,
            filename: req.file.filename,
            path: uploadPath,
            baseDir: __dirname
        });
        
        // Sanitize the file path for URL
        let relativePath;
        try {
            // Ensure proper path calculation depending on OS
            relativePath = uploadPath.replace(path.join(__dirname, 'public'), '');
            // Make sure path uses forward slashes for URLs
            relativePath = relativePath.replace(/\\/g, '/');
            // Add leading slash if missing
            if (!relativePath.startsWith('/')) {
                relativePath = '/' + relativePath;
            }
        } catch (pathError) {
            console.error('Path calculation error:', pathError);
            // Fallback to a simple path
            relativePath = '/uploads/' + req.file.filename;
        }
        
        console.log('Calculated relative path:', relativePath);
        
        return res.json({
            success: true,
            url: relativePath,
            name: fileName,
            size: req.file.size,
            mime: req.file.mimetype
        });
    } catch (error) {
        console.error('Error uploading file:', error);
        return res.status(500).json({ 
            error: 'Er is een fout opgetreden bij het uploaden van het bestand',
            details: error.message
        });
    }
});

