app.get('/api/messages/:otherUserId', async (req, res) => {
    try {
        const { otherUserId } = req.params;
        const userId = req.session.user.id;
        
        const [messages] = await pool.query(`
            SELECT m.*, 
            CASE WHEN m.receiver_id = ? AND m.is_read = 0 THEN 0 ELSE 1 END as is_read
            FROM messages m 
            WHERE (m.sender_id = ? AND m.receiver_id = ?) 
               OR (m.sender_id = ? AND m.receiver_id = ?)
            ORDER BY m.timestamp ASC
        `, [userId, userId, otherUserId, otherUserId, userId]);
        
        const formattedMessages = messages.map(msg => ({
            id: msg.id,
            sender_id: msg.sender_id,
            receiver_id: msg.receiver_id,
            message: msg.message,
            fileUrl: msg.file_url,
            timestamp: msg.timestamp,
            is_read: msg.is_read === 1
        }));
        
        return res.json(formattedMessages);
    } catch (error) {
        console.error('Error fetching messages:', error);
        return res.status(500).json({ error: 'Er is een fout opgetreden bij het ophalen van de berichten' });
    }
});

