app.get('/api/task_stats', async (req, res) => {
    try {
        // Aantal taken die vandaag vervallen
        const today = new Date().toISOString().split('T')[0];
        const [dueTodayResult] = await pool.query(`
            SELECT COUNT(*) as count FROM tasks 
            WHERE is_completed = 0 
            AND is_deleted = 0 
            AND DATE(due_date) = ?
        `, [today]);
        
        // Aantal achterstallige taken
        const [overdueResult] = await pool.query(`
            SELECT COUNT(*) as count FROM tasks 
            WHERE is_completed = 0 
            AND is_deleted = 0 
            AND due_date < NOW()
        `);
        
        // Aantal taken voltooid deze week
        const startOfWeek = moment().startOf('week').format('YYYY-MM-DD');
        const endOfWeek = moment().endOf('week').format('YYYY-MM-DD');
        
        const [completedResult] = await pool.query(`
            SELECT COUNT(*) as count FROM tasks 
            WHERE is_completed = 1 
            AND completed_at BETWEEN ? AND ?
        `, [`${startOfWeek} 00:00:00`, `${endOfWeek} 23:59:59`]);
        
        return res.json({
            dueToday: dueTodayResult[0].count,
            overdue: overdueResult[0].count,
            completedThisWeek: completedResult[0].count
        });
    } catch (error) {
        console.error('Error fetching task stats:', error);
        return res.status(500).json({ error: 'Er is een fout opgetreden bij het ophalen van de statistieken' });
    }
});

