// Delete task endpoint (handles both soft and hard deletion)
app.delete('/api/tasks/:taskId', async (req, res) => {
    try {
        const { taskId } = req.params;
        const { permanent } = req.query; // Use permanent=true for hard delete
        
        // Log the delete request
        console.log(`Delete task request for task ID: ${taskId}, permanent: ${permanent}`);
        
        // Get user info for logging
        const user = req.session.user;
        if (!user) {
            return res.status(401).json({ error: 'Niet ingelogd' });
        }
        
        // Verify the task exists
        const [taskResult] = await pool.query(
            'SELECT id, title FROM tasks WHERE id = ?',
            [taskId]
        );
        
        if (!taskResult || taskResult.length === 0) {
            return res.status(404).json({ error: 'Taak niet gevonden' });
        }
        
        const taskTitle = taskResult[0].title;
        
        if (permanent === 'true') {
            // Hard delete - completely remove the task and related records
            
            // Start a transaction to ensure all related records are deleted
            const connection = await pool.getConnection();
            await connection.beginTransaction();
            
            try {
                // Delete related records first (foreign key constraints)
                await connection.query('DELETE FROM task_tags WHERE task_id = ?', [taskId]);
                await connection.query('DELETE FROM task_attachments WHERE task_id = ?', [taskId]);
                await connection.query('DELETE FROM task_timeline WHERE task_id = ?', [taskId]);
                await connection.query('DELETE FROM task_comments WHERE task_id = ?', [taskId]);
                
                // Finally delete the task itself
                await connection.query('DELETE FROM tasks WHERE id = ?', [taskId]);
                
                // Commit the transaction
                await connection.commit();
                connection.release();
                
                console.log(`Task ${taskId} permanently deleted by user ${user.username}`);
                
                return res.json({
                    success: true,
                    message: 'Taak permanent verwijderd',
                    deletedTaskId: taskId
                });
                
            } catch (txError) {
                // Something went wrong, rollback the transaction
                await connection.rollback();
                connection.release();
                
                console.error('Error during task deletion transaction:', txError);
                return res.status(500).json({
                    error: 'Er is een fout opgetreden bij het verwijderen van de taak',
                    details: txError.message
                });
            }
        } else {
            // Soft delete - mark the task as deleted
            try {
                // Check if we have the necessary columns for soft delete
                const [columns] = await pool.query('SHOW COLUMNS FROM tasks');
                const columnNames = columns.map(col => col.Field);
                
                // See if we have soft delete columns
                const hasIsDeleted = columnNames.includes('isDeleted');
                const hasDeletedAt = columnNames.includes('deletedAt');
                const hasDeletedBy = columnNames.includes('deletedBy');
                
                if (hasIsDeleted) {
                    // We have soft delete capability
                    let updateQuery = 'UPDATE tasks SET ';
                    const updateParams = [];
                    
                    // Build dynamic update query based on available columns
                    const updates = [];
                    
                    if (hasIsDeleted) {
                        updates.push('isDeleted = 1');
                    }
                    
                    if (hasDeletedAt) {
                        updates.push('deletedAt = NOW()');
                    }
                    
                    if (hasDeletedBy && user) {
                        updates.push('deletedBy = ?');
                        updateParams.push(user.username);
                    }
                    
                    // Add these fields if they exist
                    if (columnNames.includes('status')) {
                        updates.push('status = ?');
                        updateParams.push('Verwijderd');
                    }
                    
                    if (columnNames.includes('updatedAt')) {
                        updates.push('updatedAt = NOW()');
                    }
                    
                    updateQuery += updates.join(', ');
                    updateQuery += ' WHERE id = ?';
                    updateParams.push(taskId);
                    
                    await pool.query(updateQuery, updateParams);
                    
                    // Also add a timeline entry if that table exists
                    try {
                        await pool.query(
                            'INSERT INTO task_timeline (task_id, user, action, timestamp) VALUES (?, ?, ?, NOW())',
                            [taskId, user.username, 'heeft de taak verwijderd']
                        );
                    } catch (timelineError) {
                        console.error('Error adding timeline entry:', timelineError);
                        // Non-critical, continue
                    }
                    
                    console.log(`Task ${taskId} marked as deleted by user ${user.username}`);
                    
                    return res.json({
                        success: true,
                        message: 'Taak gemarkeerd als verwijderd',
                        deletedTaskId: taskId
                    });
                } else {
                    // No soft delete capability, fall back to hard delete
                    await pool.query('DELETE FROM tasks WHERE id = ?', [taskId]);
                    
                    console.log(`Task ${taskId} hard deleted by user ${user.username} (fallback - no soft delete columns)`);
                    
                    return res.json({
                        success: true,
                        message: 'Taak verwijderd',
                        deletedTaskId: taskId
                    });
                }
            } catch (error) {
                console.error('Error soft deleting task:', error);
                return res.status(500).json({
                    error: 'Er is een fout opgetreden bij het markeren van de taak als verwijderd',
                    details: error.message
                });
            }
        }
    } catch (error) {
        console.error('Unexpected error in delete task endpoint:', error);
        return res.status(500).json({
            error: 'Er is een fout opgetreden bij het verwijderen van de taak',
            details: error.message
        });
    }
});

// Rapporten
app.post('/api/reports/export', async (req, res) => {
    try {
        const { startDate, endDate, reportType, format } = req.body;
        
        if (!startDate || !endDate || !reportType || !format) {
            return res.status(400).json({ error: 'Ontbrekende parameters' });
        }
        
        // Query opbouwen op basis van type
        let query = `
            SELECT t.id, t.title, t.description, t.assigned_to, t.due_date, 
            t.priority, t.status, t.category, t.created_at, t.created_by, 
            t.completed_at, u.username as completed_by_name
            FROM tasks t
            LEFT JOIN users u ON t.completed_by = u.id
            WHERE 1=1 
        `;
        
        // Filter op basis van type
        switch (reportType) {
            case 'completed':
                query += `AND t.is_completed = 1 `;
                break;
            case 'overdue':
                query += `AND t.is_completed = 0 AND t.due_date < NOW() `;
                break;
        }
        
        // Datum filters
        query += `AND (t.created_at BETWEEN ? AND ?
               OR t.completed_at BETWEEN ? AND ?)
               ORDER BY `;
        
        // Sorteer op basis van type
        query += reportType === 'completed' ? `t.completed_at DESC` : `t.due_date ASC`;
        
        const [tasks] = await pool.query(query, [
            `${startDate} 00:00:00`, `${endDate} 23:59:59`,
            `${startDate} 00:00:00`, `${endDate} 23:59:59`
        ]);
        
        // Genereer rapport en filename
        const timestamp = DateTime.now().toFormat('yyyyMMdd_HHmmss');
        const filename = `takenrapport_${timestamp}.${format === 'excel' ? 'xlsx' : 'pdf'}`;
        const reportsDir = path.join(__dirname, 'public', 'reports');
        
        // Check of reports directory bestaat
        if (!fs.existsSync(reportsDir)) {
            fs.mkdirSync(reportsDir, { recursive: true });
        }
        
        const filepath = path.join(reportsDir, filename);
        
        if (format === 'excel') {
            // Excel rapport genereren
            await generateExcelReport(tasks, filepath);
        } else {
            // PDF rapport genereren
            await generatePdfReport(tasks, filepath);
        }
        
        return res.json({
            success: true,
            url: `/reports/${filename}`,
            filename: filename
        });
    } catch (error) {
        console.error('Error generating report:', error);
        return res.status(500).json({ error: 'Er is een fout opgetreden bij het genereren van het rapport' });
    }
});

// Functies voor het genereren van rapporten
async function generateExcelReport(data, filepath) {
    const workbook = new ExcelJS.Workbook();
    const worksheet = workbook.addWorksheet('Taken');
    
    // Headers toevoegen
    worksheet.columns = [
        { header: 'ID', key: 'id', width: 10 },
        { header: 'Titel', key: 'title', width: 30 },
        { header: 'Beschrijving', key: 'description', width: 40 },
        { header: 'Toegewezen aan', key: 'assigned_to', width: 20 },
        { header: 'Deadline', key: 'due_date', width: 20 },
        { header: 'Prioriteit', key: 'priority', width: 15 },
        { header: 'Status', key: 'status', width: 15 },
        { header: 'Categorie', key: 'category', width: 15 },
        { header: 'Aangemaakt op', key: 'created_at', width: 20 },
        { header: 'Aangemaakt door', key: 'created_by', width: 20 },
        { header: 'Voltooid op', key: 'completed_at', width: 20 },
        { header: 'Voltooid door', key: 'completed_by_name', width: 20 }
    ];
    
    // Style voor headers
    worksheet.getRow(1).font = { bold: true };
    
    // Voeg data toe
    data.forEach(task => {
        worksheet.addRow({
            id: task.id,
            title: task.title,
            description: task.description,
            assigned_to: task.assigned_to,
            due_date: task.due_date ? moment(task.due_date).format('DD-MM-YYYY HH:mm') : '',
            priority: task.priority,
            status: task.status,
            category: task.category,
            created_at: moment(task.created_at).format('DD-MM-YYYY HH:mm'),
            created_by: task.created_by,
            completed_at: task.completed_at ? moment(task.completed_at).format('DD-MM-YYYY HH:mm') : '',
            completed_by_name: task.completed_by_name || ''
        });
    });
    
    await workbook.xlsx.writeFile(filepath);
}

async function generatePdfReport(data, filepath) {
    // Configuratie voor PDF document
    const fonts = {
        Roboto: {
            normal: 'Helvetica',
            bold: 'Helvetica-Bold',
            italics: 'Helvetica-Oblique',
            bolditalics: 'Helvetica-BoldOblique'
        }
    };
    
    const printer = new PdfPrinter(fonts);
    
    // Format data voor PDF
    const tableBody = [
        [
            { text: 'ID', style: 'tableHeader' },
            { text: 'Titel', style: 'tableHeader' },
            { text: 'Toegewezen aan', style: 'tableHeader' },
            { text: 'Deadline', style: 'tableHeader' },
            { text: 'Prioriteit', style: 'tableHeader' },
            { text: 'Status', style: 'tableHeader' }
        ]
    ];
    
    data.forEach(task => {
        tableBody.push([
            task.id.toString(),
            task.title,
            task.assigned_to || '',
            task.due_date ? moment(task.due_date).format('DD-MM-YYYY') : '',
            task.priority,
            task.status
        ]);
    });
    
    // Document definitie
    const docDefinition = {
        content: [
            { text: 'Taken Rapport', style: 'header' },
            { text: `Gegenereerd op: ${moment().format('DD-MM-YYYY HH:mm')}`, style: 'subheader' },
            {
                style: 'table',
                table: {
                    headerRows: 1,
                    widths: ['auto', '*', 'auto', 'auto', 'auto', 'auto'],
                    body: tableBody
                },
                layout: {
                    hLineWidth: function(i, node) { return 1; },
                    vLineWidth: function(i, node) { return 1; },
                    hLineColor: function(i, node) { return '#ddd'; },
                    vLineColor: function(i, node) { return '#ddd'; }
                }
            }
        ],
        styles: {
            header: {
                fontSize: 18,
                bold: true,
                margin: [0, 0, 0, 10]
            },
            subheader: {
                fontSize: 12,
                margin: [0, 0, 0, 20]
            },
            table: {
                margin: [0, 5, 0, 15]
            },
            tableHeader: {
                bold: true,
                fontSize: 12,
                color: 'black'
            }
        }
    };
    
    const pdfDoc = printer.createPdfKitDocument(docDefinition);
    const writeStream = fs.createWriteStream(filepath);
    pdfDoc.pipe(writeStream);
    pdfDoc.end();
    
    // Promise om te wachten tot het schrijven compleet is
    return new Promise((resolve, reject) => {
        writeStream.on('finish', resolve);
        writeStream.on('error', reject);
    });
}

// Socket.IO event handlers voor realtime communicatie
// Dit zou in een aparte module kunnen, maar hier toegevoegd voor volledigheid
function setupSocketHandlers(io) {
    io.on('connection', (socket) => {
        console.log('Nieuwe socket verbinding:', socket.id);
        
        // Authenticeer socket aan de hand van sessie
        const session = socket.request.session;
        if (session && session.user) {
            // Voeg gebruiker toe aan een eigen room voor gerichte berichten
            socket.join(`user:${session.user.id}`);
            console.log(`Gebruiker ${session.user.username} toegevoegd aan room user:${session.user.id}`);
        }
        
        // Event: bericht sturen
        socket.on('send_message', async (data) => {
            try {
                if (!session || !session.user) {
                    socket.emit('error', { message: 'Niet geauthenticeerd' });
                    return;
                }
                
                const { receiverId, message, fileUrl } = data;
                const senderId = session.user.id;
                
                // Bericht opslaan in database
                const [result] = await pool.query(`
                    INSERT INTO messages (sender_id, receiver_id, message, file_url, timestamp)
                    VALUES (?, ?, ?, ?, NOW())
                `, [senderId, receiverId, message || '', fileUrl || null]);
                
                const messageId = result.insertId;
                
                // Haal volledige bericht info op
                const [messages] = await pool.query(`
                    SELECT * FROM messages WHERE id = ?
                `, [messageId]);
                
                if (messages.length > 0) {
                    const newMessage = {
                        id: messages[0].id,
                        sender_id: messages[0].sender_id,
                        receiver_id: messages[0].receiver_id,
                        message: messages[0].message,
                        fileUrl: messages[0].file_url,
                        timestamp: messages[0].timestamp,
                        is_read: false
                    };
                    
                    // Stuur bericht naar afzender en ontvanger
                    socket.emit('message_sent', newMessage);
                    io.to(`user:${receiverId}`).emit('receive_message', newMessage);
                }
            } catch (error) {
                console.error('Error sending message:', error);
                socket.emit('error', { message: 'Er is een fout opgetreden bij het verzenden van het bericht' });
            }
        });
        
        // Event: taak bijgewerkt
        socket.on('task_updated', () => {
            // Broadcast naar alle clients dat taken zijn bijgewerkt
            socket.broadcast.emit('task_updated');
        });
        
        // Disconnecten
        socket.on('disconnect', () => {
            console.log('Socket verbinding verbroken:', socket.id);
        });
    });
}

app.post('/api/update_bodem_stock', (req, res) => {
  const { type, quantity, operation } = req.body;
  
  if (!type || (quantity === undefined) || !operation) {
    return res.status(400).json({ error: 'Alle velden zijn verplicht (type, quantity, operation)' });
  }
  
  let sql = '';
  if (operation === 'add') {
    sql = `
      INSERT INTO bodems_stock (bodem_type, quantity) 
      VALUES (?, ?)
      ON DUPLICATE KEY UPDATE quantity = quantity + ?
    `;
    db.query(sql, [type, quantity, quantity], (err, result) => {
      if (err) {
        console.error('Error updating bodem stock:', err);
        return res.status(500).json({ error: 'Database error bij bijwerken voorraad' });
      }
      res.json({ success: true, message: 'Voorraad bijgewerkt' });
    });
  } else if (operation === 'subtract') {
    sql = `
      UPDATE bodems_stock 
      SET quantity = GREATEST(0, quantity - ?) 
      WHERE bodem_type = ?
    `;
    db.query(sql, [quantity, type], (err, result) => {
      if (err) {
        console.error('Error updating bodem stock:', err);
        return res.status(500).json({ error: 'Database error bij bijwerken voorraad' });
      }
      res.json({ success: true, message: 'Voorraad bijgewerkt' });
    });
  } else if (operation === 'set') {
    sql = `
      INSERT INTO bodems_stock (bodem_type, quantity) 
      VALUES (?, ?)
      ON DUPLICATE KEY UPDATE quantity = ?
    `;
    db.query(sql, [type, quantity, quantity], (err, result) => {
      if (err) {
        console.error('Error setting bodem stock:', err);
        return res.status(500).json({ error: 'Database error bij instellen voorraad' });
      }
      res.json({ success: true, message: 'Voorraad ingesteld' });
    });
  } else {
    return res.status(400).json({ error: 'Ongeldige operatie. Gebruik "add", "subtract" of "set"' });
  }
});

