app.get('/api/bodems_bestellingen', (req, res) => {
    const sql = 'SELECT * FROM bodems_bestellingen ORDER BY besteldatum DESC';
    
    db.query(sql, (err, rows) => {
      if (err) {
        console.error('Error fetching bodems_bestellingen:', err);
        return res.status(500).json({ error: 'Database error', success: false });
      }
      res.json(rows);
    });
  });

  // API endpoint om een nieuwe bestelling toe te voegen
  app.post('/api/bodems_bestellingen', (req, res) => {
    const { vestiging, bodem_type, aantal, besteldatum, verwachte_leverdatum, opmerking } = req.body;
    
    if (!vestiging || !bodem_type || !aantal || !besteldatum) {
      return res.status(400).json({ error: 'Verplichte velden ontbreken', success: false });
    }
    
    const sql = `
      INSERT INTO bodems_bestellingen (
        vestiging, bodem_type, aantal, besteldatum, verwachte_leverdatum, opmerking
      ) VALUES (?, ?, ?, ?, ?, ?)
    `;
    
    db.query(sql, [vestiging, bodem_type, aantal, besteldatum, verwachte_leverdatum, opmerking], function(err, result) {
      if (err) {
        console.error('Error adding bodem bestelling:', err);
        return res.status(500).json({ error: 'Database error', success: false });
      }
      
      res.json({ 
        success: true, 
        message: 'Bestelling succesvol toegevoegd', 
        id: result.insertId 
      });
    });
  });

  // API endpoint om een bestelling bij te werken
  app.put('/api/bodems_bestellingen/:id', (req, res) => {
    const id = req.params.id;
    const { status, verwachte_leverdatum, opmerking } = req.body;
    
    if (!status) {
      return res.status(400).json({ error: 'Status is verplicht', success: false });
    }
    
    // Status onderweg is verwijderd, alleen besteld of ontvangen is toegestaan
    if (status !== 'besteld' && status !== 'ontvangen') {
      return res.status(400).json({ error: 'Ongeldige status. Gebruik "besteld" of "ontvangen"', success: false });
    }
    
    const sql = `
      UPDATE bodems_bestellingen 
      SET status = ?, verwachte_leverdatum = ?, opmerking = ?
      WHERE id = ?
    `;
    
    db.query(sql, [status, verwachte_leverdatum, opmerking, id], function(err, result) {
      if (err) {
        console.error('Error updating bodem bestelling:', err);
        return res.status(500).json({ error: 'Database error', success: false });
      }
      
      if (result.affectedRows === 0) {
        return res.status(404).json({ error: 'Bestelling niet gevonden', success: false });
      }
      
      res.json({ success: true, message: 'Bestelling succesvol bijgewerkt' });
    });
  });

  // API endpoint om een bestelling te verwijderen
  app.delete('/api/bodems_bestellingen/:id', (req, res) => {
    const id = req.params.id;
    
    const sql = 'DELETE FROM bodems_bestellingen WHERE id = ?';
    
    db.query(sql, [id], function(err, result) {
      if (err) {
        console.error('Error deleting bodem bestelling:', err);
        return res.status(500).json({ error: 'Database error', success: false });
      }
      
      if (result.affectedRows === 0) {
        return res.status(404).json({ error: 'Bestelling niet gevonden', success: false });
      }
      
      res.json({ success: true, message: 'Bestelling succesvol verwijderd' });
    });
  });

  // API endpoint om een bestelling (gedeeltelijk) als ontvangen te markeren
  app.post('/api/bodems_bestellingen/:id/ontvangen', (req, res) => {
    const id = req.params.id;
    // Optioneel aantal dat ontvangen is (standaard de gehele bestelling)
    const { aantal_ontvangen } = req.body;
    
    // Haal eerst de bestellingsinformatie op
    db.query('SELECT * FROM bodems_bestellingen WHERE id = ?', [id], (err, results) => {
      if (err) {
        console.error('Error fetching bestelling:', err);
        return res.status(500).json({ error: 'Database error', success: false });
      }
      
      if (!results || results.length === 0) {
        return res.status(404).json({ error: 'Bestelling niet gevonden', success: false });
      }
      
      const bestelling = results[0];
      
      // Als bestelling al volledig ontvangen is
      if (bestelling.status === 'ontvangen' && bestelling.aantal <= 0) {
        return res.status(400).json({ 
          error: 'Bestelling is al volledig ontvangen', 
          success: false 
        });
      }
      
      // Bepaal het aantal dat wordt ontvangen
      let aantalTeOntvangen = aantal_ontvangen ? parseInt(aantal_ontvangen) : bestelling.aantal;
      
      // Controleer of het aantal te ontvangen geldig is
      if (aantalTeOntvangen <= 0) {
        return res.status(400).json({ 
          error: 'Aantal te ontvangen moet groter zijn dan 0', 
          success: false 
        });
      }
      
      // Zorg dat we niet meer ontvangen dan besteld
      if (aantalTeOntvangen > bestelling.aantal) {
        aantalTeOntvangen = bestelling.aantal;
      }
      
      // Bereken het resterende aantal na deze ontvangst
      const resterendAantal = bestelling.aantal - aantalTeOntvangen;
      
      // Start een transactie
      db.beginTransaction(function(err) {
        if (err) {
          console.error('Transaction error:', err);
          return res.status(500).json({ error: 'Database error', success: false });
        }
        
        // Update de bestelling
        const updateSql = resterendAantal <= 0 
          ? 'UPDATE bodems_bestellingen SET status = ?, aantal = 0 WHERE id = ?' 
          : 'UPDATE bodems_bestellingen SET aantal = ? WHERE id = ?';
        
        const updateParams = resterendAantal <= 0 
          ? ['ontvangen', id] 
          : [resterendAantal, id];
        
        db.query(updateSql, updateParams, (err, result) => {
          if (err) {
            return db.rollback(function() {
              console.error('Update bestelling error:', err);
              res.status(500).json({ error: 'Database error', success: false });
            });
          }
          
          // Verhoog de voorraad met het ontvangen aantal
          db.query(
            'UPDATE bodems_stock SET quantity = quantity + ? WHERE bodem_type = ?',
            [aantalTeOntvangen, bestelling.bodem_type],
            (err, result) => {
              if (err) {
                return db.rollback(function() {
                  console.error('Update stock error:', err);
                  res.status(500).json({ error: 'Database error', success: false });
                });
              }
              
              db.commit(function(err) {
                if (err) {
                  return db.rollback(function() {
                    console.error('Commit error:', err);
                    res.status(500).json({ error: 'Database error', success: false });
                  });
                }
                
                const message = resterendAantal <= 0 
                  ? 'Bestelling volledig ontvangen en voorraad bijgewerkt' 
                  : `${aantalTeOntvangen} bodems ontvangen, ${resterendAantal} resterend. Voorraad bijgewerkt.`;
                
                res.json({ 
                  success: true, 
                  message: message,
                  aantal_ontvangen: aantalTeOntvangen,
                  resterend_aantal: resterendAantal });
                });
              }
            );
          }
        );
      });
    });
  });

