  // API endpoint om meerdere forecast items in één keer toe te voegen (bulk import)
  app.post('/api/klantforecast/bulk', (req, res) => {
    const { items } = req.body;
    
    if (!items || !Array.isArray(items) || items.length === 0) {
      return res.status(400).json({ error: 'Geen geldige items aangeleverd', success: false });
    }
    
    // Begin een transactie
    db.beginTransaction(function(err) {
      if (err) {
        console.error('Transaction error:', err);
        return res.status(500).json({ error: 'Database error', success: false });
      }
      
      const sql = `
        INSERT INTO klantforecast (
          omschrijving, artikelnummer, klant_artikelnummer, hoeveelheid, leverdatum
        ) VALUES ?
      `;
      
      // Bereid de waarden voor
      const values = items.map(item => [
        item.omschrijving, 
        item.artikelnummer, 
        item.klant_artikelnummer || null, 
        item.hoeveelheid, 
        item.leverdatum
      ]);
      
      db.query(sql, [values], function(err, result) {
        if (err) {
          return db.rollback(function() {
            console.error('Error adding bulk klantforecast items:', err);
            res.status(500).json({ error: 'Database error', success: false });
          });
        }
        
        db.commit(function(err) {
          if (err) {
            return db.rollback(function() {
              console.error('Commit error:', err);
              res.status(500).json({ error: 'Database error', success: false });
            });
          }
          
          res.json({ 
            success: true, 
            message: `${items.length} forecast items succesvol toegevoegd`,
            count: items.length
          });
        });
      });
    });
  });

