// Zorg dat 'db' hier verwijst naar je 'mysql' connection object
// Zorg dat 'isAuthenticated' correct is gedefinieerd

/**
 * @endpoint POST /api/aanmelden_pakket
 * @description Maakt een record aan in 'hout_ontvangen' met correcte kolomnamen (incl. opmerkingen).
 *              Update ook 'openstaande_bestellingen'.
 * @requires isAuthenticated
 */
/**
 * @endpoint POST /api/aanmelden_pakket
 * @description Maakt een record aan in 'hout_ontvangen' (callbacks met extra logging).
 *              Update ook 'openstaande_bestellingen'.
 * @requires isAuthenticated
 */
/**
 * @endpoint POST /api/aanmelden_pakket
 * @description Maakt een record aan in 'hout_ontvangen'.
 *              Update ook de teller in de 'bestellingen' tabel (aangepaste tabelnaam).
 * @requires isAuthenticated
 */
app.post('/api/aanmelden_pakket', isAuthenticated, (req, res) => {
    const endpointStartTime = Date.now();
    console.log(`>>> /api/aanmelden_pakket CALLED at ${new Date().toISOString()} with body:`, JSON.stringify(req.body, null, 2));

    const {
        bestelling_id, pakketnummer, houtsoort,
        exacte_dikte: reqDikte, exacte_breedte: reqBreedte, exacte_lengte: reqLengte,
        planken_per_pak, opmerking: reqOpmerking
    } = req.body;

    // Validatie (zoals voorheen)
    if (!bestelling_id || !pakketnummer || !houtsoort || reqDikte == null || reqBreedte == null || reqLengte == null || planken_per_pak == null) { /* ... */ }
    if (isNaN(parseFloat(reqDikte)) || isNaN(parseFloat(reqBreedte)) || isNaN(parseInt(reqLengte)) || isNaN(parseInt(planken_per_pak))) { /* ... */ }
    console.log("[Validation PASSED]");

    // Start Transaction
    console.log("[Step 1] Attempting to begin transaction...");
    db.beginTransaction(err => {
        if (err) { /* ... (foutafhandeling) ... */ }
        console.log("[Step 1 SUCCESS] Transaction started.");

        // 1. Controleer of pakketnummer al bestaat
        const checkSql = 'SELECT id FROM hout_ontvangen WHERE pakketnummer = ?';
        console.log(`[Step 2] Checking for existing pakketnummer: ${pakketnummer}`);
        db.query(checkSql, [pakketnummer], (err, results) => {
            if (err) { /* ... (rollback en foutafhandeling) ... */ }
            if (results && results.length > 0) { /* ... (rollback en 409 response) ... */ }
            console.log("[Step 2 Result] Pakketnummer does not exist, proceeding.");

            // 2. Voeg toe aan hout_ontvangen
            console.log("[Step 3] Inserting into hout_ontvangen...");
            const insertSql = `
                INSERT INTO hout_ontvangen
                (bestelling_id, pakketnummer, houtsoort, dikte, breedte, lengte, planken_per_pak, opmerkingen, status, aangemeld_op)
                VALUES (?, ?, ?, ?, ?, ?, ?, ?, 'klaar_voor_locatie', NOW())
            `;
            const insertValues = [ bestelling_id, pakketnummer, houtsoort, parseFloat(reqDikte), parseFloat(reqBreedte), parseInt(reqLengte, 10), parseInt(planken_per_pak, 10), reqOpmerking || null ];
            db.query(insertSql, insertValues, (err, insertResult) => {
                if (err) { /* ... (rollback en foutafhandeling) ... */ }
                if (!insertResult || typeof insertResult.insertId === 'undefined') { /* ... (rollback en foutafhandeling) ... */ }
                const newHoutOntvangenId = insertResult.insertId;
                console.log(`[Step 3 SUCCESS] Inserted into hout_ontvangen with ID: ${newHoutOntvangenId}`);

                // --- Stap 3: Werk de correcte bestellingentabel bij ---
                // GEBRUIK HIER DE JUISTE TABELNAAM (waarschijnlijk 'bestellingen')
                const updateSql = `UPDATE bestellingen SET ontvangen_pakken = ontvangen_pakken + 1 WHERE id = ?`;
                console.log(`[Step 4] Updating 'bestellingen' for ID: ${bestelling_id}`); // Log correcte tabelnaam
                db.query(updateSql, [bestelling_id], (err, updateResult) => {
                    if (err) {
                        console.error("[Step 4 FAILED] Error updating 'bestellingen':", err); // Log correcte tabelnaam
                        // Check specifiek voor 'table doesn't exist' error
                         if (err.code === 'ER_NO_SUCH_TABLE') {
                             console.error("FATAL: Tabel 'bestellingen' bestaat niet! Controleer de tabelnaam in de code.");
                         }
                        return db.rollback(() => {
                            console.log("[Step 4 Rollback] Transaction rolled back due to update error.");
                            res.status(500).json({ success: false, message: `Databasefout bij bijwerken bestelling (tabel: bestellingen).`, error: err.message });
                        });
                    }
                    console.log("[Step 4 SUCCESS] Update query executed for 'bestellingen'.");

                    if (updateResult.affectedRows === 0) {
                        console.warn(`[Step 4 Warning] Bestelling ID ${bestelling_id} niet gevonden in 'bestellingen' bij bijwerken 'ontvangen_pakken'.`);
                    } else {
                        console.log("[Step 4 Result] 'bestellingen' updated.");
                    }

                    // --- Stap 4: Commit Transaction ---
                    console.log("[Step 5] Committing transaction...");
                    db.commit(err => {
                        if (err) { /* ... (rollback en foutafhandeling) ... */ }
                        const duration = Date.now() - endpointStartTime;
                        console.log(`[Step 5 SUCCESS] Transaction committed successfully. Duration: ${duration}ms`);
                        res.status(201).json({ success: true, message: 'Pakket succesvol aangemeld in hout_ontvangen.', houtOntvangenId: newHoutOntvangenId });
                    }); // Einde commit callback
                }); // Einde update callback
            }); // Einde insert callback
        }); // Einde check callback
    }); // Einde beginTransaction callback
});

