// Update de code voor auto_order_suggestions/process route

app.post('/api/auto_order_suggestions/process', (req, res) => {
    console.log('Request body:', req.body);
    const { suggestions, action } = req.body;
    
    if (!suggestions || !Array.isArray(suggestions) || suggestions.length === 0) {
        return res.status(400).json({ error: 'Geen geldige voorstellen opgegeven' });
    }

    if (action !== 'bestellen' && action !== 'weigeren') {
        return res.status(400).json({ error: 'Ongeldige actie' });
    }

    const status = action === 'bestellen' ? 'besteld' : 'geweigerd';
    
    // Zorg ervoor dat we alleen geldige IDs hebben (voorkomt problemen met lege waarden)
    const ids = suggestions.map(s => s.id).filter(id => id);
    
    if (ids.length === 0) {
        return res.status(400).json({ error: 'Geen geldige ID\'s opgegeven' });
    }
    
    console.log('Processing IDs:', ids);
    
    // FIX: IN-query met een array in MySQL heeft een speciaal formaat nodig
    // We maken een query met het juiste aantal placeholders voor onze ids
    const placeholders = ids.map(() => '?').join(',');
    const updateQuery = `UPDATE auto_order_suggestions SET status = ? WHERE id IN (${placeholders})`;
    
    // De eerste parameter is nog steeds de status, gevolgd door alle ids
    const updateParams = [status, ...ids];
    
    // Update de status van de voorstellen
    db.query(updateQuery, updateParams, (err, updateResult) => {
        if (err) {
            console.error('Error updating suggestions:', err);
            return res.status(500).json({ error: 'Database error: ' + err.message });
        }

        console.log('Update result:', updateResult);

        // Als bestellen, voeg ze toe aan openstaande_bestellingen
        if (action === 'bestellen') {
            // Begin een transactie
            db.beginTransaction(err => {
                if (err) {
                    console.error('Error starting transaction:', err);
                    return res.status(500).json({ error: 'Database error: ' + err.message });
                }

                // Haal de volledige gegevens op van de voorstellen
                // FIX: IN-query met zelfde structuur als hierboven
                const selectQuery = `SELECT * FROM auto_order_suggestions WHERE id IN (${placeholders})`;
                db.query(selectQuery, ids, (err, suggestionRows) => {
                    if (err) {
                        return db.rollback(() => {
                            console.error('Error fetching suggestions:', err);
                            res.status(500).json({ error: 'Database error: ' + err.message });
                        });
                    }

                    console.log('Found suggestion rows:', suggestionRows.length);
                    
                    if (suggestionRows.length === 0) {
                        return db.rollback(() => {
                            console.error('No suggestions found with the given IDs');
                            res.status(404).json({ error: 'Geen voorstellen gevonden met de opgegeven ID\'s' });
                        });
                    }

                    // Batch insert in openstaande_bestellingen
                    // Belangrijk: de bestellingen zijn PER PAK, niet per individuele plank/plaat
                    const insertValues = suggestionRows.map(s => [
                        s.soort,
                        s.dikte,
                        s.breedte,
                        s.lengte,
                        s.aantal,  // De aantal waarde is al in pakken
                        'Auto-order: ' + s.reden + ' (besteld in pakken)',
                        0  // priority
                    ]);

                    console.log('Insert values:', insertValues);

                    if (insertValues.length > 0) {
                        db.query(
                            `INSERT INTO openstaande_bestellingen 
                             (houtsoort, dikte, breedte, lengte, aantal, opmerking, priority)
                             VALUES ?`,
                            [insertValues],
                            (err, insertResult) => {
                                if (err) {
                                    return db.rollback(() => {
                                        console.error('Error inserting orders:', err);
                                        res.status(500).json({ error: 'Database error: ' + err.message });
                                    });
                                }

                                console.log('Insert result:', insertResult);

                                // Commit de transactie
                                db.commit(err => {
                                    if (err) {
                                        return db.rollback(() => {
                                            console.error('Error committing transaction:', err);
                                            res.status(500).json({ error: 'Database error: ' + err.message });
                                        });
                                    }

                                    res.json({
                                        success: true,
                                        message: `${insertValues.length} bestellingen toegevoegd`,
                                        ordersAdded: insertValues.length
                                    });
                                });
                            }
                        );
                    } else {
                        db.commit(err => {
                            if (err) {
                                return db.rollback(() => {
                                    console.error('Error committing transaction:', err);
                                    res.status(500).json({ error: 'Database error: ' + err.message });
                                });
                            }
                            res.json({ success: true, message: 'Geen bestellingen om toe te voegen' });
                        });
                    }
                });
            });
        } else {
            // Als weigeren, stuur direct een respons
            res.json({
                success: true,
                message: `${updateResult.affectedRows} voorstellen geweigerd`
            });
        }
    });
});

// 3. Run de auto-order analyse
app.post('/api/run_auto_order', (req, res) => {
    // Haal actuele voorraad en minimum niveaus op
    Promise.all([
        // 1. Haal huidige voorraad op
        new Promise((resolve, reject) => {
            db.query('SELECT * FROM hout_stock', (err, results) => {
                if (err) return reject(err);
                resolve(results);
            });
        }),
        
        // 2. Haal minimale voorraadniveaus op
        new Promise((resolve, reject) => {
            db.query('SELECT * FROM hout_min_stock', (err, results) => {
                if (err) return reject(err);
                resolve(results);
            });
        }),
        
        // 3. Haal materiaalgebruik-historiek op
        new Promise((resolve, reject) => {
            // De laatste 30 dagen aan verbruik ophalen
            const daysBack = 30;
            const query = `
                SELECT soort, dikte, breedte, SUM(aantal) as total_used
                FROM wood_consumption
                WHERE date_consumed >= DATE_SUB(CURDATE(), INTERVAL ? DAY)
                GROUP BY soort, dikte, breedte
            `;
            db.query(query, [daysBack], (err, results) => {
                if (err) return reject(err);
                resolve(results);
            });
        })
    ])
    .then(([stockData, minStockLevels, consumptionData]) => {
        // Verwerk de gegevens om auto-order voorstellen te maken
        const suggestions = [];
        
        // Controleer voorraad tegen minimum niveaus
        minStockLevels.forEach(minLevel => {
            // Zoek huidige voorraad voor dit materiaal
            const currentStock = stockData.filter(item => 
                item.soort.toLowerCase() === minLevel.soort.toLowerCase() &&
                (!minLevel.dikte || item.dikte === minLevel.dikte) &&
                (!minLevel.breedte || item.breedte === minLevel.breedte) &&
                // Check ook minimale lengte als die is ingesteld
                (!minLevel.min_lengte || item.lengte >= minLevel.min_lengte)
            );
            
            // Bereken totale voorraad
            const totalStock = currentStock.reduce((sum, item) => sum + item.aantal, 0);
            
            // Als onder minimum, maak een suggestie
            if (totalStock < minLevel.min_aantal) {
                // Bereken benodigde hoeveelheid
                const shortage = minLevel.min_aantal - totalStock;
                
                // Zoek gemiddeld verbruik
                const consumption = consumptionData.find(item => 
                    item.soort.toLowerCase() === minLevel.soort.toLowerCase() &&
                    (!minLevel.dikte || item.dikte === minLevel.dikte) &&
                    (!minLevel.breedte || item.breedte === minLevel.breedte)
                );
                
                // Bepaal bestelhoeveelheid (standaard 2 pakketten van 50 of gebaseerd op verbruik)
                let orderAmount = 100; // Standaard 2 pakketten van 50
                
                if (consumption) {
                    // Bereken dagelijks verbruik
                    const dailyUsage = consumption.total_used / 30;
                    // Bestel voor 2 weken voorraad
                    const suggestedAmount = Math.ceil(dailyUsage * 14);
                    // Minimum 50, maximum 500
                    orderAmount = Math.max(50, Math.min(500, suggestedAmount));
                }
                
                // Bepaal lengte om te bestellen:
                // Als er een min_lengte is, gebruik dan die lengte
                // Anders gebruik de meest voorkomende lengte in voorraad
                let orderLength = minLevel.min_lengte || 0;
                
                if (!orderLength && currentStock.length > 0) {
                    const lengthCounts = {};
                    currentStock.forEach(item => {
                        lengthCounts[item.lengte] = (lengthCounts[item.lengte] || 0) + 1;
                    });
                    
                    // Vind de lengte die het meest voorkomt
                    let maxCount = 0;
                    for (const [length, count] of Object.entries(lengthCounts)) {
                        if (count > maxCount) {
                            maxCount = count;
                            orderLength = parseInt(length);
                        }
                    }
                }
                
                // Als nog steeds geen lengte, gebruik standaard (bijv. 3000mm)
                if (!orderLength) {
                    orderLength = 3000;
                }
                
                suggestions.push({
                    soort: minLevel.soort,
                    dikte: minLevel.dikte,
                    breedte: minLevel.breedte,
                    lengte: orderLength,
                    aantal: orderAmount,
                    reden: `Voorraad (${totalStock}) onder minimum (${minLevel.min_aantal})` + 
                            (minLevel.min_lengte ? `, minimale lengte: ${minLevel.min_lengte}mm` : ''),
                    priority: 1
                });
            }
        });
        
        // Sla de voorstellen op in de database
        if (suggestions.length > 0) {
            // Batch insert met alle voorgestelde bestellingen
            const insertValues = suggestions.map(s => [
                s.soort, s.dikte, s.breedte, s.lengte, s.aantal, s.reden, s.priority
            ]);
            
            db.query(
                `INSERT INTO auto_order_suggestions 
                    (soort, dikte, breedte, lengte, aantal, reden, priority)
                    VALUES ?`,
                [insertValues],
                (err, result) => {
                    if (err) {
                        console.error('Error inserting suggestions:', err);
                        return res.status(500).json({ error: 'Database error' });
                    }
                    
                    res.json({
                        success: true,
                        message: `${result.affectedRows} auto-order voorstellen gegenereerd`,
                        suggestions: suggestions
                    });
                }
            );
        } else {
            res.json({
                success: true,
                message: 'Geen auto-order voorstellen nodig op dit moment',
                suggestions: []
            });
        }
    })
    .catch(err => {
        console.error('Error in auto-order analysis:', err);
        res.status(500).json({ error: 'Er is een fout opgetreden bij de analyse' });
    });
});

