// Update alle kisttellers in bulk
app.post('/api/update_completed_kisten', (req, res) => {
  const { completedKisten } = req.body;
  
  if (!completedKisten || typeof completedKisten !== 'object') {
    return res.json({ success: false, error: 'Geen geldige kistdata ontvangen' });
  }
  
  // Bouw een reeks queries op voor een transactie
  const queries = [];
  const values = [];
  
  Object.entries(completedKisten).forEach(([kistnummer, completed]) => {
    queries.push(`REPLACE INTO kist_counters (kistnummer, completed) VALUES (?, ?)`);
    values.push(kistnummer, completed);
  });
  
  if (queries.length === 0) {
    return res.json({ success: true, message: 'Geen updates om uit te voeren' });
  }
  
  // Start een transactie voor alle updates
  db.beginTransaction(err => {
    if (err) {
      console.error('Fout bij starten transactie:', err);
      return res.json({ success: false, error: err.message });
    }
    
    // Voer elke query uit binnen de transactie
    const executeQueries = (index) => {
      if (index >= queries.length) {
        // Alle queries uitgevoerd, commit de transactie
        db.commit(err => {
          if (err) {
            console.error('Fout bij commit transactie:', err);
            db.rollback(() => {});
            return res.json({ success: false, error: err.message });
          }
          return res.json({ success: true, message: 'Alle kisten bijgewerkt' });
        });
        return;
      }
      
      const queryValues = [values[index * 2], values[index * 2 + 1]];
      db.query(queries[index], queryValues, (err) => {
        if (err) {
          console.error('Fout bij uitvoeren query:', err);
          db.rollback(() => {});
          return res.json({ success: false, error: err.message });
        }
        executeQueries(index + 1);
      });
    };
    
    executeQueries(0);
  });
});

