// Maak een nieuwe kist aan
app.post('/api/cases', (req, res) => {
  const { caseLabel, caseType, originalCaseType, serialNumber, currentLocation, status, notes } = req.body;
  
  // Validatie
  if (!caseLabel || !caseType) {
    return res.status(400).json({ error: 'Kist label en type zijn verplicht' });
  }
  
  // Controleer of label al bestaat
  db.query('SELECT id FROM case_labels WHERE caseLabel = ?', [caseLabel], (err, results) => {
    if (err) {
      console.error('Database error bij controleren label:', err);
      return res.status(500).json({ error: 'Database error: ' + err.message });
    }
    
    if (results.length > 0) {
      return res.status(400).json({ error: 'Een kist met dit label bestaat al' });
    }
    
    // Kist toevoegen
    const query = `
      INSERT INTO case_labels 
      (caseLabel, caseType, originalCaseType, serialNumber, currentLocation, status, importDate, notes) 
      VALUES (?, ?, ?, ?, ?, ?, NOW(), ?)
    `;
    
    const values = [
      caseLabel,
      caseType,
      originalCaseType || caseType,
      serialNumber || null,
      currentLocation || 'Onbekend',
      status || 'Beschikbaar',
      notes || null
    ];
    
    db.query(query, values, (err, result) => {
      if (err) {
        console.error('Database error bij toevoegen kist:', err);
        return res.status(500).json({ error: 'Database error: ' + err.message });
      }
      
      res.status(201).json({
        success: true,
        id: result.insertId,
        message: 'Kist succesvol toegevoegd'
      });
    });
  });
});

// Update een bestaande kist
app.put('/api/cases/:id', (req, res) => {
  const { id } = req.params;
  const { caseLabel, caseType, originalCaseType, serialNumber, currentLocation, status, notes } = req.body;
  
  // Validatie
  if (!caseLabel || !caseType) {
    return res.status(400).json({ error: 'Kist label en type zijn verplicht' });
  }
  
  // Controleer of deze kist bestaat
  db.query('SELECT id FROM case_labels WHERE id = ?', [id], (err, results) => {
    if (err) {
      console.error('Database error bij controleren kist:', err);
      return res.status(500).json({ error: 'Database error: ' + err.message });
    }
    
    if (results.length === 0) {
      return res.status(404).json({ error: 'Kist niet gevonden' });
    }
    
    // Controleer of het nieuwe label al bestaat (bij een andere kist)
    db.query('SELECT id FROM case_labels WHERE caseLabel = ? AND id != ?', [caseLabel, id], (err, results) => {
      if (err) {
        console.error('Database error bij controleren label:', err);
        return res.status(500).json({ error: 'Database error: ' + err.message });
      }
      
      if (results.length > 0) {
        return res.status(400).json({ error: 'Een andere kist met dit label bestaat al' });
      }
      
      // Update kist
      const query = `
        UPDATE case_labels 
        SET 
          caseLabel = ?,
          caseType = ?,
          originalCaseType = ?,
          serialNumber = ?,
          currentLocation = ?,
          status = ?,
          notes = ?,
          lastUpdated = NOW()
        WHERE id = ?
      `;
      
      const values = [
        caseLabel,
        caseType,
        originalCaseType || caseType,
        serialNumber || null,
        currentLocation || 'Onbekend',
        status || 'Beschikbaar',
        notes || null,
        id
      ];
      
      db.query(query, values, (err, result) => {
        if (err) {
          console.error('Database error bij bijwerken kist:', err);
          return res.status(500).json({ error: 'Database error: ' + err.message });
        }
        
        res.json({
          success: true,
          id: id,
          message: 'Kist succesvol bijgewerkt'
        });
      });
    });
  });
});

