app.post('/api/cases/import', (req, res) => {
  const { cases } = req.body;
  
  if (!cases || !Array.isArray(cases) || cases.length === 0) {
    return res.status(400).json({ error: 'Geen geldige kisten data ontvangen' });
  }
  
  console.log('Ontvangen cases voor import (eerste item):', cases[0]);
  console.log('AANGEPASTE IMPORT: Alleen nieuwe kisten worden toegevoegd, bestaande blijven ongewijzigd.');
  
  // Begin een transactie
  db.beginTransaction(err => {
    if (err) {
      console.error('Fout bij starten transactie:', err);
      return res.status(500).json({ error: 'Database error: ' + err.message });
    }
    
    const importedIds = [];
    const skippedCount = 0; // Bijhouden hoeveel we overslaan
    
    // Verwerk elke kist
    const processNextCase = (index, skippedCount) => {
      if (index >= cases.length) {
        // Alle kisten verwerkt, commit transactie
        db.commit(err => {
          if (err) {
            console.error('Fout bij commit van transactie:', err);
            db.rollback(() => {});
            return res.status(500).json({ error: 'Database error bij commit: ' + err.message });
          }
          
          res.json({
            success: true,
            imported: importedIds.length,
            skipped: skippedCount,
            total: cases.length
          });
        });
        return;
      }
      
      const caseData = cases[index];
      
      // Basisvalidatie
      if (!caseData.caseLabel || !caseData.caseType) {
        processNextCase(index + 1, skippedCount);
        return;
      }
      
      // Controleer of kist al bestaat
      db.query('SELECT * FROM case_labels WHERE caseLabel = ?', [caseData.caseLabel], (err, results) => {
        if (err) {
          db.rollback(() => {});
          console.error('Database error bij CSV import:', err);
          return res.status(500).json({ error: 'Database error: ' + err.message });
        }
        
        // Als kist al bestaat, sla deze over (niet meer bijwerken)
        if (results.length > 0) {
          console.log(`Kist ${caseData.caseLabel} bestaat al, wordt NIET bijgewerkt.`);
          // Ga naar volgende kist zonder deze te wijzigen
          processNextCase(index + 1, skippedCount + 1);
        } else {
          // Nieuwe kist toevoegen
          const query = `
            INSERT INTO case_labels 
            (caseLabel, caseType, originalCaseType, serialNumber, currentLocation, status, packingNumber, importDate, lastUpdated, notes) 
            VALUES (?, ?, ?, ?, ?, ?, ?, ?, NOW(), ?)
          `;
          
          // Converteer importDate naar MySQL datetime formaat of gebruik huidige datum als fallback
          let importDateFormatted = null;
          
          if (caseData.importDate) {
            // Voor nieuwe records gebruiken we de datum uit kolom H van de CSV
            try {
              importDateFormatted = caseData.importDate.replace('T', ' ').substring(0, 19);
              console.log(`Nieuwe kist ${caseData.caseLabel}: Importdatum geformatteerd: ${importDateFormatted}`);
            } catch (e) {
              console.error(`Fout bij formatteren importDate voor kist ${caseData.caseLabel}:`, e);
              importDateFormatted = new Date().toISOString().slice(0, 19).replace('T', ' ');
            }
          } else {
            // Fallback
            importDateFormatted = new Date().toISOString().slice(0, 19).replace('T', ' ');
          }
          
          const values = [
            caseData.caseLabel,
            caseData.caseType,
            caseData.originalCaseType || caseData.caseType,
            caseData.serialNumber || null,
            caseData.currentLocation || 'Onbekend',
            caseData.status || 'Beschikbaar',
            caseData.packingNumber || null,
            importDateFormatted,
            caseData.notes || null
          ];
          
          db.query(query, values, (err, result) => {
            if (err) {
              db.rollback(() => {});
              console.error('Database error bij toevoegen kist in CSV import:', err);
              return res.status(500).json({ error: 'Database error: ' + err.message });
            }
            
            importedIds.push(result.insertId);
            processNextCase(index + 1, skippedCount);
          });
        }
      });
    };
    
    // Start het verwerken van de kisten
    processNextCase(0, 0);
  });
});



