app.post('/api/oilfree/stock/add', async (req, res) => {
    // Haal case_type op uit de body
    const { location, erp_code, case_type, quantity, production_location } = req.body; 

    // Validatie blijft grotendeels hetzelfde (case_type mag null zijn)
    if (!location || !erp_code || isNaN(quantity) || quantity < 0) {
        return res.status(400).json({ success: false, message: 'Locatie, ERP code en geldige hoeveelheid zijn verplicht' });
    }

    try {
        // Voeg case_type toe aan INSERT
        const sql = `
            INSERT INTO stock_oilfree (location, erp_code, case_type, quantity, production_location)
            VALUES (?, ?, ?, ?, ?)
            ON DUPLICATE KEY UPDATE 
                case_type = VALUES(case_type), 
                quantity = quantity + VALUES(quantity),
                production_location = VALUES(production_location) 
                /* Let op: ON DUPLICATE KEY UPDATE werkt alleen goed als (location, erp_code) een UNIQUE index is */
                /* Als je wilt overschrijven ipv optellen bij duplicaat: quantity = VALUES(quantity) */
        `;
        // Geef case_type mee als parameter
        await db.query(sql, [location, erp_code, case_type, quantity, production_location]); 
        res.json({ success: true });
    } catch (error) {
        console.error('Error adding oilfree stock:', error);
        res.status(500).json({ success: false, error: 'Database error', message: error.message });
    }
});




app.post('/api/oilfree/stock/update', async (req, res) => {
    const { old_location, old_erp_code, new_data } = req.body;
    // ... (validatie) ...
    const { location, erp_code, case_type, quantity, production_location } = new_data; 
    // ... (validatie) ...

    try {
        // Stap 1: Voer DELETE uit (met callback -> promise)
        const deleteSql = `DELETE FROM stock_oilfree WHERE location = ? AND erp_code = ?`;
        console.log('[POST /update] Uitvoeren delete (db.query):', deleteSql);
        await new Promise((resolve, reject) => {
            db.query(deleteSql, [old_location, old_erp_code], (err, result) => {
                if (err) {
                     console.error('[POST /update] Fout in delete db.query callback:', err);
                     return reject(err);
                 }
                console.log('[POST /update] Delete voltooid.');
                resolve(result);
            });
        });

        // Stap 2: Voer INSERT uit (met callback -> promise)
        const insertSql = `INSERT INTO stock_oilfree (location, erp_code, case_type, quantity, production_location, last_updated) VALUES (?, ?, ?, ?, ?, CURRENT_TIMESTAMP)`;
        console.log('[POST /update] Uitvoeren insert (db.query):', insertSql);
        await new Promise((resolve, reject) => {
            db.query(insertSql, [location, erp_code, case_type, quantity, production_location], (err, result) => {
                 if (err) {
                     console.error('[POST /update] Fout in insert db.query callback:', err);
                     return reject(err);
                 }
                console.log('[POST /update] Insert voltooid.');
                resolve(result);
            });
        });
        
        console.log('[POST /update] Update (delete+insert) voltooid.');
        res.json({ success: true });

    } catch (error) {
        console.error('[POST /update] FOUT tijdens update (delete+insert):', error);
        if (!res.headersSent) {
            res.status(500).json({ success: false, error: 'Database error tijdens update', message: error.message });
        }
    } 
});




