// POST nieuwe foto's voor een kist
// POST nieuwe foto's voor een kist
app.post('/api/cases/:id/photos', upload.array('photos', 5), (req, res) => {
    const { id } = req.params;
    const files = req.files;
    
    if (!files || files.length === 0) {
      return res.status(400).json({ error: 'Geen bestanden ontvangen' });
    }
    
    // Controleer of de kist bestaat
    db.query('SELECT * FROM case_labels WHERE id = ?', [id], (err, results) => {
      if (err) {
        console.error('Database error:', err);
        return res.status(500).json({ error: 'Database error: ' + err.message });
      }
      
      if (results.length === 0) {
        return res.status(404).json({ error: 'Kist niet gevonden' });
      }
      
      // Zorg dat de directory bestaat
      try {
        if (!fs.existsSync('/home/prodwilr/website/uploads/case-photos')) {
          fs.mkdirSync('/home/prodwilr/website/uploads/case-photos', { recursive: true });
        }
      } catch (error) {
        console.error('Error creating directory:', error);
        return res.status(500).json({ error: 'Fout bij maken directory: ' + error.message });
      }
      
      const insertedPhotos = [];
      let filesProcessed = 0;
      
      // Begin transactie
      db.beginTransaction(err => {
        if (err) {
          console.error('Transaction error:', err);
          return res.status(500).json({ error: 'Database error: ' + err.message });
        }
        
        files.forEach(file => {
          // Gebruik originele bestandsnaam met timestamp
          const newFilename = Date.now() + '-' + file.originalname;
          const newPath = '/home/prodwilr/website/uploads/case-photos/' + newFilename;
          
          try {
            // Kopieer bestand naar nieuwe locatie
            fs.copyFileSync(file.path, newPath);
            fs.unlinkSync(file.path); // Verwijder tijdelijk bestand
          } catch (error) {
            console.error('File operation error:', error);
            db.rollback(() => {});
            return res.status(500).json({ error: 'Bestandsoperatie mislukt: ' + error.message });
          }
          
          // Voeg record toe aan database
          db.query(
            'INSERT INTO case_photos (case_id, filename, original_filename, filepath, uploaded_at) VALUES (?, ?, ?, ?, NOW())',
            [id, newFilename, file.originalname, newPath],
            (err, result) => {
              if (err) {
                console.error('DB insert error:', err);
                db.rollback(() => {});
                return res.status(500).json({ error: 'Fout bij opslaan foto: ' + err.message });
              }
              
              insertedPhotos.push({
                id: result.insertId,
                url: `/uploads/case-photos/${newFilename}`,
                originalName: file.originalname
              });
              
              filesProcessed++;
              
              if (filesProcessed === files.length) {
                db.commit(err => {
                  if (err) {
                    db.rollback(() => {});
                    return res.status(500).json({ error: 'Fout bij commit: ' + err.message });
                  }
                  
                  res.status(201).json({
                    message: `${files.length} foto('s) succesvol geupload`,
                    photos: insertedPhotos
                  });
                });
              }
            }
          );
        });
      });
    });
  });

// DELETE een foto
app.delete('/api/cases/:id/photos/:photoId', (req, res) => {
  const { id, photoId } = req.params;
  
  // Haal eerst de bestandsgegevens op
  db.query('SELECT * FROM case_photos WHERE id = ? AND case_id = ?', [photoId, id], (err, results) => {
    if (err) {
      return res.status(500).json({ error: 'Database error: ' + err.message });
    }
    
    if (results.length === 0) {
      return res.status(404).json({ error: 'Foto niet gevonden' });
    }
    
    const photo = results[0];
    
    // Verwijder de database record
    db.query('DELETE FROM case_photos WHERE id = ?', [photoId], (err) => {
      if (err) {
        return res.status(500).json({ error: 'Fout bij verwijderen foto: ' + err.message });
      }
      
      // Verwijder ook het bestand
      fs.unlink(photo.filepath, (err) => {
        if (err) {
          console.error('Fout bij verwijderen bestand:', err);
          // Zelfs als het bestand niet kan worden verwijderd, is de operatie succesvol
        }
        
        res.json({ message: 'Foto succesvol verwijderd' });
      });
    });
  });
});

