async function findPredefinedProductionLocationBE(caseType, db) {
    // Probeer het uit stock_oilfree te halen
    return new Promise((resolve, reject) => {
        // Pas de tabelnaam (stock_oilfree) en kolomnamen (case_type, production_location) aan indien nodig.
        const query = `
            SELECT production_location 
            FROM stock_oilfree 
            WHERE case_type = ? AND (production_location = 'Genk' OR production_location = 'Wilrijk')
            GROUP BY production_location # Voorkom meerdere entries als een type op beide locaties kan, pak de eerste
            LIMIT 1
        `;
        db.query(query, [caseType], (err, results) => {
            if (err) {
                console.warn(`Kon productielocatie voor ${caseType} niet opzoeken: ${err.code}: ${err.sqlMessage}`);
                // Fallback logica blijft behouden als de query faalt of niets vindt
                if (caseType && caseType.toUpperCase().includes('VDB')) { 
                     resolve('Wilrijk');
                } else {
                     resolve('Genk');
                }
                return;
            }
            if (results.length > 0 && results[0].production_location) {
                resolve(results[0].production_location);
            } else {
                // Fallback als niet expliciet gevonden in stock_oilfree.
                if (caseType && caseType.toUpperCase().includes('VDB')) { 
                     resolve('Wilrijk');
                } else {
                     resolve('Genk');
                }
            }
        });
    });
}

app.post('/api/oilfree/orders/:orderId/email', async (req, res) => {
    const { orderId } = req.params;
    const defaultRecipient = req.body.recipient || 'Jasonploegaerts@gmail.com';

    const tempDir = path.join(__dirname, 'temp_orders_pdf');
    if (!fs.existsSync(tempDir)) {
        fs.mkdirSync(tempDir, { recursive: true });
    }

    const emailResults = [];
    const COLORS = { primary: '#007A6C', secondary: '#4A4A4A', lightGray: '#F5F5F5', border: '#DDDDDD', white: '#FFFFFF' };
    const A4_WIDTH_POINTS = 595.28;
    const PAGE_OPTIONS = { margin: 50, size: 'A4', bufferPages: true }; 
    const CONTENT_WIDTH = A4_WIDTH_POINTS - (2 * PAGE_OPTIONS.margin);

    try {
        const orderQuery = `
            SELECT o.id, o.location AS orderLocation, o.date, o.status, o.transportPlanning,
                   oi.id as itemId, oi.pils_case_label AS pilsCaseLabel, oi.case_type AS caseType, 
                   oi.erp_codes AS erpCodes, oi.quantity, oi.delivered_quantity AS deliveredQuantity, 
                   oi.status as itemStatus, oi.added_date AS addedDate
            FROM oilfree_orders o
            LEFT JOIN oilfree_order_items oi ON o.id = oi.order_id
            WHERE o.id = ?;
        `;
        
        const rows = await new Promise((resolve, reject) => {
            db.query(orderQuery, [orderId], (err, results) => {
                if (err) return reject(err);
                resolve(results);
            });
        });

        if (!rows || rows.length === 0) {
            return res.status(404).json({ message: 'Bestelling niet gevonden' });
        }

        const orderHeader = {
            id: rows[0].id,
            orderLocation: rows[0].orderLocation,
            date: new Date(rows[0].date),
            status: rows[0].status,
            transportPlanning: rows[0].transportPlanning || ''
        };
        const allOrderItems = rows.filter(r => r.itemId).map(r => ({
            itemId: r.itemId,
            pilsCaseLabel: r.pilsCaseLabel,
            caseType: r.caseType,
            erpCodes: r.erp_codes ? r.erp_codes.split(',') : [],
            quantity: r.quantity,
            deliveredQuantity: r.deliveredQuantity,
            itemStatus: r.itemStatus,
            addedDate: r.addedDate
        }));

        const itemsToProcessByProdLoc = {
            Genk: [],
            Wilrijk: [],
            Overig: [] 
        };

        for (const item of allOrderItems) {
            if (item.quantity > (item.deliveredQuantity || 0)) { 
                const prodLoc = await findPredefinedProductionLocationBE(item.caseType, db);
                if (prodLoc === 'Genk') itemsToProcessByProdLoc.Genk.push(item);
                else if (prodLoc === 'Wilrijk') itemsToProcessByProdLoc.Wilrijk.push(item);
                else itemsToProcessByProdLoc.Overig.push(item);
            }
        }

        for (const [prodLocationKey, specificItems] of Object.entries(itemsToProcessByProdLoc)) {
            if (specificItems.length > 0) {
                const orderDate = orderHeader.date;
                const formattedOrderDate = `${String(orderDate.getDate()).padStart(2, '0')}-${String(orderDate.getMonth() + 1).padStart(2, '0')}-${orderDate.getFullYear()}`;
                
                const tempFileName = `Transportplanning ${prodLocationKey} ${formattedOrderDate}.pdf`;
                const tempFilePath = path.join(tempDir, tempFileName);
                const pdfTitle = `Transportplanning ${prodLocationKey}`;

                try {
                    const doc = new PDFKit({...PAGE_OPTIONS, info: {Title: `${pdfTitle} - ${orderHeader.id}`, Author: 'Foresco Kistenbeheer'}});
                    const writeStream = fs.createWriteStream(tempFilePath);
                    doc.pipe(writeStream);

                    const logoPath = path.join(__dirname, 'uploads', 'Foresco.png');
                    if (fs.existsSync(logoPath)) doc.image(logoPath, PAGE_OPTIONS.margin, 40, { width: 150 });
                    
                    doc.fontSize(18).font('Helvetica-Bold').fillColor(COLORS.primary)
                       .text(pdfTitle.toUpperCase(), 250, 50, { align: 'left' });
                    doc.fontSize(12).font('Helvetica').fillColor(COLORS.secondary)
                       .text(orderHeader.id, 250, 75, { align: 'left' });
                    doc.fontSize(10).fillColor(COLORS.secondary)
                       .text(`Besteldatum: ${formattedOrderDate}`, PAGE_OPTIONS.margin, 100, { align: 'right' });
                    doc.moveDown(3);

                    doc.fontSize(12).font('Helvetica-Bold').fillColor(COLORS.primary)
                       .text('Algemene Informatie', PAGE_OPTIONS.margin + 10, doc.y + 5);
                    doc.moveDown(1.5);
                    doc.fontSize(10).font('Helvetica').fillColor(COLORS.secondary)
                       .text(`Bestemd voor:`, PAGE_OPTIONS.margin + 10, doc.y)
                       .text(orderHeader.orderLocation || 'N/A', PAGE_OPTIONS.margin + 150, doc.y);
                    doc.moveDown(1.5); 

                    await drawKistenSectieToPdf(doc, specificItems, db, PAGE_OPTIONS, CONTENT_WIDTH, COLORS);

                    if (orderHeader.transportPlanning && orderHeader.transportPlanning.trim() !== '') {
                        doc.moveDown(1.5); 
                        let tpSectionStartY = doc.y;
                        const lines = orderHeader.transportPlanning.split('\n').length;
                        const estimatedTextHeight = lines * 12; 
                        const headerHeight = 20 + 15; 
                        const estimatedTpTotalHeight = headerHeight + estimatedTextHeight;
                        if (tpSectionStartY + estimatedTpTotalHeight > doc.page.height - PAGE_OPTIONS.margin - 30) { 
                             doc.addPage();
                             tpSectionStartY = PAGE_OPTIONS.margin; 
                        }
                        doc.rect(PAGE_OPTIONS.margin, tpSectionStartY, CONTENT_WIDTH, 20).fill(COLORS.lightGray);
                        doc.fontSize(12).font('Helvetica-Bold').fillColor(COLORS.primary)
                           .text('Transportplanning Notities (Originele Order)', PAGE_OPTIONS.margin + 10, tpSectionStartY + 5);
                        doc.y = tpSectionStartY + 20 + 10; 
                        doc.fontSize(10).font('Helvetica').fillColor(COLORS.secondary)
                           .text(orderHeader.transportPlanning, PAGE_OPTIONS.margin + 10, doc.y, { 
                               width: CONTENT_WIDTH - 20,
                               align: 'justify' 
                           });
                    }

                    const range = doc.bufferedPageRange();
                    for (let i = range.start; i < range.start + range.count; i++) {
                        doc.switchToPage(i);
                        doc.fontSize(8).fillColor(COLORS.secondary)
                           .text(`Pagina ${i + 1} van ${range.count}`, PAGE_OPTIONS.margin, doc.page.height - PAGE_OPTIONS.margin + 10, 
                                 { align: 'center', width: CONTENT_WIDTH });
                    }
                    doc.end();
                    await new Promise((resolve, reject) => {
                        writeStream.on('finish', resolve);
                        writeStream.on('error', reject);
                    });

                    const mailSubject = `Transportplanning ${prodLocationKey} - Order: ${orderHeader.id} (${formattedOrderDate})`;
                    const mailHtml = `<p>Beste,</p><p>In bijlage vindt u de transportplanning voor <b>${prodLocationKey}</b> betreffende order <strong>${orderHeader.id}</strong> van ${formattedOrderDate}.</p><p>Bestemd voor: ${orderHeader.orderLocation}</p><p><em>Dit is een automatisch gegenereerde e-mail.</em></p>`;
                    const mailOptions = {
                        from: '"Foresco Kistenbeheer" <jason@prodwilrijk.be>', 
                        to: defaultRecipient, 
                        subject: mailSubject,
                        html: mailHtml,
                        attachments: [{ filename: tempFileName, path: tempFilePath, contentType: 'application/pdf' }]
                    };
                    await transporter.sendMail(mailOptions);
                    emailResults.push({ success: true, type: `kisten-${prodLocationKey}`, orderId: orderHeader.id, file: tempFileName, recipient: defaultRecipient });
                    console.log(`E-mail voor ${pdfTitle} (Order ${orderHeader.id}, Prod ${prodLocationKey}) succesvol verzonden.`);

                } catch (perPdfError) {
                    console.error(`Fout bij genereren/mailen PDF voor Order ${orderHeader.id}, Prod ${prodLocationKey}:`, perPdfError);
                    emailResults.push({ success: false, type: `kisten-${prodLocationKey}`, orderId: orderHeader.id, error: perPdfError.message });
                } finally {
                    if (fs.existsSync(tempFilePath)) {
                        try { fs.unlinkSync(tempFilePath); } 
                        catch (cleanupError) { console.warn(`Kon tijdelijk PDF-bestand ${tempFilePath} niet verwijderen:`, cleanupError); }
                    }
                }
            }
        }

        const allSuccessful = emailResults.every(r => r.success);
        if (emailResults.length === 0) {
            return res.status(400).json({ success: false, message: 'Geen items gevonden om te verwerken voor deze bestelling of productielocaties.' });
        }
        if (allSuccessful) {
            res.json({ success: true, message: 'Alle relevante PDF(s) succesvol gemaild.', details: emailResults });
        } else {
            const someSuccessful = emailResults.some(r => r.success);
            res.status(someSuccessful ? 207 : 500).json({ 
                success: false, 
                message: someSuccessful ? 'Sommige PDF(s) konden niet (volledig) worden verwerkt.' : 'Alle PDF(s) zijn mislukt.',
                details: emailResults 
            });
        }

    } catch (error) {
        console.error(`[PDF EMAIL ERROR - MAIN] Order ID: ${orderId}`);
        console.error('[PDF EMAIL ERROR - MAIN] Volledige error object:', error);
        res.status(500).json({ message: 'Algemene fout bij e-mailen bestelling met PDF', error: error.message });
    }
});

// Helper functie om een unieke order ID te genereren (pas aan indien nodig)
function generateNewOrderId() {
    const now = new Date();
    const year = now.getFullYear();
    const month = String(now.getMonth() + 1).padStart(2, '0'); // Maanden zijn 0-based
    const day = String(now.getDate()).padStart(2, '0');
    const hours = String(now.getHours()).padStart(2, '0');
    const minutes = String(now.getMinutes()).padStart(2, '0');
    const seconds = String(now.getSeconds()).padStart(2, '0');
    return `Bestelling-${year}-${month}-${day}-${hours}${minutes}${seconds}`;
}


app.post('/api/oilfree/orders/:orderId/transfer-undelivered', async (req, res) => {
    const oldOrderId = req.params.orderId;
    console.log(`[TRANSFER] Start overzetten niet-geleverde items voor order: ${oldOrderId}`);

    try {
        // Start transactie
        await new Promise((resolve, reject) => {
            db.beginTransaction(err => {
                if (err) return reject(err);
                console.log(`[TRANSFER] Transactie gestart voor order ${oldOrderId}`);
                resolve();
            });
        });

        // 1. Haal oude bestelling en items op
        const getOldOrderSql = `
            SELECT o.id as order_id, o.location, o.status as order_status, o.transportPlanning as old_transport_planning,
                   oi.id as item_id, oi.pils_case_label, oi.case_type, oi.erp_codes, 
                   oi.quantity, oi.production_location, oi.delivered_quantity, oi.transferred_quantity, oi.status as item_status
            FROM oilfree_orders o
            LEFT JOIN oilfree_order_items oi ON o.id = oi.order_id
            WHERE o.id = ?;
        `;
        const oldOrderRows = await new Promise((resolve, reject) => {
            db.query(getOldOrderSql, [oldOrderId], (err, results) => {
                if (err) return reject(err);
                resolve(results);
            });
        });

        if (!oldOrderRows || oldOrderRows.length === 0) {
            await new Promise((resolve) => { db.rollback(() => resolve()); });
            console.warn(`[TRANSFER] Oude order ${oldOrderId} niet gevonden.`);
            return res.status(404).json({ message: 'Originele bestelling niet gevonden.' });
        }

        const oldOrderHeader = {
            id: oldOrderRows[0].order_id,
            location: oldOrderRows[0].location,
            status: oldOrderRows[0].order_status,
            transportPlanning: oldOrderRows[0].old_transport_planning || ''
        };
        const oldOrderItems = oldOrderRows.filter(r => r.item_id).map(r => ({
            id: r.item_id,
            pils_case_label: r.pils_case_label,
            case_type: r.case_type,
            erp_codes: r.erp_codes,
            quantity: r.quantity,
            production_location: r.production_location,
            delivered_quantity: r.delivered_quantity || 0,
            transferred_quantity: r.transferred_quantity || 0,
            status: r.item_status
        }));

        // 2. Identificeer items om over te zetten
        const itemsToActuallyTransfer = [];
        for (const item of oldOrderItems) {
            const remainingToDeliver = item.quantity - item.delivered_quantity - item.transferred_quantity;
            if (remainingToDeliver > 0) {
                itemsToActuallyTransfer.push({ ...item, quantity_to_transfer: remainingToDeliver });
            }
        }

        if (itemsToActuallyTransfer.length === 0) {
            await new Promise((resolve) => { db.rollback(() => resolve()); });
            console.log(`[TRANSFER] Geen items om over te zetten voor order ${oldOrderId}.`);
            return res.status(200).json({ success: true, message: 'Geen niet-geleverde items gevonden om over te zetten.', new_order_id: null });
        }
        console.log(`[TRANSFER] ${itemsToActuallyTransfer.length} item types om over te zetten voor ${oldOrderId}.`);

        // 3. Bepaal target order ID (nieuw of bestaand voor vandaag)
        let targetOrderId;
        let targetOrderTransportPlanning;
        let isExistingDailyOrder = false;
        const todayStr = new Date().toISOString().slice(0, 10); // YYYY-MM-DD formaat voor query
        
        const searchExistingOrderSql = `
            SELECT id, transportPlanning 
            FROM oilfree_orders 
            WHERE location = ? 
              AND DATE(date) = ? 
              AND transportPlanning LIKE 'Overname restant items van bestelling%'
              AND status NOT IN ('completed', 'canceled')
            ORDER BY date DESC
            LIMIT 1;
        `;
        
        const existingDailyOrders = await new Promise((resolve, reject) => {
            db.query(searchExistingOrderSql, [oldOrderHeader.location, todayStr], (err, results) => {
                if (err) return reject(err);
                resolve(results);
            });
        });

        if (existingDailyOrders.length > 0) {
            targetOrderId = existingDailyOrders[0].id;
            const existingPlanning = existingDailyOrders[0].transportPlanning || '';
            if (!existingPlanning.includes(oldOrderId)) {
                 targetOrderTransportPlanning = `${existingPlanning}\nMeer items overgezet van bestelling ${oldOrderId}`.trim();
            } else {
                 targetOrderTransportPlanning = existingPlanning;
            }
            isExistingDailyOrder = true;
            console.log(`[TRANSFER] Bestaande dagelijkse overzet-order ${targetOrderId} gevonden voor locatie ${oldOrderHeader.location}.`);
        } else {
            targetOrderId = generateNewOrderId();
            targetOrderTransportPlanning = `Overname restant items van bestelling ${oldOrderId}`;
            isExistingDailyOrder = false;
            console.log(`[TRANSFER] Geen bestaande dagelijkse overzet-order. Nieuwe order ID wordt ${targetOrderId}.`);
        }

        // 4. Maak items voor de target bestelling
        const newOrderItemsValues = itemsToActuallyTransfer.map(item => [
            targetOrderId,
            item.pils_case_label,
            item.case_type,
            item.erp_codes, // Dit is een string uit de DB
            item.quantity_to_transfer,
            item.production_location || oldOrderHeader.location,
            0, // delivered_quantity
            new Date(), // added_date voor het nieuwe item in de overzetorder
            0, // transferred_quantity voor het nieuwe item
            'pending' // status
        ]);

        // 5. Voeg nieuwe bestelheader toe OF update bestaande
        if (!isExistingDailyOrder) {
            const insertNewOrderHeaderSql = 'INSERT INTO oilfree_orders (id, location, date, status, transportPlanning) VALUES (?, ?, NOW(), ?, ?)';
            await new Promise((resolve, reject) => {
                db.query(insertNewOrderHeaderSql, [targetOrderId, oldOrderHeader.location, 'open', targetOrderTransportPlanning], (err, result) => {
                    if (err) return reject(err);
                    console.log(`[TRANSFER] Nieuwe order header ${targetOrderId} aangemaakt.`);
                    resolve(result);
                });
            });
        } else {
            const updateExistingOrderSql = 'UPDATE oilfree_orders SET transportPlanning = ?, last_updated = NOW() WHERE id = ?';
            await new Promise((resolve, reject) => {
                db.query(updateExistingOrderSql, [targetOrderTransportPlanning, targetOrderId], (err, result) => {
                    if (err) return reject(err);
                    console.log(`[TRANSFER] Transportplanning van bestaande order ${targetOrderId} bijgewerkt.`);
                    resolve(result);
                });
            });
        }

        // 6. Voeg nieuwe bestelitems toe aan de targetOrder
        if (newOrderItemsValues.length > 0) {
            const insertNewOrderItemsSql = `
                INSERT INTO oilfree_order_items 
                (order_id, pils_case_label, case_type, erp_codes, quantity, production_location, delivered_quantity, added_date, transferred_quantity, status) 
                VALUES ?`;
            await new Promise((resolve, reject) => {
                db.query(insertNewOrderItemsSql, [newOrderItemsValues], (err, result) => {
                    if (err) return reject(err);
                    console.log(`[TRANSFER] ${newOrderItemsValues.length} items toegevoegd aan order ${targetOrderId}.`);
                    resolve(result);
                });
            });
        }

        // 7. Update oude order items (transferred_quantity)
        for (const item of itemsToActuallyTransfer) {
            const updateOldItemSql = 'UPDATE oilfree_order_items SET transferred_quantity = transferred_quantity + ? WHERE id = ?';
            await new Promise((resolve, reject) => {
                db.query(updateOldItemSql, [item.quantity_to_transfer, item.id], (err, result) => {
                    if (err) return reject(err);
                    resolve(result);
                });
            });
        }
        console.log(`[TRANSFER] transferred_quantity bijgewerkt voor items op oude order ${oldOrderId}.`);

        // 8. Update oude order header (status en transportPlanning notitie)
        let oldOrderIsNowEffectivelyComplete = true;
        const checkOldOrderItemsSql = 'SELECT quantity, delivered_quantity, transferred_quantity FROM oilfree_order_items WHERE order_id = ?';
        const updatedOldItems = await new Promise((resolve, reject) => {
            db.query(checkOldOrderItemsSql, [oldOrderId], (err, results) => {
                if (err) return reject(err);
                resolve(results);
            });
        });

        for (const item of updatedOldItems) {
            if ((item.quantity - (item.delivered_quantity || 0) - (item.transferred_quantity || 0)) > 0) {
                oldOrderIsNowEffectivelyComplete = false;
                break;
            }
        }
        
        const newOldOrderStatus = oldOrderIsNowEffectivelyComplete ? 'completed' : oldOrderHeader.status;
        const oldOrderNewTransportPlanning = `${oldOrderHeader.transportPlanning}\nItems overgezet naar bestelling ${targetOrderId}`.trim();

        const updateOldOrderHeaderSql = 'UPDATE oilfree_orders SET status = ?, transportPlanning = ?, last_updated = NOW() WHERE id = ?';
        await new Promise((resolve, reject) => {
            db.query(updateOldOrderHeaderSql, [newOldOrderStatus, oldOrderNewTransportPlanning, oldOrderId], (err, result) => {
                if (err) return reject(err);
                console.log(`[TRANSFER] Oude order header ${oldOrderId} status bijgewerkt naar ${newOldOrderStatus}. Notitie toegevoegd voor transfer naar ${targetOrderId}.`);
                resolve(result);
            });
        });

        // Commit transactie
        await new Promise((resolve, reject) => {
            db.commit(err => {
                if (err) return reject(err);
                console.log(`[TRANSFER] Transactie succesvol gecommit voor ${oldOrderId} -> ${targetOrderId}.`);
                resolve();
            });
        });

        res.json({ 
            success: true, 
            message: `Niet-geleverde items succesvol overgezet. Target bestelling ID: ${targetOrderId}`,
            original_order_id: oldOrderId,
            new_order_id: targetOrderId 
        });

    } catch (error) {
        await new Promise((resolve) => { 
            db.rollback(() => {
                console.error(`[TRANSFER] Fout tijdens overzetten items voor order ${oldOrderId}, rollback uitgevoerd. Error:`, error);
                resolve(); 
            });
        });
        res.status(500).json({ message: 'Fout bij overzetten niet-geleverde items.', error: error.message });
    }
});

// Helper functie (eerder addTableToPdf, nu meer specifiek voor kisten)
async function drawKistenSectieToPdf(doc, orderDataItems, db, pageOptions, contentWidth, colors) {
    // Input: doc, items voor een specifieke bestelopdracht (mogelijk nog niet gegroepeerd), db connection
    // Output: Tekent de kistensectie(s) op de PDF

    // 1. Groepeer items per productielocatie
    const itemsByProductionLocation = { Genk: [], Wilrijk: [], Overig: [] };
    if (!orderDataItems || !Array.isArray(orderDataItems)) {
        console.warn('[drawKistenSectieToPdf] orderDataItems is ongeldig of leeg.');
        return;
    }

    for (const item of orderDataItems) {
        // findPredefinedProductionLocationBE moet beschikbaar zijn
        const prodLoc = item.productionLocation || await findPredefinedProductionLocationBE(item.caseType, db); 
        if (prodLoc === 'Genk') itemsByProductionLocation.Genk.push(item);
        else if (prodLoc === 'Wilrijk') itemsByProductionLocation.Wilrijk.push(item);
        else itemsByProductionLocation.Overig.push(item);
    }

    // 2. Teken tabel per productielocatie
    const drawSpecificKistenTable = (locationName, items) => {
        if (!items || items.length === 0) return;
        doc.moveDown(1); 
        doc.fontSize(11).font('Helvetica-Bold').fillColor(colors.secondary)
           .text(`Vanuit Productielocatie: ${locationName}`, pageOptions.margin, doc.y);
        doc.moveDown(0.5);

        const rowHeight = 20; // Geschatte rijhoogte
        const headerY = doc.y;
        const col1X = pageOptions.margin + 5;
        const col2X = pageOptions.margin + 150;
        const col3X = pageOptions.margin + 280;
        const col4X = pageOptions.margin + 330;
        const col5X = pageOptions.margin + 450;

        doc.font('Helvetica-Bold').fontSize(9).fillColor(colors.secondary);
        doc.text('Kist Type', col1X, headerY)
           .text('ERP Code(s)', col2X, headerY)
           .text('Aantal', col3X, headerY, {width: 40, align: 'right'})
           .text('PILS Label', col4X, headerY)
           .text('Toegevoegd', col5X, headerY);
        doc.moveDown(0.5);
        doc.strokeColor(colors.border).moveTo(pageOptions.margin, doc.y).lineTo(pageOptions.margin + contentWidth, doc.y).stroke();
        doc.moveDown(0.5);
        
        doc.font('Helvetica').fontSize(9);
        items.forEach((item, index) => {
            let formattedAddedDate = 'N/A';
            if (item.addedDate) {
                try {
                    const dateObj = new Date(item.addedDate);
                    const day = String(dateObj.getUTCDate()).padStart(2, '0');
                    const month = String(dateObj.getUTCMonth() + 1).padStart(2, '0');
                    formattedAddedDate = `${day}-${month}`;
                } catch (e) { console.warn("Kon addedDate niet formatteren:", item.addedDate, e); }
            }
            const qtyToDisplay = (item.quantity || 0) - (item.deliveredQuantity || 0);
            if (qtyToDisplay <= 0 && item.hasOwnProperty('deliveredQuantity')) return;

            let currentItemY = doc.y;
            if (currentItemY + rowHeight > doc.page.height - pageOptions.margin - pageOptions.margin) { 
                doc.addPage();
                currentItemY = pageOptions.margin; 
                doc.y = currentItemY;
                doc.font('Helvetica-Bold').fontSize(9).fillColor(colors.secondary);
                doc.text('Kist Type', col1X, doc.y).text('ERP Code(s)', col2X, doc.y)
                   .text('Aantal', col3X, doc.y, {width: 40, align: 'right'})
                   .text('PILS Label', col4X, doc.y).text('Toegevoegd', col5X, doc.y);
                doc.moveDown(0.5);
                doc.strokeColor(colors.border).moveTo(pageOptions.margin, doc.y).lineTo(pageOptions.margin + contentWidth, doc.y).stroke();
                doc.moveDown(0.5);
                doc.font('Helvetica').fontSize(9);
            }

            if (index % 2 !== 0) doc.rect(pageOptions.margin, currentItemY -2, contentWidth, rowHeight).fillColor(colors.lightGray).fill();
            doc.fillColor(colors.secondary);
            doc.text(item.caseType || 'N/A', col1X, currentItemY, { width: col2X - col1X - 10 })
               .text(item.erpCodes && Array.isArray(item.erpCodes) && item.erpCodes.length > 0 ? item.erpCodes.join(', ') : (typeof item.erpCodes === 'string' ? item.erpCodes : 'N/A'), col2X, currentItemY, { width: col3X - col2X - 10 })
               .text(qtyToDisplay.toString(), col3X, currentItemY, { width: 40, align: 'right' })
               .text(item.pilsCaseLabel || 'N/A', col4X, currentItemY, { width: col5X - col4X - 10 })
               .text(formattedAddedDate, col5X, currentItemY, { width: contentWidth - col5X + pageOptions.margin -10 });
            doc.moveDown(0.8);
        });
    };

    drawSpecificKistenTable('Genk', itemsByProductionLocation.Genk);
    drawSpecificKistenTable('Wilrijk', itemsByProductionLocation.Wilrijk);
    if (itemsByProductionLocation.Overig.length > 0) {
        drawSpecificKistenTable('Overig', itemsByProductionLocation.Overig);
    }
}

// Helper functie voor artikelen sectie
function drawArtikelenSectieToPdf(doc, orderDataItems, pageOptions, contentWidth, colors) {
    const items = orderDataItems;
    if (!items || !Array.isArray(items) || items.length === 0) {
        console.warn('[drawArtikelenSectieToPdf] orderDataItems is ongeldig of leeg.');
        return;
    }

    doc.moveDown(1);
    const rowHeight = 20;
    let headerY = doc.y;
     if (headerY + rowHeight > doc.page.height - pageOptions.margin - pageOptions.margin) { // Check if header + 1 row fits
        doc.addPage();
        headerY = pageOptions.margin;
        doc.y = headerY;
    }

    const col1X = pageOptions.margin + 5;
    const col2X = pageOptions.margin + 250;
    const col3X = pageOptions.margin + 350;
    const col4X = pageOptions.margin + 420;

    doc.font('Helvetica-Bold').fontSize(9).fillColor(colors.secondary);
    doc.text('Omschrijving', col1X, headerY)
       .text('Artikelnummer', col2X, headerY)
       .text('Aantal', col3X, headerY, { width: 60, align: 'right' })
       .text('Aangevraagd', col4X, headerY);
    doc.moveDown(0.5);
    doc.strokeColor(colors.border).moveTo(pageOptions.margin, doc.y).lineTo(pageOptions.margin + contentWidth, doc.y).stroke();
    doc.moveDown(0.5);

    doc.font('Helvetica').fontSize(9);
    items.forEach((item, index) => {
        let formattedReqDate = 'N/A';
        if (item.request_date) { 
            try {
                const dateObj = new Date(item.request_date);
                const day = String(dateObj.getUTCDate()).padStart(2, '0');
                const month = String(dateObj.getUTCMonth() + 1).padStart(2, '0');
                formattedReqDate = `${day}-${month}`;
            } catch (e) { console.warn("Kon request_date niet formatteren:", item.request_date, e); }
        }
        
        let currentItemY = doc.y;
        if (currentItemY + rowHeight > doc.page.height - pageOptions.margin - pageOptions.margin) { 
            doc.addPage();
            currentItemY = pageOptions.margin;
            doc.y = currentItemY;
            doc.font('Helvetica-Bold').fontSize(9).fillColor(colors.secondary);
            doc.text('Omschrijving', col1X, doc.y).text('Artikelnummer', col2X, doc.y)
               .text('Aantal', col3X, doc.y, { width: 60, align: 'right' }).text('Aangevraagd', col4X, doc.y);
            doc.moveDown(0.5);
            doc.strokeColor(colors.border).moveTo(pageOptions.margin, doc.y).lineTo(pageOptions.margin + contentWidth, doc.y).stroke();
            doc.moveDown(0.5);
            doc.font('Helvetica').fontSize(9);
        }

        if (index % 2 !== 0) doc.rect(pageOptions.margin, currentItemY - 2, contentWidth, rowHeight).fillColor(colors.lightGray).fill();
        doc.fillColor(colors.secondary);
        doc.text(item.description || item.volledige_omschrijving || 'N/A', col1X, currentItemY, { width: col2X - col1X - 10 })
           .text(item.erpCode || item.artikelnummer || 'N/A', col2X, currentItemY, { width: col3X - col2X - 10 }) 
           .text((item.quantity || 0).toString(), col3X, currentItemY, { width: 60, align: 'right' })
           .text(formattedReqDate, col4X, currentItemY, { width: contentWidth - col4X + pageOptions.margin - 10 });
        doc.moveDown(0.8);
    });
}


app.post('/api/oilfree/email-order-compilation', async (req, res) => {
    const { recipient, orders } = req.body;
    const defaultRecipient = recipient || 'Jasonploegaerts@gmail.com';

    if (!orders || !Array.isArray(orders) || orders.length === 0) {
        return res.status(400).json({ message: 'Geen bestelopdrachten ontvangen.' });
    }

    const emailResults = [];
    const tempDir = path.join(__dirname, 'temp_orders_pdf');
    if (!fs.existsSync(tempDir)) fs.mkdirSync(tempDir, { recursive: true });

    const COLORS = { primary: '#007A6C', secondary: '#4A4A4A', lightGray: '#F5F5F5', border: '#DDDDDD', white: '#FFFFFF' };
    const A4_WIDTH_POINTS = 595.28;
    const PAGE_OPTIONS = { margin: 50, size: 'A4', bufferPages: true }; 
    const CONTENT_WIDTH = A4_WIDTH_POINTS - (2 * PAGE_OPTIONS.margin);
    const today = new Date();
    const formattedDate = `${String(today.getDate()).padStart(2, '0')}-${String(today.getMonth() + 1).padStart(2, '0')}-${today.getFullYear()}`;

    for (const originalOrderData of orders) {
        if (originalOrderData.type === 'kisten') {
            const itemsByProdLoc = { Genk: [], Wilrijk: [], Overig: [] };
            if (originalOrderData.items && Array.isArray(originalOrderData.items)) {
                for (const item of originalOrderData.items) {
                    const prodLoc = item.productionLocation || await findPredefinedProductionLocationBE(item.caseType, db);
                    if (prodLoc === 'Genk') itemsByProdLoc.Genk.push(item);
                    else if (prodLoc === 'Wilrijk') itemsByProdLoc.Wilrijk.push(item);
                    else itemsByProdLoc.Overig.push(item);
                }
            }

            for (const [prodLocationKey, specificItems] of Object.entries(itemsByProdLoc)) {
                if (specificItems.length > 0) {
                    const destLocationClean = (originalOrderData.destinationLocation || 'Onbekend').replace(/[^a-zA-Z0-9-_]/g, '_');
                    const prodKeyClean = prodLocationKey.replace(/[^a-zA-Z0-9-_]/g, '_');
                    
                    // Aangepaste bestandsnaam
                    const tempFileName = `transportplanning ${destLocationClean} (Productie ${prodKeyClean}) ${formattedDate}.pdf`;
                    const tempFilePath = path.join(tempDir, tempFileName);

                    const pdfTitle = `${originalOrderData.title || 'Kisten Bestelopdracht'} (Productie ${prodLocationKey})`;
                    const pdfOrderIdRef = `${originalOrderData.orderId || 'N/A'}-${prodLocationKey.toUpperCase()}`;

                    try {
                        const doc = new PDFDocument({...PAGE_OPTIONS, info: {Title: pdfTitle, Author: 'Foresco Kistenbeheer'}});
                        const writeStream = fs.createWriteStream(tempFilePath);
                        doc.pipe(writeStream);

                        const logoPath = path.join(__dirname, 'uploads', 'Foresco.png');
                        if (fs.existsSync(logoPath)) doc.image(logoPath, PAGE_OPTIONS.margin, 40, { width: 150 });
                        
                        doc.fontSize(18).font('Helvetica-Bold').fillColor(COLORS.primary)
                           .text(pdfTitle.toUpperCase(), 250, 50, { align: 'left' });
                        doc.fontSize(10).fillColor(COLORS.secondary)
                           .text(`Datum: ${new Date().toLocaleDateString('nl-BE')}`, PAGE_OPTIONS.margin, 100, { align: 'right' });
                        doc.moveDown(2);
                        
                        doc.fontSize(14).font('Helvetica-Bold').fillColor(COLORS.primary)
                           .text(pdfTitle, PAGE_OPTIONS.margin, doc.y);
                        doc.moveDown(0.5);
                        doc.fontSize(10).font('Helvetica').fillColor(COLORS.secondary)
                           .text(`Referentie: ${pdfOrderIdRef} | Bestemming: ${originalOrderData.destinationLocation || 'N/A'}`, PAGE_OPTIONS.margin, doc.y);
                        doc.moveDown(1);
                        doc.strokeColor(COLORS.border).moveTo(PAGE_OPTIONS.margin, doc.y).lineTo(PAGE_OPTIONS.margin + CONTENT_WIDTH, doc.y).stroke();
                        doc.moveDown(0.5);

                        await drawKistenSectieToPdf(doc, specificItems, db, PAGE_OPTIONS, CONTENT_WIDTH, COLORS); 

                        const range = doc.bufferedPageRange();
                        for (let i = range.start; i < range.start + range.count; i++) {
                            doc.switchToPage(i);
                            doc.fontSize(8).fillColor(COLORS.secondary)
                               .text(`Pagina ${i + 1} van ${range.count}`, PAGE_OPTIONS.margin, doc.page.height - PAGE_OPTIONS.margin + 10, 
                                     { align: 'center', width: CONTENT_WIDTH });
                        }
                        doc.end();
                        await new Promise((resolve, reject) => {
                            writeStream.on('finish', resolve);
                            writeStream.on('error', reject);
                        });

                        const mailSubject = `Bestelopdracht Kisten (Productie ${prodLocationKey}) - Ref: ${pdfOrderIdRef}`;
                        const mailHtml = `<p>Beste,</p><p>In bijlage vindt u de bestelopdracht voor kisten van productie ${prodLocationKey} (Referentie: ${pdfOrderIdRef}).</p><p>Bestemming: ${originalOrderData.destinationLocation || 'N/A'}</p><p><em>Dit is een automatisch gegenereerde e-mail.</em></p>`;
                        const mailOptions = {
                            from: '"Foresco Kistenbeheer" <jason@prodwilrijk.be>',
                            to: defaultRecipient,
                            subject: mailSubject,
                            html: mailHtml,
                            attachments: [{ filename: tempFileName, path: tempFilePath, contentType: 'application/pdf' }]
                        };
                        await transporter.sendMail(mailOptions);
                        emailResults.push({ success: true, type: `kisten-${prodLocationKey}`, orderId: pdfOrderIdRef, file: tempFileName, recipient: defaultRecipient });
                        console.log(`E-mail voor ${pdfTitle} succesvol verzonden.`);

                    } catch (perPdfError) {
                        console.error(`Fout bij genereren/mailen PDF voor ${pdfTitle}:`, perPdfError);
                        emailResults.push({ success: false, type: `kisten-${prodLocationKey}`, orderId: pdfOrderIdRef, error: perPdfError.message });
                    } finally {
                        if (fs.existsSync(tempFilePath)) {
                            try { fs.unlinkSync(tempFilePath); } 
                            catch (cleanupError) { console.warn(`Kon tijdelijk PDF-bestand ${tempFilePath} niet verwijderen:`, cleanupError); }
                        }
                    }
                } 
            } 
        
        } else if (originalOrderData.type === 'artikelen') {
            const destLocationClean = (originalOrderData.destinationLocation || 'Onbekend').replace(/[^a-zA-Z0-9-_]/g, '_');
            const orderTitleClean = (originalOrderData.title || 'Artikelen').replace(/[^a-zA-Z0-9-_]/g, '_');
            // Aangepaste bestandsnaam
            const tempFileName = `transportplanning ${destLocationClean} ${orderTitleClean} ${formattedDate}.pdf`;
            const tempFilePath = path.join(tempDir, tempFileName);

            const pdfTitle = originalOrderData.title || 'Artikelen Bestelopdracht';
            const pdfOrderIdRef = originalOrderData.orderId || 'N/A';

            try {
                const doc = new PDFDocument({...PAGE_OPTIONS, info: {Title: pdfTitle, Author: 'Foresco Kistenbeheer'}});
                const writeStream = fs.createWriteStream(tempFilePath);
                doc.pipe(writeStream);

                const logoPath = path.join(__dirname, 'uploads', 'Foresco.png');
                if (fs.existsSync(logoPath)) doc.image(logoPath, PAGE_OPTIONS.margin, 40, { width: 150 });
                
                doc.fontSize(18).font('Helvetica-Bold').fillColor(COLORS.primary)
                   .text(pdfTitle.toUpperCase(), 250, 50, { align: 'left' });
                doc.fontSize(10).fillColor(COLORS.secondary)
                   .text(`Datum: ${new Date().toLocaleDateString('nl-BE')}`, PAGE_OPTIONS.margin, 100, { align: 'right' });
                doc.moveDown(2);

                doc.fontSize(14).font('Helvetica-Bold').fillColor(COLORS.primary)
                   .text(pdfTitle, PAGE_OPTIONS.margin, doc.y);
                doc.moveDown(0.5);
                doc.fontSize(10).font('Helvetica').fillColor(COLORS.secondary)
                   .text(`Referentie: ${pdfOrderIdRef} | Bestemming: ${originalOrderData.destinationLocation || 'N/A'}`, PAGE_OPTIONS.margin, doc.y);
                doc.moveDown(1);
                doc.strokeColor(COLORS.border).moveTo(PAGE_OPTIONS.margin, doc.y).lineTo(PAGE_OPTIONS.margin + CONTENT_WIDTH, doc.y).stroke();
                doc.moveDown(0.5);

                drawArtikelenSectieToPdf(doc, originalOrderData.items, PAGE_OPTIONS, CONTENT_WIDTH, COLORS);

                const range = doc.bufferedPageRange();
                for (let i = range.start; i < range.start + range.count; i++) {
                    doc.switchToPage(i);
                    doc.fontSize(8).fillColor(COLORS.secondary)
                       .text(`Pagina ${i + 1} van ${range.count}`, PAGE_OPTIONS.margin, doc.page.height - PAGE_OPTIONS.margin + 10, 
                             { align: 'center', width: CONTENT_WIDTH });
                }
                doc.end();
                await new Promise((resolve, reject) => {
                    writeStream.on('finish', resolve);
                    writeStream.on('error', reject);
                });

                const mailSubject = `Bestelopdracht ${originalOrderData.title || 'Artikelen'} - Ref: ${pdfOrderIdRef}`;
                const mailHtml = `<p>Beste,</p><p>In bijlage vindt u de bestelopdracht voor ${originalOrderData.title || 'artikelen'} (Referentie: ${pdfOrderIdRef}).</p><p>Bestemming: ${originalOrderData.destinationLocation || 'N/A'}</p><p><em>Dit is een automatisch gegenereerde e-mail.</em></p>`;
                const mailOptions = {
                    from: '"Foresco Kistenbeheer" <jason@prodwilrijk.be>',
                    to: defaultRecipient,
                    subject: mailSubject,
                    html: mailHtml,
                    attachments: [{ filename: tempFileName, path: tempFilePath, contentType: 'application/pdf' }]
                };
                await transporter.sendMail(mailOptions);
                emailResults.push({ success: true, type: 'artikelen', orderId: pdfOrderIdRef, file: tempFileName, recipient: defaultRecipient });
                console.log(`E-mail voor ${pdfTitle} succesvol verzonden.`);

            } catch (perPdfError) {
                console.error(`Fout bij genereren/mailen PDF voor ${pdfTitle}:`, perPdfError);
                emailResults.push({ success: false, type: 'artikelen', orderId: pdfOrderIdRef, error: perPdfError.message });
            } finally {
                if (fs.existsSync(tempFilePath)) {
                    try { fs.unlinkSync(tempFilePath); } 
                    catch (cleanupError) { console.warn(`Kon tijdelijk PDF-bestand ${tempFilePath} niet verwijderen:`, cleanupError); }
                }
            }
        } else {
            console.warn(`Onbekend order type: ${originalOrderData.type} voor orderId ${originalOrderData.orderId}`);
            emailResults.push({ success: false, type: originalOrderData.type, orderId: originalOrderData.orderId, message: 'Onbekend type, overgeslagen.' });
        }
    } 

    const allSuccessful = emailResults.every(r => r.success);
    if (emailResults.length === 0) {
        return res.status(400).json({ success: false, message: 'Geen verwerkbare bestelopdrachten gevonden.' });
    }

    if (allSuccessful) {
        res.json({ success: true, message: 'Alle bestelopdrachten succesvol verwerkt en gemaild.', details: emailResults });
    } else {
        const someSuccessful = emailResults.some(r => r.success);
        res.status(someSuccessful ? 207 : 500).json({ 
            success: false, 
            message: someSuccessful ? 'Sommige bestelopdrachten konden niet (volledig) worden verwerkt.' : 'Alle bestelopdrachten zijn mislukt.',
            details: emailResults 
        });
    }
});
  
