  app.put('/api/interventies/:id', (req, res) => {
    const { id } = req.params;
    const { 
      toestel_id, datum, omschrijving_probleem, uitgevoerde_werken, 
      kosten, factuur_nummer, uitgevoerd_door, opmerkingen 
    } = req.body;
    
    // Validatie
    if (!toestel_id || !datum || !omschrijving_probleem || !uitgevoerde_werken || kosten === undefined) {
      return res.status(400).json({ error: 'Toestel ID, datum, omschrijving probleem, uitgevoerde werken en kosten zijn verplicht' });
    }
    
    const sql = `
      UPDATE interventies SET
      toestel_id = ?, 
      datum = ?, 
      omschrijving_probleem = ?, 
      uitgevoerde_werken = ?,
      kosten = ?, 
      factuur_nummer = ?, 
      uitgevoerd_door = ?, 
      opmerkingen = ?
      WHERE id = ?
    `;
    
    console.log(`[PUT /interventies/:id] Update interventie ${id}`);
    
    db.query(sql, [toestel_id, datum, omschrijving_probleem, uitgevoerde_werken, kosten, factuur_nummer, uitgevoerd_door, opmerkingen, id], (err, result) => {
      if (err) {
        console.error(`[PUT /interventies/:id] Fout bij updaten interventie ${id}:`, err);
        return res.status(500).json({ error: 'Database error: ' + err.message });
      }
      
      if (result.affectedRows === 0) {
        console.log(`[PUT /interventies/:id] Interventie ${id} niet gevonden voor update`);
        return res.status(404).json({ error: 'Interventie niet gevonden' });
      }
      
      console.log(`[PUT /interventies/:id] Interventie ${id} succesvol bijgewerkt`);
      res.json({ 
        success: true,
        message: 'Interventie succesvol bijgewerkt' 
      });
    });
  });
  
  // DELETE interventie
  app.delete('/api/interventies/:id', (req, res) => {
    const { id } = req.params;
    const sql = 'DELETE FROM interventies WHERE id = ?';
    
    console.log(`[DELETE /interventies/:id] Verwijderen interventie ${id}`);
    
    db.query(sql, [id], (err, result) => {
      if (err) {
        console.error(`[DELETE /interventies/:id] Fout bij verwijderen interventie ${id}:`, err);
        return res.status(500).json({ error: 'Database error: ' + err.message });
      }
      
      if (result.affectedRows === 0) {
        console.log(`[DELETE /interventies/:id] Interventie ${id} niet gevonden voor verwijderen`);
        return res.status(404).json({ error: 'Interventie niet gevonden' });
      }
      
      console.log(`[DELETE /interventies/:id] Interventie ${id} succesvol verwijderd`);
      res.json({ 
        success: true,
        message: 'Interventie succesvol verwijderd' 
      });
    });
  });
  
  // GET statistieken voor een toestel
  app.get('/api/toestellen/:id/statistics', (req, res) => {
    const { id } = req.params;
    
    console.log(`[GET /toestellen/:id/statistics] Ophalen statistieken voor toestel ${id}`);
    
    // Totale kosten ophalen
    const kostenSQL = 'SELECT SUM(kosten) as totale_kosten FROM interventies WHERE toestel_id = ?';
    
    db.query(kostenSQL, [id], (kostenErr, kostenResults) => {
      if (kostenErr) {
        console.error(`[GET /toestellen/:id/statistics] Fout bij ophalen kosten voor toestel ${id}:`, kostenErr);
        return res.status(500).json({ error: 'Database error: ' + kostenErr.message });
      }
      
      // Aantal interventies ophalen
      const aantalSQL = 'SELECT COUNT(*) as aantal_interventies FROM interventies WHERE toestel_id = ?';
      
      db.query(aantalSQL, [id], (aantalErr, aantalResults) => {
        if (aantalErr) {
          console.error(`[GET /toestellen/:id/statistics] Fout bij ophalen aantal interventies voor toestel ${id}:`, aantalErr);
          return res.status(500).json({ error: 'Database error: ' + aantalErr.message });
        }
        
        // Laatste interventie ophalen
        const laatsteSQL = 'SELECT datum FROM interventies WHERE toestel_id = ? ORDER BY datum DESC LIMIT 1';
        
        db.query(laatsteSQL, [id], (laatsteErr, laatsteResults) => {
          if (laatsteErr) {
            console.error(`[GET /toestellen/:id/statistics] Fout bij ophalen laatste interventie voor toestel ${id}:`, laatsteErr);
            return res.status(500).json({ error: 'Database error: ' + laatsteErr.message });
          }
          
          const statistics = {
            totale_kosten: kostenResults[0].totale_kosten || 0,
            aantal_interventies: aantalResults[0].aantal_interventies || 0,
            laatste_interventie: laatsteResults.length > 0 ? laatsteResults[0].datum : null
          };
          
          console.log(`[GET /toestellen/:id/statistics] Statistieken opgehaald voor toestel ${id}:`, statistics);
          res.json(statistics);
        });
      });
    });
  });
  
  // GET Rapportage data voor alle toestellen
app.get('/api/rapportage', (req, res) => {
  console.log(`[GET /api/rapportage] Ophalen rapportage data`);
  
  // Haal filters op uit query parameters
  const { jaar, locatie, merk } = req.query;
  
  console.log(`[GET /api/rapportage] Filters: jaar=${jaar || 'alle'}, locatie=${locatie || 'alle'}, merk=${merk || 'alle'}`);
  
  // Basisquery om alle toestellen op te halen, inclusief filters
  let toestelFilter = '';
  const filterParams = [];
  
  if (locatie) {
    toestelFilter += ' AND t.locatie = ?';
    filterParams.push(locatie);
  }
  
  if (merk) {
    toestelFilter += ' AND t.merk = ?';
    filterParams.push(merk);
  }
  
  const toestelSQL = `
    SELECT 
      t.id, t.beschrijving, t.serienummer, t.intern_nummer, 
      t.merk, t.type, t.type_motor, t.locatie, t.bouwjaar
    FROM toestellen t
    WHERE 1=1 ${toestelFilter}
    ORDER BY t.beschrijving ASC
  `;
  
  // Begin met ophalen van toestellen
  db.query(toestelSQL, filterParams, async (err, toestellen) => {
    if (err) {
      console.error('[GET /api/rapportage] Fout bij ophalen toestellen:', err);
      return res.status(500).json({ error: 'Database error: ' + err.message });
    }
    
    console.log(`[GET /api/rapportage] ${toestellen.length} toestellen opgehaald`);
    
    // Query voor interventies statistieken per toestel
    // Als er een jaar filter is, voeg dit dan toe
    let interventieFilter = '';
    const interventieParams = [];
    
    if (jaar) {
      interventieFilter = ' AND YEAR(i.datum) = ?';
      interventieParams.push(jaar);
    }
    
    const statsQuery = `
      SELECT 
        i.toestel_id,
        COUNT(i.id) as aantal_interventies,
        SUM(i.kosten) as totale_kosten,
        MAX(i.datum) as laatste_interventie
      FROM interventies i
      WHERE 1=1 ${interventieFilter}
      GROUP BY i.toestel_id
    `;
    
    // Haal statistieken op voor interventies
    db.query(statsQuery, interventieParams, (statsErr, stats) => {
      if (statsErr) {
        console.error('[GET /api/rapportage] Fout bij ophalen interventie statistieken:', statsErr);
        return res.status(500).json({ error: 'Database error: ' + statsErr.message });
      }
      
      // Maak een map van statistieken per toestel ID
      const statsMap = {};
      stats.forEach(stat => {
        statsMap[stat.toestel_id] = {
          aantal_interventies: stat.aantal_interventies,
          totale_kosten: stat.totale_kosten,
          laatste_interventie: stat.laatste_interventie
        };
      });
      
      // Voeg de statistieken toe aan elke toestel
      const toestellenMetStats = toestellen.map(toestel => {
        const toestelStats = statsMap[toestel.id] || {
          aantal_interventies: 0,
          totale_kosten: 0,
          laatste_interventie: null
        };
        
        return {
          ...toestel,
          stats: toestelStats
        };
      });
      
      // Query voor totale statistieken
      let totalStatsFilter = '';
      const totalStatsParams = [];
      
      if (jaar) {
        totalStatsFilter += ' AND YEAR(i.datum) = ?';
        totalStatsParams.push(jaar);
      }
      
      if (locatie || merk) {
        totalStatsFilter += ' AND i.toestel_id IN (SELECT id FROM toestellen t WHERE 1=1';
        
        if (locatie) {
          totalStatsFilter += ' AND t.locatie = ?';
          totalStatsParams.push(locatie);
        }
        
        if (merk) {
          totalStatsFilter += ' AND t.merk = ?';
          totalStatsParams.push(merk);
        }
        
        totalStatsFilter += ')';
      }
      
      const totalStatsQuery = `
        SELECT 
          COUNT(DISTINCT i.toestel_id) as aantal_toestellen,
          COUNT(i.id) as aantal_interventies,
          SUM(i.kosten) as totale_kosten
        FROM interventies i
        WHERE 1=1 ${totalStatsFilter}
      `;
      
      // Haal totale statistieken op
      db.query(totalStatsQuery, totalStatsParams, (totalStatsErr, totalStats) => {
        if (totalStatsErr) {
          console.error('[GET /api/rapportage] Fout bij ophalen totale statistieken:', totalStatsErr);
          return res.status(500).json({ error: 'Database error: ' + totalStatsErr.message });
        }
        
        // Query voor kosten per maand (voor de grafiek)
        let maandStatsFilter = '';
        const maandStatsParams = [];
        
        if (jaar) {
          maandStatsFilter += ' AND YEAR(i.datum) = ?';
          maandStatsParams.push(jaar);
        } else {
          // Als geen jaar is gespecificeerd, gebruik het huidige jaar
          const huidigJaar = new Date().getFullYear();
          maandStatsFilter += ' AND YEAR(i.datum) = ?';
          maandStatsParams.push(huidigJaar);
        }
        
        if (locatie || merk) {
          maandStatsFilter += ' AND i.toestel_id IN (SELECT id FROM toestellen t WHERE 1=1';
          
          if (locatie) {
            maandStatsFilter += ' AND t.locatie = ?';
            maandStatsParams.push(locatie);
          }
          
          if (merk) {
            maandStatsFilter += ' AND t.merk = ?';
            maandStatsParams.push(merk);
          }
          
          maandStatsFilter += ')';
        }
        
        const maandStatsQuery = `
          SELECT 
            MONTH(i.datum) as maand,
            SUM(i.kosten) as kosten
          FROM interventies i
          WHERE 1=1 ${maandStatsFilter}
          GROUP BY MONTH(i.datum)
          ORDER BY MONTH(i.datum)
        `;
        
        // Haal maandstatistieken op
        db.query(maandStatsQuery, maandStatsParams, (maandStatsErr, maandStats) => {
          if (maandStatsErr) {
            console.error('[GET /api/rapportage] Fout bij ophalen maandstatistieken:', maandStatsErr);
            return res.status(500).json({ error: 'Database error: ' + maandStatsErr.message });
          }
          
          // Zet maandstatistieken om naar bruikbaar formaat
          const maanden = ['Jan', 'Feb', 'Mar', 'Apr', 'Mei', 'Jun', 'Jul', 'Aug', 'Sep', 'Okt', 'Nov', 'Dec'];
          const kostenPerMaand = maanden.map((maand, index) => {
            const maandData = maandStats.find(m => m.maand === index + 1);
            return {
              x: maand,
              y: maandData ? parseFloat(maandData.kosten) : 0
            };
          });
          
          // Zet toestelstats om voor grafiek
          const kostenPerToestelTop10 = toestellenMetStats
            .filter(t => t.stats.totale_kosten > 0)
            .sort((a, b) => b.stats.totale_kosten - a.stats.totale_kosten)
            .slice(0, 10)
            .map(t => ({
              name: t.beschrijving,
              value: parseFloat(t.stats.totale_kosten)
            }));
          
          // Bouw het uiteindelijke response object
          const responseData = {
            toestellen: toestellenMetStats,
            stats: {
              totalDevices: toestellen.length,
              totalInterventions: totalStats[0].aantal_interventies || 0,
              totalCosts: parseFloat(totalStats[0].totale_kosten || 0),
              costsPerMonth: kostenPerMaand,
              costsPerDevice: kostenPerToestelTop10
            }
          };
          
          console.log(`[GET /api/rapportage] Rapportage data succesvol opgehaald`);
          res.json(responseData);
        });
      });
    });
  });
});

// --- SETUP Forecast Tabel ---
app.get('/api/setup-forecast-table', (req, res) => {
  const createTableSQL = `
    CREATE TABLE IF NOT EXISTS forecast_entries (
      id INT PRIMARY KEY AUTO_INCREMENT,
      data JSON NOT NULL,
      importDate DATETIME NOT NULL DEFAULT CURRENT_TIMESTAMP,
      original_date DATE NULL,
      case_label VARCHAR(255) NULL,
      INDEX idx_case_label (case_label)
    ) ENGINE=InnoDB DEFAULT CHARSET=utf8mb4;
  `;
  
  db.query(createTableSQL, (err) => {
    if (err) {
      console.error('Fout bij aanmaken forecast_entries tabel:', err);
      return res.status(500).json({ error: err.message });
    }
    
    // Voeg kolommen toe als ze nog niet bestaan (voor bestaande tabellen)
    const alterQueries = [
      'ALTER TABLE forecast_entries ADD COLUMN IF NOT EXISTS original_date DATE NULL',
      'ALTER TABLE forecast_entries ADD COLUMN IF NOT EXISTS case_label VARCHAR(255) NULL',
      'ALTER TABLE forecast_entries ADD INDEX IF NOT EXISTS idx_case_label (case_label)'
    ];
    
    let completed = 0;
    alterQueries.forEach((query, index) => {
      db.query(query, (alterErr) => {
        if (alterErr && !alterErr.message.includes('Duplicate')) {
          console.log(`Alter query ${index + 1} result:`, alterErr.message);
        }
        completed++;
        if (completed === alterQueries.length) {
          res.json({
            success: true,
            message: 'Tabel forecast_entries aangemaakt/bijgewerkt met original_date kolom'
          });
        }
      });
    });
  });
});

// --- Import Forecast Data ---
app.post('/api/forecast/import', (req, res) => {
  const { forecasts, updateExisting } = req.body;
  if (!Array.isArray(forecasts) || forecasts.length === 0) {
    return res.status(400).json({ error: 'Geen geldige forecast data ontvangen' });
  }

  // Als updateExisting flag is gezet, gebruik fallback update logica
  if (updateExisting) {
    console.log('[FORECAST IMPORT] Using fallback update mode for', forecasts.length, 'entries');
    
    // Begin transactie voor atomische updates
    db.beginTransaction((err) => {
      if (err) {
        console.error('Transaction error bij forecast fallback update:', err);
        return res.status(500).json({ error: 'Database transactie fout' });
      }

      let updatedCount = 0;
      let processedCount = 0;

      forecasts.forEach((forecast) => {
        const { caseLabel, history } = forecast;
        
        if (!caseLabel || !Array.isArray(history)) {
          console.warn('[FORECAST FALLBACK] Invalid forecast data:', forecast);
          processedCount++;
          if (processedCount === forecasts.length) {
            finishFallbackTransaction();
          }
          return;
        }

        // Zoek bestaande entry via case_label kolom (sneller dan JSON_EXTRACT)
        const findSql = 'SELECT id, data, original_date FROM forecast_entries WHERE case_label = ? ORDER BY importDate DESC LIMIT 1';
        
        db.query(findSql, [caseLabel], (err, rows) => {
          if (err) {
            console.error('Error finding forecast entry for fallback:', err);
            return db.rollback(() => {
              res.status(500).json({ error: 'Database error bij fallback zoeken' });
            });
          }

          if (rows.length > 0) {
            // Update bestaande entry
            const existingEntry = rows[0];
            let existingData = {};
            
            try {
              let raw = existingEntry.data;
              if (Buffer.isBuffer(raw)) {
                raw = raw.toString('utf8');
              }
              existingData = JSON.parse(raw);
            } catch (e) {
              console.error('Error parsing existing data for fallback:', e);
              processedCount++;
              if (processedCount === forecasts.length) {
                finishFallbackTransaction();
              }
              return;
            }

            const updatedData = {
              ...existingData,
              ...forecast,
              lastUpdated: new Date().toISOString()
            };

            const updateSql = 'UPDATE forecast_entries SET data = ? WHERE id = ?';
            const jsonData = JSON.stringify(updatedData);

            db.query(updateSql, [jsonData, existingEntry.id], (err, result) => {
              if (err) {
                console.error('Error updating forecast entry in fallback:', err);
                return db.rollback(() => {
                  res.status(500).json({ error: 'Database error bij fallback update' });
                });
              }

              if (result.affectedRows > 0) {
                updatedCount++;
                console.log(`[FORECAST FALLBACK] Updated ${caseLabel}`);
              }

              processedCount++;
              if (processedCount === forecasts.length) {
                finishFallbackTransaction();
              }
            });
          } else {
            // Entry niet gevonden, sla over
            console.warn('[FORECAST FALLBACK] Entry not found for:', caseLabel);
            processedCount++;
            if (processedCount === forecasts.length) {
              finishFallbackTransaction();
            }
          }
        });
      });

      function finishFallbackTransaction() {
        db.commit((err) => {
          if (err) {
            console.error('Commit error bij forecast fallback update:', err);
            return db.rollback(() => {
              res.status(500).json({ error: 'Database commit fout' });
            });
          }
          console.log(`[FORECAST FALLBACK] Successfully updated ${updatedCount} entries`);
          res.json({
            success: true,
            inserted: updatedCount,
            message: `${updatedCount} entries bijgewerkt via fallback`
          });
        });
      }
    });
    return;
  }

  // Normale insert logica met original_date en case_label
  const placeholders = forecasts.map(() => '(?, NOW(), ?, ?)').join(', ');
  const sql = `INSERT INTO forecast_entries (data, importDate, original_date, case_label) VALUES ${placeholders}`;
  const values = [];
  forecasts.forEach(item => {
    // Zorg ervoor dat datum in YYYY-MM-DD formaat is
    let dateFormatted = item.date || null;
    if (dateFormatted && dateFormatted.includes('T')) {
      dateFormatted = dateFormatted.split('T')[0];
    }
    
    values.push(
      JSON.stringify(item),
      dateFormatted, // original_date = datum van eerste import (alleen datum deel)
      item.caseLabel || null // case_label voor snelle lookup
    );
  });
  
  db.query(sql, values, (err, result) => {
    if (err) {
      console.error('Database error bij import forecast:', err);
      return res.status(500).json({ error: err.message });
    }
    res.json({
      success: true,
      inserted: result.affectedRows
    });
  });
});

// --- GET alle forecast entries ---
app.get('/api/forecast', (req, res) => {
  const sql = 'SELECT id, data, importDate, original_date, case_label FROM forecast_entries ORDER BY importDate DESC';
  db.query(sql, (err, rows) => {
    if (err) {
      console.error('Database error bij ophalen forecast entries:', err);
      return res.status(500).json({ error: err.message });
    }
    // Parse JSON field: support Buffer and JSON
    const result = rows.map(r => {
      let parsed = {};
      try {
        let raw = r.data;
        // Als r.data een Buffer is, zet om naar string
        if (Buffer.isBuffer(raw)) {
          raw = raw.toString('utf8');
        }
        // raw kan nu een JSON-string
        parsed = JSON.parse(raw);
      } catch (e) {
        console.error('Fout bij parsen forecast data JSON:', e, r.data);
      }
      
      // Zorg ervoor dat datums in YYYY-MM-DD formaat zijn
      let currentDate = parsed.date;
      if (currentDate && currentDate.includes('T')) {
        currentDate = currentDate.split('T')[0];
      }
      
      let originalDate = r.original_date;
      if (originalDate && typeof originalDate === 'string' && originalDate.includes('T')) {
        originalDate = originalDate.split('T')[0];
      }
      
      return {
        id: r.id,
        caseLabel: parsed.caseLabel || r.case_label,
        caseType: parsed.caseType,
        date: currentDate, // Huidige datum uit CSV (altijd meest recente)
        // Voeg eventuele historie toe als array
        history: Array.isArray(parsed.history) ? parsed.history : (parsed.history ? [parsed.history] : []),
        importDate: r.importDate,
        originalDate: originalDate // Oorspronkelijke datum uit database kolom
      };
    });
    res.json(result);
  });
});

