// 3) SHIFT REPORT (shiften + verpakte kisten)
app.get('/api/shift/report', (req, res) => {
  if (!req.session.user) 
    return res.status(401).json({ error: 'Not authenticated' });

  const date = req.query.date; // verwacht: 'YYYY-MM-DD'
  const shiftsQuery = `
    SELECT s.id, u.username, s.start_time, s.end_time,
           TIMESTAMPDIFF(MINUTE, s.start_time, s.end_time) AS minutes
    FROM Shift_airtec s
    JOIN users u ON s.user_id = u.id
    ${date ? 'WHERE DATE(s.start_time) = ?' : ''}
  `;
  const shiftsParams = date ? [date] : [];

  db.query(shiftsQuery, shiftsParams, (err, shifts) => {
    if (err) 
      return res.status(500).json({ error: 'DB error shift report' });

    // Nu de verpakte kisten per kistnummer
    const from = date + ' 00:00:00';
    const to   = date + ' 23:59:59';
    db.query(
      `SELECT kistnummer, SUM(quantity) AS total_quantity
       FROM packed_items_airtec
       WHERE date_packed BETWEEN ? AND ?
       GROUP BY kistnummer`,
      [from, to],
      (err2, packed) => {
        if (err2) 
          return res.status(500).json({ error: 'DB error packed report' });

        // Zet om naar een object { kistnummer: aantal, … }
        const packedObj = {};
        packed.forEach(r => packedObj[r.kistnummer] = r.total_quantity);

        res.json({ shifts, packed: packedObj });
      }
    );
  });
});


// Track Airtec tijdsregistratie
app.post('/api/airtec/track', async (req, res) => {
    const data = req.body;
    
    try {
        // Valideer vereiste velden
        const requiredFields = ['employee_id', 'employee_name', 'start_time'];
        for (const field of requiredFields) {
            if (!data[field]) {
                return res.status(400).json({ error: `Missing required field: ${field}` });
            }
        }
        
        // Verwerk data
        const startTime = new Date(data.start_time);
        const endTime = data.end_time ? new Date(data.end_time) : null;
        
        // Bereken duur in minuten als eindtijd aanwezig is
        let durationMinutes = null;
        if (endTime) {
            durationMinutes = (endTime - startTime) / (1000 * 60);
        }
        
        // Extract de datum uit de starttijd voor het log_date veld
        const logDate = startTime.toISOString().split('T')[0];
        
        // Database query
        const [result] = await db.query(`
            INSERT INTO airtec_time_tracking 
            (log_date, employee_id, employee_name, start_time, end_time, duration_minutes, box_type, quantity_packed, log_id) 
            VALUES (?, ?, ?, ?, ?, ?, ?, ?, ?)
        `, [
            logDate,
            data.employee_id,
            data.employee_name,
            startTime.toISOString().replace('T', ' ').substr(0, 19),
            endTime ? endTime.toISOString().replace('T', ' ').substr(0, 19) : null,
            durationMinutes,
            data.box_type || null,
            data.quantity_packed || 0,
            data.log_id || null
        ]);
        
        return res.json({
            success: true,
            id: result.insertId
        });
    } catch (error) {
        console.error('Error tracking Airtec time:', error);
        return res.status(500).json({ error: error.message });
    }
});

// Update Airtec tijdsregistratie (bijv. wanneer gestopt)
app.put('/api/airtec/track/:id', async (req, res) => {
    const id = req.params.id;
    const data = req.body;
    
    try {
        // Bouw updates
        const updates = [];
        const params = [];
        
        if (data.end_time) {
            const endTime = new Date(data.end_time);
            updates.push("end_time = ?");
            params.push(endTime.toISOString().replace('T', ' ').substr(0, 19));
            
            // Update duur als eindtijd is opgegeven
            const [record] = await db.query("SELECT start_time FROM airtec_time_tracking WHERE id = ?", [id]);
            
            if (record && record[0] && record[0].start_time) {
                const startTime = new Date(record[0].start_time);
                const durationMinutes = (endTime - startTime) / (1000 * 60);
                
                updates.push("duration_minutes = ?");
                params.push(durationMinutes);
            }
        }
        
        if (data.box_type !== undefined) {
            updates.push("box_type = ?");
            params.push(data.box_type);
        }
        
        if (data.quantity_packed !== undefined) {
            updates.push("quantity_packed = ?");
            params.push(data.quantity_packed);
        }
        
        if (updates.length === 0) {
            return res.status(400).json({ error: 'No fields to update' });
        }
        
        params.push(id); // Voor de WHERE clausule
        
        // Update de tracking record
        await db.query(
            `UPDATE airtec_time_tracking SET ${updates.join(', ')} WHERE id = ?`,
            params
        );
        
        return res.json({ success: true });
    } catch (error) {
        console.error('Error updating Airtec time tracking:', error);
        return res.status(500).json({ error: error.message });
    }
});

// Krijg rapport van Airtec tijdsregistraties
app.get('/api/airtec/report', async (req, res) => {
    try {
        const dateParam = req.query.date;
        const startDateParam = req.query.start_date;
        const endDateParam = req.query.end_date;
        
        let whereClause = "";
        const params = [];
        
        // Bouw de WHERE clausule op basis van de opgegeven parameters
        if (dateParam) {
            whereClause = "WHERE log_date = ?";
            params.push(dateParam);
        } else if (startDateParam && endDateParam) {
            whereClause = "WHERE log_date BETWEEN ? AND ?";
            params.push(startDateParam, endDateParam);
        } else if (startDateParam) {
            whereClause = "WHERE log_date >= ?";
            params.push(startDateParam);
        } else if (endDateParam) {
            whereClause = "WHERE log_date <= ?";
            params.push(endDateParam);
        }
        
        // Dagelijkse totalen query
        const [dailyTotals] = await db.query(`
            SELECT 
                log_date,
                COUNT(DISTINCT employee_id) AS total_employees,
                SUM(duration_minutes) AS total_minutes,
                COUNT(id) AS total_entries
            FROM airtec_time_tracking
            ${whereClause}
            GROUP BY log_date
            ORDER BY log_date DESC
        `, params);
        
        // Werknemer totalen query
        const [employeeTotals] = await db.query(`
            SELECT 
                employee_id,
                employee_name,
                SUM(duration_minutes) AS total_minutes,
                COUNT(id) AS total_entries
            FROM airtec_time_tracking
            ${whereClause}
            GROUP BY employee_id, employee_name
            ORDER BY total_minutes DESC
        `, params);
        
        // Kisttype totalen query
        const [boxTotals] = await db.query(`
            SELECT 
                box_type,
                SUM(quantity_packed) AS total_quantity,
                COUNT(id) AS total_entries
            FROM airtec_time_tracking
            ${whereClause}
            GROUP BY box_type
            ORDER BY total_quantity DESC
        `, params);
        
        return res.json({
            success: true,
            daily_totals: dailyTotals,
            employee_totals: employeeTotals,
            box_totals: boxTotals
        });
    } catch (error) {
        console.error('Error generating Airtec report:', error);
        return res.status(500).json({ error: error.message });
    }
});

// Voeg een update endpoint toe voor het bijwerken van de timelog state
app.post('/api/timelog/update_state', async (req, res) => {
    try {
        const { logs, box_types } = req.body;
        
        if (!logs || !Array.isArray(logs) || logs.length === 0) {
            return res.status(400).json({ error: 'No logs data provided' });
        }
        
        // Verwerk hier de box_types informatie indien nodig
        
        // Update actieve logs in database of doe andere nodige bewerkingen
        
        // Voor elke werknemer voeren we een sync uit met airtec_time_tracking
        for (const log of logs) {
            // Controleer of er al een record is met dit log_id en employee_id
            const [existing] = await db.query(
                `SELECT id FROM airtec_time_tracking 
                 WHERE log_id = ? AND employee_id = ?`,
                [log.log_id, log.employee_id]
            );
            
            if (existing && existing.length > 0) {
                // Update bestaande record
                await db.query(
                    `UPDATE airtec_time_tracking SET
                     end_time = ?,
                     box_type = ?,
                     quantity_packed = ?,
                     duration_minutes = ?
                     WHERE id = ?`,
                    [
                        log.end_time || null,
                        log.box_type || null,
                        log.quantity_packed || 0,
                        log.end_time ? 
                            (new Date(log.end_time) - new Date(log.start_time)) / (1000 * 60) : 
                            null,
                        existing[0].id
                    ]
                );
            } else {
                // Maak nieuwe record
                const startTime = new Date(log.start_time);
                const logDate = startTime.toISOString().split('T')[0];
                
                await db.query(
                    `INSERT INTO airtec_time_tracking 
                     (log_date, employee_id, employee_name, start_time, end_time, 
                      duration_minutes, box_type, quantity_packed, log_id)
                     VALUES (?, ?, ?, ?, ?, ?, ?, ?, ?)`,
                    [
                        logDate,
                        log.employee_id,
                        log.employee_name,
                        startTime.toISOString().replace('T', ' ').substr(0, 19),
                        log.end_time ? new Date(log.end_time).toISOString().replace('T', ' ').substr(0, 19) : null,
                        log.end_time ? 
                            (new Date(log.end_time) - new Date(log.start_time)) / (1000 * 60) : 
                            null,
                        log.box_type || null,
                        log.quantity_packed || 0,
                        log.log_id
                    ]
                );
            }
        }
        
        return res.json({ success: true });
    } catch (error) {
        console.error('Error updating timelog state:', error);
        return res.status(500).json({ error: error.message });
    }
});

