// Bulk update van prijzen
app.post('/api/item_prices/bulk', (req, res) => {
  const priceData = req.body;
  const itemNumbers = Object.keys(priceData);
  
  // Begin transactie
  db.beginTransaction((err) => {
    if (err) {
      console.error('Error starting transaction:', err);
      return res.status(500).json({ error: 'Database error' });
    }
    
    let completedItems = 0;
    let errors = [];
    
    // Voor elk item de prijs bijwerken
    itemNumbers.forEach(itemNumber => {
      const item = priceData[itemNumber];
      const materialsJson = JSON.stringify(item.materials || []);
      
      // Controleren of item_price al bestaat
      db.query('SELECT * FROM item_prices WHERE item_number = ?', [itemNumber], (err, results) => {
        if (err) {
          errors.push({ itemNumber, error: 'Database error' });
          return checkCompletion();
        }
        
        if (results.length > 0) {
          // Update bestaande prijs
          db.query(
            'UPDATE item_prices SET selling_price = ?, material_cost = ?, labor_cost = ?, materials = ? WHERE item_number = ?',
            [item.sellingPrice, item.materialCost, item.laborCost, materialsJson, itemNumber],
            (err) => {
              if (err) {
                errors.push({ itemNumber, error: 'Update error' });
              }
              checkCompletion();
            }
          );
        } else {
          // Maak nieuwe prijs aan
          db.query(
            'INSERT INTO item_prices (item_number, selling_price, material_cost, labor_cost, materials) VALUES (?, ?, ?, ?, ?)',
            [itemNumber, item.sellingPrice, item.materialCost, item.laborCost, materialsJson],
            (err) => {
              if (err) {
                errors.push({ itemNumber, error: 'Insert error' });
              }
              checkCompletion();
            }
          );
        }
      });
    });
    
    // Controleer of alle items verwerkt zijn
    function checkCompletion() {
      completedItems++;
      
      if (completedItems === itemNumbers.length) {
        if (errors.length > 0) {
          db.rollback(() => {
            res.status(500).json({ success: false, errors });
          });
        } else {
          db.commit(err => {
            if (err) {
              db.rollback(() => {
                res.status(500).json({ success: false, error: 'Commit error' });
              });
            } else {
              res.json({ success: true, message: 'All prices updated successfully' });
            }
          });
        }
      }
    }
  });
});

