app.post('/api/prepack_timelog/start', (req, res) => {
  const { type, werknemers } = req.body;
  const startTime = new Date();
  
  console.log('Start Prepack Tijd Registratie:', { type, werknemers, startTime });
  
  if (!type || !Array.isArray(werknemers) || werknemers.length === 0) {
    console.warn('Ongeldige invoer:', req.body);
    return res.status(400).json({ 
      success: false,
      message: 'Ongeldige invoer voor tijdsregistratie.' 
    });
  }
  
  db.query(
    'INSERT INTO prepack_timelogs (type, start_time, werknemer_ids) VALUES (?, NOW(), ?)',
    [type, JSON.stringify(werknemers)],
    (err, result) => {
      if (err) {
        console.error('Error starting prepack timelog:', err);
        return res.status(500).json({ 
          success: false, 
          message: 'Fout bij het starten van de tijdsregistratie.' 
        });
      }
      
      console.log('Prepack tijdsregistratie succesvol gestart:', result);
      res.json({ 
        success: true, 
        message: 'Tijdsregistratie gestart voor geselecteerde werknemers.',
        log_id: result.insertId
      });
    }
  );
});

// Prepack tijdsregistratie stoppen (met ondersteuning voor specifieke werknemer)
app.post('/api/prepack_timelog/:id/stop', (req, res) => {
  const { id } = req.params;
  const { employeeId } = req.body;
  
  console.log(`Stop Prepack tijdsregistratie voor log ID: ${id}, werknemer: ${employeeId || 'alle werknemers'}`);
  
  db.query('SELECT * FROM prepack_timelogs WHERE id = ?', [id], (err, results) => {
    if (err) {
      console.error('Error fetching prepack timelog:', err);
      return res.status(500).json({ 
        success: false, 
        message: 'Fout bij ophalen tijdsregistratie.' 
      });
    }
    
    if (results.length === 0) {
      return res.status(404).json({ 
        success: false, 
        message: 'Tijdsregistratie niet gevonden.' 
      });
    }
    
    const log = results[0];
    let currentEmployees = [];
    try {
      if (log.werknemer_ids && typeof log.werknemer_ids === 'string') {
        currentEmployees = JSON.parse(log.werknemer_ids);
      } else if (Array.isArray(log.werknemer_ids)) { // Fallback, though DB should store string
        currentEmployees = log.werknemer_ids;
      }
    } catch (parseError) {
      console.error(`Error parsing werknemer_ids from log ${id}:`, parseError, log.werknemer_ids);
      // Als parsen mislukt, kunnen we niet correct het aantal werknemers bepalen.
      // We kunnen kiezen voor een fallback (bv. 1) of een foutmelding geven.
      // Voor nu, laten we het aantal op 0 als het niet parseerbaar is,
      // wat resulteert in total_employee_minutes = 0.
    }
    const numberOfEmployeesForLog = currentEmployees.length > 0 ? currentEmployees.length : 0;

    if (employeeId) {
      try {
        const updatedWerknemers = currentEmployees.filter(empId => empId != employeeId);
        
        if (updatedWerknemers.length === 0) {
          db.query(
            `UPDATE prepack_timelogs SET 
               end_time = NOW(), 
               duration_minutes = TIMESTAMPDIFF(MINUTE, start_time, NOW()),
               total_employee_minutes = TIMESTAMPDIFF(MINUTE, start_time, NOW()) * ?,
               werknemer_ids = ? 
             WHERE id = ?`,
            [numberOfEmployeesForLog, JSON.stringify([]), id],
            (updateErr) => {
              if (updateErr) {
                console.error('Error stopping prepack timelog (last employee):', updateErr);
                return res.status(500).json({ 
                  success: false, 
                  message: 'Fout bij het stoppen van de tijdsregistratie.' 
                });
              }
              res.json({ 
                success: true,
                message: 'Laatste werknemer verwijderd, tijdsregistratie gestopt.' 
              });
            }
          );
        } else {
          db.query(
            'UPDATE prepack_timelogs SET werknemer_ids = ? WHERE id = ?',
            [JSON.stringify(updatedWerknemers), id],
            (updateErr) => {
              if (updateErr) {
                console.error('Error updating prepack timelog (remove employee):', updateErr);
                return res.status(500).json({ 
                  success: false, 
                  message: 'Fout bij het bijwerken van de tijdsregistratie.' 
                });
              }
              res.json({ 
                success: true,
                message: 'Werknemer verwijderd uit actieve tijdsregistratie.',
                remaining: updatedWerknemers.length
              });
            }
          );
        }
      } catch (error) { // Dit catch block is voor de JSON.parse binnen de employeeId if, maar die is nu naar boven verplaatst.
        console.error('Error processing employee IDs:', error);
        return res.status(500).json({ 
          success: false, 
          message: 'Fout bij verwerken van werknemers data.' 
        });
      }
    } else {
      db.query(
        `UPDATE prepack_timelogs SET 
           end_time = NOW(), 
           duration_minutes = TIMESTAMPDIFF(MINUTE, start_time, NOW()),
           total_employee_minutes = TIMESTAMPDIFF(MINUTE, start_time, NOW()) * ?
         WHERE id = ?`,
        [numberOfEmployeesForLog, id],
        (updateErr) => {
          if (updateErr) {
            console.error('Error stopping prepack timelog (all employees):', updateErr);
            return res.status(500).json({ 
              success: false, 
              message: 'Fout bij het stoppen van de tijdsregistratie.' 
            });
          }
          res.json({ 
            success: true,
            message: 'Tijdsregistratie succesvol gestopt voor alle werknemers.' 
          });
        }
      );
    }
  });
});

