// Meerdere materiaalprijzen opslaan/updaten
app.post('/api/material-prices', async (req, res) => {
    try {
      const pricesData = req.body;
      
      if (!Array.isArray(pricesData) || pricesData.length === 0) {
        return res.status(400).json({ error: 'Invalid data format. Expected array of price objects.' });
      }
      
      const results = [];
      const errors = [];
      
      // Process each price item
      for (const item of pricesData) {
        if (!item.material_description || typeof item.price !== 'number') {
          errors.push({
            error: 'Invalid price data. Missing required fields.',
            item: item
          });
          continue;
        }
        
        try {
          await new Promise((resolve, reject) => {
            db.query(
              `INSERT INTO material_prices 
               (material_description, price, calculation_type) 
               VALUES (?, ?, ?) 
               ON DUPLICATE KEY UPDATE 
               price = VALUES(price), 
               calculation_type = VALUES(calculation_type)`,
              [item.material_description, item.price, item.calculation_type || 'count'],
              (queryErr, result) => {
                if (queryErr) {
                  console.error('Error inserting/updating material price:', queryErr);
                  errors.push({
                    material_description: item.material_description,
                    error: queryErr.message
                  });
                  resolve();
                } else {
                  results.push({
                    material_description: item.material_description,
                    id: result.insertId || null,
                    updated: result.affectedRows > 0
                  });
                  resolve();
                }
              }
            );
          });
        } catch (err) {
          console.error('Error processing item:', err);
          errors.push({
            material_description: item.material_description,
            error: err.message
          });
        }
      }
      
      // Return results
      if (errors.length === 0) {
        res.json({ success: true, results });
      } else if (results.length === 0) {
        res.status(500).json({ 
          success: false, 
          error: 'All items failed to save',
          errors 
        });
      } else {
        res.json({ 
          success: true, 
          results,
          errors,
          message: `${results.length} items saved successfully, ${errors.length} failed`
        });
      }
      
    } catch (error) {
      console.error('Error saving material prices:', error);
      res.status(500).json({ error: error.message });
    }
  });

// Enkele materiaalprijs updaten
app.put('/api/material-prices/:description', (req, res) => {
    try {
      const { description } = req.params;
      const { price, calculation_type } = req.body;
      
      if (typeof price !== 'number') {
        return res.status(400).json({ error: 'Price must be a number' });
      }
      
      // Use callback-based query instead of Promise/await
      db.query(
        'UPDATE material_prices SET price = ?, calculation_type = ? WHERE material_description = ?',
        [price, calculation_type || 'count', description],
        (err, result) => {
          if (err) {
            console.error('Error updating material price:', err);
            return res.status(500).json({ error: err.message });
          }
          
          if (result.affectedRows === 0) {
            // If no row was updated, try to insert it
            db.query(
              'INSERT INTO material_prices (material_description, price, calculation_type) VALUES (?, ?, ?)',
              [description, price, calculation_type || 'count'],
              (insertErr, insertResult) => {
                if (insertErr) {
                  console.error('Error inserting material price:', insertErr);
                  return res.status(500).json({ error: insertErr.message });
                }
                
                res.json({ success: true, id: insertResult.insertId, created: true });
              }
            );
          } else {
            res.json({ success: true, updated: true });
          }
        }
      );
    } catch (error) {
      console.error('Error in material price endpoint:', error);
      res.status(500).json({ error: error.message });
    }
  });
  
  
  // API om materiaalkosten per artikelnummer op te halen
app.get('/api/prepack/material-costs', (req, res) => {
  const artikelNummers = req.query.items ? req.query.items.split(',') : [];
  
  if (artikelNummers.length === 0) {
    return res.json([]);
  }
  
  // Haal items op met bijbehorende stuklijst
  db.query(
    'SELECT naam, stuklijst, hout_kost, hulpstoffen FROM items WHERE naam IN (?)',
    [artikelNummers],
    (err, results) => {
      if (err) {
        console.error('Fout bij ophalen materiaalkosten:', err);
        return res.status(500).json({ error: err.message });
      }
      
      // Als er geen resultaten zijn, kijk in de material_prices tabel voor directe matches
      if (results.length === 0) {
        db.query(
          'SELECT material_description, price, calculation_type FROM material_prices WHERE material_description IN (?)',
          [artikelNummers],
          (err, materialResults) => {
            if (err) {
              console.error('Fout bij ophalen materiaalprijzen:', err);
              return res.status(500).json({ error: err.message });
            }
            
            const materialCosts = materialResults.map(item => ({
              artikelnummer: item.material_description,
              hout_kost: item.calculation_type === 'volume' ? item.price : 0,
              hulpstoffen: item.calculation_type !== 'volume' ? item.price : 0,
              materiaalkosten: item.price
            }));
            
            res.json(materialCosts);
          }
        );
        return;
      }
      
      // Verwerk de resultaten
      const itemsWithCosts = results.map(item => {
        let stuklijst = [];
        
        try {
          if (item.stuklijst && typeof item.stuklijst === 'string') {
            stuklijst = JSON.parse(item.stuklijst);
          } else if (Array.isArray(item.stuklijst)) {
            stuklijst = item.stuklijst;
          }
        } catch (e) {
          console.error(`Fout bij parsen stuklijst voor ${item.naam}:`, e);
        }
        
        return {
          artikelnummer: item.naam,
          hout_kost: item.hout_kost || 0,
          hulpstoffen: item.hulpstoffen || 0,
          materiaalkosten: (item.hout_kost || 0) + (item.hulpstoffen || 0),
          stuklijst: stuklijst
        };
      });
      
      res.json(itemsWithCosts);
    }
  );
});


// API endpoint om wijzigingen van de nacalculatie pagina op te slaan
