// API endpoint om wijzigingen van de nacalculatie pagina op te slaan
app.post('/api/prepack/save_changes', (req, res) => {
    try {
        const { changes } = req.body;
        
        if (!changes || !Array.isArray(changes) || changes.length === 0) {
            return res.status(400).json({ error: 'Geen wijzigingen ontvangen' });
        }
        
        console.log(`Verwerken van ${changes.length} wijzigingen`);
        
        let processedCount = 0;
        let successCount = 0;
        let errorCount = 0;
        const errors = [];
        
        // Functie om individuele wijzigingen te verwerken
        const processChange = (change) => {
            return new Promise((resolve) => {
                if (change.type === 'selling_price' || change.type === 'material_cost') {
                    // Update item prijzen in item_prices tabel
                    const column = change.type === 'selling_price' ? 'selling_price' : 'material_cost';
                    
                    // Eerst controleren of het item bestaat
                    db.query(
                        'SELECT id FROM item_prices WHERE item_number = ?',
                        [change.itemNumber],
                        (err, results) => {
                            if (err) {
                                console.error(`Fout bij zoeken item ${change.itemNumber}:`, err);
                                errors.push(`Fout bij item ${change.itemNumber}: ${err.message}`);
                                errorCount++;
                                resolve();
                                return;
                            }
                            
                            if (results.length > 0) {
                                // Update bestaand record
                                db.query(
                                    `UPDATE item_prices SET ${column} = ?, updated_at = CURRENT_TIMESTAMP WHERE item_number = ?`,
                                    [change.newValue, change.itemNumber],
                                    (updateErr) => {
                                        if (updateErr) {
                                            console.error(`Fout bij updaten ${change.itemNumber}:`, updateErr);
                                            errors.push(`Fout bij updaten ${change.itemNumber}: ${updateErr.message}`);
                                            errorCount++;
                                        } else {
                                            console.log(`Item ${change.itemNumber} ${column} geüpdatet naar ${change.newValue}`);
                                            successCount++;
                                        }
                                        resolve();
                                    }
                                );
                            } else {
                                // Maak nieuw record aan
                                const insertData = {
                                    item_number: change.itemNumber,
                                    [column]: change.newValue,
                                    created_at: new Date(),
                                    updated_at: new Date()
                                };
                                
                                // Zet de andere prijs op 0 als deze niet bestaat
                                if (change.type === 'selling_price') {
                                    insertData.material_cost = 0;
                                } else {
                                    insertData.selling_price = 0;
                                }
                                
                                db.query(
                                    'INSERT INTO item_prices SET ?',
                                    insertData,
                                    (insertErr) => {
                                        if (insertErr) {
                                            console.error(`Fout bij invoegen ${change.itemNumber}:`, insertErr);
                                            errors.push(`Fout bij invoegen ${change.itemNumber}: ${insertErr.message}`);
                                            errorCount++;
                                        } else {
                                            console.log(`Nieuw item ${change.itemNumber} aangemaakt met ${column} = ${change.newValue}`);
                                            successCount++;
                                        }
                                        resolve();
                                    }
                                );
                            }
                        }
                    );
                } else if (change.type === 'detailed_material_cost') {
                    // Handle detailed material costs (houtkosten and materiaalkosten)
                    const houtkosten = parseFloat(change.houtkosten) || 0;
                    const materiaalkosten = parseFloat(change.materiaalkosten) || 0;
                    const totalMaterialCost = parseFloat(change.totalMaterialCost) || (houtkosten + materiaalkosten);
                    
                    // Check if item exists
                    db.query(
                        'SELECT id FROM item_prices WHERE item_number = ?',
                        [change.itemNumber],
                        (err, results) => {
                            if (err) {
                                console.error(`Error checking item ${change.itemNumber}:`, err);
                                errors.push(`Error checking item ${change.itemNumber}: ${err.message}`);
                                errorCount++;
                                resolve();
                                return;
                            }
                            
                            if (results.length > 0) {
                                // Update existing record with both detailed and total costs
                                db.query(
                                    `UPDATE item_prices SET 
                                     houtkosten = ?, 
                                     materiaalkosten = ?, 
                                     material_cost = ?,
                                     updated_at = CURRENT_TIMESTAMP 
                                     WHERE item_number = ?`,
                                    [houtkosten, materiaalkosten, totalMaterialCost, change.itemNumber],
                                    (updateErr) => {
                                        if (updateErr) {
                                            console.error(`Error updating detailed costs for ${change.itemNumber}:`, updateErr);
                                            errors.push(`Error updating detailed costs for ${change.itemNumber}: ${updateErr.message}`);
                                            errorCount++;
                                        } else {
                                            console.log(`Updated detailed costs for ${change.itemNumber}: hout=${houtkosten}, materiaal=${materiaalkosten}, total=${totalMaterialCost}`);
                                            successCount++;
                                        }
                                        resolve();
                                    }
                                );
                            } else {
                                // Create new record
                                db.query(
                                    `INSERT INTO item_prices 
                                     (item_number, houtkosten, materiaalkosten, material_cost, selling_price, created_at, updated_at) 
                                     VALUES (?, ?, ?, ?, 0, CURRENT_TIMESTAMP, CURRENT_TIMESTAMP)`,
                                    [change.itemNumber, houtkosten, materiaalkosten, totalMaterialCost],
                                    (insertErr) => {
                                        if (insertErr) {
                                            console.error(`Error inserting detailed costs for ${change.itemNumber}:`, insertErr);
                                            errors.push(`Error inserting detailed costs for ${change.itemNumber}: ${insertErr.message}`);
                                            errorCount++;
                                        } else {
                                            console.log(`Created new record with detailed costs for ${change.itemNumber}`);
                                            successCount++;
                                        }
                                        resolve();
                                    }
                                );
                            }
                        }
                    );
                } else if (change.type === 'labor_hours') {
                    // Voor arbeidsuren, update of creëer een record in een dedicated tabel
                    // Voor nu slaan we dit over omdat arbeidsuren berekend worden uit tijdsregistraties
                    console.log(`Arbeidsuren wijziging voor ${change.date}: ${change.oldValue} -> ${change.newValue}`);
                    
                    // We kunnen dit loggen in een audit tabel of gewoon success tellen
                    successCount++;
                    resolve();
                } else {
                    console.warn(`Onbekend wijzigingstype: ${change.type}`);
                    errorCount++;
                    resolve();
                }
            });
        };
        
        // Verwerk alle wijzigingen parallel
        Promise.all(changes.map(processChange)).then(() => {
            const response = {
                success: true,
                message: `${successCount} wijzigingen succesvol verwerkt, ${errorCount} fouten`,
                details: {
                    total: changes.length,
                    success: successCount,
                    errors: errorCount
                }
            };
            
            if (errors.length > 0) {
                response.errors = errors;
            }
            
            console.log('Alle wijzigingen verwerkt:', response);
            res.json(response);
        });
        
    } catch (error) {
        console.error('Fout bij verwerken wijzigingen:', error);
        res.status(500).json({ 
            error: 'Server fout bij verwerken wijzigingen', 
            details: error.message 
        });
    }
});
// Update detailed material costs (houtkosten and materiaalkosten)
app.post('/api/prepack/save_detailed_costs', (req, res) => {
    try {
        const { itemNumber, houtkosten, materiaalkosten } = req.body;
        
        if (!itemNumber) {
            return res.status(400).json({ error: 'Item number is required' });
        }
        
        console.log(`Updating detailed costs for item ${itemNumber}: hout=${houtkosten}, materiaal=${materiaalkosten}`);
        
        // Check if item exists
        db.query(
            'SELECT id FROM item_prices WHERE item_number = ?',
            [itemNumber],
            (err, results) => {
                if (err) {
                    console.error(`Error checking item ${itemNumber}:`, err);
                    return res.status(500).json({ error: 'Database error' });
                }
                
                const houtValue = parseFloat(houtkosten) || 0;
                const materiaalValue = parseFloat(materiaalkosten) || 0;
                const totalMaterialCost = houtValue + materiaalValue;
                
                if (results.length > 0) {
                    // Update existing record
                    db.query(
                        `UPDATE item_prices SET 
                         houtkosten = ?, 
                         materiaalkosten = ?, 
                         material_cost = ?,
                         updated_at = CURRENT_TIMESTAMP 
                         WHERE item_number = ?`,
                        [houtValue, materiaalValue, totalMaterialCost, itemNumber],
                        (updateErr) => {
                            if (updateErr) {
                                console.error(`Error updating detailed costs for ${itemNumber}:`, updateErr);
                                return res.status(500).json({ error: 'Update failed' });
                            } else {
                                console.log(`Updated detailed costs for ${itemNumber}`);
                                res.json({ 
                                    success: true, 
                                    message: `Detailed costs updated for ${itemNumber}`,
                                    houtkosten: houtValue,
                                    materiaalkosten: materiaalValue,
                                    total_material_cost: totalMaterialCost
                                });
                            }
                        }
                    );
                } else {
                    // Create new record
                    db.query(
                        `INSERT INTO item_prices 
                         (item_number, houtkosten, materiaalkosten, material_cost, selling_price, created_at, updated_at) 
                         VALUES (?, ?, ?, ?, 0, CURRENT_TIMESTAMP, CURRENT_TIMESTAMP)`,
                        [itemNumber, houtValue, materiaalValue, totalMaterialCost],
                        (insertErr) => {
                            if (insertErr) {
                                console.error(`Error inserting detailed costs for ${itemNumber}:`, insertErr);
                                return res.status(500).json({ error: 'Insert failed' });
                            } else {
                                console.log(`Created new record with detailed costs for ${itemNumber}`);
                                res.json({ 
                                    success: true, 
                                    message: `New record created with detailed costs for ${itemNumber}`,
                                    houtkosten: houtValue,
                                    materiaalkosten: materiaalValue,
                                    total_material_cost: totalMaterialCost
                                });
                            }
                        }
                    );
                }
            }
        );
        
    } catch (error) {
        console.error('Error in save_detailed_costs endpoint:', error);
        res.status(500).json({ error: 'Internal server error', details: error.message });
    }
});

// Direct query to order_items table for material costs
app.get('/api/order_items', (req, res) => {
    const itemsParam = req.query.items;
    
    if (!itemsParam) {
        return res.status(400).json({ message: 'Items parameter is required' });
    }
    
    const items = itemsParam.split(',');
    const placeholders = items.map(() => '?').join(',');
    
    // Query focuses on just the essential columns you highlighted
    const query = `
        SELECT 
            item_nummer, 
            item_naam,
            hout_kost, 
            hulpstoffen
        FROM order_items 
        WHERE item_nummer IN (${placeholders}) OR item_naam IN (${placeholders})
    `;
    
    const params = [...items, ...items];
    
    db.query(query, params, (err, results) => {
        if (err) {
            console.error('Error fetching from order_items:', err);
            return res.status(500).json({ message: 'Database error' });
        }
        
        res.json(results);
    });
});
  
app.post('/api/item_prices/upsert_costs', (req, res) => {
    try {
        const items = req.body.items;
        
        if (!items || !Array.isArray(items) || items.length === 0) {
            return res.status(400).json({ error: 'No valid items provided' });
        }
        
        console.log(`Processing ${items.length} items for price updates`);
        
        // First, check if the columns exist, and alter the table if needed
        db.query(
            `SHOW COLUMNS FROM item_prices LIKE 'houtkosten'`, 
            (err, houtkostenResults) => {
                if (err) {
                    console.error('Error checking item_prices schema:', err);
                    return res.status(500).json({ error: 'Database error checking schema', details: err.message });
                }
                
                // Check if materiaalkosten column exists
                db.query(
                    `SHOW COLUMNS FROM item_prices LIKE 'materiaalkosten'`, 
                    (err, materiaalkostenResults) => {
                        if (err) {
                            console.error('Error checking item_prices schema:', err);
                            return res.status(500).json({ error: 'Database error checking schema', details: err.message });
                        }
                        
                        const alterTableQueries = [];
                        
                        // Add columns if they don't exist
                        if (houtkostenResults.length === 0) {
                            alterTableQueries.push('ADD COLUMN houtkosten DECIMAL(10,2) DEFAULT 0');
                        }
                        
                        if (materiaalkostenResults.length === 0) {
                            alterTableQueries.push('ADD COLUMN materiaalkosten DECIMAL(10,2) DEFAULT 0');
                        }
                        
                        // Also check for created_at and updated_at
                        alterTableQueries.push('ADD COLUMN IF NOT EXISTS created_at TIMESTAMP DEFAULT CURRENT_TIMESTAMP');
                        alterTableQueries.push('ADD COLUMN IF NOT EXISTS updated_at TIMESTAMP DEFAULT CURRENT_TIMESTAMP ON UPDATE CURRENT_TIMESTAMP');
                        
                        if (alterTableQueries.length > 0) {
                            // Execute ALTER TABLE query
                            const alterQuery = `ALTER TABLE item_prices ${alterTableQueries.join(', ')}`;
                            console.log('Altering table:', alterQuery);
                            
                            db.query(alterQuery, (alterErr) => {
                                if (alterErr) {
                                    console.error('Error altering item_prices table:', alterErr);
                                    return res.status(500).json({ error: 'Failed to update database schema', details: alterErr.message });
                                }
                                
                                console.log('Successfully altered item_prices table, now processing items');
                                processItems(items, res);
                            });
                        } else {
                            // Columns already exist, proceed with updates
                            processItems(items, res);
                        }
                    }
                );
            }
        );
        
    } catch (error) {
        console.error('Error in upsert_costs endpoint:', error);
        res.status(500).json({ error: 'Internal server error', details: error.message });
    }
});

// Helper function to process items
function processItems(items, res) {
    let successCount = 0;
    let errorCount = 0;
    let processedCount = 0;
    let errors = [];
    
    // Process each item
    const processItem = (index) => {
        if (index >= items.length) {
            // All items processed, send response
            return res.status(200).json({ 
                success: true, 
                message: `Processed ${processedCount} items: ${successCount} updated/inserted, ${errorCount} errors`,
                errors: errors.length > 0 ? errors : undefined
            });
        }
        
        const item = items[index];
        if (!item.item_number || (typeof item.houtkosten === 'undefined' && typeof item.materiaalkosten === 'undefined')) {
            processedCount++;
            console.log(`Skipping item at index ${index}: missing required data`);
            errors.push(`Item at index ${index}: missing required data`);
            return processItem(index + 1); // Skip this item
        }
        
        // Check if item exists
        db.query(
            'SELECT id FROM item_prices WHERE item_number = ?',
            [item.item_number],
            (err, results) => {
                if (err) {
                    console.error(`Error checking existence for item ${item.item_number}:`, err);
                    errorCount++;
                    processedCount++;
                    errors.push(`Error checking item ${item.item_number}: ${err.message}`);
                    return processItem(index + 1); // Continue with next item
                }
                
                const houtkosten = typeof item.houtkosten !== 'undefined' ? parseFloat(item.houtkosten) : 0;
                const materiaalkosten = typeof item.materiaalkosten !== 'undefined' ? parseFloat(item.materiaalkosten) : 0;
                
                if (results.length > 0) {
                    // Item exists, update it                        
                    db.query(
                        `UPDATE item_prices SET houtkosten = ?, materiaalkosten = ? WHERE item_number = ?`,
                        [houtkosten, materiaalkosten, item.item_number],
                        (updateErr) => {
                            if (updateErr) {
                                console.error(`Error updating ${item.item_number}:`, updateErr);
                                errorCount++;
                                errors.push(`Error updating item ${item.item_number}: ${updateErr.message}`);
                            } else {
                                console.log(`Updated prices for ${item.item_number}`);
                                successCount++;
                            }
                            processedCount++;
                            processItem(index + 1); // Continue with next item
                        }
                    );
                } else {
                    // Item doesn't exist, insert it
                    db.query(
                        'INSERT INTO item_prices (item_number, houtkosten, materiaalkosten) VALUES (?, ?, ?)',
                        [item.item_number, houtkosten, materiaalkosten],
                        (insertErr) => {
                            if (insertErr) {
                                console.error(`Error inserting ${item.item_number}:`, insertErr);
                                errorCount++;
                                errors.push(`Error inserting item ${item.item_number}: ${insertErr.message}`);
                            } else {
                                console.log(`Inserted new prices for ${item.item_number}`);
                                successCount++;
                            }
                            processedCount++;
                            processItem(index + 1); // Continue with next item
                        }
                    );
                }
            }
        );
    };
    
    // Start processing items
    processItem(0);
}

