// Get all tasks
app.get('/api/task-management/list', isAuthenticated, async (req, res) => {
    try {
        const query = `
            SELECT 
                t.*,
                u1.username as creator_name,
                u1.full_name as creator_full_name,
                u2.username as assignee_name,
                u2.full_name as assignee_full_name,
                DATE_FORMAT(t.createdAt, '%Y-%m-%d %H:%i:%s') as createdAt,
                DATE_FORMAT(t.dueDate, '%Y-%m-%d %H:%i:%s') as due_date
            FROM tasks t
            LEFT JOIN users u1 ON t.createdBy = u1.id
            LEFT JOIN users u2 ON t.assignedTo = u2.id
            ORDER BY t.createdAt DESC
        `;
        
        db.query(query, (err, tasks) => {
            if (err) {
                console.error('Error fetching tasks:', err);
                return res.status(500).json({ error: 'Fout bij het ophalen van taken' });
            }
            
            // Process tasks to include watchers
            const taskIds = tasks.map(t => t.id);
            if (taskIds.length === 0) {
                return res.json([]);
            }
            
            const watchersQuery = `
                SELECT tw.task_id, tw.user_id, u.username, u.full_name
                FROM task_watchers tw
                JOIN users u ON tw.user_id = u.id
                WHERE tw.task_id IN (${taskIds.map(() => '?').join(',')})
            `;
            
            db.query(watchersQuery, taskIds, (watchErr, watchers) => {
                if (watchErr) {
                    console.error('Error fetching watchers:', watchErr);
                    // Continue without watchers if there's an error
                    return res.json(tasks.map(task => ({ ...task, watchers: [] })));
                }
                
                // Group watchers by task_id
                const watchersByTask = {};
                watchers.forEach(watcher => {
                    if (!watchersByTask[watcher.task_id]) {
                        watchersByTask[watcher.task_id] = [];
                    }
                    watchersByTask[watcher.task_id].push(watcher.user_id);
                });
                
                // Add watchers to tasks
                const tasksWithWatchers = tasks.map(task => ({
                    ...task,
                    watchers: watchersByTask[task.id] || []
                }));
                
                res.json(tasksWithWatchers);
            });
        });
    } catch (error) {
        console.error('Error fetching tasks:', error);
        res.status(500).json({ error: 'Fout bij het ophalen van taken' });
    }
});

