// Create new task
app.post('/api/task-management/create', isAuthenticated, async (req, res) => {    try {        const { title, description, status, priority, task_type, assignedTo, due_date } = req.body;        const createdBy = req.session.user.id;                if (!title || !title.trim()) {            return res.status(400).json({ error: 'Titel is verplicht' });        }                const query = `            INSERT INTO tasks (title, description, status, priority, task_type, assignedTo, dueDate, createdBy, createdAt)            VALUES (?, ?, ?, ?, ?, ?, ?, ?, NOW())        `;                const values = [            title.trim(),            description || null,            status || 'todo',            priority || 'medium',            task_type || 'task',            assignedTo || null,            due_date || null,            createdBy        ];
        
        db.query(query, values, async (err, result) => {
            if (err) {
                console.error('Error creating task:', err);
                return res.status(500).json({ error: 'Fout bij het aanmaken van taak' });
            }
            
            // Fetch the created task
            const fetchQuery = `
                SELECT 
                    t.*,
                    u1.username as creator_name,
                    u1.full_name as creator_full_name,
                    u2.username as assignee_name,
                    u2.full_name as assignee_full_name,
                    DATE_FORMAT(t.createdAt, '%Y-%m-%d %H:%i:%s') as createdAt,
                    DATE_FORMAT(t.dueDate, '%Y-%m-%d %H:%i:%s') as due_date
                FROM tasks t
                LEFT JOIN users u1 ON t.createdBy = u1.id
                LEFT JOIN users u2 ON t.assignedTo = u2.id
                WHERE t.id = ?
            `;
            
            db.query(fetchQuery, [result.insertId], async (fetchErr, tasks) => {
                if (fetchErr || tasks.length === 0) {
                    return res.status(500).json({ error: 'Error fetching created task' });
                }
                
                const newTask = { ...tasks[0], watchers: [] };
                
                // Log activity
                db.query(
                    'INSERT INTO task_activities (task_id, user_id, action, created_at) VALUES (?, ?, ?, NOW())',
                    [result.insertId, createdBy, 'created']
                );
                
                // Send assignment notification if task is assigned
                if (assignedTo && assignedTo !== createdBy) {
                    try {
                        const userInfo = await getUserEmailAndName(assignedTo);
                        const shouldSend = await shouldSendNotification(assignedTo, 'task_assigned');
                        
                        if (shouldSend && userInfo.email) {
                            await sendTaskNotification('task_assigned', {
                                title: newTask.title,
                                description: newTask.description,
                                priority: newTask.priority,
                                status: newTask.status,
                                due_date: newTask.due_date
                            }, userInfo.email, userInfo.name);
                        }
                    } catch (error) {
                        console.error('Error sending assignment notification:', error);
                    }
                }
                
                // Emit to all connected clients
                io.emit('task:created', newTask);
                
                res.status(201).json(newTask);
            });
        });
    } catch (error) {
        console.error('Error creating task:', error);
        res.status(500).json({ error: 'Fout bij het aanmaken van taak' });
    }
});

