app.put('/api/task-management/:id/update', isAuthenticated, async (req, res) => {    try {        const taskId = req.params.id;        const { title, description, status, priority, task_type, assignedTo, due_date } = req.body;        const userId = req.session.user.id;                if (!title || !title.trim()) {            return res.status(400).json({ error: 'Titel is verplicht' });        }                const query = `            UPDATE tasks             SET title = ?, description = ?, status = ?, priority = ?, task_type = ?, assignedTo = ?, dueDate = ?            WHERE id = ?        `;                const values = [            title.trim(),            description || null,            status || 'todo',            priority || 'medium',            task_type || 'task',            assignedTo || null,            due_date || null,            taskId        ];
        
        db.query(query, values, (err, result) => {
            if (err) {
                console.error('Error updating task:', err);
                return res.status(500).json({ error: 'Fout bij het bijwerken van taak' });
            }
            
            if (result.affectedRows === 0) {
                return res.status(404).json({ error: 'Taak niet gevonden' });
            }
            
            // Log activity
            db.query(
                'INSERT INTO task_activities (task_id, user_id, action, created_at) VALUES (?, ?, ?, NOW())',
                [taskId, userId, 'updated']
            );
            
            // Fetch updated task
            const fetchQuery = `
                SELECT 
                    t.*,
                    u1.username as creator_name,
                    u1.full_name as creator_full_name,
                    u2.username as assignee_name,
                    u2.full_name as assignee_full_name,
                    DATE_FORMAT(t.createdAt, '%Y-%m-%d %H:%i:%s') as createdAt,
                    DATE_FORMAT(t.dueDate, '%Y-%m-%d %H:%i:%s') as due_date
                FROM tasks t
                LEFT JOIN users u1 ON t.createdBy = u1.id
                LEFT JOIN users u2 ON t.assignedTo = u2.id
                WHERE t.id = ?
            `;
            
            db.query(fetchQuery, [taskId], (fetchErr, tasks) => {
                if (fetchErr || tasks.length === 0) {
                    return res.status(500).json({ error: 'Error fetching updated task' });
                }
                
                const updatedTask = { ...tasks[0], watchers: [] };
                
                // Emit to all connected clients
                io.emit('task:updated', updatedTask);
                
                res.json(updatedTask);
            });
        });
    } catch (error) {
        console.error('Error updating task:', error);
        res.status(500).json({ error: 'Fout bij het bijwerken van taak' });
    }
});

