app.delete('/api/task-management/:id/delete', isAuthenticated, async (req, res) => {
    try {
        const taskId = req.params.id;
        const userId = req.session.user.id;
        const userRole = req.session.user.role || 'member';
        
        // Check if user has permission (only admin or creator can delete)
        db.query(
            'SELECT createdBy FROM tasks WHERE id = ?',
            [taskId],
            (err, tasks) => {
                if (err) {
                    console.error('Error checking task:', err);
                    return res.status(500).json({ error: 'Database error' });
                }
                
                if (tasks.length === 0) {
                    return res.status(404).json({ error: 'Taak niet gevonden' });
                }
                
                if (userRole !== 'admin' && tasks[0].createdBy !== userId) {
                    return res.status(403).json({ error: 'Geen toestemming om deze taak te verwijderen' });
                }
                
                // Delete task (cascades to related tables)
                db.query('DELETE FROM tasks WHERE id = ?', [taskId], (deleteErr) => {
                    if (deleteErr) {
                        console.error('Error deleting task:', deleteErr);
                        return res.status(500).json({ error: 'Fout bij het verwijderen van taak' });
                    }
                    
                    // Emit to all connected clients
                    io.emit('task:deleted', taskId);
                    
                    res.json({ success: true, message: 'Taak verwijderd' });
                });
            }
        );
    } catch (error) {
        console.error('Error deleting task:', error);
        res.status(500).json({ error: 'Fout bij het verwijderen van taak' });
    }
});

