// Update task watchers
// Update task watchers
app.put('/api/task-management/:id/watchers', isAuthenticated, async (req, res) => {
    try {
        const taskId = req.params.id;
        const { watchers } = req.body;
        const userId = req.session.user.id;
        
        if (!Array.isArray(watchers)) {
            return res.status(400).json({ error: 'Watchers moet een array zijn' });
        }
        
        // Remove duplicates and filter out invalid IDs
        const uniqueWatchers = [...new Set(watchers.filter(id => id && !isNaN(id)))];
        
        // First, remove all existing watchers for this task
        db.query('DELETE FROM task_watchers WHERE task_id = ?', [taskId], (deleteErr) => {
            if (deleteErr) {
                console.error('Error removing existing watchers:', deleteErr);
                return res.status(500).json({ error: 'Fout bij bijwerken watchers' });
            }
            
            // If no watchers to add, return success
            if (uniqueWatchers.length === 0) {
                return res.json({ 
                    success: true, 
                    message: 'Watchers bijgewerkt',
                    watchers: []
                });
            }
            
            // Insert new watchers using INSERT IGNORE to prevent duplicates
            const insertValues = uniqueWatchers.map(watcherId => [taskId, watcherId]);
            const insertQuery = 'INSERT IGNORE INTO task_watchers (task_id, user_id) VALUES ?';
            
            db.query(insertQuery, [insertValues], (insertErr) => {
                if (insertErr) {
                    console.error('Error inserting watchers:', insertErr);
                    return res.status(500).json({ error: 'Fout bij bijwerken watchers' });
                }
                
                // Log activity
                db.query(
                    'INSERT INTO task_activities (task_id, user_id, action, created_at) VALUES (?, ?, ?, NOW())',
                    [taskId, userId, 'watchers_updated']
                );
                
                res.json({ 
                    success: true, 
                    message: 'Watchers bijgewerkt',
                    watchers: uniqueWatchers
                });
            });
        });
    } catch (error) {
        console.error('Error updating watchers:', error);
        res.status(500).json({ error: 'Fout bij bijwerken watchers' });
    }
});

