// Save filter
app.post('/api/task-management/saved-filters', isAuthenticated, async (req, res) => {
    try {
        const userId = req.session.user.id;
        const { name, filterData, isDefault = false } = req.body;
        
        if (!name || !name.trim()) {
            return res.status(400).json({ error: 'Filter naam is verplicht' });
        }
        
        if (!filterData) {
            return res.status(400).json({ error: 'Filter data is verplicht' });
        }
        
        // If setting as default, unset other defaults first
        if (isDefault) {
            db.query('UPDATE task_saved_filters SET is_default = FALSE WHERE user_id = ?', [userId]);
        }
        
        const query = `
            INSERT INTO task_saved_filters (user_id, name, filter_data, is_default)
            VALUES (?, ?, ?, ?)
        `;
        
        db.query(query, [userId, name.trim(), JSON.stringify(filterData), isDefault], (err, result) => {
            if (err) {
                console.error('Error saving filter:', err);
                return res.status(500).json({ error: 'Fout bij opslaan van filter' });
            }
            
            res.json({ 
                id: result.insertId, 
                name: name.trim(), 
                filter_data: filterData, 
                is_default: isDefault,
                message: 'Filter opgeslagen' 
            });
        });
    } catch (error) {
        console.error('Error saving filter:', error);
        res.status(500).json({ error: 'Fout bij opslaan van filter' });
    }
});

