// Create subtask
app.post('/api/task-management/:taskId/subtasks', isAuthenticated, async (req, res) => {
    try {
        const parentTaskId = req.params.taskId;
        const { title, description, priority, assignedTo, due_date } = req.body;
        const createdBy = req.session.user.id;
        
        if (!title || !title.trim()) {
            return res.status(400).json({ error: 'Titel is verplicht' });
        }
        
        const query = `
            INSERT INTO task_subtasks (parent_task_id, title, description, priority, assignedTo, due_date, created_by)
            VALUES (?, ?, ?, ?, ?, ?, ?)
        `;
        
        db.query(query, [parentTaskId, title.trim(), description, priority || 'medium', assignedTo, due_date, createdBy], (err, result) => {
            if (err) {
                console.error('Error creating subtask:', err);
                return res.status(500).json({ error: 'Fout bij aanmaken van subtaak' });
            }
            
            // Send notification if assigned
            if (assignedTo) {
                queueEmailNotification(assignedTo, 'assignment', parentTaskId, {
                    subtaskTitle: title,
                    assignedBy: req.session.user.full_name || req.session.user.username
                });
            }
            
            res.json({ 
                id: result.insertId, 
                message: 'Subtaak aangemaakt',
                parent_task_id: parentTaskId,
                title: title.trim(),
                description,
                priority: priority || 'medium',
                assignedTo,
                due_date,
                status: 'todo',
                created_by: createdBy
            });
        });
    } catch (error) {
        console.error('Error creating subtask:', error);
        res.status(500).json({ error: 'Fout bij aanmaken van subtaak' });
    }
});

