// Get all milestones
app.get('/api/task-management/milestones', isAuthenticated, async (req, res) => {
    try {
        const query = `
            SELECT m.*, 
                   u.username as creator_name, u.full_name as creator_full_name,
                   COUNT(tmr.task_id) as task_count,
                   COUNT(CASE WHEN t.status = 'done' THEN 1 END) as completed_tasks
            FROM task_milestones m
            LEFT JOIN users u ON m.created_by = u.id
            LEFT JOIN task_milestone_relations tmr ON m.id = tmr.milestone_id
            LEFT JOIN tasks t ON tmr.task_id = t.id
            GROUP BY m.id
            ORDER BY m.due_date ASC
        `;
        
        db.query(query, (err, milestones) => {
            if (err) {
                console.error('Error fetching milestones:', err);
                return res.status(500).json({ error: 'Fout bij ophalen van mijlpalen' });
            }
            
            res.json(milestones);
        });
    } catch (error) {
        console.error('Error fetching milestones:', error);
        res.status(500).json({ error: 'Fout bij ophalen van mijlpalen' });
    }
});

