// Advanced search endpoint
app.post('/api/task-management/search', isAuthenticated, async (req, res) => {
    try {
        const { query, searchIn, filters } = req.body;
        
        if (!query || !query.trim()) {
            return res.status(400).json({ error: 'Zoekterm is verplicht' });
        }
        
        const searchTerm = `%${query.trim()}%`;
        let whereConditions = [];
        let queryParams = [];
        
        // Build search conditions based on searchIn options
        let searchConditions = [];
        
        if (searchIn.title) {
            searchConditions.push('t.title LIKE ?');
            queryParams.push(searchTerm);
        }
        
        if (searchIn.description) {
            searchConditions.push('t.description LIKE ?');
            queryParams.push(searchTerm);
        }
        
        if (searchIn.comments) {
            searchConditions.push(`EXISTS (
                SELECT 1 FROM task_comments tc 
                WHERE tc.task_id = t.id AND tc.text LIKE ?
            )`);
            queryParams.push(searchTerm);
        }
        
        if (searchIn.attachments) {
            searchConditions.push(`EXISTS (
                SELECT 1 FROM task_attachments ta 
                WHERE ta.task_id = t.id AND ta.original_filename LIKE ?
            )`);
            queryParams.push(searchTerm);
        }
        
        if (searchConditions.length > 0) {
            whereConditions.push(`(${searchConditions.join(' OR ')})`);
        }
        
        // Add filter conditions
        if (filters.status) {
            whereConditions.push('t.status = ?');
            queryParams.push(filters.status);
        }
        
        if (filters.priority) {
            whereConditions.push('t.priority = ?');
            queryParams.push(filters.priority);
        }
        
        if (filters.type) {
            whereConditions.push('t.task_type = ?');
            queryParams.push(filters.type);
        }
        
        if (filters.assignee) {
            whereConditions.push('t.assignedTo = ?');
            queryParams.push(filters.assignee);
        }
        
        if (filters.dateFrom) {
            whereConditions.push('t.dueDate >= ?');
            queryParams.push(filters.dateFrom);
        }
        
        if (filters.dateTo) {
            whereConditions.push('t.dueDate <= ?');
            queryParams.push(filters.dateTo);
        }
        
        // Build final query
        const searchQuery = `
            SELECT 
                t.id,
                t.title,
                t.description,
                t.status,
                t.priority,
                t.task_type,
                t.assignedTo,
                u1.username as creator_name,
                u1.full_name as creator_full_name,
                u2.username as assignee_name,
                u2.full_name as assignee_full_name,
                DATE_FORMAT(t.createdAt, '%Y-%m-%d %H:%i:%s') as createdAt,
                DATE_FORMAT(t.dueDate, '%Y-%m-%d %H:%i:%s') as due_date
            FROM tasks t
            LEFT JOIN users u1 ON t.createdBy = u1.id
            LEFT JOIN users u2 ON t.assignedTo = u2.id
            ${whereConditions.length > 0 ? 'WHERE ' + whereConditions.join(' AND ') : ''}
            ORDER BY t.createdAt DESC
            LIMIT 100
        `;
        
        db.query(searchQuery, queryParams, (err, results) => {
            if (err) {
                console.error('Error executing search:', err);
                return res.status(500).json({ error: 'Fout bij zoeken' });
            }
            
            // Add empty watchers array to each result
            const resultsWithWatchers = results.map(task => ({
                ...task,
                watchers: []
            }));
            
            res.json(resultsWithWatchers);
        });
        
    } catch (error) {
        console.error('Error in search endpoint:', error);
        res.status(500).json({ error: 'Fout bij zoeken' });
    }
});

// Create subtask
app.post('/api/task-management/subtasks', isAuthenticated, async (req, res) => {
    try {
        const { parent_task_id, title, description, priority, assignedTo, due_date } = req.body;
        const createdBy = req.session.user.id;
        
        if (!title || !title.trim()) {
            return res.status(400).json({ error: 'Titel is verplicht' });
        }
        
        if (!parent_task_id) {
            return res.status(400).json({ error: 'Parent task ID is verplicht' });
        }
        
        const query = `
            INSERT INTO task_subtasks (parent_task_id, title, description, priority, assignedTo, due_date, created_by, created_at)
            VALUES (?, ?, ?, ?, ?, ?, ?, NOW())
        `;
        
        const values = [
            parent_task_id,
            title.trim(),
            description || null,
            priority || 'medium',
            assignedTo || null,
            due_date || null,
            createdBy
        ];
        
        db.query(query, values, (err, result) => {
            if (err) {
                console.error('Error creating subtask:', err);
                return res.status(500).json({ error: 'Fout bij aanmaken subtaak' });
            }
            
            // Fetch the created subtask with user info
            const fetchQuery = `
                SELECT 
                    s.*,
                    u1.username as creator_name,
                    u1.full_name as creator_full_name,
                    u2.username as assignee_name,
                    u2.full_name as assignee_full_name
                FROM task_subtasks s
                LEFT JOIN users u1 ON s.created_by = u1.id
                LEFT JOIN users u2 ON s.assignedTo = u2.id
                WHERE s.id = ?
            `;
            
            db.query(fetchQuery, [result.insertId], (fetchErr, subtasks) => {
                if (fetchErr || subtasks.length === 0) {
                    return res.status(500).json({ error: 'Error fetching created subtask' });
                }
                
                res.status(201).json(subtasks[0]);
            });
        });
    } catch (error) {
        console.error('Error creating subtask:', error);
        res.status(500).json({ error: 'Fout bij aanmaken subtaak' });
    }
});

