// Update user profile
app.put('/api/task-management/profile', isAuthenticated, async (req, res) => {
    try {
        const userId = req.session.user.id;
        const { fullName, email } = req.body;
        
        if (!fullName || !fullName.trim()) {
            return res.status(400).json({ error: 'Volledige naam is verplicht' });
        }
        
        if (!email || !email.trim()) {
            return res.status(400).json({ error: 'Email adres is verplicht' });
        }
        
        // Validate email format
        const emailRegex = /^[^\s@]+@[^\s@]+\.[^\s@]+$/;
        if (!emailRegex.test(email.trim())) {
            return res.status(400).json({ error: 'Ongeldig email adres formaat' });
        }
        
        // Check if email is already in use by another user
        const checkEmailQuery = 'SELECT id FROM users WHERE email = ? AND id != ?';
        
        db.query(checkEmailQuery, [email.trim(), userId], (checkErr, existingUsers) => {
            if (checkErr) {
                console.error('Error checking email:', checkErr);
                return res.status(500).json({ error: 'Database error' });
            }
            
            if (existingUsers.length > 0) {
                return res.status(400).json({ error: 'Dit email adres is al in gebruik door een andere gebruiker' });
            }
            
            // Update user profile
            const updateQuery = 'UPDATE users SET full_name = ?, email = ? WHERE id = ?';
            
            db.query(updateQuery, [fullName.trim(), email.trim(), userId], (updateErr, result) => {
                if (updateErr) {
                    console.error('Error updating user profile:', updateErr);
                    return res.status(500).json({ error: 'Fout bij bijwerken profiel' });
                }
                
                if (result.affectedRows === 0) {
                    return res.status(404).json({ error: 'Gebruiker niet gevonden' });
                }
                
                // Update session data
                req.session.user.full_name = fullName.trim();
                req.session.user.email = email.trim();
                
                // Return updated user data
                res.json({
                    id: userId,
                    username: req.session.user.username,
                    full_name: fullName.trim(),
                    email: email.trim(),
                    role: req.session.user.role
                });
            });
        });
    } catch (error) {
        console.error('Error updating user profile:', error);
        res.status(500).json({ error: 'Fout bij bijwerken profiel' });
    }
});

// Items to Pack Report API (simplified version without packer/timer data)
app.get('/api/items_to_pack_report', (req, res) => {
    const { date } = req.query;
    
    if (!date) {
        return res.status(400).json({ error: 'Datum is verplicht' });
    }

    const reportDate = new Date(date);
    const oneDayAgo = new Date(reportDate);
    oneDayAgo.setDate(oneDayAgo.getDate() - 1);
    const oneDayAgoStr = oneDayAgo.toISOString().split('T')[0];

    // Query to get items that were still to pack on the selected date
    // This includes: current unpacked items + items that were packed after the selected date
    const itemsToPackOnDateQuery = `
        SELECT 
            SUM(amount) as total_quantity,
            COUNT(*) as total_lines,
            SUM(CASE WHEN date_added < ? THEN amount ELSE 0 END) as backlog_quantity
        FROM (
            -- Current unpacked items that existed on or before the selected date
            SELECT amount, date_added 
            FROM items_to_pack 
            WHERE date_added <= ?
            
            UNION ALL
            
            -- Items that were packed after the selected date (so they were still to pack on that date)
            SELECT amount, date_added 
            FROM packed_items 
            WHERE date_added <= ? AND date_packed > ?
        ) as items_on_date
    `;

    // Query to get packed items for the specific date (this is historical)
    const packedTodayQuery = `
        SELECT 
            COUNT(*) as packed_lines,
            SUM(amount) as packed_quantity
        FROM packed_items 
        WHERE DATE(date_packed) = ?
    `;

    // Query to get backlog breakdown by age on the selected date
    const backlogByAgeQuery = `
        SELECT 
            DATEDIFF(?, date_added) as days_old,
            COUNT(*) as count,
            SUM(amount) as quantity
        FROM (
            -- Current unpacked items that existed on or before the selected date
            SELECT amount, date_added 
            FROM items_to_pack 
            WHERE date_added <= ? AND date_added < ?
            
            UNION ALL
            
            -- Items that were packed after the selected date (so they were still to pack on that date)
            SELECT amount, date_added 
            FROM packed_items 
            WHERE date_added <= ? AND date_added < ? AND date_packed > ?
        ) as items_on_date
        GROUP BY DATEDIFF(?, date_added)
        HAVING days_old > 0
        ORDER BY days_old DESC
    `;

    // Execute all queries
    Promise.all([
        new Promise((resolve, reject) => {
            db.query(itemsToPackOnDateQuery, [oneDayAgoStr, date, date, date], (err, results) => {
                if (err) reject(err);
                else resolve(results[0]);
            });
        }),
        new Promise((resolve, reject) => {
            db.query(packedTodayQuery, [date], (err, results) => {
                if (err) reject(err);
                else resolve(results[0]);
            });
        }),
        new Promise((resolve, reject) => {
            db.query(backlogByAgeQuery, [date, date, oneDayAgoStr, date, oneDayAgoStr, date, date], (err, results) => {
                if (err) reject(err);
                else resolve(results);
            });
        })
    ])
    .then(([itemsData, packedData, backlogData]) => {
        console.log('Items data for date:', itemsData);
        console.log('Packed data:', packedData);
        console.log('Backlog breakdown query result:', backlogData);

        // Transform backlog data to match frontend expectations
        const backlogByAge = backlogData.map(item => ({
            daysOld: item.days_old,
            count: item.quantity, // Use quantity instead of count
            percentage: 0 // Will be calculated below
        }));

        // Calculate percentages for backlog breakdown
        const totalBacklogQuantity = backlogByAge.reduce((sum, item) => sum + item.count, 0);
        if (totalBacklogQuantity > 0) {
            backlogByAge.forEach(item => {
                item.percentage = (item.count / totalBacklogQuantity) * 100;
            });
        }

        // Use field names that match what the frontend expects
        const response = {
            date: date,
            totalQuantity: itemsData.total_quantity || 0,
            totalLines: itemsData.total_lines || 0,
            backlogQuantity: itemsData.backlog_quantity || 0,
            priorityQuantity: 0, // We don't have priority data anymore
            packedQuantity: packedData.packed_quantity || 0,
            packedLines: packedData.packed_lines || 0,
            backlogByAge: backlogByAge
        };

        res.json(response);
    })
    .catch(error => {
        console.error('Error generating items to pack report:', error);
        res.status(500).json({ error: 'Fout bij genereren rapport' });
    });
});

