// API endpoint voor barcode generatie (optioneel - server-side)
app.post('/api/barcode/generate', async (req, res) => {
    try {
        const { text, format = 'CODE128', width = 2, height = 80 } = req.body;
        
        if (!text || typeof text !== 'string') {
            return res.status(400).json({ 
                error: 'Text is required and must be a string' 
            });
        }

        if (text.length > 100) {
            return res.status(400).json({ 
                error: 'Text cannot exceed 100 characters' 
            });
        }

        // Validatie voor specifieke formaten
        const validFormats = ['CODE128', 'CODE39', 'EAN13', 'EAN8', 'UPC'];
        if (!validFormats.includes(format)) {
            return res.status(400).json({ 
                error: 'Invalid barcode format' 
            });
        }

        // Format-specifieke validatie
        switch(format) {
            case 'EAN13':
                if (!/^\d{12,13}$/.test(text)) {
                    return res.status(400).json({ 
                        error: 'EAN13 requires 12 or 13 digits' 
                    });
                }
                break;
            case 'EAN8':
                if (!/^\d{7,8}$/.test(text)) {
                    return res.status(400).json({ 
                        error: 'EAN8 requires 7 or 8 digits' 
                    });
                }
                break;
            case 'UPC':
                if (!/^\d{11,12}$/.test(text)) {
                    return res.status(400).json({ 
                        error: 'UPC requires 11 or 12 digits' 
                    });
                }
                break;
        }

        const barcodeData = {
            text: text,
            format: format,
            width: parseInt(width),
            height: parseInt(height),
            timestamp: new Date().toISOString(),
            id: Date.now().toString()
        };

        res.json({
            success: true,
            data: barcodeData,
            message: 'Barcode data generated successfully'
        });

    } catch (error) {
        console.error('Barcode generation error:', error);
        res.status(500).json({ 
            error: 'Internal server error during barcode generation' 
        });
    }
});

