// API endpoint om barcode te valideren (optioneel)
app.post('/api/barcode/validate', (req, res) => {
    try {
        const { text, format } = req.body;
        
        if (!text || !format) {
            return res.status(400).json({ 
                error: 'Text and format are required' 
            });
        }

        let isValid = true;
        let validationMessage = 'Barcode is valid';

        // Validatie logica
        switch(format) {
            case 'CODE128':
                // CODE128 accepteert bijna alle ASCII karakters
                isValid = /^[\x00-\x7F]*$/.test(text);
                if (!isValid) validationMessage = 'CODE128 supports ASCII characters only';
                break;
                
            case 'CODE39':
                // CODE39 ondersteunt beperkte karakterset
                isValid = /^[A-Z0-9\-. $/+%]*$/.test(text);
                if (!isValid) validationMessage = 'CODE39 supports uppercase letters, numbers, and specific symbols only';
                break;
                
            case 'EAN13':
                isValid = /^\d{12,13}$/.test(text);
                if (!isValid) validationMessage = 'EAN13 requires exactly 12 or 13 digits';
                break;
                
            case 'EAN8':
                isValid = /^\d{7,8}$/.test(text);
                if (!isValid) validationMessage = 'EAN8 requires exactly 7 or 8 digits';
                break;
                
            case 'UPC':
                isValid = /^\d{11,12}$/.test(text);
                if (!isValid) validationMessage = 'UPC requires exactly 11 or 12 digits';
                break;
                
            default:
                isValid = false;
                validationMessage = 'Unsupported barcode format';
        }

        res.json({
            success: true,
            data: {
                text: text,
                format: format,
                isValid: isValid,
                message: validationMessage
            }
        });

    } catch (error) {
        console.error('Barcode validation error:', error);
        res.status(500).json({ 
            error: 'Internal server error during validation' 
        });
    }
});

// Nieuwe API endpoint voor automatische prijssynchronisatie
app.post('/api/prepack/sync_price_to_all', (req, res) => {
    const { itemNumber, priceType, newValue, houtkosten, hulpstoffenkosten } = req.body;
    
    if (!itemNumber) {
        return res.status(400).json({ error: 'itemNumber is verplicht' });
    }
    
    try {
        console.log(`Starting automatic price sync for item ${itemNumber}, type: ${priceType}, value: ${newValue}`);
        
        // Bepaal welke update query we nodig hebben
        if (priceType === 'selling_price' || priceType === 'material_cost') {
            // Update standaard prijzen in item_prices tabel
            const column = priceType === 'selling_price' ? 'selling_price' : 'material_cost';
            
            db.query(
                `UPDATE item_prices SET ${column} = ?, updated_at = CURRENT_TIMESTAMP WHERE item_number = ?`,
                [newValue, itemNumber],
                (err, result) => {
                    if (err) {
                        console.error(`Fout bij synchroniseren ${priceType} voor ${itemNumber}:`, err);
                        return res.status(500).json({ error: `Database fout bij synchroniseren ${priceType}` });
                    }
                    
                    console.log(`Synchronized ${priceType} for item ${itemNumber}: ${result.affectedRows} rows updated`);
                    res.json({ 
                        success: true, 
                        message: `${priceType} voor item ${itemNumber} gesynchroniseerd`,
                        affectedRows: result.affectedRows
                    });
                }
            );
        } else if (priceType === 'material_details' && (houtkosten !== undefined || hulpstoffenkosten !== undefined)) {
            // Update gedetailleerde materiaalkosten (houtkosten en hulpstoffenkosten)
            
            // Eerst controleren of het item bestaat in item_prices
            db.query(
                'SELECT id FROM item_prices WHERE item_number = ?',
                [itemNumber],
                (err, results) => {
                    if (err) {
                        console.error(`Fout bij zoeken item ${itemNumber}:`, err);
                        return res.status(500).json({ error: 'Database fout bij zoeken item' });
                    }
                    
                    const hout = parseFloat(houtkosten) || 0;
                    const hulpstoffen_cost = parseFloat(hulpstoffenkosten) || 0;
                    const total_material_cost = hout + hulpstoffen_cost;
                    
                    if (results.length > 0) {
                        // Update bestaand record
                        db.query(
                            'UPDATE item_prices SET houtkosten = ?, materiaalkosten = ?, material_cost = ?, updated_at = CURRENT_TIMESTAMP WHERE item_number = ?',
                            [hout, hulpstoffen_cost, total_material_cost, itemNumber],
                            (updateErr, updateResult) => {
                                if (updateErr) {
                                    console.error(`Fout bij updaten materiaaldetails voor ${itemNumber}:`, updateErr);
                                    return res.status(500).json({ error: 'Database fout bij updaten materiaaldetails' });
                                }
                                
                                console.log(`Synchronized material details for item ${itemNumber}: ${updateResult.affectedRows} rows updated`);
                                res.json({ 
                                    success: true, 
                                    message: `Materiaaldetails voor item ${itemNumber} gesynchroniseerd`,
                                    affectedRows: updateResult.affectedRows,
                                    houtkosten: hout,
                                    hulpstoffenkosten: hulpstoffen_cost,
                                    totalMaterialCost: total_material_cost
                                });
                            }
                        );
                    } else {
                        // Maak nieuw record aan
                        db.query(
                            'INSERT INTO item_prices (item_number, houtkosten, materiaalkosten, material_cost, selling_price) VALUES (?, ?, ?, ?, ?)',
                            [itemNumber, hout, hulpstoffen_cost, total_material_cost, 0],
                            (insertErr, insertResult) => {
                                if (insertErr) {
                                    console.error(`Fout bij invoegen materiaaldetails voor ${itemNumber}:`, insertErr);
                                    return res.status(500).json({ error: 'Database fout bij invoegen materiaaldetails' });
                                }
                                
                                console.log(`Created new item with material details for ${itemNumber}: ${insertResult.affectedRows} rows inserted`);
                                res.json({ 
                                    success: true, 
                                    message: `Nieuw item ${itemNumber} aangemaakt met materiaaldetails`,
                                    affectedRows: insertResult.affectedRows,
                                    houtkosten: hout,
                                    hulpstoffenkosten: hulpstoffen_cost,
                                    totalMaterialCost: total_material_cost
                                });
                            }
                        );
                    }
                }
            );
        } else {
            return res.status(400).json({ error: 'Ongeldig priceType of ontbrekende gegevens' });
        }
        
    } catch (error) {
        console.error('Fout bij automatische prijssynchronisatie:', error);
        res.status(500).json({ 
            error: 'Server fout bij automatische prijssynchronisatie', 
            details: error.message 
        });
    }
});

// POST endpoint for /api/order_items to handle large lists of items in request body
app.post('/api/order_items', (req, res) => {
    const { items } = req.body;
    
    if (!items || !Array.isArray(items) || items.length === 0) {
        return res.status(400).json({ message: 'Items array is required in request body' });
    }
    
    const placeholders = items.map(() => '?').join(',');
    
    // Query focuses on just the essential columns you highlighted
    const query = `
        SELECT 
            item_nummer, 
            item_naam,
            hout_kost, 
            hulpstoffen
        FROM order_items 
        WHERE item_nummer IN (${placeholders}) OR item_naam IN (${placeholders})
    `;
    
    const params = [...items, ...items];
    
    db.query(query, params, (err, results) => {
        if (err) {
            console.error('Error fetching from order_items:', err);
            return res.status(500).json({ message: 'Database error' });
        }
        
        res.json(results);
    });
});
  
